FS.policy.canReleasePayment = function (rawRole, cid) {
  const role = FS.role.normalize(rawRole);
  const mode = FS.control.get(cid);

  if (role === "owner") return true;
  if (mode === FS.control.MODES.OWNER) return true;

  if (mode === FS.control.MODES.ASSISTED) {
    return ["manager", "cfo"].includes(role);
  }

  // Controlled: CFO only (matches backend)
  return ["cfo"].includes(role);
};

FS.policy.requiresVendorVerifiedForPayment = function (cid, vendor) {
  const mode = FS.control.get(cid);

  // owner-managed: never block
  if (mode === FS.control.MODES.OWNER) return false;

  // assisted but review disabled: don't block
  if (mode === FS.control.MODES.ASSISTED && !FS.control.isReviewEnabled?.(cid)) return false;

  // if compliance is required, enforce verified
  const required = (vendor?.compliance_required ?? vendor?.complianceRequired) === true;

  // also enforce if vendor status is blocked
  const vStatus = String(vendor?.vendor_status || vendor?.vendorStatus || "").toLowerCase();
  if (vStatus === "blocked") return true;

  if (!required) return false;

  const cStatus = String(vendor?.compliance_status || vendor?.complianceStatus || "draft").toLowerCase();
  return cStatus !== "verified";
};

