FS.policy.ppeReviewRequired = function (cid, action) {
  const id = FS.control.resolveCid(cid);
  const pol = FS.policy.companyPolicy?.[id] || {};
  const mode = FS.control.get(id);

  // Owner-managed: only if explicitly enabled for PPE
  if (mode === FS.control.MODES.OWNER) {
    return !!pol.ppe_review_enabled;
  }

  // Controlled: always require review
  if (mode === FS.control.MODES.CONTROLLED) return true;

  // Assisted: require review if enabled
  return !!pol.ppe_review_enabled;
};

