FS.ui.promptReviewChoice = function (cid) {
  const id = FS.control.resolveCid(cid);
  if (!id) return;

  const mode = FS.control.get(id);
  if (mode !== FS.control.MODES.ASSISTED) return;

  const policy = window.CURRENT_COMPANY?.credit_policy || {};

  console.log("[promptReviewChoice]", {
    id,
    mode,
    policyMode: policy.mode,
    review_choice_made: policy.review_choice_made,
    review_enabled: policy.review_enabled,
  });

  if (policy.review_choice_made === true) return;

  const snoozeKey = `fs.review_choice_snooze.${id}`;
  const snoozeUntil = Number(localStorage.getItem(snoozeKey) || 0);
  if (Date.now() < snoozeUntil) return;

  if (document.getElementById("fsReviewChoiceBanner")) return;

  const banner = document.createElement("div");
  banner.id = "fsReviewChoiceBanner";
  banner.className =
    "fixed bottom-4 left-4 right-4 md:left-auto md:right-4 md:w-[420px] z-[9999] " +
    "bg-white border border-slate-200 shadow-lg rounded-xl p-4";

  banner.innerHTML = `
    <div class="text-sm font-semibold text-slate-800">Invoice review mode (Assisted)</div>
    <div class="text-xs text-slate-600 mt-1">
      Choose how invoices behave:
      <ul class="list-disc ml-5 mt-1">
        <li><b>Stay relaxed</b>: save + post + journal can happen without review.</li>
        <li><b>Activate review</b>: clerks draft only; approvers post/journal.</li>
      </ul>
    </div>
    <div class="flex gap-2 mt-3">
      <button id="fsStayRelaxed" class="flex-1 text-xs px-3 py-2 rounded-lg border border-slate-200 hover:bg-slate-50">
        Stay relaxed
      </button>
      <button id="fsActivateReview" class="flex-1 text-xs px-3 py-2 rounded-lg bg-slate-900 text-white hover:opacity-90">
        Activate review
      </button>
    </div>
    <button id="fsReviewChoiceClose" class="mt-2 text-[11px] text-slate-500 underline">
      Decide later
    </button>
  `;

  document.body.appendChild(banner);

  const close = () => banner.remove();

  document.getElementById("fsStayRelaxed")?.addEventListener("click", async () => {
    try {
      await FS.policy.setCompanyPolicy(id, { mode: "assisted", review_enabled: false, review_choice_made: true });
    } finally { close(); }

    await ensureCompanyDataLoaded?.();
    FS.control.syncFromCompany?.(window.CURRENT_COMPANY);
    applyInvoiceButtonsByMode?.();
  });

  document.getElementById("fsActivateReview")?.addEventListener("click", async () => {
    try {
      await FS.policy.setCompanyPolicy(id, { mode: "assisted", review_enabled: true, review_choice_made: true });
    } finally { close(); }

    await ensureCompanyDataLoaded?.();
    FS.control.syncFromCompany?.(window.CURRENT_COMPANY);
    applyInvoiceButtonsByMode?.();
  });

  document.getElementById("fsReviewChoiceClose")?.addEventListener("click", () => {
    // optional snooze
    localStorage.setItem(snoozeKey, String(Date.now() + 24 * 60 * 60 * 1000));
    close();
  });
};
