FS.modePrompt = FS.modePrompt || {};

FS.modePrompt.open = function openModePrompt({ title, message, bullets, enableLabel, keepLabel, onEnable, onKeep }) {
  const overlay = document.getElementById("modePromptOverlay");
  const msgEl = document.getElementById("fspMessage");
  const titleEl = document.getElementById("fspTitle");
  const bulletsEl = document.getElementById("fspBullets");
  const btnKeep = document.getElementById("fspKeep");
  const btnEnable = document.getElementById("fspEnable");
  const btnClose = document.getElementById("fspClose");

  if (!overlay || !msgEl || !btnKeep || !btnEnable) return;

  titleEl.textContent = title || "Workflow suggestion";
  msgEl.textContent = message || "";

  bulletsEl.innerHTML = "";
  if (Array.isArray(bullets) && bullets.length) {
    bulletsEl.innerHTML = `<ul>${bullets.map(b => `<li>${escapeHtml(String(b))}</li>`).join("")}</ul>`;
  }

  btnEnable.textContent = enableLabel || "Enable";
  btnKeep.textContent = keepLabel || "Keep current";

  function close() {
    overlay.classList.add("hidden");
    overlay.onclick = null;
    btnClose.onclick = null;
    btnKeep.onclick = null;
    btnEnable.onclick = null;
  }

  overlay.classList.remove("hidden");

  overlay.onclick = (e) => {
    if (e.target === overlay) close();
  };
  btnClose.onclick = () => {
    onKeep?.();
    close();
  };
  btnKeep.onclick = () => {
    onKeep?.();
    close();
  };
  btnEnable.onclick = async () => {
    try { await onEnable?.(); }
    finally { close(); }
  };
};

