// =====================================================
// Money / currency helpers (single source of truth)
// =====================================================

// 1) Set this when company context loads (from backend)
// Example: window.setCompanyCurrency(company.currency)
window.CURRENT_CURRENCY = null;

window.setCompanyCurrency = function setCompanyCurrency(code) {
  const c = String(code || "").trim().toUpperCase();
  window.CURRENT_CURRENCY = c || null;
};

// 2) Resolve currency with clear priority
function resolveCurrency(currency) {
  return (
    String(currency || "").trim().toUpperCase() ||
    String(window.CURRENT_CURRENCY || "").trim().toUpperCase() ||
    String(window.CURRENT_COMPANY?.currency || "").trim().toUpperCase() || // if you store it here
    String(document.getElementById("invCurrency")?.value || "").trim().toUpperCase() ||
    String(document.getElementById("billCurrency")?.value || "").trim().toUpperCase() ||
    "USD" // ultimate fallback (choose USD as safest global default)
  );
}
window.resolveCurrency = resolveCurrency;

// 3) Main formatter (use everywhere)
window.money = function money(n, currency) {
  const x = Number(n || 0);
  const cur = resolveCurrency(currency);

  // If currency code is invalid, Intl throws. Fall back to a plain number.
  try {
    return new Intl.NumberFormat(undefined, {
      style: "currency",
      currency: cur,
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    }).format(Number.isFinite(x) ? x : 0);
  } catch (_) {
    // fallback: "1234.56 CUR"
    const safe = Number.isFinite(x) ? x : 0;
    return `${safe.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })} ${cur}`;
  }
};

// 4) Backwards-compatible alias (so old code keeps working)
window.fmtMoney = function fmtMoney(n, currency) {
  return window.money(n, currency);
};

// 6) Plain 2dp number (no currency symbol) for inputs
function fmt2(x) {
  const n = Number(String(x ?? "0").replace(/,/g, "")) || 0;
  return n.toFixed(2);
}
window.fmt2 = fmt2;

// 7) Set either .value (inputs) or .textContent (labels)
// NOTE: This is numeric 2dp, not currency formatted (good for inputs)
function setMoney(id, val) {
  const el = document.getElementById(id);
  if (!el) return;
  const v = fmt2(val);
  if ("value" in el) el.value = v;
  else el.textContent = v;
}
window.setMoney = setMoney;

// 8) Parse money strings safely ("1,234.56", "R 1 234,56", etc.)
function parseMoney(v) {
  const s = String(v ?? "")
    .replace(/\s/g, "")
    .replace(/,/g, "")
    .replace(/[^\d.-]/g, "");

  const n = parseFloat(s);
  return Number.isFinite(n) ? n : 0;
}
window.parseMoney = parseMoney;

