  // ==========================================================
  // 10) MAP helper (safe here)
  // ==========================================================
  let companyMap;
  let companyMapMarker;

  function initCompanyMapFromAddress(address) {
    const mapEl = document.getElementById("companyMap");
    if (!mapEl || !address) return;

    if (!window.google || !google.maps || !google.maps.Geocoder) {
      console.warn("Google Maps not available, skipping company map.");
      return;
    }

    const geocoder = new google.maps.Geocoder();
    geocoder.geocode({ address }, function (results, status) {
      if (status !== "OK" || !results || !results.length) {
        console.warn("Geocode failed:", status);
        return;
      }

      const loc = results[0].geometry.location;

      if (!companyMap) {
        companyMap = new google.maps.Map(mapEl, { center: loc, zoom: 15, mapTypeId: "roadmap" });
      } else {
        companyMap.setCenter(loc);
      }

      if (companyMapMarker) companyMapMarker.setMap(null);

      companyMapMarker = new google.maps.Marker({
        map: companyMap,
        position: loc,
        title: "Registered Address",
      });
    });
  }
  window.initCompanyMapFromAddress = initCompanyMapFromAddress;

