  function applyLoggedOutUI() {
    const signinBtn = document.getElementById("signinBtn");
    const signupBtn = document.getElementById("signupBtn");
    const logoutBtn = document.getElementById("logoutBtn");
    const dateRange = document.getElementById("dateRange");
    const refreshBtn = document.getElementById("refreshBtn");
    const companyBadge = document.getElementById("companyBadge");
    const userAvatar = document.getElementById("userAvatar");
    const roleBadge = document.getElementById("roleBadge");
    const userMenu = document.getElementById("userMenu");

    signinBtn && signinBtn.classList.remove("hidden");
    if (signupBtn) signupBtn.classList.remove("hidden");

    logoutBtn && logoutBtn.classList.add("hidden");
    dateRange && dateRange.classList.add("hidden");
    refreshBtn && refreshBtn.classList.add("hidden");
    roleBadge && roleBadge.classList.add("hidden");
    userMenu && userMenu.classList.add("hidden");

    if (companyBadge) {
      companyBadge.textContent = "Your company";
      companyBadge.classList.add("hidden");
    }
    if (userAvatar) userAvatar.textContent = "??";
  }
window.applyLoggedOutUI = applyLoggedOutUI; // ✅ export

  function applyAuthUI(user) {
    const signinBtn = document.getElementById("signinBtn");
    const signupBtn = document.getElementById("signupBtn");
    const logoutBtn = document.getElementById("logoutBtn");
    const dateRange = document.getElementById("dateRange");
    const refreshBtn = document.getElementById("refreshBtn");
    const companyBadge = document.getElementById("companyBadge");
    const userAvatar = document.getElementById("userAvatar");
    const roleBadge = document.getElementById("roleBadge");
    const userMenu = document.getElementById("userMenu");

    if (!user) {
      applyLoggedOutUI();
      return;
    }

    const storedCompany =
      user.company_name ||
      (user.company && user.company.name) ||
      store.get("companyName", "Your company");

    store.set("companyName", storedCompany);

    if (companyBadge) {
      companyBadge.textContent = storedCompany;
      companyBadge.classList.remove("hidden");
    }

    const rawRole =
      (user && (user.role || user.system_role || user.user_role)) ||
      window.FS_USER_ROLE ||
      store.get("userRole", "viewer");

    const appRole = window.normalizeRole(rawRole);
    const roleLabel = window.ROLE_LABELS[appRole] || appRole;

    store.set("userRole", appRole);
    window.FS_USER_ROLE = appRole;

    if (roleBadge) {
      roleBadge.textContent = roleLabel;
      roleBadge.classList.remove("hidden");
    }

    const email = user.email || store.get("userEmail", "") || "";
    const initials = email ? email[0].toUpperCase() : "U";
    if (userAvatar) userAvatar.textContent = initials;

    if (userMenu) userMenu.classList.remove("hidden");

    const accEmail = document.getElementById("accEmail");
    const accRole = document.getElementById("accRole");
    const accCompany = document.getElementById("accCompany");
    if (accEmail) accEmail.textContent = email || "—";
    if (accRole) accRole.textContent = roleLabel;
    if (accCompany) accCompany.textContent = storedCompany;

    signinBtn?.classList.add("hidden");
    signupBtn?.classList.add("hidden");
    logoutBtn?.classList.remove("hidden");
    dateRange?.classList.remove("hidden");
    refreshBtn?.classList.remove("hidden");
  }

