  // Optional: load current user helper
  window.loadCurrentUser = async function loadCurrentUser() {
    if (typeof window.apiFetch !== "function") {
      console.error("❌ loadCurrentUser: apiFetch not defined.");
      return null;
    }
    if (!window.ENDPOINTS?.auth?.me) {
      console.error("❌ loadCurrentUser: ENDPOINTS.auth.me missing");
      return null;
    }

    try {
      const me = await window.apiFetch(window.ENDPOINTS.auth.me, { method: "GET" });
      window.currentUser = me;
      console.log("[Auth] User loaded successfully:", me);
      return me;
    } catch (err) {
      console.error("[Auth] loadCurrentUser failed:", err);
      return null;
    }
  };

  async function handleLoginSubmission(event) {
    if (event && event.preventDefault) event.preventDefault();

    const email = document.getElementById("loginEmail")?.value.trim().toLowerCase();
    const password = document.getElementById("loginPassword")?.value;

    try {
      const res = await fetch(ENDPOINTS.auth.signin, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ email, password }),
      });

      const data = await res.json();
      console.log("Signin response:", data);

      if (!res.ok) {
        alert(data.detail || data.error || "Login failed");
        return;
      }

      setToken(data.token, true);
      localStorage.setItem("token", data.token);

      store.set("userEmail", email);

      const user = data.user || {};

      const companyName = user.company_name || (user.company && user.company.name);

      if (typeof updateCompanyProfileFromUser === "function") {
        updateCompanyProfileFromUser(user);
      }

      if (companyName) store.set("companyName", companyName);

      if (user.company_id != null) {
        localStorage.setItem(COMPANY_KEY, String(user.company_id));
        localStorage.setItem("company_id", String(user.company_id));
      }

      if (typeof refreshCompanyStore === "function") refreshCompanyStore();

      if (user.industry) store.set("fs_industry", user.industry);
      if (user.sub_industry) store.set("fs_subindustry", user.sub_industry);

      let rawRole = (user && (user.role || user.system_role)) || null;
      if (rawRole) {
        const lowered = String(rawRole).toLowerCase();
        let normalized = lowered;
        if (lowered === "owner") normalized = "cfo";
        store.set("userRole", normalized);
        window.FS_USER_ROLE = normalized;
      }

      if (!store.get(K.TRIAL)) store.set(K.TRIAL, "1");

      // if you have applyLoggedInUI elsewhere, keep it
      if (typeof applyLoggedInUI === "function") applyLoggedInUI();
      applyAuthUI(user);

      const intended = localStorage.getItem("fs:intended_screen");
      if (intended) {
        localStorage.removeItem("fs:intended_screen");
        // If you are still on signin.html, redirect back to app shell
        // If signin.html is the same app shell, just switchScreen(intended)
        try { window.switchScreen?.(intended); } catch (e) {}
      }

      // IMPORTANT: bootstrapApp must be defined later in file
      if (typeof bootstrapApp === "function") {
        await bootstrapApp(user);
      } else {
        console.warn("bootstrapApp not defined yet (will run later if you call it).");
      }
    } catch (e) {
      console.error("Login error:", e);
      alert("Network error logging in.");
    }
  }
  window.handleLoginSubmission = handleLoginSubmission;

function renderNavTree(items) {
  const menu = document.getElementById("sidebarMenu");
  if (!menu) return;

  function nodeIcon(node, fallback = "•") {
    return node.icon || fallback;
  }

  function renderNode(node, depth = 0) {
    const pad = 10 + depth * 14; // indentation per level

    // If it has children, render as a group header (not clickable unless it has screen)
    const hasKids = Array.isArray(node.children) && node.children.length > 0;

    // clickable item if it has screen
    const isClickable = !!node.screen;

    const row = `
      <div class="${depth === 0 ? "nav-parent-row" : "nav-child-row"}"
           style="display:flex; align-items:center; gap:10px; padding:8px 10px; padding-left:${pad}px;">
        <span class="nav-ico" style="width:22px; display:inline-flex; justify-content:center;">
          ${nodeIcon(node)}
        </span>

        ${
          isClickable
            ? `<button class="nav-item-link"
                       data-nav="${node.screen}"
                       style="all:unset; cursor:pointer; flex:1;">
                 <span style="font-weight:${depth === 0 ? 600 : 500};">${node.name}</span>
               </button>`
            : `<span style="font-weight:${depth === 0 ? 600 : 500};">${node.name}</span>`
        }
      </div>
    `;

    const kids = hasKids
      ? `<div class="nav-children">
           ${node.children.map(ch => renderNode(ch, depth + 1)).join("")}
         </div>`
      : "";

    // wrap parent
    return `
      <div class="${depth === 0 ? "nav-parent" : "nav-child"}">
        ${row}
        ${kids}
      </div>
    `;
  }

  menu.innerHTML = items.map(p => renderNode(p, 0)).join("");

  // ✅ wire clicks (works for all nested levels)
  menu.querySelectorAll(".nav-item-link[data-nav]").forEach(btn => {
    btn.addEventListener("click", async (e) => {
      e.preventDefault();
      e.stopPropagation();
      const screen = btn.getAttribute("data-nav");
      await window.switchScreen?.(screen);
    });
  });
}

window.__FS_DASHBOARD_CACHE__ = window.__FS_DASHBOARD_CACHE__ || null;
window.__FS_DASHBOARD_CACHE_KEY__ = window.__FS_DASHBOARD_CACHE_KEY__ || "";

async function getDashboardData(periodKey = "this_month", { force = false } = {}) {
  const cid = getActiveCompanyId?.() || window.CURRENT_COMPANY_ID;
  if (!cid) return null;

  const cacheKey = `${cid}::${periodKey}`;

  if (!force && window.__FS_DASHBOARD_CACHE__ && window.__FS_DASHBOARD_CACHE_KEY__ === cacheKey) {
    return window.__FS_DASHBOARD_CACHE__;
  }

  const snap = await apiFetch(
    ENDPOINTS.dashboardSnapshot(cid, {
      preset: periodKey,
      method: "direct",
    })
  );

  window.__FS_DASHBOARD_CACHE__ = snap || null;
  window.__FS_DASHBOARD_CACHE_KEY__ = cacheKey;

  return window.__FS_DASHBOARD_CACHE__;
}

