async function fetchCompanyUsers(companyId) {
  return apiFetch(ENDPOINTS.companyUsers(companyId), { method: "GET" });
}

async function refreshUsersScreen() {
  const cid = getActiveCompanyId?.() || window.CURRENT_COMPANY_ID;
  if (!cid) return;

  const payload = await fetchCompanyUsers(cid);

  // keep this around for your "invite owner" logic if you want
  window.CURRENT_COMPANY_OWNER_USER_ID = payload?.owner_user_id || null;

  renderUsersTable(payload);      // <-- updated signature (payload)
  bindUserRowClicks?.(cid);       // <-- if you added the “edit role” modal
}

function canEditRoles() {
  const r = FS.role.normalize(getCurrentRole?.() || "");
  return ["owner", "admin", "cfo"].includes(r);
}

function fillRoleSelect(sel, current) {
  const roles = ["viewer","clerk","assistant","junior","senior","manager","accountant","cfo","admin","owner"];
  sel.innerHTML = roles.map(r =>
    `<option value="${esc(r)}"${r===current ? " selected" : ""}>${esc(r)}</option>`
  ).join("");
}

function isSeniorFullAccess() {
  const role = window.normalizeRole?.(window.getCurrentRole?.() || localStorage.getItem("userRole") || "viewer");
  return role === "senior";
}
window.isSeniorFullAccess = isSeniorFullAccess;

function openRoleModal({ companyId, userId, email, role }) {
  if (!canEditRoles()) return;

  const modal = document.getElementById("roleModal");
  const emailEl = document.getElementById("roleModalEmail");
  const sel = document.getElementById("roleModalSelect");
  const msg = document.getElementById("roleModalMsg");

  modal.dataset.companyId = String(companyId);
  modal.dataset.userId = String(userId);

  emailEl.textContent = email;
  fillRoleSelect(sel, role);

  msg.classList.add("hidden");
  msg.textContent = "";

  modal.classList.remove("hidden");
  modal.classList.add("flex");
}

function closeRoleModal() {
  const modal = document.getElementById("roleModal");
  modal.classList.add("hidden");
  modal.classList.remove("flex");
}

function bindUserRowClicks(companyId) {
  document.querySelectorAll("#usersTableBody .user-row").forEach(tr => {
    tr.addEventListener("click", () => {
      if (!canEditRoles()) return;
      openRoleModal({
        companyId,
        userId: tr.dataset.userId,
        email: tr.dataset.email,
        role: tr.dataset.role || "viewer"
      });
    });
  });

  document.getElementById("roleModalClose")?.addEventListener("click", closeRoleModal);
  document.getElementById("roleModalCancel")?.addEventListener("click", closeRoleModal);

  document.getElementById("roleModalSave")?.addEventListener("click", async () => {
    const modal = document.getElementById("roleModal");
    const cid = modal.dataset.companyId;
    const uid = modal.dataset.userId;
    const role = document.getElementById("roleModalSelect").value;

    const msg = document.getElementById("roleModalMsg");
    msg.classList.remove("hidden");
    msg.className = "text-xs mt-2 text-slate-600";

    try {
      await apiFetch(ENDPOINTS.companyUserRole(cid, uid), {
        method: "PATCH",
        body: JSON.stringify({ role })
      });
      msg.textContent = "Role updated.";
      await refreshUsersScreen(); // reload table
      closeRoleModal();
    } catch (e) {
      msg.className = "text-xs mt-2 text-red-600";
      msg.textContent = e?.message || "Failed to update role";
    }
  });
}

function bindRoleModalHandlers() {
  const modal = document.getElementById("roleModal");
  if (!modal) return;

  // ✅ Avoid double-binding (you currently rebind inside refreshUsersScreen)
  if (modal.dataset.bound === "1") return;
  modal.dataset.bound = "1";

  const closeBtn = document.getElementById("roleModalClose");
  const cancelBtn = document.getElementById("roleModalCancel");
  const saveBtn = document.getElementById("roleModalSave");

  const sel = document.getElementById("roleModalSelect");
  const msg = document.getElementById("roleModalMsg");

  // -----------------------------
  // Close helpers
  // -----------------------------
  const safeClose = () => {
    try { closeRoleModal?.(); } catch {}
  };

  closeBtn?.addEventListener("click", safeClose);
  cancelBtn?.addEventListener("click", safeClose);

  // Click outside dialog closes (optional)
  modal.addEventListener("click", (e) => {
    if (e.target === modal) safeClose();
  });

  // ESC closes (optional)
  document.addEventListener("keydown", (e) => {
    if (e.key === "Escape" && !modal.classList.contains("hidden")) safeClose();
  });

  // -----------------------------
  // ✅ Event delegation for user row clicks
  // Works even after table rerender
  // -----------------------------
  document.addEventListener("click", (e) => {
    const row = e.target?.closest?.("#usersTableBody .user-row");
    if (!row) return;

    if (!canEditRoles?.()) return;

    // companyId: prefer active company, fallback to what you passed earlier
    const cid = getActiveCompanyId?.() || window.CURRENT_COMPANY_ID;
    if (!cid) return;

    openRoleModal?.({
      companyId: cid,
      userId: row.dataset.userId,
      email: row.dataset.email,
      role: row.dataset.role || "viewer",
    });
  });

  // -----------------------------
  // Save handler (PATCH role)
  // -----------------------------
  saveBtn?.addEventListener("click", async () => {
    const cid = modal.dataset.companyId;
    const uid = modal.dataset.userId;
    const role = sel?.value;

    if (!cid || !uid) return;

    if (msg) {
      msg.classList.remove("hidden");
      msg.className = "text-xs mt-2 text-slate-600";
      msg.textContent = "Updating role...";
    }

    saveBtn.disabled = true;

    try {
      await apiFetch(ENDPOINTS.companyUserRole(cid, uid), {
        method: "PATCH",
        body: JSON.stringify({ role }),
      });

      if (msg) {
        msg.className = "text-xs mt-2 text-emerald-700";
        msg.textContent = "Role updated.";
      }

      // refresh list + close
      await refreshUsersScreen?.();
      safeClose();
    } catch (e) {
      if (msg) {
        msg.className = "text-xs mt-2 text-red-600";
        msg.textContent = e?.message || "Failed to update role";
      }
    } finally {
      saveBtn.disabled = false;
    }
  });
}

window.hydrateAccountSettings = function hydrateAccountSettings() {
  const u = window.currentUser;
  if (!u) return;

  // Inputs
  const first = document.getElementById("accFirstName");
  const last  = document.getElementById("accLastName");

  // Read-only fields
  const email   = document.getElementById("accEmail");
  const roleEl  = document.getElementById("accRole");
  const company = document.getElementById("accCompany");

  if (first) first.value = u.first_name || u.firstname || "";
  if (last)  last.value  = u.last_name  || u.lastname  || "";

  if (email) email.textContent = u.email || "—";

  if (roleEl) {
    const r = window.normalizeRole?.(u.system_role || u.role);
    roleEl.textContent = window.ROLE_LABELS?.[r] || r || "—";
  }

  if (company) {
    company.textContent =
      u.company_name ||
      u.company?.name ||
      "—";
  }
};

