async function renderUsersTable() {
  const tbody = document.getElementById("usersTableBody");
  const empty = document.getElementById("usersEmpty");
  const countEl = document.getElementById("usersCount");
  if (!tbody) return;

  tbody.innerHTML = `<tr><td colspan="5" class="py-3 px-3 text-sm text-gray-500">Loading users...</td></tr>`;

  let users = [];
  try {
    const data = await apiFetch(window.ENDPOINTS.users);
    users = data.users || [];
  } catch (err) {
    console.warn("Could not load users:", err?.message || err);
    users = [];
  }

  if (!users.length) {
    tbody.innerHTML = "";
    empty?.classList.remove("hidden");
    if (countEl) countEl.textContent = "";
    return;
  }

  empty?.classList.add("hidden");
  if (countEl) countEl.textContent = `${users.length} user${users.length > 1 ? "s" : ""}`;

  tbody.innerHTML = "";
  users.forEach((u) => {
    const tr = document.createElement("tr");
    tr.className = "border-t border-gray-100";

    const systemRole = u.system_role || u.min_role || "viewer";
    const label = ROLE_LABELS?.[systemRole] || systemRole;
    const status = u.is_confirmed ? "Active" : (u.invite_status || "Invite pending");

    tr.innerHTML = `
      <td class="py-2 px-3 text-gray-800">${(u.first_name || "")} ${(u.last_name || "")}</td>
      <td class="py-2 px-3 text-gray-700">${u.email || ""}</td>
      <td class="py-2 px-3 text-gray-500">${u.business_role || "-"}</td>
      <td class="py-2 px-3 text-gray-700">${label}</td>
      <td class="py-2 px-3 text-gray-500">${status}</td>
    `;
    tbody.appendChild(tr);
  });
}
window.renderUsersTable = renderUsersTable;


async function initUsersScreen() {
  if (!isLoggedIn()) return;

  window.toggleInviteAccessScope?.();
  window.populateInviteRoleSelect?.();

  const form = document.getElementById("inviteForm");
  if (!form) return;

  if (form.dataset.bound !== "1") {
    form.dataset.bound = "1";

    document.getElementById("inviteAccessScope")?.addEventListener("change", () => {
      window.populateInviteRoleSelect?.();
    });

    form.addEventListener("submit", async function (e) {
      e.preventDefault();

      const email = document.getElementById("inviteEmail")?.value?.trim() || "";
      const role  = document.getElementById("inviteRole")?.value || "";
      const accessScope = document.getElementById("inviteAccessScope")?.value || "core";

      if (!email || !role) {
        showInviteMessage("Email and role are required.", "error");
        return;
      }

      const btn = form.querySelector('button[type="submit"]');
      if (btn) btn.disabled = true;

      showInviteMessage("Sending invite...", "success");

      try {
        const payload = await sendInvite(email, role, accessScope);

        try {
          await maybePromptAfterInvite(payload?.role || role);
        } catch (e) {
          console.warn("[ModePrompt] maybePromptAfterInvite failed:", e);
        }

        showInviteMessage(`Invite sent to ${email}.`, "success");
        form.reset();

        window.toggleInviteAccessScope?.();
        window.populateInviteRoleSelect?.();

        await refreshUsersScreen();
      } catch (err) {
        showInviteMessage(err?.message || "Failed to send invite.", "error");
      } finally {
        if (btn) btn.disabled = false;
      }
    });

    bindRoleModalHandlers?.();
  }

  await refreshUsersScreen();
}

window.toggleInviteAccessScope = function toggleInviteAccessScope() {
  const wrap = document.getElementById("inviteAccessScopeWrap");
  const sel = document.getElementById("inviteAccessScope");
  if (!wrap || !sel) return;

  const user = window.currentUser || {};
  const isPractitioner =
    String(user.user_type || "").toLowerCase() === "practitioner" ||
    !!user?.dashboards?.practitioner;

  const isEnterprise =
    String(user.user_type || "").toLowerCase() === "enterprise" ||
    !!user?.dashboards?.internal;

  if (isEnterprise && !isPractitioner) {
    wrap.classList.add("hidden");
    sel.value = "core";
    return;
  }

  if (isPractitioner) {
    wrap.classList.remove("hidden");
    if (!sel.value) sel.value = "assignment";
    return;
  }

  wrap.classList.add("hidden");
  sel.value = "core";
};


  // Decide if a nav item should be visible based on COMPANY_PROFILE
function companyAllowsFeature(feature) {
  if (!feature) return true;

  const c = window.CURRENT_COMPANY || {};
  const p = window.COMPANY_PROFILE || {};

  const companyKnown =
    (c && Object.keys(c).length) || (p && Object.keys(p).length);
  if (!companyKnown) return true;

  const inventoryMode = (c.inventory_mode ?? p.inventory_mode ?? "none");
  const usesInventory = String(inventoryMode).toLowerCase() !== "none";

  if (feature === "inventory-module") return usesInventory;
  if (feature === "pos") return usesInventory;          // ✅ POS depends on inventory
  if (feature === "service-billing") return true;       // ✅ allow in hybrid too

  return true;
}

function featureAllowed(feature) {
  if (!feature) return true;

  // Plan flags (keep)
  if (typeof hasFeature === "function" && !hasFeature(feature)) return false;

  // ✅ If company not loaded yet, don't hide menu
  const c = window.CURRENT_COMPANY;
  if (!c) return true;

  // ✅ If companyAllowsFeature not defined, don't hide
  if (typeof companyAllowsFeature !== "function") return true;

  // ✅ If companyAllowsFeature throws, don't hide
  try {
    return companyAllowsFeature(feature);
  } catch (e) {
    console.warn("[featureAllowed] companyAllowsFeature failed:", e);
    return true;
  }
}

  function currentIndustry() {
    // Prefer backend/PROFILE, fall back to in-memory store
    if (CURRENT_COMPANY && CURRENT_COMPANY.industry) {
      return String(CURRENT_COMPANY.industry).toLowerCase();
    }
    if (COMPANY_PROFILE && COMPANY_PROFILE.industry) {
      return String(COMPANY_PROFILE.industry).toLowerCase();
    }
    return (store.get("fs_industry", "") || "").toLowerCase();
  }

function renderUsersTable(payload) {
  const body  = document.getElementById("usersTableBody");
  const empty = document.getElementById("usersEmpty");
  const count = document.getElementById("usersCount");

  const members = payload?.members || [];
  const invites = payload?.invites || [];

  if (count) count.textContent = `${members.length} user${members.length === 1 ? "" : "s"}`;

  if (!members.length && !invites.length) {
    if (body) body.innerHTML = "";
    empty?.classList.remove("hidden");
    return;
  }
  empty?.classList.add("hidden");

  const rows = [];

  // Members
  for (const m of members) {
    const name = [m.first_name, m.last_name].filter(Boolean).join(" ") || "—";
    const email = m.email || "—";
    const sysRole = m.role || "viewer";
    const status = (m.is_active === false) ? "Inactive" : "Active";

    rows.push(`
      <tr class="border-t hover:bg-slate-50 user-row"
          data-user-id="${m.user_id}"
          data-email="${esc(String(email))}"
          data-role="${esc(String(sysRole))}">
        <td class="py-2 px-3">${esc(name)}</td>
        <td class="py-2 px-3">${esc(email)}</td>
        <td class="py-2 px-3">—</td>
        <td class="py-2 px-3">${esc(sysRole)}</td>
        <td class="py-2 px-3">${esc(status)}</td>
      </tr>
    `);
  }

  // Pending invites (optional display)
  for (const inv of invites) {
    rows.push(`
      <tr class="border-t bg-amber-50/30">
        <td class="py-2 px-3">—</td>
        <td class="py-2 px-3">${esc(inv.email || "")}</td>
        <td class="py-2 px-3">—</td>
        <td class="py-2 px-3">${esc(inv.role || "viewer")}</td>
        <td class="py-2 px-3">Invited</td>
      </tr>
    `);
  }

  if (body) body.innerHTML = rows.join("");
}

  /* ==============================
   * Sidebar Renderer (recursive)
   * ============================== */
function renderNavMenu(menu, targetEl, level = 0) {
  const ul = document.createElement("ul");
  ul.classList.add("nav-level-" + level);
  if (level > 0) ul.style.display = "none";

  menu.forEach((item) => {
    // ✅ unified visibility rule
    if (!shouldShowNavItem(item)) return;

    const li = document.createElement("li");
    li.classList.add("nav-item");

    const link = document.createElement("a");
    link.classList.add("nav-item-link");

    link.innerHTML = `
      <span class="nav-icon">${item.icon || "•"}</span>
      <span class="nav-item-label">${item.name}</span>
    `;

    // ---------------------------
    // SCREEN LINK
    // ---------------------------
    if (item.screen) {
      link.setAttribute("data-nav", item.screen);
      link.classList.add("hover");
      li.appendChild(link);
    }

    // ---------------------------
    // WIZARD LINK
    // ---------------------------
    else if (item.wizard) {
      link.setAttribute("data-wizard", item.wizard);
      link.classList.add("hover");
      li.appendChild(link);
    }

    // ---------------------------
    // PARENT WITH CHILDREN
    // ---------------------------
    else if (item.children) {
      link.classList.add("parent");
      link.innerHTML += `<span class="ml-auto text-xs">▸</span>`;
      li.appendChild(link);

      const visibleChildren = item.children.filter(shouldShowNavItem);

      // render children only if any are visible
      let childUl = null;
      if (visibleChildren.length) {
        childUl = renderNavMenu(visibleChildren, li, level + 1);
      }

      // ✅ ALWAYS attach click
      link.addEventListener("click", (e) => {
        e.preventDefault();

        // no visible children → tell user why
        if (!childUl) {
          alert("This section is not available on your plan / role.");
          return;
        }

        const open = childUl.style.display !== "none";
        childUl.style.display = open ? "none" : "block";
        link.querySelector(".ml-auto").textContent = open ? "▸" : "▾";
      });
    }
    
    ul.appendChild(li);
  });

  targetEl.appendChild(ul);
  return ul;
}

function bindNav() {
  $("#mainNav")?.addEventListener("click", (e) => {
    const link = e.target.closest(".nav-item-link,[data-nav],[data-wizard]");
    if (!link) return;

    const wizard = link.dataset.wizard;
    if (wizard && wizardMap[wizard]) {
      e.preventDefault();
      wizardMap[wizard]();
      return;
    }

    const nav = link.dataset.nav;
    if (nav) {
      e.preventDefault();
      switchScreen(nav);
    }
  });

  // In-content links (if you have any)
  $$("main [data-nav]").forEach((a) =>
    a.addEventListener("click", (e) => {
      const name = e.currentTarget.getAttribute("data-nav");
      if (name) {
        e.preventDefault();
        switchScreen(name);
      }
    })
  );

  $("#mobileMenu")?.addEventListener("click", () => {
    $("aside")?.classList.toggle("hidden");
  });

  $("#signinBtn")?.addEventListener("click", handleSigninClick);

  $("#logoutBtn")?.addEventListener("click", (e) => {
    e.preventDefault();

    clearToken();
    localStorage.removeItem("authToken");
    localStorage.removeItem("userEmail");
    localStorage.removeItem("userRole");
    localStorage.removeItem("companyName");
    window.FS_USER_ROLE = null;

    applyLoggedOutUI();
    switchScreen("sign-in");
  });

  $("#accountSettingsBtn")?.addEventListener("click", (e) => {
    e.preventDefault();
    switchScreen("company");
  });

  $("#changePasswordLink")?.addEventListener("click", (e) => {
    e.preventDefault();
    switchScreen("change-password");
  });

  $("#backToSigninLink")?.addEventListener("click", (e) => {
    e.preventDefault();
    switchScreen("sign-in");
  });
}

window.getCurrentPermissions = function getCurrentPermissions() {
  return window.currentUser?.permissions || {};
};

window.hasPermission = function hasPermission(key) {
  if (window.isSeniorFullAccess?.()) return true;

  const perms = window.getCurrentPermissions?.() || {};
  return perms[key] === true;
};

function canSeeMenuItem(item) {
  if (!item) return false;

  // ✅ Senior Accountant sees all menu items
  if (window.isSeniorFullAccess?.()) return true;

  if (item.feature && !hasFeature(item.feature)) return false;

  if (item.permission) {
    return window.hasPermission?.(item.permission) === true;
  }

  if (item.minRole) {
    return window.canSeeRole?.(item.minRole) === true;
  }

  return true;
}
window.canSeeMenuItem = canSeeMenuItem;

function canOpenScreen(name) {
  const resolved = resolveScreenName(name);
  const rule = SCREEN_POLICY[resolved];

  // strict allowlist (recommended)
  return !!rule;
}
window.canOpenScreen = canOpenScreen;

function shouldShowNavItem(item) {
  if (!item) return false;

  // ✅ Senior Accountant sees all nav items
  if (window.isSeniorFullAccess?.()) return true;

  if (item.enterpriseOnly && !window.CURRENT_COMPANY?.is_enterprise) return false;

  if (item.feature) {
    const ok = (typeof featureAllowed === "function")
      ? featureAllowed(item.feature)
      : (typeof hasFeature === "function")
        ? hasFeature(item.feature)
        : true;
    if (!ok) return false;
  }

  if (item.screen) {
    if (!canOpenScreen(item.screen)) return false;
    const access = window.guardScreenAccess?.(item.screen);
    if (!access?.ok) return false;
  }

  if (!item.screen) {
    if (!canSeeMenuItem(item)) return false;
  }

  if (!item.screen && Array.isArray(item.children)) {
    return item.children.some(shouldShowNavItem);
  }

  return true;
}

async function setupNav() {
  const host = $("#mainNav");
  if (!host) return;

  host.innerHTML = "";
  renderNavMenu(NAV_MENU, host);
  bindNav();

  // Optional: soft-disable Credit Control if user can't approve
  const approvalsLink = host.querySelector('[data-nav="cust-approvals"]');
  if (approvalsLink) {
    const canApprove = typeof userCanApproveCustomers === "function"
      ? userCanApproveCustomers()
      : true;

    approvalsLink.classList.toggle("opacity-50", !canApprove);
    approvalsLink.style.pointerEvents = canApprove ? "" : "none";
    approvalsLink.title = canApprove ? "" : "You do not have permission to approve customers";
  }
}

