function getEffectivePermissions() {
  const me = window.currentUser || {};
  const perms = { ...(me.permissions || {}) };

  const ctx =
    window.FS_DELEGATED_WORKSPACE?.getPostingContext?.() ||
    window.__FS_POSTING_CONTEXT__ ||
    null;

  const isDelegatedProvisioned =
    !!ctx &&
    (ctx.accessMode === "delegated_workspace" || ctx.launchMode === "posting") &&
    Number(ctx.targetCompanyId || ctx.companyId || 0) > 0;

  if (!isDelegatedProvisioned) return perms;

  // no extra fake grants here — backend token should already carry what is allowed
  return perms;
}
window.getEffectivePermissions = getEffectivePermissions;

// Optional feature check
function hasFeature(flag) {
  if (window.isSeniorFullAccess?.()) return true;
  if (!flag) return true;

  const f = window.CURRENT_COMPANY?.features || {};
  if (flag in f) return !!f[flag];
  return true;
}

function canSeeMenuItem(item) {
  if (!item) return false;

  if (item.feature && !hasFeature(item.feature)) return false;

  if (item.permission) {
    return window.hasPermission?.(item.permission) === true;
  }

  if (item.minRole) {
    return window.canSeeRole?.(item.minRole) === true;
  }

  return true;
}
window.canSeeMenuItem = canSeeMenuItem;

function getStoredUser() {
  try {
    return JSON.parse(localStorage.getItem("fs_user") || "null") || {};
  } catch (_) {
    return {};
  }
}

function getDashboardRole() {
  const me = window.currentUser || {};
  const role = String(window.getCurrentRole?.() || me.role || "viewer").toLowerCase();

  if (["cfo", "partner", "director", "manager", "senior"].includes(role)) return "executive";
  if (["assistant", "junior", "accountant"].includes(role)) return "manager";
  return "operator";
}

