function destroyChart(name) {
  if (window[name] && typeof window[name].destroy === "function") {
    window[name].destroy();
  }
  window[name] = null;
}

function makeLineChart(canvasId, chartKey, labels, data, label) {
  const el = document.getElementById(canvasId);
  if (!el) return null;

  destroyChart(chartKey);

  window[chartKey] = new Chart(el, {
    type: "line",
    data: {
      labels,
      datasets: [{ label, data, tension: 0.35 }]
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      plugins: { legend: { display: true } }
    }
  });

  return window[chartKey];
}

function renderInsightBanner(data) {
  const host = document.getElementById("insights");
  if (!host) return;

  const revenueGrowth = Number(data?.revenueGrowthPct || 0);
  const margin = Number(data?.netMarginPct || 0);
  const ar90 = Number(data?.ar90Plus || 0);

  const items = [];

  if (revenueGrowth > 0) items.push(`Revenue increased by ${revenueGrowth.toFixed(1)}% this period.`);
  if (revenueGrowth < 0) items.push(`Revenue declined by ${Math.abs(revenueGrowth).toFixed(1)}% this period.`);
  if (margin < 10) items.push(`Net margin is low at ${margin.toFixed(1)}%.`);
  if (ar90 > 0) items.push(`${money(ar90)} is overdue beyond 90 days.`);

  if (!items.length) items.push("No major financial exceptions detected for this period.");

  host.innerHTML = items.map(x => `<li>${x}</li>`).join("");
}

(function () {
  function safeParse(json, fallback = null) {
    try {
      return JSON.parse(json);
    } catch {
      return fallback;
    }
  }

  function getAuthStorageKey() {
    if (localStorage.getItem("access_token") !== null) return "access_token";
    return "token";
  }

  function getPostingContext() {
    return safeParse(localStorage.getItem("fs_posting_context") || "null", null);
  }

  function getReturnContext() {
    return safeParse(localStorage.getItem("fs_pr_return_context") || "null", null);
  }

  function isDelegatedPostingMode() {
    const ctx = getPostingContext();
    return !!(ctx && (ctx.accessMode === "delegated_workspace" || ctx.launchMode === "posting"));
  }

  function getDelegatedTargetCompanyId() {
    const ctx = getPostingContext();
    return Number(ctx?.targetCompanyId || ctx?.companyId || 0) || null;
  }

  function getDelegatedSourceCompanyId() {
    const ctx = getPostingContext();
    return Number(ctx?.sourceCompanyId || 0) || null;
  }

  function getDelegatedEngagementId() {
    const ctx = getPostingContext();
    return Number(ctx?.engagementId || 0) || null;
  }

  function setDelegatedGlobals(ctx) {
    if (!ctx) return;

    const targetCompanyId = Number(ctx.targetCompanyId || ctx.companyId || 0) || null;
    if (!targetCompanyId) return;

    window.__FS_DELEGATED_POSTING__ = true;
    window.__FS_POSTING_CONTEXT__ = ctx;
    window.__COMPANY_ID__ = targetCompanyId;
    window.__PR_ACTIVE_COMPANY_ID__ = targetCompanyId;
    window.__FS_TARGET_COMPANY_ID__ = targetCompanyId;
    window.__FS_SOURCE_COMPANY_ID__ = Number(ctx.sourceCompanyId || 0) || null;
    window.__FS_ENGAGEMENT_ID__ = Number(ctx.engagementId || 0) || null;

    try {
      if (typeof window.setActiveCompanyId === "function") {
        window.setActiveCompanyId(targetCompanyId);
      }
    } catch (e) {
      console.warn("setActiveCompanyId failed during delegated restore", e);
    }
  }

  function restorePostingContext() {
    const ctx = getPostingContext();
    if (!ctx || typeof ctx !== "object") return null;

    const normalized = {
      targetCompanyId: Number(ctx.targetCompanyId || ctx.companyId || 0) || null,
      sourceCompanyId: Number(ctx.sourceCompanyId || 0) || null,
      engagementId: Number(ctx.engagementId || 0) || null,
      engagementName: ctx.engagementName || null,
      launchMode: String(ctx.launchMode || "").toLowerCase() || null,
      accessMode: String(ctx.accessMode || "").toLowerCase() || null,
      mode: String(ctx.mode || "").toLowerCase() || null,
      companyId: Number(ctx.companyId || ctx.targetCompanyId || 0) || null,
    };

    setDelegatedGlobals(normalized);

    console.log("[PostingContext] restored", {
      targetCompanyId: normalized.targetCompanyId,
      sourceCompanyId: normalized.sourceCompanyId,
      engagementId: normalized.engagementId,
      launchMode: normalized.launchMode,
      accessMode: normalized.accessMode,
    });

    return normalized;
  }

  function resolveInitialCompanyId() {
    const delegatedCid = getDelegatedTargetCompanyId();
    if (delegatedCid) return delegatedCid;

    const returnCtx = getReturnContext();
    const returnCid = Number(returnCtx?.companyId || 0) || null;
    if (returnCid) return returnCid;

    return Number(window.__PR_ACTIVE_COMPANY_ID__ || window.__COMPANY_ID__ || 0) || null;
  }

  function ensureDelegatedUiBadge() {
    const host = document.getElementById("delegatedWorkspaceBanner");
    if (!host) return;

    let ctx = {};
    try {
      ctx = JSON.parse(localStorage.getItem("fs_posting_context") || "{}");
    } catch (_) {}

    ctx = {
      ...ctx,
      ...(window.__PR_POSTING_CONTEXT__ || {})
    };

    const engagementName =
      ctx.engagementName ||
      ctx.engagement?.engagement_name ||
      "Engagement";

    host.classList.remove("hidden");
    host.textContent = engagementName;
  }

  function escapeHtml(value) {
    return String(value ?? "")
      .replaceAll("&", "&amp;")
      .replaceAll("<", "&lt;")
      .replaceAll(">", "&gt;")
      .replaceAll('"', "&quot;")
      .replaceAll("'", "&#39;");
  }

  function hideMembershipOnlyUi() {
    if (!isDelegatedPostingMode()) return;

    const selectors = [
      '[data-nav="users"]',
      '[data-nav="company-settings"]',
      '[data-nav="tax-settings"]',
      '[data-nav="governance"]',
      '#nav-users',
      '#nav-company-settings',
      '#nav-tax-settings',
      '#nav-governance',
      '#screen-users',
    ];

    selectors.forEach((sel) => {
      document.querySelectorAll(sel).forEach((el) => {
        el.classList.add("hidden");
      });
    });
  }

  function bindReturnToPractitionerWorkspace() {
    const btn = document.getElementById("returnToPractitionerBtn");
    if (!btn) return;

    let ctx = null;
    try {
      ctx = JSON.parse(localStorage.getItem("fs_posting_context") || "null");
    } catch {
      ctx = null;
    }

    if (!ctx?.engagementId) {
      btn.classList.add("hidden");
      return;
    }

    btn.classList.remove("hidden");

    btn.onclick = async (e) => {
      e.preventDefault();
      e.stopPropagation();

      try {
        const res = await apiFetch(ENDPOINTS.auth.restoreNative, {
          method: "POST",
        });

        if (!res?.ok || !res?.token) {
          throw new Error(res?.error || "Failed to restore native context");
        }

        window.setToken(res.token, true);

        const returnCtx = {
          companyId: Number(res.company_id || ctx.sourceCompanyId || 0) || null,
          engagementId: Number(ctx.engagementId || 0) || null,
          customerId: Number(ctx.customerId || 0) || null,
          engagement: ctx.engagement || null,
          returnScreen: "assignments",
        };

        localStorage.setItem("fs_pr_return_context", JSON.stringify(returnCtx));

        localStorage.removeItem("fs_posting_context");
        localStorage.removeItem("fs_home_token");
        localStorage.removeItem("company_id");

        window.__FS_DELEGATED_POSTING__ = false;
        window.__FS_POSTING_CONTEXT__ = null;
        window.__FS_TARGET_COMPANY_ID__ = null;
        window.__FS_SOURCE_COMPANY_ID__ = null;
        window.__PR_ACTIVE_COMPANY_ID__ = null;

        window.currentUser = null;
        localStorage.removeItem("fs_user");
        sessionStorage.removeItem("fs_user");

        window.location.href =
          ctx.returnTo || "practitionerdashboard.html#screen=assignments";
      } catch (err) {
        console.error("Failed to return to practitioner workspace", err);
      }
    };
  }
  window.bindReturnToPractitionerWorkspace = bindReturnToPractitionerWorkspace;

  function updatePostingCompanyBadge() {
    const badge = document.getElementById("companyBadge");
    if (!badge) return;

    let ctx = {};
    try {
      ctx = JSON.parse(localStorage.getItem("fs_posting_context") || "{}");
    } catch (_) {}

    ctx = {
      ...ctx,
      ...(window.__PR_POSTING_CONTEXT__ || {})
    };

    const customerName =
      ctx.customerName ||
      ctx.engagement?.customer_name ||
      "";

    const companyId = Number(ctx.targetCompanyId || ctx.companyId || 0);

    if (!companyId) {
      badge.textContent = "Your company";
      return;
    }

    badge.textContent = customerName || "Client";
    badge.classList.remove("hidden");
  }
  window.updatePostingCompanyBadge = updatePostingCompanyBadge;

  function decorateApiHeadersWithDelegatedContext(headers) {
    if (!isDelegatedPostingMode()) return headers;

    const next = headers instanceof Headers ? headers : new Headers(headers || {});
    const ctx = getPostingContext();

    if (ctx?.engagementId) next.set("X-FS-Engagement-Id", String(ctx.engagementId));
    if (ctx?.sourceCompanyId) next.set("X-FS-Source-Company-Id", String(ctx.sourceCompanyId));
    if (ctx?.targetCompanyId) next.set("X-FS-Target-Company-Id", String(ctx.targetCompanyId));

    return next;
  }

  function patchApiFetchForDelegatedContext() {
    if (typeof window.apiFetch !== "function") return;
    if (window.__FS_PATCHED_API_FETCH_FOR_DELEGATED__) return;

    const original = window.apiFetch;

    window.apiFetch = async function patchedApiFetch(url, options = {}) {
      const headers = decorateApiHeadersWithDelegatedContext(options.headers);
      return original(url, { ...options, headers });
    };

    window.__FS_PATCHED_API_FETCH_FOR_DELEGATED__ = true;
  }

  function initDelegatedWorkspaceMode() {
    const ctx = restorePostingContext();
    if (!ctx) return null;

    patchApiFetchForDelegatedContext();
    ensureDelegatedUiBadge();
    hideMembershipOnlyUi();
    bindReturnToPractitionerWorkspace();

    return ctx;
  }

  // expose helpers for bootstrap / debugging
  window.FS_DELEGATED_WORKSPACE = {
    getPostingContext,
    getDelegatedTargetCompanyId,
    getDelegatedSourceCompanyId,
    getDelegatedEngagementId,
    isDelegatedPostingMode,
    resolveInitialCompanyId,
    restorePostingContext,
    initDelegatedWorkspaceMode,
  };

  // run early
  initDelegatedWorkspaceMode();
})();

function updatePostingEngagementBadge() {
  const badge = document.getElementById("postingEngagementBadge");
  if (!badge) return;

  let ctx = {};
  try {
    ctx = JSON.parse(localStorage.getItem("fs_posting_context") || "{}");
  } catch (_) {}

  ctx = {
    ...ctx,
    ...(window.__PR_POSTING_CONTEXT__ || {})
  };

  const engagementName =
    ctx.engagementName ||
    ctx.engagement?.engagement_name ||
    "";

  badge.textContent = engagementName || "Engagement";
  badge.classList.remove("hidden");
}

function shouldShowDashboardSwitcher(me) {
  const userType = String(me?.user_type || "").toLowerCase();
  const canEnterprise = !!me?.dashboards?.enterprise;
  const canPractitioner = !!me?.dashboards?.practitioner;

  // only practitioner accounts can see dashboard switching
  if (userType !== "practitioner") return false;

  // must have both dashboards enabled
  return canEnterprise && canPractitioner;
}

async function returnToPractitionerNative() {
  const res = await apiFetch("/api/auth/restore-native-context", {
    method: "POST"
  });

  if (!res?.ok || !res?.token) {
    throw new Error(res?.error || "Failed to restore native context");
  }

  window.setToken(res.token, true);
  localStorage.removeItem("fs_posting_context");
  localStorage.removeItem("fs_home_token");

  const returnCtx = {
    companyId: res.company_id || null,
    returnScreen: "assignments",
  };
  localStorage.setItem("fs_pr_return_context", JSON.stringify(returnCtx));

  window.location.href = "practitionerdashboard.html#screen=assignments";
}

function initDashboardModeSwitcher(currentMode = "internal") {
  const wrap = document.getElementById("dashboardModeSwitcherWrap");
  const select = document.getElementById("dashboardModeSwitcher");
  if (!wrap || !select) return;

  let me = null;
  try {
    me =
      window.currentUser ||
      JSON.parse(localStorage.getItem("fs_user") || "null") ||
      {};
  } catch (_) {
    me = window.currentUser || {};
  }

  const userScope = String(
    me?.access_scope ||
    me?.token_access_scope ||
    ""
  ).toLowerCase();

  const tokenSaysDelegated =
    me?.is_delegated_company_access === true ||
    userScope === "delegated_workspace";

  const postingCtx =
    window.__FS_POSTING_CONTEXT__ ||
    window.__PR_POSTING_CONTEXT__ ||
    window.FS_DELEGATED_WORKSPACE?.getPostingContext?.() ||
    (tokenSaysDelegated ? window.restorePostingContext?.() : null) ||
    null;

  const delegatedFromCtx =
    tokenSaysDelegated &&
    !!postingCtx &&
    (
      postingCtx.accessMode === "delegated_workspace" ||
      postingCtx.launchMode === "posting" ||
      postingCtx.mode === "delegated"
    );

  const isDelegatedPosting =
    tokenSaysDelegated ||
    String(currentMode || "").toLowerCase() === "delegated" ||
    !!window.__FS_DELEGATED_POSTING__ ||
    delegatedFromCtx;

  if (isDelegatedPosting) {
    wrap.classList.add("hidden");
    wrap.style.display = "none";
    select.disabled = true;
    select.onchange = null;
    return;
  }

  const show = shouldShowDashboardSwitcher(me);

  if (!show) {
    wrap.classList.add("hidden");
    wrap.style.display = "none";
    select.onchange = null;
    return;
  }

  wrap.classList.remove("hidden");
  wrap.style.display = "block";
  select.disabled = false;

  const normalizedMode = String(currentMode || "internal").toLowerCase();

  select.value =
    normalizedMode === "internal" || normalizedMode === "practitioner"
      ? normalizedMode
      : "internal";

  select.onchange = () => {
    let liveMe = null;
    try {
      liveMe =
        window.currentUser ||
        JSON.parse(localStorage.getItem("fs_user") || "null") ||
        {};
    } catch (_) {
      liveMe = window.currentUser || {};
    }

    const liveScope = String(
      liveMe?.access_scope ||
      liveMe?.token_access_scope ||
      ""
    ).toLowerCase();

    const liveTokenSaysDelegated =
      liveMe?.is_delegated_company_access === true ||
      liveScope === "delegated_workspace";

    const liveCtx =
      window.__FS_POSTING_CONTEXT__ ||
      window.__PR_POSTING_CONTEXT__ ||
      window.FS_DELEGATED_WORKSPACE?.getPostingContext?.() ||
      null;

    const delegatedNow =
      liveTokenSaysDelegated &&
      (
        !!window.__FS_DELEGATED_POSTING__ ||
        (
          !!liveCtx &&
          (
            liveCtx.accessMode === "delegated_workspace" ||
            liveCtx.launchMode === "posting" ||
            liveCtx.mode === "delegated"
          )
        )
      );

    if (delegatedNow) {
      console.warn("Blocked mode switch during delegated workspace");
      select.value = "internal";
      return;
    }

    const next = String(select.value || "").toLowerCase();

    if (next === "internal") {
      window.location.href = "dashboard.html";
      return;
    }

    if (next === "practitioner") {
      window.location.href = "practitionerdashboard.html";
      return;
    }
  };
}

function renderPostingDashboardContextBanner(mount, me, postingCtx = null) {
  const storedCtx = (() => {
    try {
      return JSON.parse(localStorage.getItem("fs_posting_context") || "{}");
    } catch {
      return {};
    }
  })();

  const ctx = {
    ...storedCtx,
    ...(window.__PR_POSTING_CONTEXT__ || {}),
    ...(postingCtx || {}),
  };

  window.__PR_POSTING_CONTEXT__ = ctx;

  const isDelegated =
    !!ctx &&
    (
      ctx.accessMode === "delegated_workspace" ||
      ctx.launchMode === "posting" ||
      Number(ctx.targetCompanyId || ctx.companyId || 0) > 0
    );

  const activeCompanyId =
    Number(ctx.targetCompanyId || ctx.companyId || 0) ||
    Number(window.getActiveCompanyId?.() || 0) ||
    Number(window.CURRENT_COMPANY_ID || 0) ||
    0;

  const engagementName =
    ctx.engagementName ||
    ctx.engagement?.engagement_name ||
    "--";

  const companyLabel =
    ctx.companyName ||
    ctx.targetCompanyName ||
    window.CURRENT_COMPANY?.name ||
    `Company ${activeCompanyId || "--"}`;

  if (!isDelegated) {
    mount.innerHTML = `
      <div class="card p-6">
        <div class="flex flex-wrap items-center justify-between gap-3">
          <div>
            <div class="panel-title">Dashboard</div>
            <div class="panel-subtitle mt-1">
              ${esc(companyLabel)}
            </div>
          </div>
        </div>
      </div>
    `;
    return;
  }

  mount.innerHTML = `
    <div class="card p-4">
      <div class="flex flex-wrap items-center justify-between gap-3">
        <div>
          <div class="panel-title">${esc(engagementName || "Engagement")}</div>
        </div>
      </div>
    </div>
  `;
}

function guardScreenAccess(name) {
  const resolved = resolveScreenName(name);
  const rule = SCREEN_POLICY[resolved];
  if (!rule) return { ok: false, reason: "unknown" };

  // Auth gate
  if (rule.auth !== "public" && !isLoggedIn()) {
    return { ok: false, reason: "auth" };
  }

  // ✅ Senior Accountant full-access override
  if (window.isSeniorFullAccess?.()) {
    return { ok: true, resolved };
  }

  // Delegated provisioned workspace unlock
  // This is checked before normal permission/role denial so operational setup
  // screens can still open in provisioned delegated workspaces.
  if (canUseDelegatedProvisionedScreen(resolved, rule)) {
    // still respect feature gate if present
    if (rule.feature && !hasFeature(rule.feature)) {
      return { ok: false, reason: "feature" };
    }

    // still respect policy gates that should remain active
    if (rule.policy === "approveCustomer") {
      const cid = FS?.control?.resolveCid?.() || null;
      const meRole = window.getCurrentRole?.() || "viewer";
      const allowed = FS?.policy?.canApproveCustomer?.(meRole, cid) === true;
      if (!allowed) return { ok: false, reason: "policy" };
    }

    return { ok: true, resolved, via: "delegated_provisioned_unlock" };
  }

  // Permission-first gate
  if (rule.permission) {
    if (!window.hasPermission?.(rule.permission)) {
      return { ok: false, reason: "permission" };
    }
  } else if (rule.minRole && !window.canSeeRole(rule.minRole)) {
    return { ok: false, reason: "role" };
  }

  // Feature gate
  if (rule.feature && !hasFeature(rule.feature)) {
    return { ok: false, reason: "feature" };
  }

  // Policy gate
  if (rule.policy === "approveCustomer") {
    const cid = FS?.control?.resolveCid?.() || null;
    const meRole = window.getCurrentRole?.() || "viewer";
    const allowed = FS?.policy?.canApproveCustomer?.(meRole, cid) === true;
    if (!allowed) return { ok: false, reason: "policy" };
  }

  return { ok: true, resolved };
}
window.guardScreenAccess = guardScreenAccess;

function canUseDelegatedProvisionedScreen(screenName, rule) {
  const ctx =
    window.FS_DELEGATED_WORKSPACE?.getPostingContext?.() ||
    window.__FS_POSTING_CONTEXT__ ||
    null;

  const isDelegatedProvisioned =
    !!ctx &&
    (ctx.accessMode === "delegated_workspace" || ctx.launchMode === "posting") &&
    Number(ctx.targetCompanyId || ctx.companyId || 0) > 0;

  if (!isDelegatedProvisioned) return false;

  // Never unlock native-admin / membership-only screens here
  const blockedScreens = new Set([
    "users",
    "governance",
    "security",
    "subscription",
  ]);

  if (blockedScreens.has(screenName)) return false;

  // Permission-driven operational unlocks
  const effectivePerms =
    window.getEffectivePermissions?.() ||
    window.currentUser?.permissions ||
    {};

  // Explicit permission route
  if (rule?.permission && effectivePerms[rule.permission] === true) {
    return true;
  }

  // Screen-specific operational exceptions
  const allowedScreens = new Set([
    "banking",
    "bankAccounts",
    "bankSetup",
    "vat",
    "vatSettings",
    "vatRecon",
    "tax",
    "taxSettings",
    "incomeTax",
    "reporting",
    "company",
    "journal",
    "journalDesk",
    "ar",
    "ap",
    "fixedAssets",
    "inventory",
    "reports",
    "trialBalance",
    "pnl",
    "cashflow",
  ]);

  return allowedScreens.has(screenName);
}

function resolveScreenName(name) {
  const n = String(name || "").trim();

  const alias = {
    // existing
    "period-lock": "period-locks",
    "ctrl-ar-reconcile": "ar-recon",

    // AP aliases
    "ap-bills": "ap",
    "bills": "ap",
    "ap-payments": "ap",

    // Fixed assets naming mismatch
    "fixed-assets": "fixedassets",
    "fixed-asset-register": "fixedassets",

    // AR aliases
    "invoices": "ar-invoices",
    "quotes": "ar-quotes",
    "receipts": "ar-receipts",

    // Revenue aliases
    "revenue-desk": "revenue",
    "revenue-contracts": "revenue",
    "revenue-runs": "revenue",
  };

  return alias[n] || n;
}

  /* ==============================
   * Mode (Enterprise vs Practitioner)
   * ============================== */
function applyMode() {
  const isDelegated =
    !!window.__FS_DELEGATED_POSTING__ ||
    !!window.__FS_POSTING_CONTEXT__;

  if (isDelegated) {
    console.log("applyMode skipped in delegated workspace");
    return;
  }

  const mode = $("#modeSelect")?.value;
  if (!mode) return;

  store.set(K.MODE, mode);
  $$(".enterprise-only").forEach(
    (el) => (el.style.display = mode === "enterprise" ? "" : "none")
  );
  setupNav();
}

function warnScreensMissingPolicy(menu) {
  const missing = [];
  (function walk(items) {
    (items || []).forEach((it) => {
      if (it.screen && !SCREEN_POLICY[it.screen]) missing.push(it.screen);
      if (it.children) walk(it.children);
    });
  })(menu);

  const uniq = [...new Set(missing)];
  if (uniq.length) console.warn("[SCREEN_POLICY] missing:", uniq);
}

// call after NAV_MENU is defined
warnScreensMissingPolicy(NAV_MENU);

