function ensureWidget(name, fn) {
  if (typeof window[name] === "function") return;
  window[name] = fn;
}

function _setText(id, txt) {
  const el = document.getElementById(id);
  if (el) el.textContent = txt;
}

function _setHTML(id, html) {
  const el = document.getElementById(id);
  if (el) el.innerHTML = html;
}

