function isInventoryRoute(name) {
  return [
    "inventory-items",
    "inventory-movements",
    "reorder",
    "stocktake",
    "inventory-valuation",
  ].includes(String(name || ""));
}

function renderCatalogScreen(name) {
  const mount = document.getElementById("catalogMount");
  if (!mount) {
    console.warn("[Catalog] catalogMount not found");
    return;
  }

  // hard reset
  mount.innerHTML = "";

  try { store?.set?.("fs_catalog_subscreen", name); } catch {}
  setCatalogContextHeader?.();
  bindCatalogQuickTabs?.();

  const invEnabled = !!isInventoryEnabledForCompany?.();
  const routeName = String(name || "");

  // ✅ only block inventory-only routes
  if (!invEnabled && isInventoryRoute(routeName)) {
    mount.innerHTML = `
      <div class="border rounded p-3 text-sm text-slate-600">
        <div class="font-semibold">Inventory is disabled for this company</div>
        <div class="text-xs text-slate-500 mt-1">
          Inventory features are unavailable. You can still use <b>Service Items</b>.
        </div>
      </div>
    `;
    return;
  }

  const mountTpl = (tplId) => {
    const tpl = document.getElementById(tplId);
    if (!tpl || !tpl.content) {
      mount.innerHTML = `<div class="text-xs text-red-600 p-2">Missing template: ${esc(tplId)}</div>`;
      return false;
    }
    mount.appendChild(tpl.content.cloneNode(true));
    return true;
  };

  const routes = {
    "inventory-items": {
      tpl: "tpl-inventory-items",
      enter: () => { bindInventoryItemsUI?.(); loadInventoryItems?.(); },
    },

    "inventory-movements": {
      tpl: "tpl-inventory-movements",
      enter: () => { bindInventoryMovementsUI?.(); loadInventoryMovements?.(); },
    },

    "reorder": {
      tpl: "tpl-reorder",
      enter: () => { bindReorderUI?.(); loadReorderAlerts?.(); },
    },

    "stocktake": {
      tpl: "tpl-stocktake",
      enter: () => { bindStocktakeUI?.(); },
    },

    "inventory-valuation": {
      tpl: "tpl-inventory-valuation",
      enter: () => {
        bindInventoryValuationUI?.();
        const el = document.getElementById("valAsOf");
        if (el && !el.value) el.value = new Date().toISOString().slice(0, 10);
        loadInventoryValuation?.();
      },
    },

    // ✅ always allowed (service-only companies)
    "service-items": {
      tpl: "tpl-service-items",
      enter: () => { bindServiceItemsUI?.(); loadServiceItems?.(); },
    },
  };

  const r = routes[routeName];
  if (r) {
    const ok = mountTpl(r.tpl);
    if (ok) {
      try { r.enter?.(); } catch (e) { console.warn("[Catalog] enter failed:", routeName, e); }
    }
    return;
  }

  mount.innerHTML = `
    <div class="border rounded p-3 text-sm text-slate-600">
      <div class="font-semibold">${esc(String(routeName || "Catalog"))}</div>
      <div class="text-xs text-slate-500 mt-1">Coming soon.</div>
    </div>
  `;
}
window.renderCatalogScreen = renderCatalogScreen;

