async function loadCompanyProfile(companyId) {
  const status = document.getElementById("companyProfileStatus");
  const setStatus = (msg, isError = false) => {
    if (!status) return;
    status.textContent = msg;
    status.classList.toggle("text-red-600", !!isError);
    status.classList.toggle("text-emerald-600", !isError);
  };

  const setVal = (id, v) => {
    const el = document.getElementById(id);
    if (el) el.value = v == null ? "" : String(v);
  };

  const setText = (id, v) => {
    const el = document.getElementById(id);
    if (!el) return;
    const s = (v == null ? "" : String(v)).trim();
    el.textContent = s || "—";
  };

  try {
    setStatus("Loading...");

    // ✅ Always fetch from backend
    const data = await apiFetch(ENDPOINTS.company(companyId), { method: "GET" });

    // -----------------------------
    // 1) Editable form: "Update company"
    // (Only fills if the inputs exist)
    // -----------------------------
    setVal("cpName",            data.name || data.company_name || "");
    setVal("cpEmail",           data.company_email || data.email || "");
    setVal("cpPhone",           data.company_phone || data.phone || "");
    setVal("cpLogoUrl",         data.logo_url || "");
    setVal("cpRegNo",           data.company_reg_no || data.reg_no || data.registration_no || "");
    setVal("cpTin",             data.tin || data.tax_number || "");
    setVal("cpVat",             data.vat || data.vat_number || "");
    setVal("cpCountry",         data.country || data.country_code || "");
    setVal("cpPhysicalAddress", data.physical_address || "");
    setVal("cpPostalAddress",   data.postal_address || "");

    // -----------------------------
    // 2) Read-only view: "My company"
    // (Only fills if those nodes exist)
    // -----------------------------
    setText("mcName",      data.name || data.company_name);
    setText("mcRegNo",     data.company_reg_no || data.reg_no || data.registration_no);
    setText("mcTin",       data.tin || data.tax_number);
    setText("mcVat",       data.vat || data.vat_number);
    setText("mcEmail",     data.company_email || data.email);
    setText("mcPhone",     data.company_phone || data.phone);
    setText("mcPhysical",  data.physical_address);
    setText("mcPostal",    data.postal_address);

    // ✅ NEW: hydrate company credit policy fields (if present)
    writeCompanyCreditPolicyToForm(data);

    // -----------------------------
    // 3) Badges / header displays
    // -----------------------------
    setText("vatNumberDisplay", data.vat || data.vat_number);
    setText("taxNumberDisplay", data.tin || data.tax_number);

    // System company code badge
    const sysCode =
      data.system_code ||
      data.system_company_code ||
      data.tenant_code ||
      data.code;

    setText("companySystemCodeBadge", sysCode);

    // -----------------------------
    // 4) Keep global in-memory objects in sync
    // -----------------------------
    window.CURRENT_COMPANY = { ...(window.CURRENT_COMPANY || {}), ...data };
    window.COMPANY_PROFILE = { ...(window.COMPANY_PROFILE || {}), ...data };

    // ✅ also expose for non-window code (if you still use these globals)
    if (typeof CURRENT_COMPANY !== "undefined") CURRENT_COMPANY = window.CURRENT_COMPANY;
    if (typeof CURRENT_COMPANY_ID !== "undefined" && data?.id) CURRENT_COMPANY_ID = Number(data.id);

    // ✅ sync backend policy.mode → localStorage mode (ONCE)
    try {
      FS.control.syncFromCompany?.(window.CURRENT_COMPANY);
    } catch (e) {
      console.warn("[ControlMode] syncFromCompany failed:", e);
    }

    // ✅ show Assisted choice banner (only once per company)
    try {
      FS.ui.promptReviewChoice?.(window.CURRENT_COMPANY_ID);
    } catch (e) {
      console.warn("[UI] promptReviewChoice failed:", e);
    }

    // ✅ refresh invoice buttons state (draft/approve/send)
    try {
      applyInvoiceButtonsByMode?.();
    } catch (e) {
      console.warn("[UI] applyInvoiceButtonsByMode failed:", e);
    }

    // ✅ ADD THIS (so non-window code sees it too)
    if (typeof CURRENT_COMPANY !== "undefined") CURRENT_COMPANY = window.CURRENT_COMPANY;
    if (typeof CURRENT_COMPANY_ID !== "undefined" && data?.id) CURRENT_COMPANY_ID = Number(data.id);

    // ✅ 1) sync local control mode from backend (if backend sends mode)
    FS.control.syncFromCompany?.(window.CURRENT_COMPANY);

    // ✅ 2) show Assisted choice banner (only once per company)
    FS.ui.promptReviewChoice?.(window.CURRENT_COMPANY_ID);

    // ✅ 3) refresh invoice buttons state (draft/approve/send)
    applyInvoiceButtonsByMode();

    // -----------------------------
    // 5) Update any tax UI helper (badge + toggle label text etc.)
    // -----------------------------
    if (typeof hydrateCompanyTaxUI === "function") {
      hydrateCompanyTaxUI(data);
    }

    // -----------------------------
    // 6) Map refresh
    // -----------------------------
    const addr =
      (data.physical_address || "").trim() ||
      (data.postal_address || "").trim() ||
      (data.address || "").trim() ||
      "";

    if (addr && typeof initCompanyMapFromAddress === "function") {
      initCompanyMapFromAddress(addr);
    }

    // ✅ Fill read-only "My company" view
    if (typeof hydrateMyCompanyView === "function") {
      hydrateMyCompanyView(data);
    }

    setStatus("Loaded");
    setTimeout(() => setStatus(""), 900);
    return data;
  } catch (e) {
    console.error("loadCompanyProfile failed:", e);
    setStatus(e?.message || "Failed to load", true);
    throw e;
  }
}

function readCompanyCreditPolicyFromForm() {
  const num = (id, fallback = 0) => {
    const raw = (document.getElementById(id)?.value || "").trim();
    const v = parseFloat(raw);
    return Number.isFinite(v) ? v : fallback;
  };

  return {
    default_credit_limit: num("cpDefaultCreditLimit", 0),
    approval_threshold: num("cpApprovalThreshold", 0),
    kyc_threshold: num("cpKycThreshold", 0),
    clerk_request_cap: num("cpClerkRequestCap", 0),
    require_kyc_for_any_credit: !!document.getElementById("cpRequireKycForAnyCredit")?.checked,
  };
}

// 2) define + export autofix runner (RIGHT HERE)
window.runMgmtPacksAutofix = async function () {
  const cid = getActiveCompanyId?.() || CURRENT_COMPANY_ID;
  if (!cid) return;

  // (optional) UI feedback
  const root = document.getElementById("mgmtPacksRoot");
  if (root) root.insertAdjacentHTML(
    "afterbegin",
    `<div class="text-sm text-slate-500 mb-2">Auto-configuring…</div>`
  );

  await apiFetch(ENDPOINTS.managementPacksAutofix(cid), { method: "POST" });
  await loadManagementPacks(cid);
};

async function loadManagementPacks(companyId) {
  const cid = companyId || getActiveCompanyId?.() || CURRENT_COMPANY_ID;
  const root = document.getElementById("mgmtPacksRoot");
  if (!root || !cid) return;

  root.innerHTML = `<div class="text-sm text-slate-500">Loading management packs…</div>`;

  let data;
  try {
    data = await apiFetch(ENDPOINTS.managementPacks(cid), { method: "GET" });
  } catch (e) {
    console.warn("[MgmtPacks] API failed:", e);
    root.innerHTML = `
      <div class="border rounded-xl p-3 bg-red-50 text-sm text-red-800">
        Failed to load management packs: ${String(e?.message || e)}
      </div>
    `;
    return;
  }

  const badge = (status) => {
    const map = {
      READY:       "bg-green-100 text-green-700 border-green-200",
      NEEDS_SETUP: "bg-amber-100 text-amber-700 border-amber-200",
      BLOCKED:     "bg-red-100 text-red-700 border-red-200",
      OPTIONAL:    "bg-slate-100 text-slate-700 border-slate-200",
    };
    const cls = map[status] || map.NEEDS_SETUP;
    const txt = status === "NEEDS_SETUP" ? "Needs setup" : status[0] + status.slice(1).toLowerCase();
    return `<span class="inline-flex items-center px-2 py-0.5 text-xs border rounded-full ${cls}">${txt}</span>`;
  };

  const toBtn = (screen, label, primary=false) => `
    <button class="px-3 py-1.5 text-sm rounded-lg ${primary ? "bg-[var(--fs-navy)] text-white" : "border hover:bg-slate-50"}"
      onclick="window.switchScreen?.('${screen}')">
      ${label}
    </button>
  `;

  // ✅ top actions (optional)
  const topActions = (data.actions || []).map(a => {
    if (a.type === "autofix") {
      return `<button class="ml-2 px-3 py-1.5 text-sm rounded-lg bg-[var(--fs-navy)] text-white"
        onclick="window.runMgmtPacksAutofix?.()">${a.label || "Auto-configure"}</button>`;
    }
    return "";
  }).join("");

  const blockers = (data.critical_blockers || []).slice(0, 5).map(b => `
    <li class="text-sm">
      <span class="font-medium">${b.pack}:</span> ${b.label}
      ${b.fix_screen ? `<button class="ml-2 text-[var(--fs-teal)] hover:underline" onclick="switchScreen('${b.fix_screen}')">Fix</button>` : ""}
    </li>
  `).join("");

  const cards = (data.packs || []).map(p => {
    const missing = (p.missing || []).slice(0, 3).map(m => `
      <li class="text-sm text-slate-600">
        • ${m.label}
        ${m.fix_screen ? `<button class="ml-2 text-[var(--fs-teal)] hover:underline" onclick="switchScreen('${m.fix_screen}')">Fix</button>` : ""}
      </li>
    `).join("");

    const openBtn = p.open_screen ? toBtn(p.open_screen, "Open") : "";
    const fixBtn =
      p.fix_screen ? toBtn(p.fix_screen, "Fix setup", true) :
      (p.fix_action === "autofix_controls" ? `
        <button class="px-3 py-1.5 text-sm rounded-lg bg-[var(--fs-navy)] text-white"
          onclick="window.runMgmtPacksAutofix?.()">
          Auto-configure
        </button>
      ` : "");

    return `
      <div class="border rounded-xl p-4 bg-white shadow-sm">
        <div class="flex items-start justify-between gap-3">
          <div>
            <div class="flex items-center gap-2">
              <div class="font-semibold text-[var(--fs-navy)]">${p.title}</div>
              ${badge(p.status)}
            </div>
            <div class="text-xs text-slate-500 mt-1">${p.summary || ""}</div>
          </div>
          <div class="flex gap-2">${p.status === "READY" ? openBtn : (fixBtn || openBtn)}</div>
        </div>
        ${missing ? `<ul class="mt-3 space-y-1">${missing}</ul>` : ""}
      </div>
    `;
  }).join("");

  root.innerHTML = `
    <div class="mb-4">
      <div class="flex items-center justify-between">
        <div>
          <div class="text-lg font-bold text-[var(--fs-navy)]">Management Packs</div>
          <div class="text-sm text-slate-500">Company readiness & setup status</div>
        </div>
        <div class="text-sm text-slate-600">
          Setup score: <span class="font-semibold">${data.score?.ready || 0}/${data.score?.total || 0}</span>
          ${topActions}
        </div>
      </div>

      ${blockers ? `
        <div class="mt-3 border rounded-xl p-3 bg-red-50">
          <div class="font-semibold text-red-800 text-sm mb-1">Critical blockers</div>
          <ul class="space-y-1">${blockers}</ul>
        </div>
      ` : ""}
    </div>

    <div class="grid grid-cols-1 md:grid-cols-2 gap-3">
      ${cards}
    </div>
  `;
}
window.loadManagementPacks = loadManagementPacks;

function writeCompanyCreditPolicyToForm(company) {
  const p = company?.credit_policy || {};

  const setVal = (id, val) => {
    const el = document.getElementById(id);
    if (el) el.value = (val ?? 0).toString();
  };

  setVal("cpDefaultCreditLimit", p.default_credit_limit ?? 0);
  setVal("cpApprovalThreshold", p.approval_threshold ?? 0);
  setVal("cpKycThreshold", p.kyc_threshold ?? 0);
  setVal("cpClerkRequestCap", p.clerk_request_cap ?? 0);

  const ck = document.getElementById("cpRequireKycForAnyCredit");
  if (ck) ck.checked = !!p.require_kyc_for_any_credit;
}

async function saveCompanyProfile(companyId) {
  const status = document.getElementById("companyProfileStatus");
  const setStatus = (msg, isError = false) => {
    if (!status) return;
    status.textContent = msg;
    status.classList.toggle("text-red-600", !!isError);
    status.classList.toggle("text-emerald-600", !isError);
  };

  try {
    setStatus("Saving...");

    const payload = {
      name: (document.getElementById("cpName")?.value || "").trim() || null,
      company_email: (document.getElementById("cpEmail")?.value || "").trim() || null,
      company_phone: (document.getElementById("cpPhone")?.value || "").trim() || null,
      logo_url: (document.getElementById("cpLogoUrl")?.value || "").trim() || null,
      company_reg_no: (document.getElementById("cpRegNo")?.value || "").trim() || null,
      tin: (document.getElementById("cpTin")?.value || "").trim() || null,
      vat: (document.getElementById("cpVat")?.value || "").trim() || null,
      physical_address: (document.getElementById("cpPhysicalAddress")?.value || "").trim() || null,
      postal_address: (document.getElementById("cpPostalAddress")?.value || "").trim() || null,

      // ✅ policy
      credit_policy: readCompanyCreditPolicyFromForm(),
    };

    const saved = await apiFetch(ENDPOINTS.company(companyId), {
      method: "PUT",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload),
    });

    // ✅ Refresh CURRENT_COMPANY immediately (helps customer screen right away)
    if (typeof CURRENT_COMPANY !== "undefined") {
      CURRENT_COMPANY = { ...(CURRENT_COMPANY || {}), ...(saved || {}) };
    }

    const addr = payload.physical_address || payload.postal_address || "";
    if (addr && typeof initCompanyMapFromAddress === "function") {
      initCompanyMapFromAddress(addr);
    }

    await loadCompanyProfile(companyId);

    setStatus("Saved");
    setTimeout(() => setStatus(""), 1500);
  } catch (e) {
    console.error("saveCompanyProfile failed:", e);
    setStatus(e?.message || "Failed to save", true);
  }
}


function initCompanyProfileUI(companyId) {
  const form = document.getElementById("companyProfileForm");
  const resetBtn = document.getElementById("companyProfileReload");

  bindCompanyLogoUploader(companyId);

  if (form && form.dataset.bound !== "1") {
    form.dataset.bound = "1";
    form.addEventListener("submit", async (e) => {
      e.preventDefault();
      await saveCompanyProfile(companyId);
    });
  }

  if (resetBtn && resetBtn.dataset.bound !== "1") {
    resetBtn.dataset.bound = "1";
    resetBtn.addEventListener("click", async () => {
      await loadCompanyProfile(companyId);
    });
  }
}


window.bindCompanyLogoUploader = function bindCompanyLogoUploader(companyId) {
  const btn = document.getElementById("btnUploadLogo");
  const file = document.getElementById("cpLogoFile");
  const msg  = document.getElementById("cpLogoMsg");
  const prev = document.getElementById("cpLogoPreview");
  const fb   = document.getElementById("cpLogoFallback");
  const hiddenUrl = document.getElementById("cpLogoUrl");
  const btnRemove = document.getElementById("btnRemoveLogo");

  if (!btn || !file) return;
  if (btn.dataset.bound === "1") return; // prevent double binding
  btn.dataset.bound = "1";

  const setPreview = (url) => {
    if (hiddenUrl) hiddenUrl.value = url || "";
    if (prev && url) {
      prev.src = url;
      prev.classList.remove("hidden");
      fb?.classList.add("hidden");
    } else {
      prev?.classList.add("hidden");
      fb?.classList.remove("hidden");
    }
  };

  btn.addEventListener("click", () => file.click());

  file.addEventListener("change", async () => {
    const f = file.files?.[0];
    if (!f) return;

    msg && (msg.textContent = "Uploading…");

    try {
      const fd = new FormData();
      fd.append("logo", f);

      const res = await apiFetch(ENDPOINTS.companyLogo(companyId), {
        method: "POST",
        body: fd,
      });

      // bust cache
      const url = (res.logo_url || "").trim();
      const cacheBusted = url ? `${url}?t=${Date.now()}` : "";
      setPreview(cacheBusted);

      // also update CURRENT_COMPANY if present
      if (typeof CURRENT_COMPANY !== "undefined" && CURRENT_COMPANY) {
        CURRENT_COMPANY.logo_url = url;
      }

      msg && (msg.textContent = "Logo uploaded");
    } catch (e) {
      console.error("Logo upload failed:", e);
      msg && (msg.textContent = e?.message || "Upload failed");
    } finally {
      file.value = "";
    }
  });

  if (btnRemove) {
    btnRemove.addEventListener("click", async () => {
      msg && (msg.textContent = "Removing…");
      try {
        await apiFetch(ENDPOINTS.companyLogo(companyId), { method: "DELETE" });
        setPreview("");
        if (typeof CURRENT_COMPANY !== "undefined" && CURRENT_COMPANY) {
          CURRENT_COMPANY.logo_url = null;
        }
        msg && (msg.textContent = "Removed");
      } catch (e) {
        msg && (msg.textContent = e?.message || "Failed to remove");
      }
    });
  }

  // if company already loaded
  const existing = (window.CURRENT_COMPANY?.logo_url || "").trim();
  if (existing) setPreview(`${existing}?t=${Date.now()}`);
};

function hydrateMyCompanyView(company) {
  const setText = (id, val) => {
    const el = document.getElementById(id);
    if (el) el.textContent = (val == null || String(val).trim() === "") ? "—" : String(val);
  };

  if (!company) return;

  setText("mcName", company.name || company.company_name);
  setText("mcRegNo", company.company_reg_no || company.reg_no || company.registration_no);
  setText("mcTin", company.tin || company.tax_number);
  setText("mcVat", company.vat || company.vat_number);
  setText("mcIndustry", company.industry);
  setText("mcSubIndustry", company.sub_industry || company.subIndustry);
  setText("mcFinYearStart", company.fin_year_start);
  setText("mcEmail", company.company_email || company.email);
  setText("mcPhone", company.company_phone || company.phone);
  setText("mcPhysical", company.physical_address);
  setText("mcPostal", company.postal_address);

  // System company code badge (if backend provides)
  const sys = company.system_code || company.system_company_code || company.code;
  const badge = document.getElementById("companySystemCodeBadge");
  if (badge) badge.textContent = sys || "—";
}

function initCompanyTabs() {
  const host = document.getElementById("companyTabs");
  if (!host) return;

  const tabs = Array.from(host.querySelectorAll(".company-tab"));
  const panels = Array.from(document.querySelectorAll("#screen-company .company-panel"));

  const show = (key) => {
    tabs.forEach(t => t.classList.toggle("active", t.dataset.tab === key));
    panels.forEach(p => p.classList.toggle("hidden", p.dataset.panel !== key));
  };

  tabs.forEach(t => t.addEventListener("click", () => show(t.dataset.tab)));
  show("profile");
}

function initCompanyAccordion() {
  const root = document.getElementById("companyAccordion");
  if (!root) return;

  // bind once
  if (root.dataset.bound === "1") return;
  root.dataset.bound = "1";

  root.querySelectorAll(".acc-item").forEach((item) => {
    const btn  = item.querySelector(".acc-btn");
    const body = item.querySelector(".acc-body");
    if (!btn || !body) return;

    // ensure hidden governs the initial state
    if (!body.classList.contains("hidden")) body.classList.add("hidden");

    btn.addEventListener("click", () => {
      const isOpen = item.classList.contains("open");

      // close others
      root.querySelectorAll(".acc-item").forEach((x) => {
        x.classList.remove("open");
        x.querySelector(".acc-body")?.classList.add("hidden");
      });

      // open clicked
      if (!isOpen) {
        item.classList.add("open");
        body.classList.remove("hidden");
      }
    });
  });
}

function openCompanyPanel(panelKey) {
  initCompanyAccordion();

  const root = document.getElementById("companyAccordion");
  if (!root) return;

  // close all first
  root.querySelectorAll(".acc-item").forEach((x) => {
    x.classList.remove("open");
    x.querySelector(".acc-body")?.classList.add("hidden");
  });

  const item = root.querySelector(`.acc-item[data-panel="${panelKey}"]`);
  if (!item) return;

  item.classList.add("open");
  item.querySelector(".acc-body")?.classList.remove("hidden");
}
