function initCoaDropdownsFromCOA(list = COA) {
  const secSel = document.getElementById("coaSectionSel");
  const catSel = document.getElementById("coaCategorySel");
  const subSel = document.getElementById("coaSubCategorySel");
  if (!secSel || !catSel || !subSel) return;

  // ✅ Section = fixed FS-level sections
  const sections = Object.keys(COA_CLASSIFIER);

  secSel.innerHTML =
    `<option value="">—</option>` +
    sections.map(s => `<option value="${escapeHtml(s)}">${escapeHtml(s)}</option>`).join("");

  // Reset downstream
  catSel.innerHTML = `<option value="">—</option>`;
  subSel.innerHTML = `<option value="">—</option>`;

  secSel.onchange = () => {
    const sec = secSel.value;
    const cats = sec ? Object.keys(COA_CLASSIFIER[sec] || {}) : [];

    catSel.innerHTML =
      `<option value="">—</option>` +
      cats.map(c => `<option value="${escapeHtml(c)}">${escapeHtml(c)}</option>`).join("");

    subSel.innerHTML = `<option value="">—</option>`;
  };

  catSel.onchange = () => {
    const sec = secSel.value;
    const cat = catSel.value;
    const subs = (sec && cat) ? (COA_CLASSIFIER[sec]?.[cat] || []) : [];

    subSel.innerHTML =
      `<option value="">—</option>` +
      subs.map(o => `<option value="${escapeHtml(o)}">${escapeHtml(o)}</option>`).join("");
  };
}


function escapeHtml(s){
  return String(s).replaceAll("&","&amp;").replaceAll("<","&lt;").replaceAll(">","&gt;").replaceAll('"',"&quot;");
}

function subcategoryOptionsForSection(section) {
  const s = (section || "").toLowerCase();

  // Balance sheet style sections
  if (s.includes("asset")) {
    // If your sections include "Current Assets"/"Non-current assets" etc:
    if (s.includes("non-current")) return ["Non-current asset"];
    if (s.includes("current")) return ["Current asset"];
    // Otherwise let user choose:
    return ["Current asset", "Non-current asset"];
  }

  if (s.includes("liabil")) {
    if (s.includes("non-current")) return ["Non-current liability"];
    if (s.includes("current")) return ["Current liability"];
    return ["Current liability", "Non-current liability"];
  }

  if (s.includes("equity") || s.includes("capital") || s.includes("reserves")) {
    return ["Equity"];
  }

  // P&L style sections
  if (s.includes("revenue") || s.includes("income")) {
    // "Other income" treated separately
    if (s.includes("other")) return ["Other income"];
    return ["Revenue"];
  }

  if (s.includes("cost of sales") || s.includes("cogs")) return ["Cost of sales"];

  if (s.includes("operating") || s.includes("expense")) return ["Operating expense"];

  if (s.includes("finance")) return ["Finance cost"];

  if (s.includes("other")) return ["Other income", "Other expense"];

  if (s.includes("tax")) return ["Tax"];

  if (s.includes("adjust")) return ["Adjustment"];

  // fallback
  return ["—"];
}

function populateSubcategoryFromSection() {
  const secSel = document.getElementById("coaSectionSel");
  const subSel = document.getElementById("coaSubCategorySel");
  if (!secSel || !subSel) return;

  const opts = subcategoryOptionsForSection(secSel.value);

  subSel.innerHTML =
    `<option value="">—</option>` +
    opts
      .filter(o => o !== "—")
      .map(o => `<option value="${escapeHtml(o)}">${escapeHtml(o)}</option>`)
      .join("");
}

function startNewAccountFlow() {
  CURRENT_COA_MODE = "new";
  CURRENT_COA_CODE = null;

  const metaCode    = document.getElementById("coaMetaCode");
  const metaSection = document.getElementById("coaMetaSection");
  const metaGroup   = document.getElementById("coaMetaGroup");
  const metaPosting = document.getElementById("coaMetaPosting");
  const emptyMsg    = document.getElementById("coaDetailEmpty");

  const nameInput  = document.getElementById("coaAccountName");
  const repInput   = document.getElementById("coaReportingDescMain");
  const rulesInput = document.getElementById("coaPostingRulesMain");
  const ifrsInput  = document.getElementById("coaIfrsTag");

  if (emptyMsg) emptyMsg.style.display = "none";

  if (metaCode)    metaCode.textContent    = "New";
  if (metaSection) metaSection.textContent = "Select section in COA list";
  if (metaGroup)   metaGroup.textContent   = "—";
  if (metaPosting) metaPosting.textContent = "Yes";

  if (nameInput)  nameInput.value  = "";
  if (repInput)   repInput.value   = "";
  if (rulesInput) rulesInput.value = "";
  if (ifrsInput)  ifrsInput.value  = "";

  // scroll into view on narrow screens
  document.getElementById("coaDetail")?.scrollIntoView({
    behavior: "smooth",
    block: "start",
  });
}

async function handleCoaSave() {
  const cid = getActiveCompanyId();
  if (!cid) {
    alert("No active company – cannot save account.");
    return;
  }

  const nameInput  = document.getElementById("coaAccountName");
  const repInput   = document.getElementById("coaReportingDescMain");
  const rulesInput = document.getElementById("coaPostingRulesMain");
  const ifrsInput  = document.getElementById("coaIfrsTag");

  // NEW dropdowns / flags
  const secSel   = document.getElementById("coaSectionSel");
  const catSel   = document.getElementById("coaCategorySel");
  const subSel   = document.getElementById("coaSubCategorySel");   // optional
  const cfSel    = document.getElementById("coaCfSectionSel");     // optional
  const postChk  = document.getElementById("coaPostingChk");       // optional

  const payload = {
    mode: CURRENT_COA_MODE || "new",
    code: CURRENT_COA_CODE || null,

    name: (nameInput?.value || "").trim(),
    section: (secSel?.value || "").trim(),
    category: (catSel?.value || "").trim(),

    reporting_description: (repInput?.value || "").trim(),
    posting_rules: (rulesInput?.value || "").trim(),
    standard: (ifrsInput?.value || "").trim(),

    posting: postChk ? !!postChk.checked : true,

    // ✅ correct meaning
    subcategory: (subSel?.value || "").trim() || null,

    // ✅ cashflow
    cf_section: (cfSel?.value || "operating").trim(),
    cf_bucket: null
  };

  if (!payload.name) {
    alert("Please enter an account name.");
    return;
  }

  if (payload.mode === "new" && !payload.standard) {
    const ok = confirm(
      "You are creating a new account without an IFRS tag.\n\n" +
      "It’s recommended to tag it (e.g. IAS 1 / IFRS 16) for reporting.\n\n" +
      "Continue anyway?"
    );
    if (!ok) return;
  }

  // Optional: warn if new account has no category/section (helps correct bucket allocation)
  if (payload.mode === "new" && (!payload.section || !payload.category)) {
    const ok = confirm(
      "This new account has no Section/Category.\n" +
      "That can cause it to be allocated to a generic bucket (e.g. 9000 range).\n\n" +
      "Continue anyway?"
    );
    if (!ok) return;
  }

  try {
    const res = await apiFetch(ENDPOINTS.coaSave(cid), {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload),
    });

    // if backend returns updated COA list, re-render + rebuild dropdowns/index
    if (Array.isArray(res)) {
      window.COA = res;
      if (typeof buildCoaIndex === "function") buildCoaIndex();
      if (typeof initCoaDropdownsFromCOA === "function") initCoaDropdownsFromCOA(COA);
      renderCOATable(COA);

      // reselect same account (edit) after refresh if possible
      if (payload.mode === "edit" && payload.code) {
        const again = (COA || []).find(a => String(a.code) === String(payload.code));
        if (again && typeof selectCoaAccount === "function") selectCoaAccount(again);
      }
    }

    alert("Account saved successfully.");
  } catch (err) {
    console.error("COA save failed:", err);
    alert("Could not save account. Check console / backend logs.");

    // after POST succeeds
    const latest = await apiFetch(ENDPOINTS.coa(cid)); // GET company COA
    const rows = Array.isArray(latest) ? latest : (latest?.rows || latest?.coa || []);
    window.COA = rows.map(mapCoaRow);

    buildCoaIndex();
    initCoaDropdownsFromCOA(COA);
    renderCOATable(COA);

    // optionally auto-select the newly created one by name
    const created = COA[COA.length - 1];
    if (created) selectCoaAccount(created);
  }
}

async function handleCoaArchive() {
  if (!CURRENT_COA_CODE) {
    alert("No account selected to archive/delete.");
    return;
  }

  const cid = getActiveCompanyId();
  if (!cid) {
    alert("No active company – cannot archive.");
    return;
  }

  const ok = confirm(
    `Are you sure you want to archive/delete account ${CURRENT_COA_CODE}?\n` +
    "You should ensure it has no live postings before deleting."
  );
  if (!ok) return;

  try {
    const res = await apiFetch(ENDPOINTS.coaDelete(cid, CURRENT_COA_CODE), {
      method: "DELETE",
    });

    // If backend returns updated COA list:
    if (Array.isArray(res)) {
      window.COA = res;
      renderCOATable(COA);
    } else {
      // or just remove locally:
      window.COA = (COA || []).filter(
        (a) => String(a.code) !== String(CURRENT_COA_CODE)
      );
      renderCOATable(COA);
    }

    CURRENT_COA_CODE = null;
    CURRENT_COA_MODE = "view";

    const emptyMsg = document.getElementById("coaDetailEmpty");
    if (emptyMsg) emptyMsg.style.display = "block";

    alert("Account archived/deleted.");
  } catch (err) {
    console.error("COA archive failed:", err);
    alert("Could not archive/delete account. Check console / backend logs.");
  }
}

  function classifyCoaType(a) {
    // Try type first, then section, then category
    const raw = (a.type || a.section || a.category || "").toLowerCase();

    if (raw.includes("asset"))        return "asset";
    if (raw.includes("liabil"))       return "liability";
    if (raw.includes("equity"))       return "equity";
    if (raw.includes("income") ||
        raw.includes("revenue"))      return "income";
    if (raw.includes("expense") ||
        raw.includes("cost of sales") ||
        raw.includes("cogs"))         return "expense";
    if (raw.includes("adjust"))       return "adjustment";

    return "other";
  }

  function findDefaultArAccountCode() {
  if (!Array.isArray(COA)) return "1100"; // fallback

  const acc = COA.find(a =>
    /trade debtors|accounts receivable/i.test(a.name || "") ||
    /trade debtors|receivable/i.test(a.category || "")
  );
  return acc ? acc.code : "1100";
}

function findDefaultSalesAccountCode() {
  if (!Array.isArray(COA)) return "4000"; // fallback

  const acc = COA.find(a =>
    /sales|revenue/i.test(a.name || "") &&
    /income|revenue/i.test(a.section || "")
  );
  return acc ? acc.code : "4000";
}

  // ===========================
  // COA list + initial detail
  // ===========================
function renderCOATable(list = COA) {
  const host = document.getElementById("coaList");
  if (!host) return;

  const hasSelectFn = (typeof selectCoaAccount === "function");

  if (!list || !list.length) {
    host.innerHTML = `<div class="text-slate-500 text-xs">No accounts.</div>`;

    // Optional: show "select an account" message in the detail panel
    const emptyMsg = document.getElementById("coaDetailEmpty");
    if (emptyMsg) emptyMsg.style.display = "block";
    return;
  }

  // Left-hand account list
  host.innerHTML = list.map((a) => {
    const typeBucket = classifyCoaType(a);

    return `
      <button
        type="button"
        class="w-full text-left px-2 py-1 rounded hover:bg-slate-50 border text-sm flex items-center gap-2"
        data-coa-code="${a.code}"
        data-coa-type="${typeBucket}"
      >
        <span class="font-mono text-[11px] text-slate-500">${a.code}</span>
        <span class="flex-1 truncate">${a.name}</span>
      </button>
    `;
  }).join("");

  // Default selection: first account
  //if (hasSelectFn && list[0]) {
  //selectCoaAccount(list[0]);
  //}
}

