function bindCoaScreen() {
  const drawer       = document.getElementById("coaDrawer");
  const openBtn      = document.getElementById("openCoaDrawer");
  const closeBtn     = document.getElementById("closeCoaDrawer");
  const addBtn       = document.getElementById("addAccountBtn");
  const filterPanel  = document.getElementById("coaFilterFloating");
  const openFilter   = document.getElementById("openFilterPanel");
  const closeFilter  = document.getElementById("closeFilterPanel");
  const saveBtn      = document.getElementById("coaSaveBtn");
  const archiveBtn   = document.getElementById("coaArchiveBtn");

  // Avoid double-binding when switching back to COA
  if (drawer && !drawer.dataset.bound) {
    drawer.dataset.bound = "1";

    // Open drawer
    if (openBtn) {
      openBtn.addEventListener("click", () => {
        drawer.classList.add("active");
      });
    }

    // Close drawer
    if (closeBtn) {
      closeBtn.addEventListener("click", () => {
        drawer.classList.remove("active");
      });
    }

    // Add Account → open drawer + start “new account” flow
    if (addBtn) {
      addBtn.addEventListener("click", () => {
        drawer.classList.add("active");

        if (typeof startNewAccountFlow === "function") {
          startNewAccountFlow();
        } else {
          const emptyMsg = document.getElementById("coaDetailEmpty");
          if (emptyMsg) emptyMsg.style.display = "block";
        }
      });
    }

    // Filter panel hidden by default
    if (filterPanel) {
      filterPanel.style.display = "none";
    }

    // Show filters
    if (openFilter && filterPanel) {
      openFilter.addEventListener("click", () => {
        filterPanel.style.display = "block";
      });
    }

    // Hide filters
    if (closeFilter && filterPanel) {
      closeFilter.addEventListener("click", () => {
        filterPanel.style.display = "none";
      });
    }

    // Save / Archive buttons (edit + new)
    if (saveBtn && typeof handleCoaSave === "function") {
      saveBtn.addEventListener("click", handleCoaSave);
    }
    if (archiveBtn && typeof handleCoaArchive === "function") {
      archiveBtn.addEventListener("click", handleCoaArchive);
    }
  }

  // Hook filter pills if available
  if (typeof bindCoaFilters === "function") {
    bindCoaFilters();
  }
}

function selectCoaAccount(acc) {
  if (!acc) return;

  // mark selection
  CURRENT_COA_MODE = "edit";
  CURRENT_COA_CODE = String(acc.code || "");

  // hide empty message
  const emptyMsg = document.getElementById("coaDetailEmpty");
  if (emptyMsg) emptyMsg.style.display = "none";

  // meta
  const metaCode    = document.getElementById("coaMetaCode");
  const metaSection = document.getElementById("coaMetaSection");
  const metaGroup   = document.getElementById("coaMetaGroup");
  const metaPosting = document.getElementById("coaMetaPosting");

  if (metaCode)    metaCode.textContent    = acc.code || "—";
  if (metaSection) metaSection.textContent = acc.section || "—";
  if (metaGroup)   metaGroup.textContent   = acc.category || "—";
  if (metaPosting) metaPosting.textContent = acc.posting ? "Yes" : "No";

  // fields
  const nameInput  = document.getElementById("coaAccountName");
  const repInput   = document.getElementById("coaReportingDescMain");
  const rulesInput = document.getElementById("coaPostingRulesMain");
  const ifrsInput  = document.getElementById("coaIfrsTag");

  if (nameInput)  nameInput.value  = acc.name || "";
  if (repInput)   repInput.value   = acc.reportingDescription || acc.reporting_description || "";
  if (rulesInput) rulesInput.value = acc.postingRules || acc.posting_rules || "";
  if (ifrsInput)  ifrsInput.value  = acc.standard || acc.ifrs_tag || "";

  // optional: mirror to right "Sheets" textareas if you still keep them
  const repSheet = document.getElementById("coaRepDesc");
  const postSheet = document.getElementById("coaPosting");
  if (repSheet) repSheet.value = repInput?.value || "";
  if (postSheet) postSheet.value = rulesInput?.value || "";

  const secSel = document.getElementById("coaSectionSel");
  const catSel = document.getElementById("coaCategorySel");
  if (secSel) secSel.value = acc.section || "";
  if (secSel) secSel.dispatchEvent(new Event("change"));
  if (catSel) catSel.value = acc.category || "";

  const subSel  = document.getElementById("coaSubCategorySel");
  const cfSel   = document.getElementById("coaCfSectionSel");
  const postChk = document.getElementById("coaPostingChk");

  if (secSel) secSel.value = acc.section || "";
  if (secSel) secSel.dispatchEvent(new Event("change"));
  if (catSel) catSel.value = acc.category || "";

  if (subSel) subSel.value = acc.cf_bucket || "";
  if (cfSel)  cfSel.value  = acc.cf_section || "operating";
  if (postChk) postChk.checked = !!acc.posting;
  if (subSel) {
    populateSubcategoryFromSection(); // ensure options exist first
    subSel.value = acc.sub_category || acc.account_class || acc.cf_bucket || "";
  }
}

  function bindCOA() {
    // ─────────────────────────────────────
    // 1) Header tabs: All / Assets / Liabilities / Equity / Income / Expense / Adjustments
    // ─────────────────────────────────────
    document.querySelectorAll("[data-coa-tab]").forEach((btn) => {
      btn.addEventListener("click", () => {
        const tabRaw = btn.getAttribute("data-coa-tab") || "";
        const tab = tabRaw.trim().toLowerCase();

        let filtered = COA; // default = everything

        if (tab && tab !== "all") {
          const normalized = tabRaw
            .replace(/ies$/i, "y")  // Liabilities → Liability
            .replace(/s$/i, "");    // Assets → Asset

          const target = normalized.toLowerCase();

          filtered = COA.filter((a) => {
            const sec = (a.section || "").toLowerCase();
            const cat = (a.category || "").toLowerCase();
            return sec === target || cat === target; // match section OR category
          });
        }

        renderCOATable(filtered);
      });
    });

    // ─────────────────────────────────────
    // 2) LEFT CATEGORY LIST (accounts groups)
    // ─────────────────────────────────────
    const catHost = document.getElementById("coaCategories");
    if (catHost) {
      catHost.addEventListener("click", (e) => {
        const btn = e.target.closest("[data-coa-category]");
        if (!btn) return;

        const catKey = (btn.getAttribute("data-coa-category") || "").toLowerCase();
        console.log("COA category clicked:", catKey);

        let filtered = COA;
        if (catKey && catKey !== "all") {
          filtered = COA.filter(
            (a) => (a.category || "").toLowerCase() === catKey
          );
        }

        renderCOATable(filtered);
      });
    }

    // ─────────────────────────────────────
    // 3) Middle list → Fill editable form (DO NOT innerHTML replace)
    // ─────────────────────────────────────
    const listHost = document.getElementById("coaList");
    if (listHost) {
      listHost.addEventListener("click", (e) => {
        const btn = e.target.closest("[data-coa-code]");
        if (!btn) return;

        const code = btn.getAttribute("data-coa-code");
        const acc  = (COA || []).find((a) => String(a.code) === String(code));
        if (!acc) return;

        if (typeof selectCoaAccount === "function") {
          selectCoaAccount(acc);
        }
      });
    }


        // ─────────────────────────────────────
        // 4) COA header pills (All / Assets / Liabilities / etc.)
        // ─────────────────────────────────────
        const coaDrawer = document.getElementById("coaDrawer");
        if (coaDrawer) {
          coaDrawer.addEventListener("click", (e) => {
            const pill = e.target.closest(".coa-filter");
            if (!pill) return;

            const filter = pill.dataset.coaFilter || "all";

            // Activate correct pill
            document.querySelectorAll(".coa-filter").forEach((btn) =>
              btn.classList.remove("active")
            );
            pill.classList.add("active");

            // Apply filter
            applyCoaFilter(filter);
          });
        }
      }

