async function handleARRedirectFromJournal(btn, meta = {}) {
  try {
    const code  = (btn?.dataset?.code || "").trim();
    const label = (btn?.dataset?.label || btn?.textContent || "").trim();

    console.log("[JRNL→AR] redirect", { code, label, meta });

    // 1️⃣ Go to AR screen first
    if (typeof window.switchScreen === "function") {
      window.switchScreen("ar-invoices");
    }

    // Small delay ensures DOM + panes mounted
    await new Promise(r => setTimeout(r, 80));

    // 2️⃣ Check customers exist
    let customers =
      (Array.isArray(window.CUSTOMERS) && window.CUSTOMERS.length)
        ? window.CUSTOMERS
        : [];

    if (!customers.length) {
      try { customers = await fetchCustomersFromBackend?.(true); } catch {}
    }

    if (!customers?.length) {
      window.showToast?.(
        "No customers found. Add a customer before posting receivables.",
        "warning"
      );

      window.switchScreen?.("customers");
      return;
    }

    // 3️⃣ Open picker pane
    const pane = document.getElementById("arCustomerPane");
    if (pane) {
      pane.classList.remove("hidden");
      pane.setAttribute("aria-hidden", "false");
    }

    // Optional overlay if you use one
    document.getElementById("arOverlay")?.classList.remove("hidden");

    // 4️⃣ Render customer list
    await renderArCustomerList({
      closeOnPick: true,
      fromJournal: true,
      journalMeta: meta,
    });

    // 5️⃣ Explain WHY user was redirected
    window.showToast?.(
      `“${label}” must be posted via Invoices. Choose a customer.`,
      "info"
    );

  } catch (e) {
    console.error("[JRNL→AR] redirect failed:", e);
  }
}
window.handleARRedirectFromJournal = handleARRedirectFromJournal;

