// Sort: Debit first, VAT middle, Credit last
function sortJournalLines(lines = []) {
  const sk = (ln) => {
    const dr = +ln.debit || 0;
    const cr = +ln.credit || 0;
    const isVat = !!ln.is_vat || !!ln.autoVat || String(ln.autoSide || "").toLowerCase().includes("vat");
    if (dr > 0 && !isVat) return 10;
    if (isVat) return 20;
    if (cr > 0 && !isVat) return 30;
    return 99;
  };
  return [...lines].sort((a, b) => sk(a) - sk(b));
}

