function handleJournalAccountSelected(side, accountCode, meta = {}) {
  console.log("✅ IFRS HANDLER v2026-02-11 A", { side, accountCode, meta });
  if (!accountCode) return;

  // Try lookup, but DON'T hard-return if missing
  const accFound =
    window.getCoaAccount?.(accountCode) || window.getCoaByCode?.(accountCode);

  const acc = accFound || {
    code: accountCode,
    name: meta.label || meta.name || accountCode,
    standard: meta.standard || "",
    cf_bucket: meta.cf_bucket || "",
    cf_section: meta.cf_section || "",
    posting_rules: meta.posting_rules || "",
  };

  console.log("[IFRS] acc lookup", {
    found: !!accFound,
    accountCode,
    acc_standard: acc.standard,
    acc_cf_bucket: acc.cf_bucket,
    meta_standard: meta.standard,
    meta_cf_bucket: meta.cf_bucket,
    hasOpenLeaseWizard: typeof window.openLeaseWizard,
  });

  // --- helpers ---
  const toUpper = (s) => String(s || "").trim().toUpperCase();
  const toLower = (s) => String(s || "").trim().toLowerCase();
  const uniq = (arr) => Array.from(new Set((arr || []).filter(Boolean)));

  // Standards (acc first, then meta)
  const standards = (() => {
    const ms = String(acc.standard || meta.standard || "").trim();
    if (!ms) return [];
    return uniq(ms.split(",").map(s => toUpper(s)));
  })();

  // Posting rules NOTE (acc first, then meta)
  const pr = String(
    acc.postingRules || acc.posting_rules || meta.posting_rules || ""
  );
  const hasPostingNote = pr.toUpperCase().includes("NOTE");

  // ✅ QUICK DIRECT IFRS16 redirect (doesn't require topics list)
  const cfBucket = String(acc.cf_bucket || meta.cf_bucket || "").trim().toLowerCase();
  const directLeaseRedirect =
    standards.includes("IFRS 16") &&
    ["lease_liability", "rou_asset", "lease_receivable"].includes(cfBucket);

  console.log("[IFRS16] direct redirect check", { standards, cfBucket, directLeaseRedirect });

  if (directLeaseRedirect) {
    window.showToast?.(
      "Lease account selected (IFRS 16). Opening Lease Wizard to capture lease metadata and build the amortization schedule…",
      "info"
    );
    console.log("[IFRS16] calling openLeaseWizard now");
    window.openLeaseWizard?.({
      side,
      account: acc,
      accountCode,
      standard: "IFRS 16",
      cf_bucket: cfBucket,
      cf_section: acc.cf_section || meta.cf_section || null,
      journal: {
        date: meta.date || meta.tx_date || null,
        amount: meta.amount || null,
        currency: meta.currency || null,
      },
    });
    return;
  }

  // -------------------------
  // Topics-based reminders (so you remember what you implemented)
  // -------------------------
  const topics = Array.isArray(window.IFRS_NOTE_TOPICS) ? window.IFRS_NOTE_TOPICS : [];
  const matched = topics
    .map(t => ({
      ...t,
      keyU: toUpper(t.key),
      statusU: toLower(t.status),
    }))
    .filter(t => standards.includes(t.keyU));

  console.log("[IFRS] matched/topics", {
    standards,
    matched: matched.map(m => ({ key: m.keyU, status: m.statusU, action: m.action })),
  });

  // If any matched topics that are warn/partial, show reminder
  const warnOrPartial = matched.filter(m => m.statusU === "warn" || m.statusU === "partial");
  if (warnOrPartial.length) {
    const lines = warnOrPartial.map(m => `• ${m.title || m.keyU}`).join("\n");
    window.showToast?.(
      `${acc.name || acc.code || "Account"} triggers IFRS/IAS notes (not automated yet):\n${lines}`,
      "warning"
    );
  }

  // Posting rules NOTE reminder
  if (hasPostingNote) {
    window.showToast?.("This account requires a disclosure note (not automated yet).", "warning");
  }
}
window.handleJournalAccountSelected = handleJournalAccountSelected;

function initJournalUI() {
  console.log("[JRNL] initJournalUI called");

  // ✅ Always ensure guards exist (even on re-entry)
  const ensureGuards = () => {
    try { bindJournalAccountGuards?.(); } catch (e) {
      console.warn("[JRNL] bindJournalAccountGuards failed:", e);
    }
    try { bindJournalVatGuards?.(); } catch (e) {
      console.warn("[JRNL] bindJournalVatGuards failed:", e);
    }
  };

  // ✅ If already wired once, just refresh visuals + ensure guards
  if (window._journalUIBound) {
    ensureGuards();
    renderJournalTable?.();
    recalcJournalSummary?.();
    renderRecentJournals?.().catch(e => console.warn("renderRecentJournals failed", e));
    return;
  }
  window._journalUIBound = true;

  const addBtn  = document.getElementById("addLine");
  const postBtn = document.getElementById("postBatch");
  const form    = document.getElementById("jrnlForm");

  // --- 1) Wire buttons once ---
  if (addBtn) addBtn.addEventListener("click", () => addJournalFromInput?.());

  if (postBtn) {
    postBtn.addEventListener("click", (e) => {
      e.preventDefault();
      postJournalBatch?.().catch((err) => console.error("postJournalBatch error", err));
    });
  }

  // --- 2) Keyboard shortcuts once ---
  if (form) {
    form.addEventListener("keydown", (e) => {
      if (e.key === "Enter" && !e.ctrlKey && !e.shiftKey) {
        e.preventDefault();
        addJournalFromInput?.();
      } else if (e.key === "Enter" && e.ctrlKey) {
        e.preventDefault();
        postJournalBatch?.().catch((err) =>
          console.error("postJournalBatch error (Ctrl+Enter)", err)
        );
      }
    });
  }

  // --- 3) Amount helpers ---
  attachAmountAutoCalc?.(document.getElementById("jrnlDebit"));
  attachAmountAutoCalc?.(document.getElementById("jrnlCredit"));

  wireAmountMath?.(document);               // ✅ enables + - * / () on blur/enter
  wireJournalAmountCalculator?.();          // ✅ optional

  // --- 4) Account combos ---
  populateJournalAccountOptions?.();

  wireJournalAccountCombo({
    categoryId: "jrnlAccountCategory",
    triggerId: "jrnlAccountTrigger",
    menuId: "jrnlAccountMenu",
    searchId: "jrnlAccountSearch",
    optionsId: "jrnlAccountOptions",
    labelId: "jrnlAccountLabel",
    hiddenId: "jrnlAccount",
  });

  wireJournalAccountCombo({
    categoryId: "jrnlAccountCategoryCr",
    triggerId: "jrnlAccountCrTrigger",
    menuId: "jrnlAccountCrMenu",
    searchId: "jrnlAccountCrSearch",
    optionsId: "jrnlAccountCrOptions",
    labelId: "jrnlAccountCrLabel",
    hiddenId: "jrnlAccountCr",
  });

  // ✅ Add AR/AP enforcement guard (must be AFTER combos exist)
  ensureGuards();

  // ✅ VAT dropdown + custom % textbox wiring
  wireJournalVatRateUI?.();

  // --- 5) Initial render ---
  renderJournalTable?.();
  recalcJournalSummary?.();

  // ✅ This wires filters + refresh + search, and also loads the list once
  bindPostedJournalFilters?.();
}

function safeCalc(expr) {
  const s = String(expr || "").trim();

  // allow only digits, dots, spaces, operators, parentheses
  if (!/^[0-9+\-*/().\s]+$/.test(s)) return null;

  // Shunting-yard to RPN + evaluate
  const prec = { "+": 1, "-": 1, "*": 2, "/": 2 };
  const ops = [];
  const out = [];

  // tokenize numbers/operators/parens
  const tokens = s.match(/\d+(\.\d+)?|[()+\-*/]/g);
  if (!tokens) return null;

  for (let i = 0; i < tokens.length; i++) {
    const t = tokens[i];

    if (/^\d/.test(t)) {
      out.push(parseFloat(t));
      continue;
    }

    if (t === "(") { ops.push(t); continue; }
    if (t === ")") {
      while (ops.length && ops[ops.length - 1] !== "(") out.push(ops.pop());
      if (ops.pop() !== "(") return null;
      continue;
    }

    // operator
    while (
      ops.length &&
      ops[ops.length - 1] in prec &&
      prec[ops[ops.length - 1]] >= prec[t]
    ) out.push(ops.pop());

    ops.push(t);
  }

  while (ops.length) {
    const op = ops.pop();
    if (op === "(" || op === ")") return null;
    out.push(op);
  }

  // eval RPN
  const stack = [];
  for (const x of out) {
    if (typeof x === "number") { stack.push(x); continue; }
    const b = stack.pop();
    const a = stack.pop();
    if (typeof a !== "number" || typeof b !== "number") return null;

    if (x === "+") stack.push(a + b);
    else if (x === "-") stack.push(a - b);
    else if (x === "*") stack.push(a * b);
    else if (x === "/") stack.push(b === 0 ? NaN : a / b);
    else return null;
  }

  const result = stack.pop();
  if (!Number.isFinite(result)) return null;
  return result;
}

function wireAmountMath(root = document) {
  root.querySelectorAll("input.jrnl-amt").forEach((inp) => {
    const run = () => {
      const raw = inp.value;
      if (!raw) return;

      const hasOps = /[+\-*/()]/.test(raw);
      if (!hasOps) return; // if it's just a number, leave it

      const v = safeCalc(raw);
      if (v == null) return; // keep user input if invalid

      // format to 2 decimals (or whatever your system uses)
      inp.value = (Math.round(v * 100) / 100).toFixed(2);

      // trigger your recalculation if you have one
      inp.dispatchEvent(new Event("input", { bubbles: true }));
      inp.dispatchEvent(new Event("change", { bubbles: true }));
    };

    inp.addEventListener("blur", run);
    inp.addEventListener("keydown", (e) => {
      if (e.key === "Enter") run();
    });
  });
}

function wireJournalAmountCalculator() {
  const debit = document.getElementById("jrnlDebit");
  const credit = document.getElementById("jrnlCredit");
  const debitPrev = document.getElementById("jrnlDebitPreview");
  const creditPrev = document.getElementById("jrnlCreditPreview");

  [[debit, debitPrev], [credit, creditPrev]].forEach(([el, prev]) => {
    if (!el) return;

    const preview = () => {
      const v = parseAmountExpression(el.value);
      if (!prev) return;
      prev.textContent = (v && !isNaN(v)) ? `= ${v.toFixed(2)}` : "";
    };

    const commit = () => {
      const v = parseAmountExpression(el.value);
      if (v && !isNaN(v)) el.value = v.toFixed(2);
      preview();
    };

    el.addEventListener("input", preview);   // live preview
    el.addEventListener("blur", commit);     // commit on exit
    el.addEventListener("keydown", (e) => {
      if (e.key === "Enter") { e.preventDefault(); commit(); }
    });
  });
}

function parseShorthandNumber(s) {
  // accepts: 1k, 2m, 3.5m, 4.2K (and plain numbers)
  const t = String(s || "").trim().toLowerCase().replace(/,/g, "");
  const m = t.match(/^(-?\d+(\.\d+)?)(k|m)?$/);
  if (!m) return null;

  const n = parseFloat(m[1]);
  if (!Number.isFinite(n)) return null;

  const suf = m[3];
  if (suf === "k") return n * 1000;
  if (suf === "m") return n * 1000000;
  return n;
}

function normalizeAmountExpr(expr) {
  // Convert commas, and convert shorthand tokens inside expressions:
  // "1k + 2.5m" -> "1000 + 2500000"
  let s = String(expr || "").trim();
  if (!s) return "";

  s = s.replace(/,/g, "");

  // replace tokens like 3.5m or 10k when they appear as standalone numbers
  s = s.replace(/(-?\d+(\.\d+)?)([kKmM])\b/g, (full) => {
    const v = parseShorthandNumber(full);
    return v == null ? full : String(v);
  });

  return s;
}

function formatMoney(n) {
  const v = Number(n);
  if (!Number.isFinite(v)) return "";
  return v.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 });
}

// ✅ single entry point used everywhere (replaces parseAmountExpression)
function parseAmountExpression(input) {
  const raw = String(input || "").trim();
  if (!raw) return 0;

  // if it's just a single number/shorthand (no operators), parse quickly
  if (!/[+\-*/()]/.test(raw)) {
    const v = parseShorthandNumber(raw);
    return v == null ? 0 : +Number(v).toFixed(2);
  }

  // otherwise normalize (k/m + commas), then safe-calc
  const norm = normalizeAmountExpr(raw);
  const v = safeCalc(norm);
  if (v == null) return 0;
  return +Number(v).toFixed(2);
}

async function assertNotLocked(dateISO, module = "gl") {
  const cid = getActiveCompanyId?.() || CURRENT_COMPANY_ID;
  if (!cid) throw new Error("No active company.");

  const d = String(dateISO || isoToday()).slice(0, 10);
  const m = String(module || "gl").toLowerCase();

  const url = ENDPOINTS.periodLocks.check(cid, d, m);

  const data = await apiFetch(url, { method: "GET" }); // returns JSON directly
  if (data?.locked) {
    const err = new Error(`Period is locked for ${m.toUpperCase()} on ${d}`);
    err.code = "PERIOD_LOCKED";
    err.status = 409; // useful for UI handlers
    throw err;
  }
  return true;
}

function fillSelectFromCurrentCOA(
  selectEl,
  { placeholder = "Select account…", filterFn = null, labelFn = null } = {}
) {
  if (!selectEl) return;

  const list = Array.isArray(window.CURRENT_COA) ? window.CURRENT_COA : [];
  if (!list.length) {
    selectEl.innerHTML = `<option value="">COA not loaded yet</option>`;
    return;
  }

  const rows = filterFn ? list.filter(filterFn) : list;

  // default label: NAME ONLY (cleaned)
  const getLabel =
    typeof labelFn === "function"
      ? labelFn
      : (a) => {
          const nm = (a?.name || "").toString().trim();
          // fallback: if name missing, show code (better than blank)
          return nm || String(a?.code || "");
        };

  selectEl.innerHTML = `
    <option value="">${esc(placeholder)}</option>
    ${rows
      .filter(a => a && a.code && a.posting !== false)
      .map(a => `<option value="${esc(String(a.code))}">${esc(getLabel(a))}</option>`)
      .join("")}
  `;
}

function populateJournalAccountOptions() {
  const hostDr = document.getElementById("jrnlAccountOptions");
  const hostCr = document.getElementById("jrnlAccountCrOptions");
  if (!hostDr && !hostCr) return;

  const list = Array.isArray(window.CURRENT_COA) ? window.CURRENT_COA : [];
  if (!list.length) return;

  const normCat = (a) => {
    const c = (a.category || a.section || a.group || "").toString().toLowerCase();
    if (c.includes("asset")) return "asset";
    if (c.includes("liab")) return "liability";
    if (c.includes("exp")) return "expense";
    if (c.includes("rev") || c.includes("income")) return "income";
    if (c.includes("equity")) return "equity";
    if (c.includes("adjust")) return "adjustment";
    return "";
  };

  const toStr = (v) => (v === null || v === undefined ? "" : String(v));
  const getTc = (a) => toStr(a.template_code || a.templateCode || a.tc).trim(); // supports multiple shapes

  const makeBtn = (a) => {
    const code  = toStr(a.code).trim();
    const name  = toStr(a.name).trim();
    const label = name || code;

    const tc       = getTc(a);
    const family   = toStr(a.code_family || a.codeFamily).trim();
    const role     = toStr(a.role).trim();
    const section  = toStr(a.section).trim();
    const category = toStr(a.category).trim();

    // ✅ NEW: extra metadata
    const standard = toStr(a.standard).trim(); // e.g. "IAS 2" / "IFRS 16"
    const postingRules = toStr(a.posting_rules || a.postingRules).trim();
    const reportingDesc = toStr(a.reporting_description || a.reportingDescription).trim();
    const cfSection = toStr(a.cf_section || a.cfSection).trim();
    const cfBucket  = toStr(a.cf_bucket || a.cfBucket).trim();
    const posting   = (a.posting === true) ? "1" : "0";

    return `
      <button type="button"
        class="w-full text-left px-2 py-1 hover:bg-slate-100 text-xs"
        data-code="${escapeHtml(code)}"
        data-label="${escapeHtml(label)}"
        data-cat="${escapeHtml(normCat(a))}"
        data-tc="${escapeHtml(tc)}"
        data-family="${escapeHtml(family)}"
        data-role="${escapeHtml(role)}"
        data-section="${escapeHtml(section)}"
        data-category="${escapeHtml(category)}"

        data-standard="${escapeHtml(standard)}"
        data-posting="${escapeHtml(posting)}"
        data-posting-rules="${escapeHtml(postingRules)}"
        data-reporting-desc="${escapeHtml(reportingDesc)}"
        data-cf-section="${escapeHtml(cfSection)}"
        data-cf-bucket="${escapeHtml(cfBucket)}"
      >
        ${escapeHtml(label)}
      </button>
    `;
  };

  const html = list.map(makeBtn).join("");
  if (hostDr) hostDr.innerHTML = html;
  if (hostCr) hostCr.innerHTML = html;
}
window.populateJournalAccountOptions = populateJournalAccountOptions;

function populateAccountSelects() {
  const list = Array.isArray(COA) ? COA : [];

  const opts = list
    .map((a) => {
      const code = (a?.code ?? "").toString();
      const name = cleanCoaName(a?.name ?? code);
      return `<option value="${escapeHtml(code)}">${escapeHtml(name)}</option>`;
    })
    .join("");

  // ✅ 1) Only populate the ledger filter dropdown (full COA ok)
  const selLedger = document.getElementById("ledgerAccount");
  if (selLedger) {
    selLedger.innerHTML =
      `<option value="">Select account…</option>` +
      `<option value="ALL">All accounts</option>` +
      opts;

    selLedger.value = "ALL";
  }

  // ✅ 2) PROTECT quote revenue selects from being overwritten by full COA
  // If any quote line revenue selects exist, re-fill them using revenue cache
  // (This fixes the “first line shows Purchases” issue)
  if (document.querySelector("#quoteLines select.q-acct")) {
    try {
      (async () => {
        if (typeof ensureRevenueAccountsLoaded === "function") {
          await ensureRevenueAccountsLoaded();
        } else if (typeof window.loadRevenueAccountsForInvoice === "function") {
          await window.loadRevenueAccountsForInvoice();
        }

        document.querySelectorAll("#quoteLines select.q-acct").forEach((sel) => {
          const keep = sel.value; // preserve selection
          if (typeof fillRevenueSelect === "function") {
            fillRevenueSelect(sel, keep);
          }
        });
      })();
    } catch (e) {
      console.warn("[populateAccountSelects] revenue refill failed", e);
    }
  }

  populateJournalAccountOptions?.();
}

async function bindBankSetupScreen() {
  // Optional root guard if you have a dedicated container for this screen
  const root = document.getElementById("screen-bank-setup");
  if (root) {
    if (root.dataset.bound === "1") return;
    root.dataset.bound = "1";
  }

  // We support either a <form id="bankSetupForm"> or a separate save button.
  const form = document.getElementById("bankSetupForm");
  const saveBtn = document.getElementById("bankSaveBtn");

  // If neither exists, nothing to do.
  if (!form && !saveBtn) return;

  // Initial load of accounts + list
  await refreshBankAccounts();
  renderBankSetupList();

  // Helper to read form fields into payload
  function collectBankFormPayload() {
    return {
      name:                 document.getElementById("bankName")?.value.trim() || "",
      bank_name:            document.getElementById("bankBankName")?.value.trim() || "",
      account_name:         document.getElementById("bankAccountName")?.value.trim() || "",
      account_number:       document.getElementById("bankAccountNumber")?.value.trim() || "",
      branch_code:          document.getElementById("bankBranchCode")?.value.trim() || "",
      swift_code:           document.getElementById("bankSwiftCode")?.value.trim() || "",
      currency:
        document.getElementById("bankCurrency")?.value.trim() ||
        CURRENT_COMPANY?.currency ||
        "ZAR",
      ledger_account_code:  document.getElementById("bankLedgerCode")?.value.trim() || "",
      is_default_receipts:  !!document.getElementById("bankDefaultReceipts")?.checked,
      is_default_payments:  !!document.getElementById("bankDefaultPayments")?.checked,
    };
  }

  async function handleSave(e) {
    if (e) e.preventDefault();

    const cid = getActiveCompanyId();
    if (!cid) {
      alert("No active company.");
      return;
    }

    const payload = collectBankFormPayload();

    if (!payload.name || !payload.bank_name || !payload.account_number) {
      alert("Name, bank name and account number are required.");
      return;
    }

    await apiFetch(ENDPOINTS.bankAccounts(cid), {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload),
    });

    alert("Bank account saved.");

    // Refresh global cache + both screens that depend on it
    await refreshBankAccounts();
    renderBankSetupList();  // Bank Setup list
    if (typeof loadBankAccounts === "function") {
      await loadBankAccounts(); // Banking & Cashbook dropdown + cashbook
    }
  }

  // Wire either <form> submit or dedicated Save button (or both), but only once
  if (form && form.dataset.bound !== "1") {
    form.dataset.bound = "1";
    form.addEventListener("submit", handleSave);
  }

  if (saveBtn && saveBtn.dataset.bound !== "1") {
    saveBtn.dataset.bound = "1";
    saveBtn.addEventListener("click", handleSave);
  }
}

window.bindBankSetupScreen = bindBankSetupScreen;


// 🔹 Render the "Existing bank accounts" list on Bank Setup screen
