async function loadBankStatements() {
  const cid = getActiveCompanyId();
  const bankId = document.getElementById("bankAccountSelect")?.value;
  const host = document.getElementById("bankStatementList");
  if (!cid || !host) return;

  if (!bankId) {
    host.innerHTML = `<div class="text-xs text-slate-400">Select a bank account to view imports.</div>`;
    return;
  }

  const rows = await apiFetch(ENDPOINTS.bankStatementsList(cid, bankId));
  const list = Array.isArray(rows) ? rows : [];

  if (!list.length) {
    host.innerHTML = `<div class="text-xs text-slate-400">No statements imported yet.</div>`;
    return;
  }

  host.innerHTML = list.map((s) => `
    <div class="border rounded px-2 py-2 flex justify-between items-start">
      <div>
        <div class="text-sm font-medium">${s.file_name}</div>
        <div class="text-xs text-slate-500">
          ${s.status || ""} · ${s.currency || ""} · ${s.uploaded_at || ""}
        </div>
        ${s.error ? `<div class="text-xs text-red-600 mt-1">${s.error}</div>` : ""}
      </div>

      <div class="flex gap-2">
        <button class="tbtn" data-action="recon" data-import-id="${s.id}">Reconcile</button>
      </div>
    </div>
  `).join("");

  host.onclick = async (e) => {
    const btn = e.target.closest("button[data-action]");
    if (!btn) return;
    if (btn.dataset.action === "recon") {
      await startReconciliationFromImport(+btn.dataset.importId);
    }
  };
}

