async function renderCashFlow(periodKey = CURRENT_PERIOD_KEY) {
  const host = document.getElementById("cfMini");
  if (!host) return;

  const cid = getActiveCompanyId();
  if (!cid) {
    host.innerHTML = `<div class="text-xs text-red-500">No active company.</div>`;
    return;
  }

  host.innerHTML = `<div class="text-xs text-slate-400">Loading Cash Flow…</div>`;

  try {
    const pr = computePeriodRange(periodKey);
    let label = pr?.label || periodKey;

    // ✅ build params hybrid-style (calendar => from/to, FY => preset)
    const params = {
      method: "direct",
      compare: "none",
      format: "json",
    };

    if (pr?.from && pr?.to) {
      params.from = pr.from;
      params.to = pr.to;
    } else {
      params.preset = pr?.preset || periodKey;  // backend resolves FY
    }

    // ✅ IMPORTANT: don't force from/to anymore (preset is valid now)
    const url = ENDPOINTS.journal.cashflowMini(cid, params);

    const payload = await apiFetch(url);
    const rowsRaw = Array.isArray(payload) ? payload : (payload?.rows || payload?.items || []);
    const rows = Array.isArray(rowsRaw) ? rowsRaw : [];

    // ✅ backend label wins (e.g. "This financial year (2026-03-01 → 2027-02-28)")
    const metaLabel = payload?.meta?.label;
    if (metaLabel) label = metaLabel;

    if (!rows.length) {
      host.innerHTML = `<div class="text-slate-400 text-sm">No Cash Flow data for ${esc(label)}.</div>`;
      return;
    }

    const ops = rows.filter(r => r.section === "operating");
    const inv = rows.filter(r => r.section === "investing");
    const fin = rows.filter(r => r.section === "financing");

    function renderSection(list, title) {
      if (!list.length) return "";
      const total = list.reduce((s, r) => s + (+r.amount || 0), 0);

      const items = list.map(r => `
        <div class="flex items-center justify-between text-xs">
          <span class="truncate pr-2">${esc(r.label || "")}</span>
          <span class="tabular-nums">${fmt(+r.amount || 0)}</span>
        </div>
      `).join("");

      return `
        <div class="mt-1">
          <div class="text-xs font-semibold text-slate-500 mb-1">${esc(title)}</div>
          ${items}
          <div class="border-t pt-1 mt-1 flex items-center justify-between text-xs font-semibold">
            <span>Net ${esc(title)}</span>
            <span class="tabular-nums">${fmt(total)}</span>
          </div>
        </div>
      `;
    }

    host.innerHTML = `
      <div class="space-y-2">
        <div class="flex items-center justify-between text-[11px] text-slate-500 mb-1">
          <span>Period</span>
          <span class="truncate max-w-[65%] text-right">${esc(label)}</span>
        </div>
        ${renderSection(ops, "Operating Activities")}
        ${renderSection(inv, "Investing Activities")}
        ${renderSection(fin, "Financing Activities")}
      </div>
    `;
  } catch (err) {
    console.error("renderCashFlow error:", err);
    host.innerHTML = `<div class="text-xs text-red-500">Error loading Cash Flow.</div>`;
  }
}

function renderCashFlowFullHtml(stmt, { periodLabel = "", preview_columns = 1, cols_mode = 1 } = {}) {
  const meta = stmt?.meta || {};
  const method = String(meta.method || "direct").toLowerCase();     // direct|indirect
  const basis  = String(meta.basis  || "external").toLowerCase();   // external|management
  const pv = Number(preview_columns || meta.preview_columns || 1);  // 1|2
  const cm = Number(cols_mode || meta.cols_mode || 1);              // 1|2|3

  const isMgmt = (basis === "management" || basis === "internal");
  const isIndirect = (method === "indirect");

  // ---------- INDIRECT ----------
  if (isIndirect) {
    if (isMgmt) {
      // ✅ choose mgmt indirect renderer by cols_mode (if you have 2-col + 3-col)
      if (cm === 3 && typeof window.renderCashFlowIndirectMgmt3ColHtml === "function") {
        return window.renderCashFlowIndirectMgmt3ColHtml(stmt, { periodLabel });
      }
      if (typeof window.renderCashFlowIndirectMgmt2ColHtml === "function") {
        return window.renderCashFlowIndirectMgmt2ColHtml(stmt, { periodLabel });
      }
    }

    // fallback existing indirect renderers
    if (pv === 2 && typeof window.renderCashFlowIndirect2ColHtml === "function") {
      return window.renderCashFlowIndirect2ColHtml(stmt, { periodLabel });
    }
    if (typeof window.renderCashFlowIndirectFullHtml === "function") {
      return window.renderCashFlowIndirectFullHtml(stmt, { periodLabel });
    }
  }

  // ---------- DIRECT ----------
  if (pv === 2 && typeof window.renderCashFlowDirect2ColHtml === "function") {
    return window.renderCashFlowDirect2ColHtml(stmt, { periodLabel });
  }
  if (typeof window.renderCashFlowDirectFullHtml === "function") {
    return window.renderCashFlowDirectFullHtml(stmt, { periodLabel });
  }

  return `<pre class="text-[11px] whitespace-pre-wrap">${esc(JSON.stringify(stmt, null, 2))}</pre>`;
}


function renderCashFlowDirectFullHtml(stmt, { periodLabel = "" } = {}) {
  const meta = stmt?.meta || {};
  const company  = meta.company_name || "Company";
  const currency = meta.currency || "";
  const periodTo = meta?.period?.to || "";
  const periodFrom = meta?.period?.from || "";

  const fmtAmt = (x) => fmtBracket(Number(x || 0));

  // compare columns from payload (if compare is enabled, backend should send 2 cols)
  const cols = Array.isArray(stmt?.columns) ? stmt.columns : [{ key: "cur", label: "Current" }];
  const colA = cols[0] || { key: "cur", label: "Current" };
  const colB = cols[1] || null;

  const hasCompare = !!colB; // ✅ compare ON when 2 columns exist

  const sections = Array.isArray(stmt?.sections) ? stmt.sections : [];
  const byKey = Object.fromEntries(sections.map(s => [s.key, s]));
  const op  = byKey.operating || {};
  const inv = byKey.investing || {};
  const fin = byKey.financing || {};

  // Direct method detail list is in: lines[0].detail[curKey]
  function detailList(sec, key) {
    const first = Array.isArray(sec?.lines) ? sec.lines[0] : null;
    const list = first?.detail?.[key] || [];
    return Array.isArray(list) ? list : [];
  }

  function sectionHeader(title) {
    return `
      <tr>
        <td colspan="${hasCompare ? 3 : 2}"
            class="pt-3 pb-1 font-semibold text-slate-800 uppercase text-[11px]">
          ${esc(title)}
        </td>
      </tr>
    `;
  }

  // ✅ DETAIL ROWS: show CURRENT only; prior column blank (exactly what you asked)
  function detailRow(name, amtCur) {
    return `
      <tr class="border-b border-slate-100">
        <td class="py-[2px] pr-3">${esc(name)}</td>
        <td class="py-[2px] text-right tabular-nums">${amtCur != null ? fmtAmt(amtCur) : ""}</td>
        ${hasCompare ? `<td class="py-[2px] text-right tabular-nums"></td>` : ""}
      </tr>
    `;
  }

  // ✅ TOTAL/SUBTOTAL ROWS: show BOTH current & prior when compare exists
  function totalRow(label, a, b, { double = false } = {}) {
    const cls = double
      ? "font-semibold border-t-2 border-slate-400"
      : "font-semibold border-t border-slate-300";
    return `
      <tr class="${cls}">
        <td class="py-2 pr-3">${esc(label)}</td>
        <td class="py-2 text-right tabular-nums">${fmtAmt(a)}</td>
        ${hasCompare ? `<td class="py-2 text-right tabular-nums">${fmtAmt(b)}</td>` : ""}
      </tr>
    `;
  }

  const opDetails  = detailList(op,  colA.key);
  const invDetails = detailList(inv, colA.key);
  const finDetails = detailList(fin, colA.key);

  const opRows = opDetails.length
    ? opDetails.slice(0, 40).map(d =>
        detailRow(d.account_name || d.description || d.ref || "", d.amount)
      ).join("")
    : `<tr><td colspan="${hasCompare ? 3 : 2}" class="text-xs text-slate-400 py-2">No operating activity.</td></tr>`;

  const invRows = invDetails.length
    ? invDetails.slice(0, 40).map(d =>
        detailRow(d.account_name || d.description || d.ref || "", d.amount)
      ).join("")
    : `<tr><td colspan="${hasCompare ? 3 : 2}" class="text-xs text-slate-400 py-2">No investing activity.</td></tr>`;

  const finRows = finDetails.length
    ? finDetails.slice(0, 40).map(d =>
        detailRow(d.account_name || d.description || d.ref || "", d.amount)
      ).join("")
    : `<tr><td colspan="${hasCompare ? 3 : 2}" class="text-xs text-slate-400 py-2">No financing activity.</td></tr>`;

  // totals per column key
  const opTotA  = Number(op?.totals?.[colA.key] ?? 0);
  const invTotA = Number(inv?.totals?.[colA.key] ?? 0);
  const finTotA = Number(fin?.totals?.[colA.key] ?? 0);

  const opTotB  = hasCompare ? Number(op?.totals?.[colB.key] ?? 0) : 0;
  const invTotB = hasCompare ? Number(inv?.totals?.[colB.key] ?? 0) : 0;
  const finTotB = hasCompare ? Number(fin?.totals?.[colB.key] ?? 0) : 0;

  const netA = Number(stmt?.net_change?.values?.[colA.key] ?? 0);
  const netB = hasCompare ? Number(stmt?.net_change?.values?.[colB.key] ?? 0) : 0;

  const openA = Number(stmt?.opening_balance?.values?.[colA.key] ?? 0);
  const openB = hasCompare ? Number(stmt?.opening_balance?.values?.[colB.key] ?? 0) : 0;

  const closeA = Number(stmt?.closing_balance?.values?.[colA.key] ?? 0);
  const closeB = hasCompare ? Number(stmt?.closing_balance?.values?.[colB.key] ?? 0) : 0;

  return `
    <div class="w-full flex justify-center print:block">
      <div class="w-full max-w-[900px] bg-white px-6 py-4 print:max-w-none print:px-0">
        <div class="mb-3 text-left">
          <div class="text-sm font-bold tracking-wide">${esc(String(company).toUpperCase())}</div>
          <div class="text-xs font-semibold">${esc("STATEMENT OF CASH FLOWS (Direct method)")}</div>
          <div class="text-xs">
            ${esc(periodFrom && periodTo ? `For the period ${periodFrom} to ${periodTo}` : (periodTo ? `For the period ended ${periodTo}` : ""))}
          </div>
          ${currency ? `<div class="text-[11px] text-slate-500">(All amounts in ${esc(currency)})</div>` : ""}
          ${periodLabel ? `<div class="text-[11px] text-slate-500">Period preset: ${esc(periodLabel)}</div>` : ""}
        </div>

        <div class="border border-slate-200 bg-white rounded p-3 overflow-hidden print:border-0 print:p-0">
          <table class="w-full text-[12px] leading-tight border-collapse">
            <thead class="bg-slate-50 text-slate-600 print:bg-white">
              <tr>
                <th class="text-left py-2 px-2">Description</th>
                <th class="text-right py-2 px-2">${esc(colA.label || colA.key)}</th>
                ${hasCompare ? `<th class="text-right py-2 px-2">${esc(colB.label || colB.key)}</th>` : ""}
              </tr>
            </thead>
            <tbody>
              ${sectionHeader("Cash flows from operating activities")}
              ${opRows}
              ${totalRow(op?.label || "Net cash from operating activities", opTotA, opTotB)}

              <tr><td colspan="${hasCompare ? 3 : 2}" class="py-2"></td></tr>

              ${sectionHeader("Cash flows from investing activities")}
              ${invRows}
              ${totalRow(inv?.label || "Net cash from investing activities", invTotA, invTotB)}

              <tr><td colspan="${hasCompare ? 3 : 2}" class="py-2"></td></tr>

              ${sectionHeader("Cash flows from financing activities")}
              ${finRows}
              ${totalRow(fin?.label || "Net cash from financing activities", finTotA, finTotB)}

              <tr><td colspan="${hasCompare ? 3 : 2}" class="py-2"></td></tr>

              ${totalRow(stmt?.net_change?.label || "Net change in cash and cash equivalents", netA, netB, { double: true })}

              <tr><td colspan="${hasCompare ? 3 : 2}" class="py-2"></td></tr>

              ${totalRow(stmt?.opening_balance?.label || "Opening cash and cash equivalents", openA, openB)}
              ${totalRow(stmt?.closing_balance?.label || "Closing cash and cash equivalents", closeA, closeB)}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  `;
}

function renderCashFlowIndirectFullHtml(stmt, { periodLabel = "" } = {}) {
  const meta = stmt?.meta || {};
  const company  = meta.company_name || "Company";
  const currency = meta.currency || "";
  const periodTo = meta?.period?.to || "";
  const periodFrom = meta?.period?.from || "";

  const cols = Array.isArray(stmt?.columns) ? stmt.columns : [{ key: "cur", label: "Current" }];

  const sections = Array.isArray(stmt?.sections) ? stmt.sections : [];
  const byKey = Object.fromEntries(sections.map(s => [s.key, s]));

  const op  = byKey.operating || {};
  const inv = byKey.investing || {};
  const fin = byKey.financing || {};

  const fmtAmt = (x) => fmtBracket(Number(x || 0));

  function ths() {
    const hdr = cols.map(c => `<th class="text-right py-2 px-2">${esc(c.label || c.key)}</th>`).join("");
    return `<tr><th class="text-left py-2 px-2">Description</th>${hdr}</tr>`;
  }

  function valsTd(values) {
    return cols.map(c => {
      const v = values?.[c.key];
      return `<td class="py-[2px] text-right tabular-nums">${v == null ? "" : fmtAmt(v)}</td>`;
    }).join("");
  }

  function row(name, values) {
    return `
      <tr class="border-b border-slate-100">
        <td class="py-[2px] pr-3">${esc(name)}</td>
        ${valsTd(values)}
      </tr>
    `;
  }

  function sectionHeader(title) {
    return `
      <tr>
        <td colspan="${1 + cols.length}" class="pt-3 pb-1 font-semibold text-slate-800 uppercase text-[11px]">
          ${esc(title)}
        </td>
      </tr>
    `;
  }

  const opLines = Array.isArray(op?.lines) ? op.lines : [];
  const opRows = opLines.length
    ? opLines.map(ln => row(ln?.name || ln?.code || "", ln?.values)).join("")
    : `<tr><td colspan="${1 + cols.length}" class="text-xs text-slate-400 py-2">No operating activity.</td></tr>`;

  const invTotalRow = row(inv?.label || "Net cash from investing activities", inv?.totals);
  const finTotalRow = row(fin?.label || "Net cash from financing activities", fin?.totals);
  const netRow = row(stmt?.net_change?.label || "Net change in cash and cash equivalents", stmt?.net_change?.values);

  return `
    <div class="w-full flex justify-center print:block">
      <div class="w-full max-w-[900px] bg-white px-6 py-4 print:max-w-none print:px-0">
        <div class="mb-3 text-left">
          <div class="text-sm font-bold tracking-wide">${esc(String(company).toUpperCase())}</div>
          <div class="text-xs font-semibold">${esc("STATEMENT OF CASH FLOWS (Indirect method)")}</div>
          <div class="text-xs">
            ${esc(periodFrom && periodTo ? `For the period ${periodFrom} to ${periodTo}` : (periodTo ? `For the period ended ${periodTo}` : ""))}
          </div>
          ${currency ? `<div class="text-[11px] text-slate-500">(All amounts in ${esc(currency)})</div>` : ""}
          ${periodLabel ? `<div class="text-[11px] text-slate-500">Period preset: ${esc(periodLabel)}</div>` : ""}
        </div>

        <div class="border border-slate-200 bg-white rounded p-3 overflow-hidden print:border-0 print:p-0">
          <table class="w-full text-[12px] leading-tight border-collapse">
            <thead class="bg-slate-50 text-slate-600 print:bg-white">${ths()}</thead>
            <tbody>
              ${sectionHeader("Cash flows from operating activities")}
              ${opRows}
              ${row(op?.label || "Net cash from operating activities", op?.totals)}

              <tr><td colspan="${1 + cols.length}" class="py-2"></td></tr>

              ${sectionHeader("Cash flows from investing activities")}
              ${invTotalRow}

              <tr><td colspan="${1 + cols.length}" class="py-2"></td></tr>

              ${sectionHeader("Cash flows from financing activities")}
              ${finTotalRow}

              <tr><td colspan="${1 + cols.length}" class="py-2"></td></tr>

              <tr class="font-semibold border-t border-slate-300">${netRow}</tr>
            </tbody>
          </table>
        </div>
      </div>
    </div>
  `;
}

function renderCashFlowIndirect2ColHtml(stmt, { periodLabel = "" } = {}) {
  const meta = stmt?.meta || {};
  const company  = meta.company_name || "Company";
  const currency = meta.currency || "";
  const periodTo = meta?.period?.to || "";
  const periodFrom = meta?.period?.from || "";

  const fmtAmt = (x) => fmtBracket(Number(x || 0));
  const sections = Array.isArray(stmt?.sections) ? stmt.sections : [];
  const byKey = Object.fromEntries(sections.map(s => [s.key, s]));

  const op  = byKey.operating || {};
  const inv = byKey.investing || {};
  const fin = byKey.financing || {};

  const opLines = Array.isArray(op?.lines) ? op.lines : [];

  function detailList(sec) {
    const first = Array.isArray(sec?.lines) ? sec.lines[0] : null;
    const list = first?.detail?.cur || [];
    return Array.isArray(list) ? list : [];
  }

  function sectionHeader(title) {
    return `
      <tr>
        <td colspan="3" class="pt-3 pb-1 font-semibold text-slate-800 uppercase text-[11px]">
          ${esc(title)}
        </td>
      </tr>
    `;
  }

  function renderRow(name, amt) {
    const { inflow, outflow } = splitInOut(amt);
    return `
      <tr class="border-b border-slate-100">
        <td class="py-[2px] pr-3">${esc(name)}</td>
        <td class="py-[2px] text-right tabular-nums">${inflow ? fmtAmt(inflow) : ""}</td>
        <td class="py-[2px] text-right tabular-nums">${outflow ? fmtAmt(outflow) : ""}</td>
      </tr>
    `;
  }

  function renderTotal(label, amt, { double = false } = {}) {
    return renderNetTotalRow(label, amt, { double });
  }

  const opTotal = Number(op?.totals?.cur ?? 0);
  const invTotal = Number(inv?.totals?.cur ?? 0);
  const finTotal = Number(fin?.totals?.cur ?? 0);
  const netTotal = Number(stmt?.net_change?.values?.cur ?? 0);
  const openingTotal = Number(stmt?.opening_balance?.values?.cur ?? 0);
  const closingTotal = Number(stmt?.closing_balance?.values?.cur ?? 0);

  const investingDetails = detailList(inv);
  const financingDetails = detailList(fin);

  const opRows = opLines.length
    ? opLines.map(ln => renderRow(ln?.name || ln?.code || "", ln?.values?.cur)).join("")
    : `<tr><td colspan="3" class="text-xs text-slate-400 py-2">No operating activity.</td></tr>`;

  const invRows = investingDetails.length
    ? investingDetails.slice(0, 40).map(d => renderRow(d.account_name || d.description || d.ref || "", d.amount)).join("")
    : `<tr><td colspan="3" class="text-xs text-slate-400 py-2">No investing activity.</td></tr>`;

  const finRows = financingDetails.length
    ? financingDetails.slice(0, 40).map(d => renderRow(d.account_name || d.description || d.ref || "", d.amount)).join("")
    : `<tr><td colspan="3" class="text-xs text-slate-400 py-2">No financing activity.</td></tr>`;

  return `
    <div class="w-full flex justify-center print:block">
      <div class="w-full max-w-[900px] bg-white px-6 py-4 print:max-w-none print:px-0">
        <div class="mb-3 text-left">
          <div class="text-sm font-bold tracking-wide">${esc(String(company).toUpperCase())}</div>
          <div class="text-xs font-semibold">${esc("STATEMENT OF CASH FLOWS (Indirect method)")}</div>
          <div class="text-xs">
            ${esc(periodFrom && periodTo ? `For the period ${periodFrom} to ${periodTo}` : (periodTo ? `For the period ended ${periodTo}` : ""))}
          </div>
          ${currency ? `<div class="text-[11px] text-slate-500">(All amounts in ${esc(currency)})</div>` : ""}
          ${periodLabel ? `<div class="text-[11px] text-slate-500">Period preset: ${esc(periodLabel)}</div>` : ""}
        </div>

        <div class="border border-slate-200 bg-white rounded p-3 overflow-hidden print:border-0 print:p-0">
          <table class="w-full text-[12px] leading-tight border-collapse">
            <thead class="bg-slate-50 text-slate-600 print:bg-white">
              <tr>
                <th class="text-left py-2 px-2">Description</th>
                <th class="text-right py-2 px-2">Inflow</th>
                <th class="text-right py-2 px-2">Outflow</th>
              </tr>
            </thead>
            <tbody>
              ${sectionHeader("Cash flows from operating activities")}
              ${opRows}
              ${renderTotal(op?.label || "Net cash from operating activities", opTotal)}

              <tr><td colspan="3" class="py-2"></td></tr>

              ${sectionHeader("Cash flows from investing activities")}
              ${invRows}
              ${renderTotal(inv?.label || "Net cash from investing activities", invTotal)}

              <tr><td colspan="3" class="py-2"></td></tr>

              ${sectionHeader("Cash flows from financing activities")}
              ${finRows}
              ${renderTotal(fin?.label || "Net cash from financing activities", finTotal)}

              <tr><td colspan="3" class="py-2"></td></tr>

              ${renderTotal(stmt?.net_change?.label || "Net change in cash and cash equivalents", netTotal, { double: true })}

              <tr><td colspan="3" class="py-2"></td></tr>

              ${renderTotal(stmt?.opening_balance?.label || "Opening cash and cash equivalents", openingTotal)}
              ${renderTotal(stmt?.closing_balance?.label || "Closing cash and cash equivalents", closingTotal)}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  `;
}

function renderCashFlowIndirectMgmt2ColHtml(stmt, { periodLabel = "" } = {}) {
  const meta = stmt?.meta || {};
  const company  = meta.company_name || "Company";
  const currency = meta.currency || "";
  const periodTo = meta?.period?.to || "";
  const periodFrom = meta?.period?.from || "";

  const fmtAmt = (x) => fmtBracket(Number(x || 0));

  const cols = Array.isArray(stmt?.columns) ? stmt.columns : [
    { key: "brk", label: "Breakdown" },
    { key: "tot", label: "Total" },
  ];

  const colA = cols[0] || { key: "cur", label: "Current" };
  const colB = cols[1] || { key: "pri", label: "Prior" };
  const colC = cols[2] || null;

  const sections = Array.isArray(stmt?.sections) ? stmt.sections : [];
  const byKey = Object.fromEntries(sections.map(s => [s.key, s]));
  const op  = byKey.operating || {};
  const inv = byKey.investing || {};
  const fin = byKey.financing || {};

  function ths() {
    return `
      <tr>
        <th class="text-left py-2 px-2">Description</th>
        <th class="text-right py-2 px-2">${esc(colA?.label || colA?.key || "")}</th>
        <th class="text-right py-2 px-2">${esc(colB?.label || colB?.key || "")}</th>
        ${colC ? `<th class="text-right py-2 px-2">${esc(colC.label || colC.key)}</th>` : ""}
      </tr>
    `;
  }

  function tdVal(values, key) {
    const v = values?.[key];
    return (v == null || v === "") ? "" : fmtAmt(Number(v || 0));
  }

  function row(name, values, { bold=false } = {}) {
    return `
      <tr class="border-b border-slate-100 ${bold ? "font-semibold" : ""}">
        <td class="py-[2px] pr-3">${esc(name)}</td>
        <td class="py-[2px] text-right tabular-nums">${tdVal(values, colA.key)}</td>
        <td class="py-[2px] text-right tabular-nums">${tdVal(values, colB.key)}</td>
        ${colC ? `<td class="py-[2px] text-right tabular-nums">${tdVal(values, colC.key)}</td>` : ""}
      </tr>
    `;
  }

  function sectionHeader(title) {
    return `
      <tr>
        <td colspan="${colC ? 4 : 3}" class="pt-3 pb-1 font-semibold text-slate-800 uppercase text-[11px]">
          ${esc(title)}
        </td>
      </tr>
    `;
  }

  function renderSection(sec, title) {
    const lines = Array.isArray(sec?.lines) ? sec.lines : [];
    const rows = lines.length
      ? lines.map(ln => row(ln?.name || ln?.code || "", ln?.values, {
          bold: String(ln?.code || "").startsWith("SUB_") || String(ln?.code || "").startsWith("SUB")
        })).join("")
      : `<tr><td colspan="${colC ? 4 : 3}" class="text-xs text-slate-400 py-2">No data.</td></tr>`;

    // totals can be omitted if you already include a SUB row in lines
    return `${sectionHeader(title)}${rows}`;
  }

  // footer rows should be in "tot"
  const net = stmt?.net_change?.values || {};
  const open = stmt?.opening_balance?.values || {};
  const close = stmt?.closing_balance?.values || {};

  return `
    <div class="w-full flex justify-center print:block">
      <div class="w-full max-w-[900px] bg-white px-6 py-4 print:max-w-none print:px-0">
        <div class="mb-3 text-left">
          <div class="text-sm font-bold tracking-wide">${esc(String(company).toUpperCase())}</div>
          <div class="text-xs font-semibold">${esc("STATEMENT OF CASH FLOWS (Indirect method)")}</div>
          <div class="text-xs">
            ${esc(periodFrom && periodTo ? `For the period ${periodFrom} to ${periodTo}` : (periodTo ? `For the period ended ${periodTo}` : ""))}
          </div>
          ${currency ? `<div class="text-[11px] text-slate-500">(All amounts in ${esc(currency)})</div>` : ""}
          ${periodLabel ? `<div class="text-[11px] text-slate-500">Period preset: ${esc(periodLabel)}</div>` : ""}
        </div>

        <div class="border border-slate-200 bg-white rounded p-3 overflow-hidden print:border-0 print:p-0">
          <table class="w-full text-[12px] leading-tight border-collapse">
            <thead class="bg-slate-50 text-slate-600 print:bg-white">${ths()}</thead>
            <tbody>
              ${renderSection(op,  "Cash flows from operating activities")}
              <tr><td colspan="${colC ? 4 : 3}" class="py-2"></td></tr>

              ${renderSection(inv, "Cash flows from investing activities")}
              <tr><td colspan="${colC ? 4 : 3}" class="py-2"></td></tr>

              ${renderSection(fin, "Cash flows from financing activities")}
              <tr><td colspan="${colC ? 4 : 3}" class="py-2"></td></tr>

              ${row(stmt?.net_change?.label || "Net change in cash and cash equivalents", net, { bold: true })}
              <tr><td colspan="${colC ? 4 : 3}" class="py-2"></td></tr>
              ${row(stmt?.opening_balance?.label || "Opening cash and cash equivalents", open, { bold: true })}
              ${row(stmt?.closing_balance?.label || "Closing cash and cash equivalents", close, { bold: true })}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  `;
}

