function normalizeStatementToV2(t, data) {
  // Already v2
  if (data && typeof data === "object" && Array.isArray(data.columns) && Array.isArray(data.sections)) {
    return data;
  }

  // If backend returned error payload as JSON but still 200
  if (data && typeof data === "object" && (data.ok === false || data.error)) {
    return {
      meta: { statement: t, template: "ifrs", basis: "external" },
      columns: [{ key: "cur", label: "Amount" }],
      sections: [{
        key: "error",
        label: "Error",
        lines: [{ name: data.error || "Unknown error", values: { cur: 0 } }],
        totals: { cur: 0 }
      }]
    };
  }

  // ---- P&L v1 -> v2 adapter (common cases) ----
  if (t === "pnl" && data && typeof data === "object") {
    const cols = [{ key: "cur", label: "Amount" }];

    // case A: { revenue:[...], expenses:[...], net_profit: ... }
    const rev = Array.isArray(data.revenue) ? data.revenue : [];
    const exp = Array.isArray(data.expenses) ? data.expenses : [];

    if (rev.length || exp.length) {
      const mapLines = (arr) => arr.map(x => ({
        name: x.name || x.label || x.account_name || x.account || "Line",
        values: { cur: Number(x.amount ?? x.value ?? x.cur ?? 0) },
        indent: Number(x.indent || 0)
      }));

      const sum = (arr) => arr.reduce((a, x) => a + Number(x.amount ?? x.value ?? x.cur ?? 0), 0);

      const revTot = sum(rev);
      const expTot = sum(exp);
      const net = Number(data.net_profit ?? data.net_result ?? (revTot - expTot) ?? 0);

      return {
        meta: data.meta || { statement: "pnl" },
        columns: cols,
        sections: [
          { key: "revenue", label: "Revenue", lines: mapLines(rev), totals: { cur: revTot } },
          { key: "expenses", label: "Operating expenses", lines: mapLines(exp), totals: { cur: expTot } },
        ],
        net_result: { label: "Net Profit", values: { cur: net } }
      };
    }

    // case B: { rows:[...] } (trial-balance-like)
    if (Array.isArray(data.rows)) {
      const lines = data.rows.map(r => ({
        name: r.name || r.label || r.account_name || r.account || "Line",
        values: { cur: Number(r.amount ?? r.value ?? 0) }
      }));
      const total = lines.reduce((a, l) => a + Number(l.values.cur || 0), 0);

      return {
        meta: data.meta || { statement: "pnl" },
        columns: cols,
        sections: [{ key: "pnl", label: "Profit & Loss", lines, totals: { cur: total } }]
      };
    }
  }

  // Fallback: render as JSON table using v2 wrapper
  return {
    meta: { statement: t },
    columns: [{ key: "cur", label: "Value" }],
    sections: [{
      key: "raw",
      label: "Raw response",
      lines: [{ name: "See JSON below", values: { cur: 0 } }],
      totals: { cur: 0 }
    }],
    _raw: data
  };
}

function renderStatementV2Html(stmt) {
  const meta = stmt?.meta || {};

  // Always render a single Amount column for IAS‑1 external view
  const cols = Array.isArray(stmt?.columns) && stmt.columns.length
    ? stmt.columns
    : [{ key: "cur", label: "Amount" }];

  const company = meta.company_name || "Company";

  const titleMap = {
    pnl: meta.template === "npo" ? "Statement of Financial Performance" : "Statement of Profit or Loss",
    bs:  "Statement of Financial Position",
    cf:  "Statement of Cash Flows",
    tb:  "Trial Balance",
  };

  const title = titleMap[meta.statement] || "Statement";

  const periodText =
    meta.statement === "bs"
      ? `As at ${meta.as_of || meta.period?.to || ""}`
      : `For the period ${meta.period?.from || ""} to ${meta.period?.to || ""}`;

  const th = cols
    .map(c => `<th class="text-right py-2 px-2">${esc(c.label)}</th>`)
    .join("");

  function rowCells(values, bold = false) {
    return cols.map(c => {
      const v = Number(values?.[c.key] || 0);
      const cls = bold ? "font-semibold" : "";
      return `<td class="text-right py-2 px-2 tabular-nums ${cls}">${fmtBracket(v)}</td>`;
    }).join("");
  }

  // Hunter-style subtotal row (underline on amount)
  function subtotalRow(label, values, { isTotal = false } = {}) {
    const leftCls = isTotal ? "font-semibold" : "text-slate-700 font-semibold";
    const cellCls = isTotal ? "font-semibold" : "font-semibold";
    return `
      <tr>
        <td class="py-2 px-2 ${leftCls}">${esc(label)}</td>
        ${cols.map(c => {
          const v = Number(values?.[c.key] || 0);
          return `
            <td class="text-right py-2 px-2 tabular-nums ${cellCls}">
              <div class="inline-block border-b border-slate-400 pb-[1px]">
                ${fmtBracket(v)}
              </div>
            </td>
          `;
        }).join("")}
      </tr>
    `;
  }

  function renderSection(sec) {
    const lines = (sec.lines || []).map(ln => {
      // PPE special rendering (unchanged)
      if (ln.ppe_values) {
        const mode = String(ln.ppe_cols_mode || "1");

        if (mode === "1") {
          return `
            <tr class="border-b border-slate-100">
              <td class="py-2 px-2">${esc(ln.name || "")}</td>
              ${rowCells(ln.ppe_values)}
            </tr>
          `;
        }

        if (mode === "2") {
          const hasPrior = cols.some(c => c.key === "pri");
          const head = hasPrior
            ? `<th class="text-right py-2 px-2">Cost (Cur)</th>
               <th class="text-right py-2 px-2">Carrying (Cur)</th>
               <th class="text-right py-2 px-2">Cost (Pri)</th>
               <th class="text-right py-2 px-2">Carrying (Pri)</th>
               <th class="text-right py-2 px-2">Δ Carrying</th>`
            : `<th class="text-right py-2 px-2">Cost</th>
               <th class="text-right py-2 px-2">Carrying</th>`;

          const v = ln.ppe_values || {};
          const cells = hasPrior
            ? `
              <td class="text-right py-2 px-2 tabular-nums">${fmt(Number(v.cur_cost || 0))}</td>
              <td class="text-right py-2 px-2 tabular-nums font-semibold">${fmt(Number(v.cur_carrying || 0))}</td>
              <td class="text-right py-2 px-2 tabular-nums">${fmt(Number(v.pri_cost || 0))}</td>
              <td class="text-right py-2 px-2 tabular-nums font-semibold">${fmt(Number(v.pri_carrying || 0))}</td>
              <td class="text-right py-2 px-2 tabular-nums font-semibold">${fmt(Number(v.delta_carrying || 0))}</td>
            `
            : `
              <td class="text-right py-2 px-2 tabular-nums">${fmt(Number(v.cur_cost || 0))}</td>
              <td class="text-right py-2 px-2 tabular-nums font-semibold">${fmt(Number(v.cur_carrying || 0))}</td>
            `;

          return `
            <tr class="border-b border-slate-100">
              <td class="py-2 px-2">${esc(ln.name || "")}</td>
              <td class="py-2 px-2" colspan="${cols.length}">
                <div class="border border-slate-100 rounded bg-white overflow-hidden">
                  <table class="w-full text-xs">
                    <thead class="bg-slate-50 text-slate-600"><tr>${head}</tr></thead>
                    <tbody><tr>${cells}</tr></tbody>
                  </table>
                </div>
              </td>
            </tr>
          `;
        }

        // mode === "3"
        const hasPrior = cols.some(c => c.key === "pri");
        const head = hasPrior
          ? `<th class="text-right py-2 px-2">Cost (Cur)</th>
             <th class="text-right py-2 px-2">AccDep (Cur)</th>
             <th class="text-right py-2 px-2">Carrying (Cur)</th>
             <th class="text-right py-2 px-2">Cost (Pri)</th>
             <th class="text-right py-2 px-2">AccDep (Pri)</th>
             <th class="text-right py-2 px-2">Carrying (Pri)</th>
             <th class="text-right py-2 px-2">Δ Carrying</th>`
          : `<th class="text-right py-2 px-2">Cost</th>
             <th class="text-right py-2 px-2">AccDep</th>
             <th class="text-right py-2 px-2">Carrying</th>`;

        const v = ln.ppe_values || {};
        const cells = hasPrior
          ? `
            <td class="text-right py-2 px-2 tabular-nums">${fmt(Number(v.cur_cost || 0))}</td>
            <td class="text-right py-2 px-2 tabular-nums">${fmt(Number(v.cur_accdep || 0))}</td>
            <td class="text-right py-2 px-2 tabular-nums font-semibold">${fmt(Number(v.cur_carrying || 0))}</td>

            <td class="text-right py-2 px-2 tabular-nums">${fmt(Number(v.pri_cost || 0))}</td>
            <td class="text-right py-2 px-2 tabular-nums">${fmt(Number(v.pri_accdep || 0))}</td>
            <td class="text-right py-2 px-2 tabular-nums font-semibold">${fmt(Number(v.pri_carrying || 0))}</td>

            <td class="text-right py-2 px-2 tabular-nums font-semibold">${fmt(Number(v.delta_carrying || 0))}</td>
          `
          : `
            <td class="text-right py-2 px-2 tabular-nums">${fmt(Number(v.cur_cost || 0))}</td>
            <td class="text-right py-2 px-2 tabular-nums">${fmt(Number(v.cur_accdep || 0))}</td>
            <td class="text-right py-2 px-2 tabular-nums font-semibold">${fmt(Number(v.cur_carrying || 0))}</td>
          `;

        return `
          <tr class="border-b border-slate-100">
            <td class="py-2 px-2">${esc(ln.name || "")}</td>
            <td class="py-2 px-2" colspan="${cols.length}">
              <div class="border border-slate-100 rounded bg-white overflow-hidden">
                <table class="w-full text-xs">
                  <thead class="bg-slate-50 text-slate-600"><tr>${head}</tr></thead>
                  <tbody><tr>${cells}</tr></tbody>
                </table>
              </div>
            </td>
          </tr>
        `;
      }

      // Normal line
      const indent = Number(ln.indent || 0);
      const padPx = Math.max(0, Math.min(indent, 10)) * 12;
      return `
        <tr class="border-b border-slate-100">
          <td class="py-2 px-2" style="padding-left:${padPx}px">${esc(ln.name || "")}</td>
          ${rowCells(ln.values || {})}
        </tr>
      `;
    }).join("");

    const totals = subtotalRow(`${sec.label} total`, sec.totals, { isTotal: true });

    return `
      <div class="mb-4">
        <div class="text-xs font-semibold text-slate-600 mb-1">${esc(sec.label)}</div>
        <div class="border border-slate-100 rounded-lg overflow-hidden bg-white">
          <table class="w-full text-xs">
            <tbody>
              ${lines}
              ${totals}
            </tbody>
          </table>
        </div>
      </div>
    `;
  }

  // Hunter blocks renderer (unchanged)
  function renderBlocks() {
    const blocks = Array.isArray(stmt.blocks) ? stmt.blocks : [];
    if (!blocks.length) return "";

    return blocks.map(b => {
      const label = b.label || b.title || "";
      const lines = Array.isArray(b.lines) ? b.lines : [];
      const isSingle = !!b.values && !lines.length;

      if (isSingle) {
        return `
          <div class="mb-3">
            <div class="border border-slate-100 rounded-lg overflow-hidden bg-white">
              <table class="w-full text-xs">
                <tbody>
                  ${subtotalRow(label, b.values, { isTotal: true })}
                </tbody>
              </table>
            </div>
          </div>
        `;
      }

      const rows = lines.map(ln => {
        const isSub = !!ln.is_subtotal;
        const nm = ln.name || ln.label || "";
        const indent = Number(ln.indent || 0);
        const padPx = Math.max(0, Math.min(indent, 10)) * 12;

        const lessCls = ln.is_less_line ? "text-slate-600" : "";
        const nameCls = isSub ? "font-semibold" : "";
        const trCls = isSub ? "" : "border-b border-slate-100";

        if (isSub) {
          return subtotalRow(nm, ln.values || {}, { isTotal: false });
        }

        return `
          <tr class="${trCls}">
            <td class="py-2 px-2 ${lessCls} ${nameCls}" style="padding-left:${padPx}px">${esc(nm)}</td>
            ${rowCells(ln.values || {}, false)}
          </tr>
        `;
      }).join("");

      const totalsRow = b.totals ? subtotalRow(`${label} total`, b.totals, { isTotal: true }) : "";

      return `
        <div class="mb-4">
          <div class="text-xs font-semibold text-slate-600 mb-1">${esc(label)}</div>
          <div class="border border-slate-100 rounded-lg overflow-hidden bg-white">
            <table class="w-full text-xs">
              <thead class="bg-slate-50 text-slate-600">
                <tr>
                  <th class="text-left py-2 px-2">Description</th>
                  ${th}
                </tr>
              </thead>
              <tbody>
                ${rows}
                ${totalsRow}
              </tbody>
            </table>
          </div>
        </div>
      `;
    }).join("");
  }

  // ---- Header ----
  let html = `
    <div class="mb-3">
      <div class="text-lg font-bold text-slate-900">${esc(company)}</div>
      <div class="text-sm font-semibold text-slate-700">${esc(title)}</div>
      <div class="text-xs text-slate-500">${esc(periodText)}</div>
    </div>
  `;

  // Single global column header
  html += `
    <div class="border border-slate-100 rounded-lg overflow-hidden bg-white mb-2">
      <table class="w-full text-xs">
        <thead class="bg-slate-50 text-slate-600">
          <tr>
            <th class="text-left py-2 px-2">Description</th>
            ${cols.map(c => `<th class="text-right py-2 px-2">${esc(c.label || c.key)}</th>`).join("")}
          </tr>
        </thead>
      </table>
    </div>
  `;

  // Body: blocks first, else sections
  const hasBlocks   = Array.isArray(stmt.blocks)   && stmt.blocks.length;
  const hasSections = Array.isArray(stmt.sections) && stmt.sections.length;

  if (hasBlocks) {
    html += renderBlocks();
  } else if (hasSections) {
    html += stmt.sections.map(sec => renderSection(sec)).join("");
  } else {
    html += `<div class="text-xs text-slate-500">No data provided for this statement.</div>`;
  }

  // ----------------------------
  // Balance sheet check (unchanged)
  // ----------------------------
  if (meta.statement === "bs" && stmt.balance_check) {
    const bc = stmt.balance_check;
    const a  = bc.assets || {};
    const el = bc.equity_liabilities || {};
    const df = bc.difference || {};

    html += `
      <div class="mt-3 border border-slate-100 rounded-lg overflow-hidden bg-white">
        <table class="w-full text-xs">
          <thead class="bg-slate-50 text-slate-600">
            <tr>
              <th class="text-left py-2 px-2">Balance check</th>
              ${cols.map(c => `<th class="text-right py-2 px-2">${esc(c.label)}</th>`).join("")}
            </tr>
          </thead>
          <tbody>
            ${subtotalRow("Total Assets", a, { isTotal: true })}
            ${subtotalRow("Total Equity &amp; Liabilities", el, { isTotal: true })}
            <tr class="bg-slate-50 font-semibold">
              <td class="py-2 px-2">Difference (should be 0)</td>
              ${cols.map(c => {
                const v = Number(df[c.key] || 0);
                const cls = Math.abs(v) > 0.0001 ? "text-red-600" : "text-slate-700";
                return `<td class="text-right py-2 px-2 tabular-nums ${cls}">${fmtBracket(v)}</td>`;
              }).join("")}
            </tr>
          </tbody>
        </table>
      </div>
    `;
  }

  // ----------------------------
  // Net result (P&L) – always before OCI
  // ----------------------------
  if (meta.statement === "pnl" && stmt.net_result?.values) {
    html += `
      <div class="mt-4 border border-slate-100 rounded-lg overflow-hidden bg-white">
        <table class="w-full text-xs">
          <tbody>
            ${subtotalRow(stmt.net_result.label || "Net Profit", stmt.net_result.values, { isTotal: true })}
          </tbody>
        </table>
      </div>
    `;
  }

  // ----------------------------
  // Other Comprehensive Income and Total CI
  // ----------------------------
  const hasOCI = meta.statement === "pnl" && (stmt.oci || stmt.total_comprehensive_income);
  if (hasOCI) {
    const ociSections    = Array.isArray(stmt.oci?.sections) ? stmt.oci.sections : [];
    const hasOCISections = ociSections.length > 0;

    html += `
      <div class="mt-4 text-sm font-semibold text-slate-700">Other Comprehensive Income</div>
    `;

    if (hasOCISections) {
      for (const osec of ociSections) {
        html += renderSection(osec);
      }
    } else {
      html += `
        <div class="border border-slate-100 rounded-lg overflow-hidden bg-white">
          <table class="w-full text-xs">
            <tbody>
              <tr class="border-b border-slate-100">
                <td class="py-2 px-2 text-slate-500">No OCI items</td>
                ${cols.map(() => `<td class="py-2 px-2"></td>`).join("")}
              </tr>
            </tbody>
          </table>
        </div>
      `;
    }

    // OCI total, if provided
    if (stmt.oci?.total?.values) {
      html += `
        <div class="mt-3 border border-slate-100 rounded-lg overflow-hidden bg-white">
          <table class="w-full text-xs">
            <tbody>
              ${subtotalRow(stmt.oci.total.label || "Total OCI", stmt.oci.total.values, { isTotal: true })}
            </tbody>
          </table>
        </div>
      `;
    }

    // Total Comprehensive Income below OCI
    if (stmt.total_comprehensive_income?.values) {
      html += `
        <div class="mt-3 border border-slate-100 rounded-lg overflow-hidden bg-white">
          <table class="w-full text-xs">
            <tbody>
              ${subtotalRow(
                stmt.total_comprehensive_income.label || "Total Comprehensive Income",
                stmt.total_comprehensive_income.values,
                { isTotal: true }
              )}
            </tbody>
          </table>
        </div>
      `;
    }
  }

  // ✅ Wrap in page layout (A4-ish)
  return `
    <div class="mx-auto max-w-[900px]">
      <div class="bg-white rounded border border-slate-200 p-4">
        ${html}
      </div>
    </div>
  `;
}

function fmtAcct(n) {
  const v = Number(n || 0);
  const abs = Math.abs(v);
  const s = fmt(abs);
  return v < 0 ? `(${s})` : s;
}

// Hunter 3-column (tier) PnL
// Hunter 3-column (tier) PnL
function renderPnLHunter3ColHtml(stmt) {
  const meta = stmt?.meta || {};
  const company = meta.company_name || "Company";
  const title = "Income Statement";
  const periodText = `For the period ${meta.period?.from || ""} to ${meta.period?.to || ""}`;

  // Detect semi-detailed vs full (backend: meta.detail = "summary" | "mid" | "full")
  const detail = String(meta.detail || "").toLowerCase();
  const isSemi = detail === "mid";

  // ✅ If backend didn’t send c1/c2/c3, fall back to single column
  const cols = Array.isArray(stmt?.columns) && stmt.columns.length
    ? stmt.columns
    : [{ key: "cur", label: "Amount" }];

  const colKeys = cols.map(c => c.key);

  // ---- Header cells: hide first numeric column label in semi-detailed mode
  const th = cols.map(c => {
    if (isSemi && c.key === "c1") return `<th class="text-right py-2 px-2"></th>`;
    return `<th class="text-right py-2 px-2">${esc(c.label || "")}</th>`;
  }).join("");

  // blank cell if not provided
  function cell(v, { underline = false, bold = false } = {}) {
    if (v == null) return `<td class="text-right py-2 px-2"></td>`;

    const cls = bold ? "font-semibold" : "";
    const inner = underline
      ? `<div class="inline-block border-b border-slate-400 pb-[1px]">${fmtBracket(v)}</div>`
      : `${fmtBracket(v)}`;
    return `<td class="text-right py-2 px-2 tabular-nums ${cls}">${inner}</td>`;
  }

  // ---- Row values: in semi-detailed mode, move c1 → c2 and hide c1
  function rowCells(values, opts = {}) {
    const v = values || {};

    let useVals = v;
    if (isSemi && colKeys.includes("c1") && colKeys.includes("c2") && colKeys.includes("c3")) {
      const merged = { ...v };
      merged.c2 = Number(v.c2 || 0) + Number(v.c1 || 0); // everything into middle
      merged.c1 = null;                                   // hide first column
      useVals = merged;
    }

    return colKeys.map(k => cell(useVals?.[k], opts)).join("");
  }

  let rows = "";
  const blocks = Array.isArray(stmt.blocks) ? stmt.blocks : [];

  for (const b of blocks) {
    const lines = Array.isArray(b.lines) ? b.lines : [];
    const isSingle = !!b.values && lines.length === 0;

    // ✅ NEW: render single-value blocks (Gross profit, Total expenses, etc.)
    if (isSingle) {
      rows += `
        <tr class="border-b border-slate-100">
          <td class="py-2 px-2 font-semibold text-slate-900">${esc(b.label || b.title || "")}</td>
          ${rowCells(b.values || {}, { underline: true, bold: true })}
        </tr>
      `;
      continue;
    }

    // Section header
    rows += `
      <tr>
        <td class="pt-4 pb-2 px-2 font-semibold text-slate-800" colspan="${1 + cols.length}">
          ${esc(b.label || b.title || "")}
        </td>
      </tr>
    `;

    for (const ln of lines) {
      const name = ln.name || ln.label || "";
      const indent = Math.max(0, Math.min(Number(ln.indent || 0), 10));
      const padPx = indent * 16;

      const lessCls = ln.is_less_line ? "text-slate-600 italic" : "text-slate-800";

      if (ln.is_subtotal) {
        rows += `
          <tr>
            <td class="py-2 px-2 font-semibold text-slate-900">${esc(name)}</td>
            ${rowCells(ln.values || {}, { underline: true, bold: true })}
          </tr>
        `;
        continue;
      }

      rows += `
        <tr class="border-b border-slate-100">
          <td class="py-2 px-2 ${lessCls}" style="padding-left:${padPx}px">${esc(name)}</td>
          ${rowCells(ln.values || {})}
        </tr>
      `;
    }
  }

  if (stmt?.net_result?.values) {
    rows += `
      <tr><td class="pt-4" colspan="${1 + cols.length}"></td></tr>
      <tr>
        <td class="py-2 px-2 font-bold text-slate-900">${esc(stmt.net_result.label || "Net income")}</td>
        ${rowCells(stmt.net_result.values, { underline: true, bold: true })}
      </tr>
    `;
  }

  // ----------------------------
  // ✅ OCI + Total Comprehensive Income (IFRS)
  // ----------------------------
  const isIFRS = String(meta.template || "").toLowerCase() === "ifrs";

  function strongRow(label, values) {
    return `
      <tr>
        <td class="py-2 px-2 font-semibold text-slate-900">${esc(label)}</td>
        ${rowCells(values || {}, { underline: true, bold: true })}
      </tr>
    `;
  }

  function findBlock(key) {
    return blocks.find(b => String(b?.key || "").toLowerCase() === key);
  }

  if (isIFRS) {
    const ociBlock = findBlock("oci");
    const tciBlock = findBlock("tci");

    const ociLabel =
      ociBlock?.label ||
      stmt?.oci?.label ||
      "Other Comprehensive Income";

    const ociTotals =
      ociBlock?.totals ||
      stmt?.oci?.total?.values ||
      (() => {
        const z = {};
        for (const c of cols) z[c.key] = 0;
        return z;
      })();

    const tciLabel =
      tciBlock?.label ||
      stmt?.total_comprehensive_income?.label ||
      "Total Comprehensive Income";

    const tciValues =
      tciBlock?.values ||
      stmt?.total_comprehensive_income?.values ||
      stmt?.net_result?.values || ociTotals;

    rows += `<tr><td class="pt-3" colspan="${1 + cols.length}"></td></tr>`;
    rows += strongRow(ociLabel, ociTotals);
    rows += strongRow(tciLabel, tciValues);
  }

  return `
  <div class="mx-auto max-w-[900px]">
    <div class="a4-page">
      <div class="bg-white rounded border border-slate-200 p-4">

        <!-- Header (inside the page) -->
        <div class="mb-3 text-left">
          <div class="text-sm font-bold tracking-wide">${esc(String(company || "").toUpperCase())}</div>
          <div class="text-xs font-semibold">${esc(title)}</div>
          <div class="text-xs text-slate-600">${esc(periodText)}</div>
          ${meta?.currency ? `<div class="text-[11px] text-slate-500">(All amounts in ${esc(meta.currency)})</div>` : ""}
        </div>

        <!-- Table -->
        <div class="border border-slate-100 rounded-lg overflow-hidden bg-white">
          <table class="w-full text-xs">
            <thead class="bg-slate-50 text-slate-600">
              <tr>
                <th class="text-left py-2 px-2">Description</th>
                ${th}
              </tr>
            </thead>
            <tbody>${rows}</tbody>
          </table>
        </div>

      </div>
    </div>
  `;
}


// values is something like { c1: 0, c2: 100, c3: 150 }
function transformValues(values, mode) {
  const v = values || { c1: 0, c2: 0, c3: 0 };

  if (mode === 'detailed') {
    return { c1: v.c1, c2: v.c2, c3: v.c3 };
  }

  if (mode === 'semiDetailed') {
    // collapse c1 into c2, keep c3 as subtotal
    return {
      c1: null,                 // hidden column
      c2: (v.c1 || 0) + (v.c2 || 0),
      c3: v.c3 || 0
    };
  }

  if (mode === 'summary') {
    // only total column
    return {
      c1: null,
      c2: null,
      c3: v.c3 || 0
    };
  }

  return v;
}

function visibleColumns(columns, mode) {
  if (mode === 'detailed') return columns;

  if (mode === 'semiDetailed') {
    return columns.filter(c => c.key !== 'c1'); // hide adjustments
  }

  if (mode === 'summary') {
    return columns.filter(c => c.key === 'c3'); // only Total
  }

  return columns;
}

let currentMode = 'detailed'; // or from dropdown

const pnlMode = document.getElementById('pnl-mode');
if (pnlMode) {
  pnlMode.addEventListener('change', e => {
    currentMode = e.target.value;
    renderIncomeStatement(reportJson, currentMode);
  });
}

function renderIncomeStatement(report, mode) {
  const canvas = document.getElementById("stmtCanvas");
  if (!canvas) return;

  const cols = visibleColumns(report.columns, mode);
  const blocks = report.blocks || [];

  let html = `
    <table class="w-full text-xs">
      <thead class="bg-slate-50 text-slate-600">
        <tr>
          <th class="text-left py-2 px-2">Description</th>
          ${cols.map(c => `<th class="text-right py-2 px-2">${esc(c.label)}</th>`).join("")}
        </tr>
      </thead>
      <tbody>
  `;

  for (const b of blocks) {
    if (b.lines && b.lines.length) {
      html += `
        <tr>
          <td class="pt-4 pb-2 px-2 font-semibold text-slate-800" colspan="${1 + cols.length}">
            ${esc(b.label || "")}
          </td>
        </tr>
      `;
      for (const ln of b.lines) {
        const vals = transformValues(ln.values || {}, mode);
        html += `
          <tr class="${ln.is_subtotal ? "font-semibold" : ""}">
            <td class="py-1 px-2" style="padding-left:${(ln.indent || 0) * 14}px">
              ${esc(ln.name || "")}
            </td>
            ${cols.map(c => {
              const v = vals[c.key];
              const show = v != null && Math.abs(v) >= 0.005;
              return `<td class="py-1 px-2 text-right tabular-nums">${show ? fmtBracket(v) : ""}</td>`;
            }).join("")}
          </tr>
        `;
      }
    }

    if (b.values) {
      const vals = transformValues(b.values, mode);
      html += `
        <tr class="font-semibold">
          <td class="py-2 px-2">${esc(b.label || "")}</td>
          ${cols.map(c => {
            const v = vals[c.key];
            const show = v != null && Math.abs(v) >= 0.005;
            return `<td class="py-2 px-2 text-right tabular-nums">${show ? fmtBracket(v) : ""}</td>`;
          }).join("")}
        </tr>
      `;
    }
  }

  html += "</tbody></table>";
  canvas.innerHTML = html;
}

/** Renders statement rows safely (array | {rows/items/data} | HTML string) */
function renderStatementTableHtml(rows, typeKey) {
  // 1) If backend returned HTML string, just return it
  if (typeof rows === "string") {
    const s = rows.trim();
    // basic guard: if it looks like html, just show it
    if (s.startsWith("<")) return s;
    // otherwise show as plain text
    return `<pre class="text-xs whitespace-pre-wrap">${escapeHtml(s)}</pre>`;
  }

  // 2) If backend returned object wrapper, unwrap common keys
  if (rows && typeof rows === "object" && !Array.isArray(rows)) {
    rows =
      rows.rows ||
      rows.items ||
      rows.data ||
      rows.result ||
      rows.statement ||
      [];
  }

  // 3) Must be an array now
  if (!Array.isArray(rows) || rows.length === 0) {
    return `<div class="text-xs text-slate-500">No data for this period.</div>`;
  }

  const fmt = (n) => (typeof window.fmt === "function" ? window.fmt(n) : String(n));
  const safe = (s) =>
    String(s ?? "").replace(/[&<>"']/g, (c) => ({
      "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#039;"
    }[c]));

  const titleMap = {
    pnl: "Profit & Loss",
    bs:  "Balance Sheet",
    cf:  "Cash Flow",
    tb:  "Trial Balance"
  };

  const body = rows.map(r => {
    const label = safe(r.label || r.name || r.section || "");
    const amt = Number(r.amount ?? r.value ?? 0);

    const isTotal = /net profit|surplus|deficit|gross profit|total/i.test(label);
    const cls = isTotal ? "font-semibold" : "";

    return `
      <tr class="border-b border-slate-100">
        <td class="py-2 pr-3 ${cls}">${label}</td>
        <td class="py-2 text-right tabular-nums ${cls}">${fmt(amt)}</td>
      </tr>
    `;
  }).join("");

  return `
    <div class="mb-2 text-sm font-semibold text-slate-700">${titleMap[typeKey] || "Statement"}</div>
    <div class="border border-slate-100 rounded-lg overflow-hidden bg-white">
      <table class="w-full text-xs">
        <tbody>${body}</tbody>
      </table>
    </div>
  `;
}


// helper – normalize type dropdown value to backend key
function normalizeStmtType(t) {
  const s = String(t || "").toLowerCase();
  if (s.startsWith("p&l") || s.startsWith("pnl") || s === "pl") return "pnl";
  if (s.startsWith("bs") || s.includes("balance")) return "bs";
  if (s.startsWith("cf") || s.includes("cash")) return "cf";
  if (s.startsWith("tb")) return "tb";
  return s || "pnl";
}


// ✅ Keep compare + cols mode in sync, and re-render when needed
function syncCompareVsColsMode({ rerender = true } = {}) {
  const compareSel = document.getElementById("stmtCompare");
  const colsSel    = document.getElementById("stmtColsMode");   // ✅ your new select
  const typeSel    = document.getElementById("stmtType");

  if (!compareSel || !colsSel) return;

  const colsMode = String(colsSel.value || "1");
  const cmp      = (compareSel.value || "none").toLowerCase();

  // 2/3 columns => compare must be none
  if (colsMode !== "1") {
    if (compareSel.value !== "none") compareSel.value = "none";
    compareSel.disabled = true;
    compareSel.classList.add("opacity-60");
  } else {
    compareSel.disabled = false;
    compareSel.classList.remove("opacity-60");
  }

  // compare enabled => force cols mode to 1 and lock cols selector
  if (cmp !== "none") {
    if (colsSel.value !== "1") colsSel.value = "1";
    colsSel.disabled = true;
    colsSel.classList.add("opacity-60");
  } else {
    colsSel.disabled = false;
    colsSel.classList.remove("opacity-60");
  }

  // optional: hide/disable cols mode when statement type doesn't support it
  // (keep simple; only P&L really uses 2/3 column modes)
  const t = (typeSel?.value || "pnl").toLowerCase();
  if (t !== "pnl") {
    // don't break BS now; just softly lock to 1 for non-PnL
    if (colsSel.value !== "1") colsSel.value = "1";
    colsSel.disabled = true;
    colsSel.classList.add("opacity-60");

    // re-enable compare for BS/TB if you want (BS has its own compare logic)
    compareSel.disabled = false;
    compareSel.classList.remove("opacity-60");
  }

  if (!rerender) return;

  // Re-render current statement (safe, async)
  const stmtType = typeSel?.value || "pnl";
  renderStatementViewer(stmtType).catch(err =>
    console.error("syncCompareVsColsMode rerender error:", err)
  );
}

// wire up
document.getElementById("stmtCompare")?.addEventListener("change", () => syncCompareVsColsMode());
document.getElementById("stmtColsMode")?.addEventListener("change", () => syncCompareVsColsMode());
document.getElementById("stmtType")?.addEventListener("change", () => syncCompareVsColsMode());

// call once on load
syncCompareVsColsMode({ rerender: false });

function updateStmtViewerMethodVisibility(stmtType) {
  const el = document.getElementById("stmtCfMethod");
  if (!el) return;
  el.style.display = (normalizeStmtType(stmtType) === "cf") ? "" : "none";
}

document.getElementById("stmtType")?.addEventListener("change", (e) => {
  updateStmtViewerMethodVisibility(e.target.value);
});

// ✅ fallback renderer for unexpected JSON
function renderJsonAsSimpleTable(x) {
  // array -> simple table
  if (Array.isArray(x)) return renderMiniTableHtml(x);

  // object with sections -> flatten to rows
  if (x && Array.isArray(x.sections)) {
    const rows = [];

    for (const sec of x.sections) {
      if (sec.label) rows.push({ label: sec.label, amount: sec.total ?? 0 });

      for (const ln of (sec.lines || [])) {
        rows.push({
          label: `${ln.code || ""} ${ln.name || ""}`.trim(),
          amount: ln.amount ?? 0,
        });
      }
    }

    if (x.net_result) rows.push({ label: x.net_result.label, amount: x.net_result.amount });

    return renderMiniTableHtml(rows);
  }

  return `<div class="text-xs text-red-500">Unexpected statement response shape.</div>`;
}

function looksLikeFullPageHtml(html) {
  const s = String(html || "").toLowerCase();
  return s.includes("<html") || s.includes("<head") || s.includes("<body");
}

function extractBodyInnerHtml(html) {
  const s = String(html || "");
  const m = s.match(/<body[^>]*>([\s\S]*?)<\/body>/i);
  return m ? m[1] : s;
}


function esc(s){ return String(s??"").replace(/[&<>"']/g,c=>({ "&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#039;" }[c])); }



// helper used above
function escapeHtml(s) {
  return String(s ?? "").replace(/[&<>"']/g, (c) => ({
    "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#039;"
  }[c]));
}

function renderMiniTableHtml(rows) {
  const list = Array.isArray(rows) ? rows : (rows?.rows || rows?.items || []);
  if (!list.length) return `<div class="text-xs text-slate-500">No data.</div>`;

  return `
    <div class="space-y-1">
      ${list.map(r => {
        const label = String(r.label || r.name || "");
        const amt   = Number(r.amount || 0);
        const cls   = amt < 0 ? "text-red-500" : "text-slate-800";
        return `
          <div class="flex items-center justify-between text-xs">
            <span>${label}</span>
            <span class="${cls}">${fmt(amt)}</span>
          </div>
        `;
      }).join("")}
    </div>
  `;
}

// optional: expose it
window.renderMiniTableHtml = window.renderMiniTableHtml || renderMiniTableHtml;

async function downloadFile(url, filename) {
  const resp = await fetch(url, {
    method: "GET",
    headers: AUTH_HEADER(), // if you use auth
  });

  if (!resp.ok) throw new Error("Download failed");

  const blob = await resp.blob();
  const a = document.createElement("a");
  a.href = window.URL.createObjectURL(blob);
  a.download = filename;
  a.click();
}

async function exportStatement(stmtType, format) {
  const cid = (typeof getActiveCompanyId === "function" ? getActiveCompanyId() : null);
  if (!cid) return alert("No active company.");

  const { from, to } = computePeriodRange(CURRENT_PERIOD_KEY);

  const t = normalizeStmtType(stmtType);

  if (t === "notes") {
    if (typeof restoreNotesIfPresent === "function" && restoreNotesIfPresent()) {
      return;
    }
  }

  if (typeof updateStmtViewerMethodVisibility === "function") {
    updateStmtViewerMethodVisibility(t);
  }

  const fmt = String(format || "xlsx").toLowerCase();

  let url = "";
  switch (t) {
    case "pnl":   url = ENDPOINTS.pnl(cid, from, to, fmt); break;
    case "bs":    url = ENDPOINTS.bs(cid, to, fmt); break;
    case "cf":    url = ENDPOINTS.cashflow(cid, from, to, fmt); break;
    case "tb":    url = ENDPOINTS.trialBalance(cid, from, to, fmt); break;
    case "notes": url = ENDPOINTS.notes(cid, from, to, fmt); break;
    default:
      return alert("Unknown statement type.");
  }

  const template = document.getElementById("stmtTemplate")?.value || "ifrs";
  const basis    = document.getElementById("stmtBasis")?.value || "external";
  const compare  = document.getElementById("stmtCompare")?.value || "none";
  const detail   = document.getElementById("stmtDetail")?.value || "summary";

  const params = { template, basis, compare };

  if (t === "pnl") {
    params.detail = detail;
  }

  url = addQueryParamsAbs(url, params);

  const ext = (fmt === "sars_xml") ? "xml" : fmt;
  const filename = `${t}_${from}_${to}.${ext}`;

  await downloadFile(url, filename);
}

