// ✅ NEW: silently mark Notes as active WITHOUT firing change handlers
function setActiveStmtTypeSilent(t) {
  const norm = normalizeStmtType(t || "notes");
  window.ACTIVE_STMT_TYPE = norm;

  const el = document.getElementById("stmtType"); // your hidden input
  if (el) el.value = norm;
}


function bindGenerateNotesBtnReportsScreen() {
  const btn = document.getElementById("generateNotesBtn");
  if (!btn || btn.dataset.bound === "1") return;

  btn.addEventListener("click", async () => {
    const cid = window.getActiveCompanyId?.() || window.CURRENT_COMPANY_ID;
    if (!cid) return alert("No active company selected.");

    const packEl = document.getElementById("notesPack");
    const noteKey = packEl?.value || "ifrs16";
    const reg = NOTES_REGISTRY[noteKey];
    if (!reg) return alert("Unknown notes pack selected.");

    const period = getCurrentStmtPeriodForNotes();

    try {
      btn.disabled = true;

      const out = await reg.fetch(cid, period);

      renderNotesIntoStatementViewer(noteKey, out.html, {
        noteKey,
        label: reg.label,
        period,
        ...out.meta,
      });

    } catch (e) {
      alert(e?.message || `Failed to generate ${reg?.label || "notes"}.`);
    } finally {
      btn.disabled = false;
    }
  });

  btn.dataset.bound = "1";
}

function getCurrentStmtPeriodForNotes() {
  const p = window._stmtPeriod || {};
  let from = p.from || null;
  let to = p.to || null;
  const preset =
    p.preset ||
    document.getElementById("stmtPreset")?.value ||
    "this_year";
  const as_of = p.as_of || to || null;

  if ((!from || !to) && preset) {
    const r = computePeriodRange(preset);
    if (r?.from && r?.to) {
      from = r.from;
      to = r.to;
    }
  }

  return { from, to, preset, as_of };
}

function saveRenderedNotesState(noteKey, html, meta = {}) {
  window._notesState = {
    noteKey,
    html,
    meta,
    renderedAt: new Date().toISOString(),
  };
}

function renderNotesIntoStatementViewer(noteKey, html, meta = {}) {
  const canvas = document.getElementById("stmtCanvas");
  if (canvas) canvas.innerHTML = html;

  setActiveStmtTypeSilent("notes");
  saveRenderedNotesState(noteKey, html, meta);
}

