async function fillBankAccountSelect(selectElOrId, opts = {}) {
  const sel =
    (typeof selectElOrId === "string")
      ? document.getElementById(selectElOrId)
      : selectElOrId;

  if (!sel) return [];

  const {
    placeholder = "Select bank…",
    includeEmpty = true,
    onAfterFill = null,
  } = opts;

  const accounts = await refreshBankAccounts(); // ✅ reuse your existing fetch/caching

  if (!accounts.length) {
    sel.innerHTML = `<option value="">No bank accounts</option>`;
    return [];
  }

  sel.innerHTML =
    (includeEmpty ? `<option value="">${placeholder}</option>` : "") +
    accounts.map((a) => {
      const id = a.id ?? a.bank_account_id ?? "";
      const label =
        (a.name || a.account_name || a.bank_name || "Bank") +
        (a.account_number ? ` (${a.account_number})` : "");
      return `<option value="${String(id)}">${label}</option>`;
    }).join("");

  if (typeof onAfterFill === "function") {
    await onAfterFill(accounts, sel);
  }

  return accounts;
}
window.fillBankAccountSelect = fillBankAccountSelect;

(function () {
  function showMsg(el, msg, type = "error") {
    if (!el) return;
    el.textContent = msg || "";
    el.classList.toggle("hidden", !msg);
    el.classList.toggle("text-rose-600", type === "error");
    el.classList.toggle("text-emerald-600", type === "ok");
  }

  function openModal(modal) {
    modal?.classList.remove("hidden");
  }
  function closeModal(modal) {
    modal?.classList.add("hidden");
  }

  function _readLeasePayForm() {
    const cid = getActiveCompanyId?.() || window.CURRENT_COMPANY_ID;

    const leaseId = Number(document.getElementById("lpLeaseId")?.value || 0);

    const amountRaw = (document.getElementById("lpAmount")?.value || "").trim();
    const amount = amountRaw.replace(/,/g, ""); // ✅ avoid Decimal crash

    const payment_date = (document.getElementById("lpDate")?.value || "").trim();

    const bank_account_id = Number(document.getElementById("lpBankId")?.value || 0);

    const reference = (document.getElementById("lpRef")?.value || "").trim() || null;
    const description = (document.getElementById("lpDesc")?.value || "").trim() || null;

    const schedule_id = Number(document.getElementById("lpScheduleId")?.value || 0) || null;

    return {
      cid,
      leaseId,
      payload: { amount, payment_date, bank_account_id, reference, description, schedule_id },
    };
  }

  function _validateLeasePayForm({ cid, leaseId, payload }) {
    if (!cid) return "Missing company id";
    if (!leaseId) return "Missing lease id";
    if (!payload.payment_date) return "payment_date is required (YYYY-MM-DD)";
    if (!payload.bank_account_id) return "bank_account_id is required";
    if (!payload.amount || Number(payload.amount) <= 0) return "amount must be > 0";
    return "";
  }


  function leasePayMsg(msg = "", type = "error") {
    const el = document.getElementById("lpMsg"); // message div on screen
    if (!el) return;

    el.textContent = msg || "";
    el.classList.toggle("hidden", !msg);
    el.classList.toggle("text-rose-600", type === "error");
    el.classList.toggle("text-emerald-600", type === "ok");
  }

  async function leasePayPreview() {
    try {
      leasePayMsg(""); // clear

      const form = _readLeasePayForm();
      const err = _validateLeasePayForm(form);
      if (err) return leasePayMsg(err);

      const { cid, leaseId, payload } = form;

      const data = await apiFetch(
        ENDPOINTS.leases.payments.preview(cid, leaseId),
        { method: "POST", body: JSON.stringify(payload) }
      );

      renderLinesTableSimple(
        document.getElementById("lpPreviewLines"),
        data.preview_journal_lines || []
      );

      leasePayMsg("Preview ready ✓", "ok");
    } catch (err) {
      leasePayMsg(err?.message || "Preview failed");
    }
  }

  async function leasePayPost() {
    try {
      leasePayMsg(""); // clear

      const form = _readLeasePayForm();
      const err = _validateLeasePayForm(form);
      if (err) return leasePayMsg(err);

      const { cid, leaseId, payload } = form;

      const out = await apiFetch(
        ENDPOINTS.leases.payments.post(cid, leaseId),
        { method: "POST", body: JSON.stringify(payload) }
      );

      leasePayMsg(`Payment posted ✓ Journal #${out?.journal_id || ""}`, "ok");

      // refresh history
      await loadLeasePaymentsHistory(cid, leaseId);

      // optional: clear preview lines after posting
      renderLinesTableSimple(document.getElementById("lpPreviewLines"), []);
    } catch (err) {
      leasePayMsg(err?.message || "Posting failed");
    }
  }

  // --------------------
  // Bind buttons (once)
  // --------------------
  //document.getElementById("lpBtnPreview")?.addEventListener("click", leasePayPreview);
  //document.getElementById("lpBtnPost")?.addEventListener("click", leasePayPost);

  async function loadBankAccounts(cid) {
    // expects: GET /api/companies/<cid>/bank_accounts
    const rows = await apiFetch(ENDPOINTS.bankAccounts(cid), { method: "GET" });
    // support both {ok:true, rows:[...]} or plain array
    const list = Array.isArray(rows) ? rows : (rows?.rows || rows?.bank_accounts || []);
    return list || [];
  }

  function renderHistory(hostEl, rows, { onOpenJournal } = {}) {
    if (!hostEl) return;
    if (!Array.isArray(rows) || !rows.length) {
      hostEl.innerHTML = `<div class="text-xs text-slate-500 px-3 py-2">No payments yet</div>`;
      return;
    }

    hostEl.innerHTML = `
      <div class="border rounded overflow-hidden">
        <table class="min-w-full text-xs">
          <thead class="bg-slate-50 border-b border-slate-200">
            <tr>
              <th class="px-2 py-2 text-left w-[110px]">Date</th>
              <th class="px-2 py-2 text-left">Ref</th>
              <th class="px-2 py-2 text-right w-28">Amount</th>
              <th class="px-2 py-2 text-right w-24">Interest</th>
              <th class="px-2 py-2 text-right w-24">Principal</th>
              <th class="px-2 py-2 text-left w-28">Journal</th>
            </tr>
          </thead>
          <tbody>
            ${rows.map(r => {
              const jid = r.journal_id || r.posted_journal_id || "";
              return `
                <tr class="border-b border-slate-100">
                  <td class="px-2 py-2">${esc(String(r.payment_date || r.date || ""))}</td>
                  <td class="px-2 py-2 text-slate-700">${esc(String(r.reference || ""))}</td>
                  <td class="px-2 py-2 text-right tabular-nums">${Number(r.amount_gross || r.amount || 0).toFixed(2)}</td>
                  <td class="px-2 py-2 text-right tabular-nums">${Number(r.interest_amount || 0).toFixed(2)}</td>
                  <td class="px-2 py-2 text-right tabular-nums">${Number(r.principal_amount || 0).toFixed(2)}</td>
                  <td class="px-2 py-2">
                    ${jid ? `<button data-journal="${esc(String(jid))}" class="text-[11px] text-blue-600 hover:underline">${esc(String(jid))}</button>` : ""}
                  </td>
                </tr>
              `;
            }).join("")}
          </tbody>
        </table>
      </div>
    `;

    hostEl.querySelectorAll("[data-journal]").forEach(btn => {
      btn.addEventListener("click", () => {
        const jid = btn.getAttribute("data-journal");
        if (jid && onOpenJournal) onOpenJournal(jid);
      });
    });
  }

  async function loadLeasePaymentsHistory(cid, leaseId) {
    const res = await apiFetch(ENDPOINTS.leases.payments.list(cid, leaseId), { method: "GET" });
    return res?.payments || [];
  }

  // Expose a single entry point
// ============================================================
// 1) UPDATE: openLeasePaymentModal -> lpBtnPost now requests approval when needed
// ============================================================
window.openLeasePaymentModal = async function openLeasePaymentModal({
  lease_id,
  lease_name = "",
  lessor_name = "",
  schedule_id = null, // optional
  default_amount = "",
  default_date = "",
} = {}) {
  const modal = document.getElementById("leasePayModal");
  if (!modal) return;

  const msgEl = document.getElementById("lpMsg");
  showMsg(msgEl, "");

  const cid = getActiveCompanyId?.();
  const leaseId = Number(lease_id || 0);
  if (!cid || !leaseId) {
    showMsg(msgEl, "Missing company or lease id", "error");
    return;
  }

  // ✅ active lease context
  window.__ACTIVE_LEASE_ID = leaseId;
  window.renderLeaseScreen?.();

  // header
  const hdr = document.getElementById("lpHdrMeta");
  if (hdr) hdr.textContent = `${lease_name || `Lease ${leaseId}`} • ${lessor_name || ""}`.trim();

  // context hidden fields
  const elLeaseId = document.getElementById("lpLeaseId");
  const elSchedId = document.getElementById("lpScheduleId");
  if (elLeaseId) elLeaseId.value = String(leaseId);
  if (elSchedId) elSchedId.value = schedule_id ? String(schedule_id) : "";

  // defaults
  const lpDate = document.getElementById("lpDate");
  const lpAmount = document.getElementById("lpAmount");
  if (lpDate && default_date) lpDate.value = String(default_date).slice(0, 10);
  if (lpAmount && default_amount) lpAmount.value = String(default_amount);

  // refs to inputs (used a lot)
  const elBank   = document.getElementById("lpBankId");
  const elRef    = document.getElementById("lpRef");
  const elDesc   = document.getElementById("lpDesc");
  const elLines  = document.getElementById("lpPreviewLines");
  const elHist   = document.getElementById("lpHistory");

  // render empty state first
  renderLinesTableSimple(elLines, []);
  renderHistory(elHist, []);

  // ✅ load bank accounts once
  if (elBank && elBank.dataset.loaded !== "1") {
    try {
      const banks = (await refreshBankAccounts?.()) || [];
      if (!banks.length) {
        elBank.innerHTML = `<option value="">No bank accounts</option>`;
      } else {
        elBank.innerHTML =
          `<option value="">Select bank…</option>` +
          banks
            .map((b) => {
              const id = b.id ?? b.bank_account_id ?? b.account_id ?? "";
              const label = [b.name, b.account_name, b.bank_name, b.account_number]
                .filter(Boolean)
                .join(" • ");
              return `<option value="${esc(String(id))}">${esc(label || `Bank ${id}`)}</option>`;
            })
            .join("");
        elBank.dataset.loaded = "1";
      }
    } catch (e) {
      console.error("[LeasePay] bank load failed:", e);
      showMsg(msgEl, e?.message || "Failed to load bank accounts", "error");
    }
  }

  // ✅ history
  async function refreshHistory(targetLeaseId = leaseId) {
    const rows = await loadLeasePaymentsHistory(cid, targetLeaseId);
    renderHistory(elHist, rows, {
      onOpenJournal: (jid) => {
        closeModal(modal);
        switchScreen?.("journal");
        window.fetchJournalDetail?.(jid);
      },
    });
  }

  try {
    await refreshHistory(leaseId);
  } catch (e) {
    showMsg(msgEl, e?.message || "Failed to load payment history", "error");
  }

  openModal(modal);

  // ------------------------------------------------------------
  // Bind once (listeners)
  // ------------------------------------------------------------
  if (modal.dataset.bound === "1") return;
  modal.dataset.bound = "1";

  const btnClose   = document.getElementById("lpBtnClose");
  const btnRefresh = document.getElementById("lpBtnRefresh");
  const btnPreview = document.getElementById("lpBtnPreview");
  const btnPost    = document.getElementById("lpBtnPost");

  btnClose?.addEventListener("click", () => closeModal(modal));
  modal.querySelector(".absolute.inset-0")?.addEventListener("click", () => closeModal(modal));

  btnRefresh?.addEventListener("click", async () => {
    try {
      const leaseId2 = Number(elLeaseId?.value || 0);
      await refreshHistory(leaseId2);
      showMsg(msgEl, "Refreshed.", "ok");
      setTimeout(() => showMsg(msgEl, ""), 1200);
    } catch (e) {
      showMsg(msgEl, e?.message || "Refresh failed", "error");
    }
  });

  btnPreview?.addEventListener("click", async () => {
    try {
      showMsg(msgEl, "");

      const leaseId2 = Number(elLeaseId?.value || 0);
      const amount = lpAmount?.value;
      const payment_date = lpDate?.value;
      const bank_account_id = Number(elBank?.value || 0);
      const reference = elRef?.value || null;
      const description = elDesc?.value || null;

      const schedule_id_val = elSchedId?.value;
      const schedule_id2 = schedule_id_val ? Number(schedule_id_val) : null;

      if (!payment_date) return showMsg(msgEl, "payment_date is required", "error");
      if (!bank_account_id) return showMsg(msgEl, "bank_account_id is required", "error");

      const data = await apiFetch(ENDPOINTS.leases.payments.preview(cid, leaseId2), {
        method: "POST",
        body: JSON.stringify({
          amount,
          payment_date,
          bank_account_id,
          reference,
          description,
          schedule_id: schedule_id2,
        }),
      });

      renderLinesTableSimple(elLines, data?.preview_journal_lines || []);
      showMsg(msgEl, "Preview ready.", "ok");
      setTimeout(() => showMsg(msgEl, ""), 1200);
    } catch (e) {
      showMsg(msgEl, e?.message || "Preview failed", "error");
    }
  });

  // ✅ UPDATED: Post button requests approval (if required) WITHOUT rendering journal.
  // Journal render happens on APPROVAL DECISION (Approve) in approvals screen.
  btnPost?.addEventListener("click", async () => {
    try {
      showMsg(msgEl, "");

      const leaseId2 = Number(elLeaseId?.value || 0);

      const payload = {
        amount: lpAmount?.value,
        payment_date: lpDate?.value,
        bank_account_id: Number(elBank?.value || 0),
        reference: elRef?.value || null,
        description: elDesc?.value || null,
        schedule_id: (elSchedId?.value ? Number(elSchedId.value) : null),

        // helpful context for approvals
        lease_name,
        lessor_name,
      };

      if (!payload.payment_date) return showMsg(msgEl, "payment_date is required", "error");
      if (!payload.bank_account_id) return showMsg(msgEl, "bank_account_id is required", "error");

      const needsApproval =
        (typeof shouldRequestLeasePaymentApproval === "function")
          ? !!shouldRequestLeasePaymentApproval()
          : false;

      // ------------------------------------------------------------
      // APPROVAL PATH (request only; do NOT post; do NOT redirect)
      // ------------------------------------------------------------
      if (needsApproval) {
        if (typeof window.requestLeaseApproval !== "function") {
          return showMsg(msgEl, "requestLeaseApproval is not loaded", "error");
        }

        showMsg(msgEl, "Requesting approval…", "ok");

        await window.requestLeaseApproval({
          cid,
          lease_id: leaseId2,
          action: "lease_pay",
          lease_name: lease_name || `Lease ${leaseId2}`,
          amount: Number(String(payload.amount || "0").replace(/,/g, "")) || 0,
          currency: window.CURRENT_COMPANY?.base_currency || "ZAR",
          payload_json: {
            lease_id: leaseId2,
            lease_name,
            lessor_name,
            ...payload,
          },
        });

        // optional: refresh history (nothing posted yet, but request may show elsewhere)
        await refreshHistory(leaseId2);

        renderLinesTableSimple(elLines, []);
        showMsg(msgEl, "Approval requested. Waiting for decision.", "ok");
        setTimeout(() => showMsg(msgEl, ""), 1500);
        return;
      }

      // ------------------------------------------------------------
      // NO APPROVAL: POST IMMEDIATELY (existing behaviour)
      // ------------------------------------------------------------
      const out = await apiFetch(ENDPOINTS.leases.payments.post(cid, leaseId2), {
        method: "POST",
        body: JSON.stringify(payload),
      });

      // ✅ OPTIONAL UX: show IFRS monthly preview in Journal screen
      try {
        const as_of = payload.payment_date;
        const r = await fetchLeaseMonthPreviewForDate(cid, leaseId2, as_of);
        if (r && Array.isArray(r.preview_journal_lines) && r.preview_journal_lines.length) {
          closeModal(modal);
          switchScreen?.("journal");
          loadMonthlyIFRSPreviewIntoJournal?.(r);
        }
      } catch (e) {
        console.warn("[LeasePay] Could not load monthly IFRS preview:", e);
      }

      // refresh history + clear preview
      await refreshHistory(leaseId2);
      renderLinesTableSimple(elLines, []);
      showMsg(msgEl, `Posted. Journal ${out?.journal_id || ""}`.trim(), "ok");
    } catch (e) {
      showMsg(msgEl, e?.message || "Posting failed", "error");
    }
  });
};
})();

(function () {
  const $ = (id) => document.getElementById(id);

  function esc(s) {
    return String(s ?? "")
      .replaceAll("&", "&amp;")
      .replaceAll("<", "&lt;")
      .replaceAll(">", "&gt;")
      .replaceAll('"', "&quot;");
  }

  function showMsg(el, msg, type = "error") {
    if (!el) return;
    el.textContent = msg || "";
    el.classList.toggle("hidden", !msg);
    el.classList.toggle("text-rose-600", type === "error");
    el.classList.toggle("text-emerald-600", type === "ok");
  }


  function setActiveTab(tab) {
    document.querySelectorAll('#screen-leases [data-lease-tab]').forEach((b) => {
      const on = b.dataset.leaseTab === tab;
      b.classList.toggle("bg-slate-900", on);
      b.classList.toggle("text-white", on);
      b.classList.toggle("border-slate-900", on);
    });
  }

  // ✅ cache last loaded rows so filters can re-render without re-fetch
  let _monthlyRows = [];
  let _paymentRows = [];

  // ============================================================
  // PAYMENTS TAB: filters + table
  // ============================================================
  function renderPaymentsUI(mount) {
    mount.innerHTML = `
      <div class="flex items-center justify-between gap-3 mb-3">
        <div class="text-sm font-semibold">Lease Payments</div>
      </div>

      <div class="border rounded-xl p-3 bg-slate-50 mb-3">
        <div class="grid grid-cols-1 md:grid-cols-6 gap-2">
          <div class="md:col-span-2">
            <label class="text-xs text-slate-500">Lease ID *</label>
            <input id="lpFilterLeaseId" class="w-full border rounded px-2 py-1 text-sm" placeholder="e.g. 12">
          </div>

          <div>
            <label class="text-xs text-slate-500">From</label>
            <input id="lpFilterFrom" type="date" class="w-full border rounded px-2 py-1 text-sm">
          </div>

          <div>
            <label class="text-xs text-slate-500">To</label>
            <input id="lpFilterTo" type="date" class="w-full border rounded px-2 py-1 text-sm">
          </div>

          <div class="md:col-span-2">
            <label class="text-xs text-slate-500">Search (ref / memo)</label>
            <input id="lpFilterQ" class="w-full border rounded px-2 py-1 text-sm" placeholder="e.g. EFT / INV / bank ref">
          </div>
        </div>

        <div class="flex items-center gap-2 mt-3">
          <button id="btnLpLoad" class="px-3 py-1.5 rounded bg-slate-900 text-white text-sm">Load</button>
          <button id="btnLpPay" class="px-3 py-1.5 rounded border text-sm bg-white">Pay (open modal)</button>
        </div>
      </div>

      <div class="border rounded-xl overflow-hidden">
        <table class="min-w-full text-sm">
          <thead class="bg-slate-50 border-b">
            <tr>
              <th class="text-left p-2 w-[120px]">Date</th>
              <th class="text-left p-2">Ref</th>
              <th class="text-right p-2 w-[140px]">Amount</th>
              <th class="text-right p-2 w-[120px]">Interest</th>
              <th class="text-right p-2 w-[120px]">Principal</th>
              <th class="text-left p-2 w-[120px]">Journal</th>
            </tr>
          </thead>
          <tbody id="lpTableBody"></tbody>
        </table>
      </div>
      <div id="leasePaymentsMsg" class="text-sm hidden"></div>
    `;
  }

  function renderPaymentsTable(rows, { q = "" } = {}) {
    const body = $("lpTableBody");
    if (!body) return;

    const qq = String(q || "").trim().toLowerCase();

    const filtered = (Array.isArray(rows) ? rows : []).filter((r) => {
      if (!qq) return true;
      const t = [
        r.reference,
        r.description,
        r.memo,
        r.notes,
        r.journal_id,
      ].join(" ").toLowerCase();
      return t.includes(qq);
    });

    if (!filtered.length) {
      body.innerHTML = `<tr><td colspan="6" class="p-3 text-xs text-slate-500">No payments found</td></tr>`;
      return;
    }

    body.innerHTML = filtered.map((r) => {
      const jid = r.journal_id || r.posted_journal_id || "";
      return `
        <tr class="border-t">
          <td class="p-2">${esc(String(r.payment_date || r.date || ""))}</td>
          <td class="p-2 text-slate-700">${esc(String(r.reference || ""))}</td>
          <td class="p-2 text-right tabular-nums">${fmtMoney(r.amount_gross ?? r.amount ?? 0)}</td>
          <td class="p-2 text-right tabular-nums">${fmtMoney(r.interest_amount ?? 0)}</td>
          <td class="p-2 text-right tabular-nums">${fmtMoney(r.principal_amount ?? 0)}</td>
          <td class="p-2">
            ${jid ? `<button class="text-[11px] text-blue-600 hover:underline" data-journal="${esc(String(jid))}">${esc(String(jid))}</button>` : ""}
          </td>
        </tr>
      `;
    }).join("");

    body.querySelectorAll("[data-journal]").forEach((btn) => {
      btn.addEventListener("click", () => {
        const jid = btn.getAttribute("data-journal");
        if (!jid) return;
        window.switchScreen?.("journal");
        window.fetchJournalDetail?.(jid);
      });
    });
  }

  async function loadPayments() {
    const msgEl = $("leasePaymentsMsg");
    showMsg(msgEl, "");

    const cid = window.getActiveCompanyId?.();
    const leaseId = Number(($("lpFilterLeaseId")?.value || "").trim() || 0);
    const q = $("lpFilterQ")?.value || "";

    if (!cid) return showMsg(msgEl, "No company selected");
    if (!leaseId) return showMsg(msgEl, "Lease ID is required");

    // backend list: GET /leases/<lease_id>/payments
    const res = await window.apiFetch(
      window.endpoints.leases.payments.list(cid, leaseId),
      { method: "GET" }
    );

    const rows = res?.payments || res?.rows || (Array.isArray(res) ? res : []);
    renderPaymentsTable(rows, { q });
    showMsg(msgEl, "Loaded.", "ok");
    setTimeout(() => showMsg(msgEl, ""), 900);
  }

  // ============================================================
  // MONTHLY DUE TAB: filters + table + post actions
  // ============================================================
  function renderMonthlyUI(mount) {
    mount.innerHTML = `
      <div class="flex items-center justify-between gap-3 mb-3">
        <div class="text-sm font-semibold">Monthly Due (IFRS 16)</div>
      </div>

      <div id="leaseMonthlyMsg" class="text-sm hidden"></div>

      <div class="border rounded-xl p-3 bg-slate-50 mb-3">
        <div class="grid grid-cols-1 md:grid-cols-6 gap-2">
          <div class="md:col-span-2">
            <label class="text-xs text-slate-500">As of (optional)</label>
            <input id="lmAsOf" type="date" class="w-full border rounded px-2 py-1 text-sm">
          </div>

          <div class="md:col-span-2">
            <label class="text-xs text-slate-500">Search (lease/lessor)</label>
            <input id="lmQ" class="w-full border rounded px-2 py-1 text-sm" placeholder="e.g. Motus / lease name">
          </div>

          <div class="md:col-span-2 flex items-end gap-2">
            <button id="btnLmLoad" class="px-3 py-1.5 rounded bg-slate-900 text-white text-sm">Load</button>
          </div>
        </div>
      </div>

      <div class="border rounded-xl overflow-hidden">
        <table class="min-w-full text-sm">
          <thead class="bg-slate-50 border-b">
            <tr>
              <th class="text-left p-2">Lease</th>
              <th class="text-left p-2">Lessor</th>
              <th class="text-left p-2 w-[110px]">Period</th>
              <th class="text-right p-2 w-[140px]">Due</th>
              <th class="text-right p-2 w-[160px]">Actions</th>
            </tr>
          </thead>
          <tbody id="lmTableBody"></tbody>
        </table>
      </div>
    `;
  }

  function renderMonthlyTable(rows, { q = "" } = {}) {
    const body = $("lmTableBody");
    if (!body) return;

    const qq = String(q || "").trim().toLowerCase();

    const filtered = (Array.isArray(rows) ? rows : []).filter((r) => {
      if (!qq) return true;
      const t = [r.lease_name, r.lessor_name, r.name].join(" ").toLowerCase();
      return t.includes(qq);
    });

    if (!filtered.length) {
      body.innerHTML = `<tr><td colspan="5" class="p-3 text-xs text-slate-500">Nothing due</td></tr>`;
      return;
    }

    body.innerHTML = filtered.map((r) => {
      const leaseId = r.lease_id ?? r.id ?? "";
      const periodNo = r.period_no ?? r.period ?? r.period_number ?? "";
      const due =
        (r?.amounts?.payment ?? null) ??
        r.amount_due ??
        r.due_amount ??
        r.payment_amount ??
        0;

      return `
        <tr class="border-t">
          <td class="p-2">
            <div class="font-medium">${esc(String(r.lease_name || r.name || `Lease ${leaseId}`))}</div>
            <div class="text-xs text-slate-500">ID: ${esc(String(leaseId))}</div>
          </td>
          <td class="p-2">${esc(String(r.lessor_name || ""))}</td>
          <td class="p-2">${esc(String(periodNo || ""))}</td>
          <td class="p-2 text-right tabular-nums">${fmtMoney(due)}</td>
          <td class="p-2 text-right">
            <button class="px-2 py-1 rounded border text-xs bg-white" data-lm-pay="1"
              data-lease-id="${esc(String(leaseId))}"
              data-lease-name="${esc(String(r.lease_name || r.name || ""))}"
              data-lessor-name="${esc(String(r.lessor_name || ""))}"
              data-schedule-id="${esc(String(r.schedule_id || ""))}"
              data-due="${esc(String(due))}">
              Pay
            </button>
            <button class="px-2 py-1 rounded bg-slate-900 text-white text-xs ml-2" data-lm-post="1"
              data-lease-id="${esc(String(leaseId))}"
              data-period-no="${esc(String(periodNo))}">
              Post
            </button>
          </td>
        </tr>
      `;
    }).join("");

    // Pay -> opens your modal
    body.querySelectorAll("[data-lm-pay]").forEach((btn) => {
      btn.addEventListener("click", () => {
        const lease_id = Number(btn.getAttribute("data-lease-id") || 0);
        const schedule_id = btn.getAttribute("data-schedule-id") || null;

        window.openLeasePaymentModal?.({
          lease_id,
          lease_name: btn.getAttribute("data-lease-name") || "",
          lessor_name: btn.getAttribute("data-lessor-name") || "",
          schedule_id: schedule_id ? Number(schedule_id) : null,
          default_amount: btn.getAttribute("data-due") || "",
          default_date: new Date().toISOString().slice(0, 10),
        });
      });
    });

    // Post -> calls leases/<id>/period/<no>/post
    body.querySelectorAll("[data-lm-post]").forEach((btn) => {
      btn.addEventListener("click", async () => {
        const msgEl = $("leaseMonthlyMsg");
        showMsg(msgEl, "");

        const cid = window.getActiveCompanyId?.();
        const leaseId = btn.getAttribute("data-lease-id");
        const periodNo = btn.getAttribute("data-period-no");

        if (!cid || !leaseId || !periodNo) return showMsg(msgEl, "Missing lease/period");

        try {
          await window.apiFetch(
            window.endpoints.leases.postMonth(cid, leaseId, periodNo),
            { method: "POST" }
          );
          showMsg(msgEl, "Posted.", "ok");
          setTimeout(() => showMsg(msgEl, ""), 900);
        } catch (e) {
          showMsg(msgEl, e?.message || "Posting failed");
        }
      });
    });
  }

  async function loadMonthlyDue() {
    const msgEl = $("leaseMonthlyMsg");
    showMsg(msgEl, "");

    const cid = window.getActiveCompanyId?.();
    if (!cid) return showMsg(msgEl, "No company selected");

    const as_of = ($("lmAsOf")?.value || "").trim();
    const q = $("lmQ")?.value || "";

    const res = await window.apiFetch(
      window.endpoints.leases.monthlyDue(cid, { as_of }),
      { method: "GET" }
    );

    // allow multiple shapes
    const rows = res?.rows || res?.due || res?.leases || (Array.isArray(res) ? res : []);

    // ✅ store for filter re-render
    _monthlyRows = rows;

    renderMonthlyTable(rows, { q });

    showMsg(msgEl, "Loaded.", "ok");
    setTimeout(() => showMsg(msgEl, ""), 900);
  }

  function bindMonthlyEvents() {
    $("btnLmLoad")?.addEventListener("click", loadMonthlyDue);

    // optional: live filter without refetch
    $("lmQ")?.addEventListener("input", () => {
      renderMonthlyTable(_monthlyRows, { q: $("lmQ")?.value || "" });
    });
  }

  function bindPaymentsEvents() {
    $("btnLpLoad")?.addEventListener("click", loadPayments);

    $("lpFilterQ")?.addEventListener("input", () => {
      renderPaymentsTable(_paymentRows, { q: $("lpFilterQ")?.value || "" });
    });
  }

  function showTab(tab) {
    const mount = document.getElementById("leasesMount");
    if (!mount) return;

    setActiveTab(tab);

    if (tab === "monthly") {
      renderMonthlyUI(mount);
      bindMonthlyEvents();
      return;
    }

    if (tab === "payments") {
      renderPaymentsUI(mount);
      bindPaymentsEvents();
      return;
    }
  }

  // expose ONE entrypoint so other code can call into this IIFE
  window.renderLeaseMonthlyDueView = function (mount) {
    renderMonthlyUI(mount);
    bindMonthlyEvents();
  };

  window.renderLeasePaymentsView = function (mount) {
    renderPaymentsUI(mount);
    bindPaymentsEvents();
  };

  // init default tab when screen exists
  const mount = document.getElementById("leasesMount");
  if (mount) showTab("monthly");

  // tab click wiring
  document.querySelectorAll('#screen-leases [data-lease-tab]').forEach(btn => {
    btn.addEventListener("click", () => {
      const tab = btn.dataset.leaseTab;      // "monthly" | "payments" | ...
      showTab(tab);
    });
  });
})();

window.LEASE_UI = window.LEASE_UI || { state: {} };
window.LEASE_UI.state = window.LEASE_UI.state || {
  tab: "monthly",
  leaseId: null,
  mods: [],
  terms: [],
  _lastModId: null,
  _lastTermId: null,
};


function leaseCtx() {
  const cid = FS.control.resolveCid?.() || window.getActiveCompanyId?.() || window.CURRENT_COMPANY_ID;
  const role = (typeof getCurrentRole === "function") ? getCurrentRole() : (window.currentRole?.() || "viewer");
  const mode = FS.control.get(cid);
  const reviewOn = FS.control.isReviewEnabled?.(cid) === true;
  const canApprove = FS.policy.canApproveLease(role, cid);
  const autoPosts = FS.policy.leaseAutoPosts(cid);
  return { cid, role, mode, reviewOn, canApprove, autoPosts };
}

function applyLeaseModalPolicy(modalKind /* "mod" | "term" */) {
  const { cid, mode, reviewOn, canApprove, autoPosts } = leaseCtx();

  // buttons
  const isMod = modalKind === "mod";
  const btnDraft  = document.getElementById(isMod ? "leaseModSaveDraft" : "leaseTermSaveDraft");
  const btnPost   = document.getElementById(isMod ? "leaseModPost" : "leaseTermPost");
  const btnPrev   = document.getElementById(isMod ? "leaseModPreview" : "leaseTermPreview");
  const meta      = document.getElementById(isMod ? "leaseModMeta" : "leaseTermMeta");

  // defaults
  btnPrev?.classList.remove("hidden");
  btnDraft?.classList.remove("hidden");

  // Post visibility
  // Owner: always show
  // Assisted: show if (autoPosts) OR (canApprove)
  // Controlled: show only if canApprove
  let canPostUi = false;
  if (mode === FS.control.MODES.OWNER) canPostUi = true;
  else if (mode === FS.control.MODES.ASSISTED) canPostUi = autoPosts || canApprove;
  else if (mode === FS.control.MODES.CONTROLLED) canPostUi = canApprove;

  if (btnPost) btnPost.classList.toggle("hidden", !canPostUi);

  // Draft label: in review flows, saving should create "draft" (or "approved" if auto-post path)
  // We keep Draft button always, but message tells user what happens.
  if (meta) {
    meta.textContent = `Mode: ${mode}${mode === FS.control.MODES.ASSISTED ? (reviewOn ? " (review ON)" : " (review OFF)") : ""}`;
  }

  return { cid, canPostUi, autoPosts, canApprove, mode, reviewOn };
}

function shouldRequestLeasePaymentApproval() {
  const { cid, mode, reviewOn, canApprove, autoPosts } = leaseCtx();

  // OWNER: never needs approval
  if (mode === FS.control.MODES.OWNER) return false;

  // CONTROLLED: if you cannot approve, you must request approval
  if (mode === FS.control.MODES.CONTROLLED) return !canApprove;

  // ASSISTED:
  // - if review is OFF OR autoPosts is ON -> no approval
  // - if review is ON and you cannot approve -> request approval
  if (mode === FS.control.MODES.ASSISTED) {
    if (!reviewOn) return false;
    if (autoPosts) return false;
    return !canApprove;
  }

  return false;
}

async function submitModDraft() {
  const { cid, canPostUi, autoPosts, canApprove, mode } = applyLeaseModalPolicy("mod");
  const leaseId = window.LEASE_UI.state.leaseId;
  if (!cid || !leaseId) return msg("leaseModMsg", "Missing company or lease", "error");

  // basic permission to create
  if (!FS.policy.canCreateLeaseChange(getCurrentRole(), cid)) {
    return msg("leaseModMsg", "You are not allowed to create lease changes in this mode.", "error");
  }

  const payload = {
    modification_date: document.getElementById("leaseModDate").value || null,
    change_type: document.getElementById("leaseModType").value || null,
    new_payment: document.getElementById("leaseModNewPayment").value || null,
    new_rate: document.getElementById("leaseModNewRate").value || null,
    new_end_date: document.getElementById("leaseModNewEnd").value || null,
    reason: document.getElementById("leaseModReason").value || null,
  };

  if (!payload.modification_date) return msg("leaseModMsg", "Modification date is required", "error");

  // Decide status:
  // - If autoPosts is true, backend might auto-post on create OR allow immediate post; keep status "approved" to show intent.
  // - Else "draft"
  const wantsApproved = (mode === FS.control.MODES.OWNER) || (mode === FS.control.MODES.ASSISTED && autoPosts) || canApprove;
  payload.status = wantsApproved ? "approved" : "draft";

  msg("leaseModMsg", "Saving...");
  try {
    const out = await window.apiFetch(ENDPOINTS.leases.createModification(cid, leaseId), {
      method: "POST",
      body: JSON.stringify(payload),
    });

    window.LEASE_UI.state._lastModId = out?.id;

    // If in auto-post mode, you can immediately call POST (optional)
    if (mode === FS.control.MODES.ASSISTED && autoPosts && canPostUi&& window.LEASE_UI.state._lastModId) {
      msg("leaseModMsg", "Saved. Auto-posting...");
      await postMod(); // uses state._lastModId
      return;
    }

    msg("leaseModMsg", payload.status === "draft" ? `Draft saved (#${out?.id || "?"})` : `Saved (#${out?.id || "?"})`);
    await render();
  } catch (e) {
    msg("leaseModMsg", e.message || "Failed", "error");
  }
}
window.submitModDraft = submitModDraft;

async function submitTermDraft() {
  const msg = (id, text, kind="info") => window.msg?.(id, text, kind);
  const { cid, canPostUi, autoPosts, canApprove, mode } = applyLeaseModalPolicy("term");
  const leaseId = window.LEASE_UI.state.leaseId;
  if (!cid || !leaseId) return msg("leaseTermMsg", "Missing company or lease", "error");

  if (!FS.policy.canCreateLeaseChange(getCurrentRole(), cid)) {
    return msg("leaseTermMsg", "You are not allowed to create lease changes in this mode.", "error");
  }

  const payload = {
    termination_date: document.getElementById("leaseTermDate").value || null,
    settlement_amount: document.getElementById("leaseTermSettlement").value || 0,
    reason: document.getElementById("leaseTermReason").value || null,
  };

  if (!payload.termination_date) return msg("leaseTermMsg", "Termination date is required", "error");

  const wantsApproved = (mode === FS.control.MODES.OWNER) || (mode === FS.control.MODES.ASSISTED && autoPosts) || canApprove;
  payload.status = wantsApproved ? "approved" : "draft";

  msg("leaseTermMsg", "Saving...");
  try {
    const out = await window.apiFetch(ENDPOINTS.leases.createTermination(cid, leaseId), {
      method: "POST",
      body: JSON.stringify(payload),
    });

    window.LEASE_UI.state._lastTermId = out?.id;

    if (mode === FS.control.MODES.ASSISTED && autoPosts && canPostUi && window.LEASE_UI.state._lastTermId) {
      msg("leaseTermMsg", "Saved. Auto-posting...");
      await window.postTerm();
      return;
    }

    msg("leaseTermMsg", payload.status === "draft" ? `Draft saved (#${out?.id || "?"})` : `Saved (#${out?.id || "?"})`);
    await render();
  } catch (e) {
    msg("leaseTermMsg", e.message || "Failed", "error");
  }
}
window.submitTermDraft = submitTermDraft;

