  function isoDate(v) {
    if (!v) return "";
    // handles "Wed, 29 Oct 2025 00:00:00 GMT" and ISO strings
    const d = new Date(v);
    if (Number.isNaN(d.getTime())) return String(v).slice(0, 10);
    return d.toISOString().slice(0, 10);
  }

  function toISODate(v) {
    // Accepts "YYYY-MM-DD" or "MM/DD/YYYY"
    const s = String(v || "").trim();
    if (!s) return "";

    // ISO already
    if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s;

    // MM/DD/YYYY
    const m = s.match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
    if (m) return `${m[3]}-${m[1]}-${m[2]}`;

    // Fallback: Date parse (last resort)
    const d = new Date(s);
    if (!Number.isFinite(d.getTime())) return "";
    return d.toISOString().slice(0, 10);
  }

  function isoMonthBounds(anyISO) {
    const d = new Date(anyISO + "T00:00:00");
    const ps = new Date(d.getFullYear(), d.getMonth(), 1).toISOString().slice(0,10);
    const pe = new Date(d.getFullYear(), d.getMonth() + 1, 0).toISOString().slice(0,10);
    return { ps, pe };
  }

  function usageSetMsg(msg, type="info") {
    const el = document.getElementById("faUsageMsg");
    if (!el) return;
    el.textContent = msg || "";
    el.className = type === "error" ? "mb-3 text-sm text-red-600" : "mb-3 text-sm text-slate-500";
  }

  function openUsageModal(assetId) {
    const modal = ensureUsageModal();
    USAGE_ASSET_ID = Number(assetId || 0);
    modal.dataset.assetId = String(USAGE_ASSET_ID);

    const row = REGISTER_ROWS.find(r => Number(r.id ?? r.asset_id) === USAGE_ASSET_ID) || {};

    // ✅ detect mode from asset row (fallback DELTA)
    USAGE_MODE = String(row.uop_usage_mode || row.uopUsageMode || "DELTA").toUpperCase();
    if (USAGE_MODE !== "READING") USAGE_MODE = "DELTA";

    const unitName = (row.uop_unit_name || row.uopUnitName || "units").trim() || "units";
    const totalUnits = num(row.uop_total_units);

    const avail = isoDate(
      row.available_for_use_date ||
      row.available_for_use ||      // optional legacy alias
      row.acquisition_date
    );

    const psEl = document.getElementById("faUsagePeriodStart");
    const peEl = document.getElementById("faUsagePeriodEnd");
    const unitsEl = document.getElementById("faUsageUnits");
    const notesEl = document.getElementById("faUsageNotes");

    // -------------------------
    // ✅ default dates by mode
    // -------------------------
    if (USAGE_MODE === "READING") {
      // reading is a snapshot at a date: ps = pe
      const today = toISODate(new Date().toISOString().slice(0, 10)); // YYYY-MM-DD
      if (psEl) psEl.value = today;
      if (peEl) peEl.value = today;
    } else {
      // DELTA: default to current month bounds
      const b = monthBoundsISO();
      if (psEl) psEl.value = b.period_start;
      if (peEl) peEl.value = b.period_end;
    }

    if (unitsEl) unitsEl.value = "";
    if (notesEl) notesEl.value = "";

    // Show avail-for-use line
    const afuEl = document.getElementById("faUsageAvailForUse");
    if (afuEl) afuEl.textContent = avail ? `Available for use: ${avail}` : "Available for use: —";

    // Apply min + clamp start/end
    if (avail) {
      psEl?.setAttribute("min", avail);
      peEl?.setAttribute("min", avail);

      if (psEl && psEl.value < avail) psEl.value = avail;
      if (peEl && peEl.value < avail) peEl.value = avail;

      // ✅ enforce ps <= pe always
      if (psEl && peEl && peEl.value < psEl.value) peEl.value = psEl.value;

      // ✅ for READING: force ps = pe after clamp
      if (USAGE_MODE === "READING" && psEl && peEl) psEl.value = peEl.value;
    } else {
      psEl?.removeAttribute("min");
      peEl?.removeAttribute("min");
    }

    document.getElementById("faUsageUnitName").textContent = unitName;
    document.getElementById("faUsageAssetLabel").textContent =
      row.asset_name || row.name || `Asset #${USAGE_ASSET_ID}`;

    document.getElementById("faUsageAssetMeta").textContent =
      `Method: ${(row.depreciation_method || "—")} • Lifetime: ${totalUnits ? totalUnits.toLocaleString() : "—"} ${unitName} • Mode: ${USAGE_MODE}`;

    const hintEl = document.getElementById("faUsageHint");
    if (hintEl) {
      hintEl.textContent =
        USAGE_MODE === "READING"
          ? `Enter the meter/odometer reading on this date (a snapshot).`
          : (totalUnits > 0
              ? `Tip: keep period usage realistic vs lifetime ${totalUnits.toLocaleString()} ${unitName}.`
              : "");
    }

    usageSetMsg(
      USAGE_MODE === "READING"
        ? "Enter the reading for the selected date. Depreciation will use the difference vs prior reading/opening."
        : "Enter actual units used for the period. This drives UOP depreciation.",
      "info"
    );

    modal.classList.remove("hidden");
    document.body.classList.add("overflow-hidden");
  }

  function closeUsageModal() {
    const modal = document.getElementById("faUsageModal");
    if (!modal) return;
    modal.classList.add("hidden");
    document.body.classList.remove("overflow-hidden");
    usageSetMsg("", "info");
    USAGE_ASSET_ID = 0;
  }

  function usagePayloadFromUI() {
    const ps0 = toISODate(document.getElementById("faUsagePeriodStart")?.value);
    const pe0 = toISODate(document.getElementById("faUsagePeriodEnd")?.value);
    const units = num(document.getElementById("faUsageUnits")?.value);
    const notes = (document.getElementById("faUsageNotes")?.value || "").trim() || null;

    if (!ps0) throw new Error("Period start is required.");
    if (!pe0) throw new Error("Period end is required.");

    const mode = String(USAGE_MODE || "DELTA").toUpperCase();

    // ✅ mode-specific validation
    if (mode === "READING") {
      if (units < 0) throw new Error("Reading must be 0 or more.");
    } else {
      if (units <= 0) throw new Error("Units used must be > 0.");
    }

    let ps = ps0;
    let pe = pe0;

    if (mode === "READING") {
      // ✅ reading is a snapshot on a date -> force single day
      pe = pe0 || ps0;
      ps = pe;
    } else {
      // ✅ DELTA: same-month clamp
      const mb = isoMonthBounds(ps0);
      if (ps < mb.ps) ps = mb.ps;
      if (pe > mb.pe) pe = mb.pe;
      if (pe < ps) pe = ps;
    }

    return {
      asset_id: USAGE_ASSET_ID,
      period_start: ps,
      period_end: pe,
      units_used: units,     // DELTA: usage, READING: meter reading
      notes,
      status: "posted",      // ✅ depreciation sees it immediately
    };
  }

  async function submitUsage() {
    const cid = getActiveCompanyId?.() || window.CURRENT_COMPANY_ID;
    if (!cid) return usageSetMsg("No active company.", "error");
    if (!USAGE_ASSET_ID) return;

    try {
      usageSetMsg("Saving…", "info");
      const payload = usagePayloadFromUI();

      // if mode is "READING", force single-day snapshot
      if (payload?.mode === "READING" || payload?.uop_usage_mode === "READING") {
        payload.period_start = payload.period_end;
      }

      const url = window.ENDPOINTS?.assets?.createUsage
        ? window.ENDPOINTS.assets.createUsage(cid)
        : `/api/companies/${cid}/asset-usage`; // implement backend route

      await apiFetch(url, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });

      usageSetMsg("Saved.", "info");
      closeUsageModal();

      // Optional: refresh register
      await refreshFixedAssetsRegister();
    } catch (e) {
      usageSetMsg(e?.message || "Failed to save usage.", "error");
    }
  }

