  function toggleObligationFields() {
    const timing = document.getElementById("revRecognitionTiming")?.value;

    const overTimeBlock = document.getElementById("revOverTimeBlock");
    const pitBlock = document.getElementById("revPointInTimeBlock");

    if (timing === "point_in_time") {
      overTimeBlock?.classList.add("hidden");
      pitBlock?.classList.remove("hidden");

      if ($("revProgressMethod")) $("revProgressMethod").value = "";
    } else {
      overTimeBlock?.classList.remove("hidden");
      pitBlock?.classList.add("hidden");

      if ($("revProgressMethod") && !$("revProgressMethod").value) {
        $("revProgressMethod").value = "cost_to_cost";
      }
      if ($("revPitDate")) $("revPitDate").value = $("revPitDate").value || "";
      if ($("revPitTrigger")) $("revPitTrigger").value = "";
    }
  }

  function toggleFinancingFields() {
    const checked = !!$("revHasFinancing")?.checked;
    const box = $("revFinancingFields");
    if (!box) return;

    box.classList.toggle("hidden", !checked);

    if (!checked) {
      if ($("revFinancingRate")) $("revFinancingRate").value = "";
      if ($("revFinancingStartDate")) $("revFinancingStartDate").value = "";
      if ($("revFinancingEndDate")) $("revFinancingEndDate").value = "";
      if ($("revFinancingNotes")) $("revFinancingNotes").value = "";
    }
  }

  function applyRevenueSetupDefaults() {
    if (typeof window.getRevenueSetupPolicy !== "function") return;

    const setup = window.getRevenueSetupPolicy() || {};

    if ($("revChkCollectability")) {
      $("revChkCollectability").checked = !!setup?.contract_rules?.collectability_required;
    }
    if ($("revChkRights")) {
      $("revChkRights").checked = !!setup?.contract_rules?.rights_required;
    }
    if ($("revChkTerms")) {
      $("revChkTerms").checked = !!setup?.contract_rules?.payment_terms_required;
    }
    if ($("revChkSubstance")) {
      $("revChkSubstance").checked = !!setup?.contract_rules?.commercial_substance_required;
    }

    if ($("revRecognitionTiming") && setup?.obligation_rules?.default_recognition_timing) {
      $("revRecognitionTiming").value = setup.obligation_rules.default_recognition_timing;
    }

    if ($("revProgressMethod") && setup?.obligation_rules?.default_progress_method) {
      $("revProgressMethod").value = setup.obligation_rules.default_progress_method;
    }
  }

  function validateContractCriteria() {
    if ($("revChkCollectability") && !$("revChkCollectability").checked) {
      return "Collectability criteria not satisfied.";
    }
    if ($("revChkRights") && !$("revChkRights").checked) {
      return "Rights are not identifiable.";
    }
    if ($("revChkTerms") && !$("revChkTerms").checked) {
      return "Payment terms are not identifiable.";
    }
    if ($("revChkSubstance") && !$("revChkSubstance").checked) {
      return "Commercial substance criteria not satisfied.";
    }
    return null;
  }

  function refreshSettlementPatternHelp() {
    const sel = $("revSettlementPattern");
    const el = $("revSettlementPatternHelp");
    if (!sel || !el) return;

    const v = (sel.value || "").trim();

    if (!v) {
      el.textContent = "";
      el.classList.add("hidden");
      return;
    }

    const helpMap = {
      revenue_before_billing:
        "Use when work is performed before the customer is invoiced. Invoice posting clears Contract Asset later.",
      billing_before_revenue:
        "Use when the customer is invoiced before the service is fully earned. Billing posts to Contract Liability first.",
      cash_before_service:
        "Use when cash is received before service delivery. The amount stays in Contract Liability until revenue is earned.",
    };

    el.textContent = helpMap[v] || "";
    el.classList.toggle("hidden", !helpMap[v]);
  }

  function setActiveTab(tab) {
    state.tab = tab;

    const panes = {
      contracts: $("revPaneContracts"),
      obligations: $("revPaneObligations"),
      billings: $("revPaneBillings"),
      progress: $("revPaneProgress"),
      runs: $("revPaneRuns"),
    };

    Object.entries(panes).forEach(([k, el]) => {
      if (!el) return;
      if (k === tab) el.classList.remove("hidden");
      else el.classList.add("hidden");
    });

    document.querySelectorAll("[data-rev-tab]").forEach((btn) => {
      btn.classList.toggle("bg-[var(--fs-navy)]", btn.dataset.revTab === tab);
      btn.classList.toggle("text-white", btn.dataset.revTab === tab);
    });
    syncRevenueMainWidthState(); // add this
  }

  async function loadRevenueCustomers() {
    const sel = $("revCustomerId");
    if (!sel) return;

    let customers =
      (Array.isArray(window.CUSTOMERS) && window.CUSTOMERS.length)
        ? window.CUSTOMERS
        : [];

    if (!customers.length) {
      try {
        customers = await fetchCustomersFromBackend?.(true) || [];
      } catch (_) {
        customers = [];
      }
    }

    sel.innerHTML = `
      <option value="">Select customer</option>
      ${customers.map(c => `
        <option value="${esc(String(c.id || ""))}">
          ${esc(c.name || c.customer_name || `Customer ${c.id}`)}
        </option>
      `).join("")}
    `;
  }

  function setContractViewMode(mode = "preview") {
    $("revContractPreviewWrap")?.classList.toggle("hidden", mode !== "preview");
    $("revContractFormWrap")?.classList.toggle("hidden", mode !== "form");
  }

  function setObligationViewMode(mode = "preview") {
    $("revObligationPreviewWrap")?.classList.toggle("hidden", mode !== "preview");
    $("revObligationFormWrap")?.classList.toggle("hidden", mode !== "form");
  }

  function hydrateContractForm(c = {}) {
    if ($("revCustomerId")) {
      $("revCustomerId").value = c.customer_id || "";
    }

    $("revContractId").value = c.id || "";
    $("revContractNumber").value = c.contract_number || "";
    $("revContractTitle").value = c.contract_title || "";
    $("revContractCurrency").value = resolveCurrency(c.contract_currency);

    $("revContractDate").value = toDateInputValue(c.contract_date);
    $("revStartDate").value = toDateInputValue(c.start_date);
    $("revEndDate").value = toDateInputValue(c.end_date);

    $("revBillingMethod").value = c.billing_method || "milestone";
    $("revSettlementPattern").value = c?.payload_json?.settlement_pattern || "";
    refreshSettlementPatternHelp();
    $("revTransactionPrice").value = num(c.transaction_price).toFixed(2);
    $("revVariableConstrained").value = num(c.variable_consideration_constrained).toFixed(2);
    $("revIsOverTime").checked = !!c.is_over_time;
    $("revHasFinancing").checked = !!c.has_significant_financing_component;
    const financing = c?.payload_json?.financing || {};

    if ($("revFinancingRate")) {
      $("revFinancingRate").value =
        financing.rate != null && financing.rate !== ""
          ? Number(financing.rate)
          : "";
    }

    if ($("revFinancingStartDate")) {
      $("revFinancingStartDate").value = toDateInputValue(financing.start_date);
    }

    if ($("revFinancingEndDate")) {
      $("revFinancingEndDate").value = toDateInputValue(financing.end_date);
    }

    if ($("revFinancingNotes")) {
      $("revFinancingNotes").value = financing.notes || "";
    }
    $("revContractNotes").value = c.notes || "";

    const im = c?.payload_json?.ifrs15_initial_measurement || {};
    if ($("revChkCollectability")) $("revChkCollectability").checked = !!im.collectability_probable;
    if ($("revChkRights")) $("revChkRights").checked = !!im.rights_identifiable;
    if ($("revChkTerms")) $("revChkTerms").checked = !!im.payment_terms_identifiable;
    if ($("revChkSubstance")) $("revChkSubstance").checked = !!im.commercial_substance;

    $("revContractStatusPill").textContent = c.status || "draft";
    state.selectedContract = c?.id ? c : null;

    renderContractKpis(c);
    refreshRevenueObligationActions();
  }

  async function loadRevenueCashBankAccounts() {
    const el = document.getElementById("revCashBankAccountId");
    if (!el) return;

    const cid = activeCid();
    if (!cid) return;

    const url =
      (typeof ENDPOINTS?.bankAccounts === "function")
        ? ENDPOINTS.bankAccounts(cid)
        : `${API_BASE}/api/companies/${cid}/bank_accounts`;

    try {
      const keep = String(el.value || "");

      el.innerHTML = `<option value="">Loading bank accounts…</option>`;

      const raw = await apiFetch(url, { method: "GET" });
      const payload = (typeof unwrapApi === "function") ? unwrapApi(raw) : raw;

      const rows =
        Array.isArray(payload) ? payload :
        Array.isArray(payload?.data) ? payload.data :
        Array.isArray(payload?.accounts) ? payload.accounts :
        [];

      el.innerHTML = `<option value="">-- Select bank account --</option>`;

      if (!rows.length) {
        el.insertAdjacentHTML(
          "beforeend",
          `<option value="" disabled>(No bank accounts found)</option>`
        );
        return;
      }

      rows.forEach((b) => {
        const id = b.id ?? b.bank_account_id ?? null;
        if (!id) return;

        const bankName = b.bank_name || b.name || "Bank";
        const acctName = b.account_name || b.label || "";
        const acctNo = b.account_number || "";
        const ccy = b.currency || b.bank_currency || "";

        const label = [
          bankName,
          acctName,
          acctNo ? `(${acctNo})` : "",
          ccy ? `• ${ccy}` : "",
        ].filter(Boolean).join(" ");

        el.insertAdjacentHTML(
          "beforeend",
          `<option value="${id}">${label}</option>`
        );
      });

      if (keep) el.value = keep;

    } catch (e) {
      console.warn("[Revenue] loadRevenueCashBankAccounts failed", e);
      el.innerHTML = `<option value="" disabled>(Failed to load)</option>`;
    }
  }

  function buildRevenueCashRedirectPayload() {
    const contractId =
      Number($("revContractId")?.value || 0) || null;

    const contractNumber =
      $("revContractNumber")?.value?.trim() || "";

    const customerId =
      Number($("revCustomerId")?.value || 0) || null;

    const customerName =
      $("revCustomerId")?.selectedOptions?.[0]?.textContent?.trim() || "";

    const obligationId =
      Number($("revObligationId")?.value || 0) || null;

    const eventDate =
      $("revCashDate")?.value || null;

    const amount =
      num($("revCashAmount")?.value);

    const currency =
      resolveCurrency($("revCashCurrency")?.value);

    const notes =
      $("revCashNotes")?.value?.trim() || "";

    const bankAccountId =
      Number($("revCashBankAccountId")?.value || 0) || null;

    return {
      contractId,
      contractNumber,
      customerId,
      customerName,
      obligationId,
      eventDate,
      amount,
      currency,
      notes,
      bankAccountId,
    };
  }

  async function loadRevenueObligationCatalog() {
    const dl = $("revObligationCatalogList");
    if (!dl) return [];

    await window.loadInvoiceItemCatalog?.();

    const catalog = window._INV_ITEM_CATALOG || {};
    const byValue = catalog.byValue || new Map();

    dl.innerHTML = "";

    const seen = new Set();
    const items = [];

    for (const [friendly, meta] of byValue.entries()) {
      if (!friendly || !meta) continue;

      const key = `${meta.type || ""}|${meta.id || ""}|${friendly}`;
      if (seen.has(key)) continue;
      seen.add(key);

      const opt = document.createElement("option");
      opt.value = friendly;
      opt.dataset.type = meta.type || "";
      opt.dataset.id = meta.id != null ? String(meta.id) : "";
      opt.dataset.code = meta.code || "";
      opt.dataset.name = meta.name || "";
      opt.dataset.price = meta.price != null ? String(meta.price) : "";
      opt.dataset.revenue_account = meta.revenue_account || "";
      opt.dataset.vat_code = meta.vat_code || "";

      dl.appendChild(opt);
      items.push({
        label: friendly,
        ...meta,
      });
    }

    return items;
  }
  window.loadRevenueObligationCatalog = loadRevenueObligationCatalog;

  function findRevenueObligationCatalogMeta(rawValue) {
    const v = String(rawValue || "").trim();
    if (!v) return null;

    const dl = $("revObligationCatalogList");
    const norm = (s) => String(s || "").trim().toLowerCase();

    const opt = Array.from(dl?.options || []).find(o => norm(o.value) === norm(v));
    if (opt) {
      return {
        type: opt.dataset.type || "",
        id: opt.dataset.id ? Number(opt.dataset.id) : null,
        code: opt.dataset.code || "",
        name: opt.dataset.name || v,
        price: Number(opt.dataset.price || 0),
        revenue_account: opt.dataset.revenue_account || null,
        vat_code: opt.dataset.vat_code || null,
        label: opt.value,
      };
    }

    const catalog = window._INV_ITEM_CATALOG || {};
    const byValue = catalog.byValue || new Map();
    const byCode = catalog.byCode || new Map();
    const byName = catalog.byName || new Map();

    return (
      byValue.get(v) ||
      byCode.get(norm(v)) ||
      byName.get(norm(v)) ||
      null
    );
  }

  function applyCatalogMetaToObligationForm(meta) {
    if (!meta) return;

    const hint = $("revObligationCatalogHint");

    if (!$("revObligationCode")?.value?.trim() && meta.code) {
      $("revObligationCode").value = meta.code;
    }

    if (!$("revObligationName")?.value?.trim() || $("revObligationName").value === meta.label) {
      $("revObligationName").value = meta.name || meta.label || "";
    }

    if (num($("revSSP")?.value) === 0 && Number(meta.price || 0) > 0) {
      $("revSSP").value = Number(meta.price).toFixed(2);
    }

    if (num($("revAllocatedPrice")?.value) === 0 && Number(meta.price || 0) > 0) {
      $("revAllocatedPrice").value = Number(meta.price).toFixed(2);
    }

    if (hint) {
      const parts = [
        meta.type ? `Type: ${meta.type}` : "",
        meta.code ? `Code: ${meta.code}` : "",
        meta.vat_code ? `VAT: ${meta.vat_code}` : "",
      ].filter(Boolean);

      hint.textContent = parts.join(" • ");
      hint.classList.toggle("hidden", !parts.length);
    }
  }

  function bindRevenueObligationCatalogPicker() {
    const input = $("revObligationName");
    if (!input || input.dataset.boundCatalog === "1") return;

    const handlePick = () => {
      const meta = findRevenueObligationCatalogMeta(input.value);
      if (!meta) return;
      applyCatalogMetaToObligationForm(meta);
    };

    input.addEventListener("change", handlePick);
    input.addEventListener("blur", handlePick);

    input.dataset.boundCatalog = "1";
  }

  function hydrateObligationForm(o = {}) {
    const pj = o?.payload_json || {};

    const catalogItemLabel =
      o.catalog_item_label ??
      pj.catalog_item_label ??
      "";

    const catalogItemType =
      o.catalog_item_type ??
      pj.catalog_item_type ??
      "";

    const catalogItemCode =
      o.catalog_item_code ??
      pj.catalog_item_code ??
      "";

    const vatCode =
      o.vat_code ??
      pj.vat_code ??
      "";

    $("revObligationId").value = o.id || "";
    $("revObligationCode").value = o.obligation_code || catalogItemCode || "";

    const displayName =
      catalogItemLabel ||
      o.obligation_name ||
      "";

    $("revObligationName").value = displayName;
    $("revRecognitionTiming").value = o.recognition_timing || "over_time";
    $("revProgressMethod").value = o.progress_method || "cost_to_cost";
    if ($("revPitTrigger")) {
      $("revPitTrigger").value = o.recognition_trigger || pj.recognition_trigger || "";
    }
    $("revSSP").value = num(o.standalone_selling_price).toFixed(2);
    $("revAllocatedPrice").value = num(o.allocated_transaction_price).toFixed(2);
    $("revExpectedCost").value = num(o.expected_total_cost).toFixed(2);
    $("revPitDate").value = String(o.recognized_at_point_in_time_date || "").slice(0, 10);
    $("revDistinctFlag").checked = o.distinct_flag !== false;
    $("revObligationNotes").value = o.notes || "";

    state.selectedObligation = o?.id ? o : null;

    const hint = $("revObligationCatalogHint");
    if (hint) {
      const parts = [
        catalogItemType ? `Type: ${catalogItemType}` : "",
        catalogItemCode ? `Code: ${catalogItemCode}` : "",
        vatCode ? `VAT: ${vatCode}` : "",
      ].filter(Boolean);

      hint.textContent = parts.join(" • ");
      hint.classList.toggle("hidden", !parts.length);
    }

    toggleObligationFields();
  }

