// Global cache (keep if you already have it elsewhere)
let REVENUE_ACCOUNTS_CACHE = [];

/**
 * Load revenue accounts into the invoice header dropdown (#invRevenueAccount)
 * Supports BOTH:
 *  - legacy numeric templates (template_code starts with "4")
 *  - new reporting codes (PL_REV_4000 etc) via code_family / family
 *  - fallback heuristics (section/category/name contains revenue/income/sales)
 */

function toISODate(d) {
  // returns YYYY-MM-DD in local time
  const yyyy = d.getFullYear();
  const mm = String(d.getMonth() + 1).padStart(2, "0");
  const dd = String(d.getDate()).padStart(2, "0");
  return `${yyyy}-${mm}-${dd}`;
}

function termsToDays(terms) {
  const t = String(terms || "").toLowerCase().trim();

  if (!t) return 0;
  if (t === "on_receipt" || t.includes("receipt") || t.includes("on receipt") || t === "0") return 0;

  // handle "15", "30", "net 15", "15 days"
  const n = parseInt(t.replace(/[^\d]/g, ""), 10);
  return Number.isFinite(n) ? n : 0;
}

async function preflightCreditCheck(companyId, invoice) {
  const customerId = invoice.customer_id;
  const amount = invoice.total || invoice.total_amount || 0;
  const asAt = (invoice.invoice_date || isoToday()).slice(0,10);

  if (!customerId) return { ok: true };

  const resp = await apiFetch(ENDPOINTS.ar.creditCheck(companyId, customerId, amount, asAt), { method: "GET" });
  const data = resp.data || resp;

  return data;
}


function addDaysISO(isoDate, days) {
  const parts = String(isoDate || "").slice(0, 10).split("-").map(Number);
  if (parts.length !== 3 || parts.some(n => !Number.isFinite(n))) return "";

  const [y, m, d] = parts;
  const dt = new Date(y, (m - 1), d);
  if (isNaN(dt.getTime())) return "";

  dt.setDate(dt.getDate() + (Number(days) || 0));

  const yyyy = dt.getFullYear();
  const mm = String(dt.getMonth() + 1).padStart(2, "0");
  const dd = String(dt.getDate()).padStart(2, "0");
  return `${yyyy}-${mm}-${dd}`;
}

function computeDueDate(invoiceISO, terms) {
  const inv = String(invoiceISO || "").slice(0, 10);
  if (!inv) return "";

  const days = termsToDays(terms);   // 0 / 15 / 30
  return addDaysISO(inv, days);
}

// Accepts: "5", "5%", "0.05"  -> returns rate 0..1
function parsePercent(input) {
  let s = String(input ?? "").trim();
  if (!s) return 0;

  s = s.replace(/\s+/g, "");
  const hadPct = s.endsWith("%");
  if (hadPct) s = s.slice(0, -1);

  s = s.replace(",", ".");
  let n = Number(s);
  if (!Number.isFinite(n) || n < 0) return 0;

  if (hadPct) return Math.min(n / 100, 1);
  if (n <= 1) return Math.min(n, 1);     // 0.05 => 5%
  return Math.min(n / 100, 1);           // 5 => 5%
}

function syncInvoiceDueDateLabel() {
  const invDate = document.getElementById("invDate")?.value;     // YYYY-MM-DD
  const terms   = document.getElementById("invTerms")?.value;    // on_receipt / 15 / 30
  const out     = document.getElementById("invDueDateLabel");

  if (!out) return;
  if (!invDate) { out.textContent = "—"; return; }

  const due = computeDueDate(invDate, terms);
  out.textContent = due || "—";
}

