async function openInvoiceFromApprovalHandoff() {
  const cid = getActiveCompanyId?.() || CURRENT_COMPANY_ID;
  if (!cid) return false;

  const reqId = store?.get?.("fs_ar_approval_request_id");
  const invId = store?.get?.("fs_ar_approval_invoice_id");

  if (!reqId || !invId) return false;

  // clear handoff (so refresh doesn’t reopen again)
  store?.set?.("fs_ar_approval_request_id", null);
  store?.set?.("fs_ar_approval_invoice_id", null);

  // Put AR in “review mode” so clerk buttons behave
  window._INV_REVIEW_MODE = true;
  window._INV_TOTALS_LOCKED = true;

  // ✅ You must have a loader; if you already do, use yours here.
  // Suggested: loadInvoiceById(cid, invId) fills the form + lines and sets invId field
  if (typeof window.loadInvoiceById === "function") {
    await window.loadInvoiceById(cid, Number(invId));
  } else {
    // Minimal fallback: at least set invId so approve/post can work
    const idEl = document.getElementById("invId");
    if (idEl) idEl.value = String(invId);
  }

  // Update UI (optional)
  document.getElementById("invStatus") && (document.getElementById("invStatus").textContent = "Pending approval");

  // Ensure buttons match policy
  if (typeof applyInvoiceButtonsByMode === "function") applyInvoiceButtonsByMode();

  return true;
}
window.openInvoiceFromApprovalHandoff = openInvoiceFromApprovalHandoff;

function updateInvoiceActionButtons() {
  const cid = FS.control.resolveCid();
  if (!cid) return;

  const mode = FS.control.get(cid);
  const role = FS.role.normalize(getCurrentRole?.() || "");

  const canApprove = !!FS.policy.canApproveInvoice(role, cid);
  const canDraft = !!FS.policy.canCreateInvoiceDraft?.(role, cid);

  // ✅ use your REAL ids from HTML
  const btnDraft = document.getElementById("invSaveDraft");
  const btnReq   = document.getElementById("invApprove"); // you are using this as “Request approval / Approve” button
  const btnPost  = document.getElementById("invPost");

  // Draft
  if (btnDraft) {
    btnDraft.disabled = !canDraft;
    btnDraft.classList.toggle("opacity-50", !canDraft);
  }

  // OWNER-MANAGED
  if (mode === FS.control.MODES.OWNER) {
    // Owner can post; keep “Approve/Request” hidden if you want
    btnReq?.classList.add("hidden");
    btnPost?.classList.remove("hidden");
    if (btnPost) {
      btnPost.disabled = !canApprove; // will be true in owner mode
      btnPost.classList.toggle("opacity-50", btnPost.disabled);
    }
    return;
  }

  // ASSISTED / CONTROLLED
  if (canApprove) {
    // Approver sees Post
    btnReq?.classList.add("hidden");
    btnPost?.classList.remove("hidden");
    if (btnPost) {
      btnPost.disabled = false;
      btnPost.classList.remove("opacity-50");
    }
  } else {
    // Maker sees Request Approval (your invApprove button)
    btnPost?.classList.add("hidden");
    btnReq?.classList.remove("hidden");
    if (btnReq) {
      btnReq.disabled = false;
      btnReq.classList.remove("opacity-50");
    }
  }
}

