async function commitInvoice(action) {
  const cid = FS.control.resolveCid();
  if (!cid) throw new Error("No company selected.");

  const roleRaw = (typeof getCurrentRole === "function") ? getCurrentRole() : "";
  const role = FS.role.normalize(roleRaw);

  const mode = FS.control.get(cid);

  // ✅ policy gates
  const canApprove = !!FS.policy.canApproveInvoice(role, cid);

  // ✅ NEW: maker gate (draft/create permission)
  // If you don't have this yet, add it (see below)
  const canDraft = typeof FS.policy.canCreateInvoiceDraft === "function"
    ? !!FS.policy.canCreateInvoiceDraft(role, cid)
    : (mode === FS.control.MODES.OWNER); // safe fallback: only owner-managed can draft

  async function ensureInvoiceRowExistsDraftOnly() {
    let invId = parseInt(document.getElementById("invId")?.value || "0", 10) || 0;

    // If it doesn't exist yet, create ONCE
    if (!invId) {
      const saved = await saveInvoiceDraft("draft"); // create invoice row once
      invId = saved?.id || 0;
      if (invId) document.getElementById("invId").value = String(invId);
    }

    if (!invId) throw new Error("Could not create invoice.");
    return invId;
  }

  async function ensureInvoiceRowExistsForPosting() {
    // ✅ only allocate number when posting (NOT on draft)
    await ensureInvoiceNumberOnCommit?.();

    let invId = parseInt(document.getElementById("invId")?.value || "0", 10) || 0;
    if (!invId) {
      const saved = await saveInvoiceDraft("draft");
      invId = saved?.id || 0;
      if (invId) document.getElementById("invId").value = String(invId);
    }

    if (!invId) throw new Error("Could not create invoice.");
    return invId;
  }

  // ---------------------------
  // ACTION: draft
  // ---------------------------
  if (action === "draft") {
    // ✅ replaced "clerk only" with policy-driven maker gate
    if (!canDraft) {
      throw new Error("You are not allowed to save draft invoices in this mode.");
    }

    // ✅ Create once if needed, else update once
    await ensureInvoiceRowExistsDraftOnly();

    if (parseInt(document.getElementById("invId")?.value || "0", 10)) {
      await saveInvoiceDraft("draft"); // update existing
    }

    return { ok: true, flow: "draft_only" };
  }

  // ---------------------------
  // ACTION: submit_for_approval
  // Save/update invoice, then submit to inbox (pending_approval)
  // ---------------------------
  if (action === "submit_for_approval") {
    if (!canDraft) {
      throw new Error("You are not allowed to submit invoices in this mode.");
    }

    // create/update invoice first (no number allocation needed)
    await ensureInvoiceRowExistsDraftOnly();
    await saveInvoiceDraft("draft"); // save latest edits

    const invId = parseInt(document.getElementById("invId")?.value || "0", 10) || 0;
    if (!invId) throw new Error("Invoice ID missing.");

    return await submitInvoiceForApprovalFlow({ cid, invId }); // sets pending_approval
  }

  // ---------------------------
  // ACTION: approve_post
  // ---------------------------
  if (action === "approve_post") {
    const invId = await ensureInvoiceRowExistsForPosting();
    const autoPosts = !!FS.policy.invoiceAutoPosts?.(cid);

    // if user is not allowed AND company is not auto-posting -> always submit approval
    if (!canApprove && !autoPosts) {
      return await submitInvoiceForApprovalFlow({ cid, invId });
    }

    // allowed users can post
    try {
      const posted = await postInvoiceAccordingToPolicy(invId);
      return { ok: true, flow: "post", invId, posted: posted?.data || posted };
    } catch (e) {
      // fallback: if backend denies posting, submit for approval instead
      const status = e?.status || e?.httpStatus || e?.response?.status;
      if (status === 401 || status === 403) {
        return await submitInvoiceForApprovalFlow({ cid, invId });
        await refreshRevenueBillingOverviewFromInvoice(posted || { revenue_contract_id: invoice?.revenue_contract_id });
      }
      throw e;
    }
  }

throw new Error("Unknown action: " + action);
}

// ✅ Helper to toggle disabled state cleanly (no stuck grey)
function setBtnDisabled(btn, disabled, reason = "") {
  if (!btn) return;

  btn.disabled = !!disabled;
  btn.classList.toggle("opacity-60", !!disabled);
  btn.classList.toggle("cursor-not-allowed", !!disabled);

  if (disabled) {
    btn.setAttribute("aria-disabled", "true");
    if (reason) btn.setAttribute("title", reason);
  } else {
    btn.removeAttribute("aria-disabled");
    btn.removeAttribute("title");
  }
}

// ✅ Decide which invoice buttons are enabled by mode + role
function applyInvoiceButtonsByMode() {
  const cid = FS.control.resolveCid();
  const btnDraft   = document.getElementById("invSaveDraft");
  const btnApprove = document.getElementById("invApprove");
  const btnSend    = document.getElementById("invSend");
  if (!btnDraft && !btnApprove && !btnSend) return;

  const role = FS.role.normalize(getCurrentRole?.() || "");
  const mode = FS.control.get(cid);

  // YOU need a real owner check (see section 4)
  const isOwner = FS.policy.isOwnerUser();

  const canApprove = !!FS.policy.canApproveInvoice?.(role, cid);

  setBtnDisabled(btnDraft, false);
  setBtnDisabled(btnApprove, false);
  setBtnDisabled(btnSend, false);

  if (mode === FS.control.MODES.OWNER) {
    return; // everything allowed
  }

  if (mode === FS.control.MODES.ASSISTED) {
    const reviewOn = FS.control.isReviewEnabled?.(cid);
    if (!reviewOn) return; // relaxed assisted: auto-post allowed

    // ✅ review enabled: owner can approve/post, everyone else drafts
    setBtnDisabled(btnDraft, isOwner);         // owner doesn’t need draft
    setBtnDisabled(btnApprove, !isOwner);      // only owner approves/posts
    setBtnDisabled(btnSend, !isOwner);
    return;
  }

  // CONTROLLED
  setBtnDisabled(btnDraft, false);             // let anyone draft (your choice)
  setBtnDisabled(btnApprove, !canApprove);
  setBtnDisabled(btnSend, !canApprove);
}

async function postInvoiceToJournal(invoice) {
  const cid = (typeof getActiveCompanyId === "function")
    ? getActiveCompanyId()
    : (getActiveCompanyId?.() || null);

  if (!cid) throw new Error("No active company - please sign in again.");
  if (!invoice) throw new Error("No invoice payload provided.");

  const entryDate =
    invoice.invoice_date ||
    invoice.date ||
    document.getElementById("invDate")?.value ||
    new Date().toISOString().slice(0, 10);

  // ✅ Ensure AR control + fallback income exist
  const arCode = invoice.arAccountCode || findDefaultArAccountCode?.();
  if (!arCode) throw new Error("No AR control account found (arAccountCode).");

  const fallbackIncome = findDefaultSalesAccountCode?.();
  if (!fallbackIncome) throw new Error("No default Sales/Income account found.");

  // VAT code → rate
  const vatRateFromCode = (code) => {
    const c = String(code || "").toUpperCase();
    if (c === "STANDARD") return 15;
    return 0;
  };

  // --- read header discount/other (optional) ---
  const headerDiscount =
    Number(invoice.discount ?? invoice.disc ?? invoice.header_discount ?? 0) || 0;

  const headerOther =
    Number(invoice.other ?? invoice.other_charges ?? invoice.otherCharges ?? 0) || 0;

  // ✅ Build income lines from your invoice line schema:
  // Your collectInvoiceFromForm lines are: { quantity, unit_price, vatCode, account_code, description, itemName }
  const rawIncomeLines = (invoice.lines || [])
    .map((ln) => {
      const qty = Number(ln.quantity ?? ln.qty ?? 0) || 0;
      const unitPrice = Number(ln.unit_price ?? ln.unitPrice ?? 0) || 0;
      const netAmount = Math.max(0, qty * unitPrice);

      const incomeAccount =
        String(ln.account_code || ln.incomeAccount || fallbackIncome).trim();

      const memo = `Invoice ${invoice.number || invoice.id || ""} - ${
        (ln.description || ln.itemName || "").trim()
      }`.trim();

      // Drop empty
      if (!netAmount) return null;

      return {
        account: incomeAccount,
        debit: 0,
        credit: netAmount,       // NET
        memo,
        section: "income",
        vatEnabled: !!invoice.vat_enabled,
        vatMode: "exclusive",
        vatRate: vatRateFromCode(ln.vatCode),
      };
    })
    .filter(Boolean);

  if (!rawIncomeLines.length) {
    throw new Error("Invoice has no valid lines to post.");
  }

  // ✅ Apply header discount by proportional reduction across income lines (keeps multi-income split)
  // Note: this reduces VAT too (because VAT is expanded after this).
  const netBefore = rawIncomeLines.reduce((s, l) => s + (Number(l.credit) || 0), 0);
  const disc = Math.max(0, headerDiscount);

  const incomeLines = rawIncomeLines.map((l) => {
    if (disc <= 0 || netBefore <= 0) return l;
    const share = (Number(l.credit) || 0) / netBefore;
    const discAlloc = disc * share;
    const newCredit = Math.max(0, (Number(l.credit) || 0) - discAlloc);
    return { ...l, credit: newCredit };
  });

  // ✅ Add "other charges" as extra income (optional)
  // If you have a dedicated account, replace fallbackIncome with that.
  if (headerOther > 0) {
    incomeLines.push({
      account: fallbackIncome,
      debit: 0,
      credit: headerOther,
      memo: `Invoice ${invoice.number || invoice.id || ""} - other charges`.trim(),
      section: "income",
      vatEnabled: !!invoice.vat_enabled,
      vatMode: "exclusive",
      vatRate: 0,
    });
  }

  const netTotal = incomeLines.reduce((s, l) => s + (Number(l.credit) || 0), 0);

  // ✅ Expand VAT from income lines
  const vatCfg = buildVatConfigFromCoa?.() || {};
  const expanded = expandVatForBatch?.(incomeLines, vatCfg) || {};
  const expandedLines = Array.isArray(expanded.lines) ? expanded.lines : incomeLines;
  const vatTotal = Number(expanded.vatTotal || 0) || 0;

  const grossInclVat = netTotal + vatTotal;

  // ✅ Add AR control line using GROSS
  expandedLines.push({
    account: arCode,
    debit: grossInclVat,
    credit: 0,
    memo: `Invoice ${invoice.number || invoice.id || ""} - AR control`.trim(),
    section: "asset",
    vatEnabled: false,
    vatMode: "none",
    vatRate: 0,
  });

  // ✅ Journal payload
  const payload = {
    date: entryDate,
    ref: invoice.number || null,
    description: invoice.customer_name || invoice.customerName || "Invoice",
    gross_amount: grossInclVat,
    net_amount: netTotal,
    vat_amount: vatTotal,
    lines: expandedLines.map((ln) => ({
      account_code: String(ln.account),
      debit: Number(ln.debit || 0) || 0,
      credit: Number(ln.credit || 0) || 0,
      description: ln.memo || "",
    })),
  };

  // ✅ Post journal
  await postJournalEntry(payload);

  // ✅ Optionally mark invoice as posted
  //if (invoice.id && typeof ENDPOINTS?.invoiceMarkPosted === "function") {
   // await apiFetch(ENDPOINTS.invoiceMarkPosted(cid, invoice.id), { method: "POST" });
 // }

  alert("Invoice posted to journal ✅");
}

// Make invoice form read-only for reviewers based on control mode + role
function lockInvoiceFormForReviewers(status = "", invoiceId = 0, mode = "edit") {
  const cid = window.getActiveCompanyId?.() || window.CURRENT_COMPANY_ID || 1;

  // ✅ Single-owner: never lock (fast)
  if (window.FS?.control?.isOwnerManaged?.(cid)) return;

  const roleRaw =
    (typeof getCurrentRole === "function" ? getCurrentRole() : (getCurrentUserRole?.() || "")) || "";
  const role = window.FS?.role?.normalize ? FS.role.normalize(roleRaw) : String(roleRaw).toLowerCase();

  const st = String(status || "").toLowerCase();

  // ✅ Lock only when editing an existing draft-ish invoice (not when creating new)
  const isExisting = Number(invoiceId) > 0 && mode !== "new";
  const isDraftish = ["draft", "pending", "submitted", "review"].includes(st);

  if (!isExisting || !isDraftish) return;

  // --- Decide who can edit in review modes ---
  const isApprover = !!window.FS?.policy?.canApproveInvoice?.(role, cid);

  // ASSISTED: allow most non-clerks to edit (you can tighten if you want)
  if (FS.control.isAssisted(cid)) {
    // Only clerks should be locked, others can still edit
    const shouldLock = (role === "clerk");
    applyInvoiceLockUI(shouldLock);
    return;
  }

  // CONTROLLED: only approvers can edit; everyone else locked
  if (FS.control.isControlled(cid)) {
    const shouldLock = !isApprover;
    applyInvoiceLockUI(shouldLock);
    return;
  }

  // fallback
  applyInvoiceLockUI(false);

  // --- helper ---
  function applyInvoiceLockUI(shouldLock) {
    // ✅ ensure we actually find the invoice screen
    const scope =
      document.getElementById("screen-ar") ||
      document.getElementById("screen-ar-invoices") ||
      document.querySelector("#screen-ar .invoice") ||
      document.querySelector("#invoiceForm") ||
      document; // fallback

    // ✅ align global behaviour with UI
    window._INV_TOTALS_LOCKED = true;
    window._INV_REVIEW_MODE = !!shouldLock;

    const fields = scope.querySelectorAll("input, textarea, select, button");

    fields.forEach((el) => {
      // keep approve/send clickable (policy should still gate server-side)
      if (el.id === "invApprove" || el.id === "invSend") return;

      // disable recalc in review mode
      if (el.id === "invRecalc") {
        el.disabled = true;
        el.classList.toggle("opacity-60", true);
        el.classList.toggle("cursor-not-allowed", true);
        return;
      }

      // Draft button rule
      if (el.id === "invSaveDraft") {
        el.disabled = shouldLock;
        el.classList.toggle("opacity-60", shouldLock);
        el.classList.toggle("cursor-not-allowed", shouldLock);
        return;
      }

      el.disabled = shouldLock;
      el.classList.toggle("bg-slate-100", shouldLock);
      el.classList.toggle("cursor-not-allowed", shouldLock);
      el.classList.toggle("opacity-60", shouldLock);
    });
  }
}

function confirmCreditOverrideModal({ customerName, limit, current, invoice, projected }) {
  return new Promise((resolve) => {
    let host = document.getElementById("fsModalHost");
    if (!host) {
      host = document.createElement("div");
      host.id = "fsModalHost";
      document.body.appendChild(host);
    }

    host.innerHTML = `
      <div style="position:fixed; inset:0; background:rgba(0,0,0,.35); display:flex; align-items:center; justify-content:center; z-index:9999;">
        <div class="card p-3" style="width:min(560px, 92vw);">
          <div style="font-weight:800; color:var(--fs-navy); font-size:16px;">Credit limit exceeded</div>
          <div style="margin-top:6px; color:var(--fs-muted); font-size:12px;">
            Customer: <b>${esc(customerName)}</b>
          </div>

          <div style="margin-top:10px; display:grid; grid-template-columns:1fr 1fr; gap:10px;">
            <div class="pill">Limit: <b>${money(limit)}</b></div>
            <div class="pill">Current: <b>${money(current)}</b></div>
            <div class="pill">Invoice: <b>${money(invoice)}</b></div>
            <div class="pill">Projected: <b>${money(projected)}</b></div>
          </div>

          <div style="margin-top:12px; display:flex; gap:10px; justify-content:flex-end;">
            <button id="btnCreditCancel" class="btn">Cancel</button>
            <button id="btnCreditProceed" class="btn btn-highlight">Proceed anyway</button>
          </div>
        </div>
      </div>
    `;

    host.querySelector("#btnCreditCancel").onclick = () => { host.innerHTML = ""; resolve(false); };
    host.querySelector("#btnCreditProceed").onclick = () => { host.innerHTML = ""; resolve(true); };
  });
}

async function renderPostedInvoiceList() {
  const cid = getActiveCompanyId?.() || window.CURRENT_COMPANY_ID;
  const host = document.getElementById("postedInvoiceList");
  if (!cid || !host) return;

  host.innerHTML = `<div class="text-xs text-slate-400">Loading…</div>`;

  try {
    // only posted invoices
    const data = await apiFetch(
      `${ENDPOINTS.invoices(cid)}?status=posted`
    );

    const rows = Array.isArray(data)
      ? data
      : (data.invoices || data.items || []);

    if (!rows.length) {
      host.innerHTML = `<div class="text-xs text-slate-400">No posted invoices</div>`;
      return;
    }

    host.innerHTML = rows.map(inv => {
      const id   = inv.id;
      const num  = inv.number || `INV-${id}`;
      const cust = inv.customer_name || "Unnamed Customer";
      const dt   = inv.invoice_date || "";

      return `
        <button
          type="button"
          class="w-full text-left p-2 border rounded hover:bg-slate-50"
          data-posted-inv="${id}"
        >
          <div class="font-medium">${esc(cust)}</div>
          <div class="text-xs text-slate-500">
            #${esc(num)} • ${esc(dt)}
          </div>
        </button>
      `;
    }).join("");

    host.querySelectorAll("[data-posted-inv]").forEach(btn => {
      btn.addEventListener("click", async () => {
        const id = Number(btn.dataset.postedInv);
        if (!id) return;
        await openInvoiceViewer?.(id);
      });
    });

  } catch (err) {
    console.error(err);
    host.innerHTML =
      `<div class="text-xs text-red-500">Failed to load posted invoices</div>`;
  }
}

window.renderPostedInvoiceList = renderPostedInvoiceList; 

/**
 * Post an invoice while respecting policy + approval flow.
 * FIXES:
 * 1) Reads invoice GET response correctly when backend wraps as {ok,data}
 * 2) Treats 202 (queued) as NOT posted yet → polls until status becomes "posted"
 * 3) Only refreshes cashflow/TB after it is truly posted
 */
async function postInvoiceAccordingToPolicy(invoiceId) {
  const cid = window.getActiveCompanyId?.() || window.CURRENT_COMPANY_ID;
  if (!cid) throw new Error("No active company.");

  const roleRaw = (typeof getCurrentRole === "function") ? getCurrentRole() : "";
  const role = window.FS?.role?.normalize ? FS.role.normalize(roleRaw) : String(roleRaw || "").toLowerCase();

  const autoPosts  = !!window.FS?.policy?.invoiceAutoPosts?.(cid); // true = no review required
  const canApprove = !!window.FS?.policy?.canApproveInvoice?.(role, cid);

  const canPost =
    typeof window.FS?.policy?.canPostInvoice === "function"
      ? !!window.FS.policy.canPostInvoice(role, cid)
      : (canApprove || role === "owner");

  // -----------------------------
  // Helper: unwrap {ok,data} API shape safely
  // -----------------------------
  const unwrap = (x) => (x && typeof x === "object" && "data" in x) ? (x.data || {}) : (x || {});

  // -----------------------------
  // Helper: fetch invoice (unwrapped)
  // -----------------------------
  async function fetchInvoice() {
    const wrap = await apiFetch(ENDPOINTS.invoice(cid, invoiceId), { method: "GET" });
    return unwrap(wrap);
  }

  // -----------------------------
  // Helper: poll until invoice.status === "posted"
  // (handles backend returning 202 Accepted / queued)
  // -----------------------------
  async function waitForPosted({ maxMs = 15000, intervalMs = 500 } = {}) {
    const deadline = Date.now() + maxMs;

    while (Date.now() < deadline) {
      await new Promise((r) => setTimeout(r, intervalMs));
      const inv = await fetchInvoice();
      const st = String(inv?.status || "").toLowerCase();

      if (st === "posted") return inv;

      // optional: if you have an explicit failure status
      if (st === "failed" || st === "error") {
        throw new Error("Posting failed on server. Check job logs.");
      }
    }

    // still not posted after polling window
    throw new Error("Posting queued but invoice never became POSTED. Worker/job may be down.");
  }

  // -----------------------------
  // If review is required and user can't approve/post: submit to approval inbox
  // -----------------------------
  if (!autoPosts && (!canApprove || !canPost)) {
    const res = await apiFetch(ENDPOINTS.invoiceSubmit(cid, invoiceId), {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({}),
    });

    await renderDraftInvoiceList?.();
    await renderPostedInvoiceList?.();

    showToast?.("Sent to Approvals inbox.");
    return res;
  }

  // If no review required, still enforce canPost
  if (!canPost) throw new Error("You are not allowed to post invoices.");

  // -----------------------------
  // OPTIONAL: Credit check gate
  // -----------------------------
  const inv0 = await fetchInvoice(); // ✅ correct shape
  const customerId = inv0?.customer_id || inv0?.customerId || null;
  const amount = Number(inv0?.total_amount || inv0?.total || inv0?.gross_amount || inv0?.totalAmount || 0);

  const isOwner = role === "owner";
  const canOverride = isOwner || role === "cfo" || role === "admin";

  if (customerId && amount > 0 && ENDPOINTS?.ar?.creditCheck) {
    const asAt = (document.getElementById("invDate")?.value || "").slice(0, 10) || null;

    let check = null;
    try {
      check = await apiFetch(ENDPOINTS.ar.creditCheck(cid, customerId, amount, asAt), { method: "GET" });
      check = unwrap(check);
    } catch (e) {
      console.warn("creditCheck failed (skipping UI warning):", e);
    }

    if (check && check.ok === true) {
      if (check.blocked) {
        if (!canOverride) {
          throw new Error(
            `Credit limit exceeded. Limit: ${money(check.limit)} | Current: ${money(check.current)} | Projected: ${money(check.projected)}`
          );
        }

        const ok = await confirmCreditOverrideModal({
          customerName: check.customer_name || String(customerId),
          limit: check.limit,
          current: check.current,
          invoice: check.invoice,
          projected: check.projected,
        });

        if (!ok) return; // cancelled
      } else if (check.warning) {
        showToast?.(`Credit usage: projected ${money(check.projected)} of ${money(check.limit)}`);
      }
    }
  }

  // -----------------------------
  // Post (backend may return 202 queued)
  // -----------------------------
  const postResWrap = await apiFetch(`${ENDPOINTS.invoice(cid, invoiceId)}/post`, { method: "POST" });
  const postRes = unwrap(postResWrap);

  // If backend returns 200 with already-posted invoice, accept it
  const immediateStatus = String(postRes?.status || "").toLowerCase();
  let finalInv = null;

  if (immediateStatus === "posted") {
    finalInv = postRes;
  } else {
    // ✅ queued / async → poll the invoice until status flips
    showToast?.("Posting queued… confirming posting.");
    finalInv = await waitForPosted({ maxMs: 15000, intervalMs: 500 });
  }

  // -----------------------------
  // Refresh UI AFTER true post
  // -----------------------------
  await renderDraftInvoiceList?.();
  await renderPostedInvoiceList?.();
  await renderCashFlow?.(CURRENT_PERIOD_KEY);

  // If you have these screens/functions, uncomment:
  // await renderTrialBalance?.(CURRENT_PERIOD_KEY);
  // await renderLedger?.(CURRENT_PERIOD_KEY);

  showToast?.("Invoice posted ✅");

  // return the truly posted invoice
  return { ok: true, data: finalInv, post_response: postResWrap };
}

// expose if needed
window.postInvoiceAccordingToPolicy = postInvoiceAccordingToPolicy;

function bindInvoicePostingUI() {
  const btnDraft   = document.getElementById("invSaveDraft");
  const btnApprove = document.getElementById("invApprove"); // will act as Request Approval for makers
  const btnSend    = document.getElementById("invSend");
  const btnPost    = document.getElementById("invPost");    // optional: if you keep a separate Post button

  // If AR screen not mounted yet
  if (!btnDraft && !btnApprove && !btnSend && !btnPost) return;

  // ✅ Due date UI should be bound ASAP (once elements exist)
  bindInvoiceDueDateUI?.();
  syncInvoiceDueDateLabel?.();

  // helper: refresh buttons (single source of truth)
  const refreshButtons = () => {
    if (typeof updateInvoiceActionButtons === "function") updateInvoiceActionButtons();
    else if (typeof applyInvoiceButtonsByMode === "function") applyInvoiceButtonsByMode();
  };

  // helper: decide if current user is approver
  function getInvoiceRoleContext() {
    const cid = FS.control.resolveCid();
    const mode = FS.control.get(cid);
    const role = FS.role.normalize(getCurrentRole?.() || "");
    const canApprove = !!FS.policy.canApproveInvoice(role, cid);
    return { cid, mode, role, canApprove };
  }

  // ---------------------------
  // Draft button: always calls commitInvoice("draft")
  // (commitInvoice itself enforces clerk-only in assisted/controlled)
  // ---------------------------
  if (btnDraft && btnDraft.dataset.bound !== "1") {
    btnDraft.dataset.bound = "1";
    btnDraft.type = "button";
    btnDraft.addEventListener("click", async (e) => {
      e.preventDefault();
      try {
        // NEW: makers submit for approval using Save Draft button
        const res = await commitInvoice("submit_for_approval");
        // draft saved → you can reset or keep open; keeping your behavior:
        resetInvoiceForm();
        await renderDraftInvoiceList?.();
        return res;
      } catch (err) {
        console.error("Draft error:", err);
        alert(err.message || "Could not save draft.");
      } finally {
        refreshButtons();
      }
    });
  }

  // ---------------------------
  // Approve button:
  // - If maker => Request approval (commitInvoice("approve_post") will send to inbox)
  // - If approver => Post immediately (commitInvoice("approve_post") posts)
  // So we keep one call, but update label + UX
  // ---------------------------
  if (btnApprove && btnApprove.dataset.bound !== "1") {
    btnApprove.dataset.bound = "1";
    btnApprove.type = "button";
    btnApprove.addEventListener("click", async (e) => {
      e.preventDefault();
      try {
        const { canApprove, mode } = getInvoiceRoleContext();

        const res = await commitInvoice("approve_post");

        // If maker route: sent_to_inbox (do NOT render cashflow yet, nothing posted)
        if (res?.flow === "sent_to_inbox") {
          // optional: keep invoice open; but you currently reset → ok
          resetInvoiceForm();
          await renderDraftInvoiceList?.();
          alert("Sent to Approvals inbox. Awaiting review.");
          return;
        }

        // If approver route: posted
        if (res?.flow === "post") {
          await renderCashFlow?.(CURRENT_PERIOD_KEY);
          resetInvoiceForm();
          await renderDraftInvoiceList?.();
          alert("Invoice posted ✅");
          return;
        }

        // fallback
        resetInvoiceForm();
        await renderDraftInvoiceList?.();
        return res;

      } catch (err) {
        console.error("Approve/Request error:", err);
        alert(err.message || "Could not request approval / post invoice.");
      } finally {
        refreshButtons();
      }
    });
  }

  // ---------------------------
  // Send button:
  // - Only makes sense if invoice ends up POSTED
  // - Makers should NOT send (they can request approval; approver sends after post)
  // ---------------------------
  if (btnSend && btnSend.dataset.bound !== "1") {
    btnSend.dataset.bound = "1";
    btnSend.type = "button";
    btnSend.addEventListener("click", async (e) => {
      e.preventDefault();
      try {
        const { canApprove, mode } = getInvoiceRoleContext();

        if (!canApprove && mode !== FS.control.MODES.OWNER) {
          // maker: don’t allow sending; they can request approval instead
          alert("You can’t send invoices in review mode. Request approval first.");
          return;
        }

        const before = parseInt(document.getElementById("invId")?.value || "0", 10) || 0;

        const res = await commitInvoice("approve_post");
        if (res?.flow !== "post") {
          alert("Invoice was not posted, so it can’t be sent yet.");
          return;
        }

        const after = parseInt(document.getElementById("invId")?.value || "0", 10) || before;
        if (!after) throw new Error("Invoice ID missing, cannot send email.");

        await sendInvoiceEmail(after);

        resetInvoiceForm();
        await renderDraftInvoiceList?.();
        alert("Invoice sent ✅");

      } catch (err) {
        console.error("Send error:", err);
        alert(err.message || "Could not post/send invoice.");
      } finally {
        refreshButtons();
      }
    });
  }

  // ---------------------------
  // Optional: separate Post button if you want it
  // (only visible for approvers via updateInvoiceActionButtons)
  // ---------------------------
  if (btnPost && btnPost.dataset.bound !== "1") {
    btnPost.dataset.bound = "1";
    btnPost.type = "button";
    btnPost.addEventListener("click", async (e) => {
      e.preventDefault();
      try {
        const { canApprove, mode } = getInvoiceRoleContext();
        if (!canApprove && mode !== FS.control.MODES.OWNER) {
          alert("You’re not allowed to post. Request approval instead.");
          return;
        }
        const res = await commitInvoice("approve_post");
        if (res?.flow === "post") {
          await renderCashFlow?.(CURRENT_PERIOD_KEY);
          resetInvoiceForm();
          await renderDraftInvoiceList?.();
        }
      } catch (err) {
        console.error("Post error:", err);
        alert(err.message || "Could not post invoice.");
      } finally {
        refreshButtons();
      }
    });
  }

  // ✅ On initial bind, keep form editable (new invoice)
  lockInvoiceFormForReviewers?.("", 0, "new");

  // ✅ Set correct enabled/disabled state NOW
  refreshButtons();

  bindInvoiceViewPrint?.();
}

async function sendInvoiceEmail(invoiceOrId) {
  const cid = getActiveCompanyId();
  if (!cid) throw new Error("No active company.");

  if (!ENDPOINTS.invoiceEmail) return;

  const invoiceId =
    typeof invoiceOrId === "object" ? invoiceOrId?.id : invoiceOrId;

  if (!invoiceId) throw new Error("No invoice id for email.");

  const res = await apiFetch(ENDPOINTS.invoiceEmail(cid, invoiceId), {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ cc_role: "cfo" }),
  });

  if (res?.error) throw new Error(res.error);
  return res;
}


async function fetchDraftInvoices() {
  const cid = getActiveCompanyId();
  if (!cid) return [];

  return await apiFetch(`${ENDPOINTS.invoices(cid)}?status=draft`);
}

async function renderDraftInvoiceList() {
  const cid = (typeof getActiveCompanyId === "function")
    ? getActiveCompanyId()
    : (window.getActiveCompanyId?.() || window.CURRENT_COMPANY_ID);

  const host = document.getElementById("draftInvoiceList");
  if (!cid || !host) return;

  host.innerHTML = `<div class="text-xs text-slate-400">Loading…</div>`;

  try {
    let resp;
    try {
      resp = await apiFetch(`${ENDPOINTS.invoices(cid)}?status=draft,pending_approval`);
    } catch (e) {
      // (only works if backend supports repeated status args)
      resp = await apiFetch(`${ENDPOINTS.invoices(cid)}?status=draft&status=pending_approval`);
    }

    // ✅ unwrap ALL common apiFetch shapes
    const payload =
      (resp && typeof resp === "object" && ("data" in resp)) ? resp.data :
      (resp && typeof resp === "object" && ("rows" in resp)) ? resp.rows :
      (resp && typeof resp === "object" && Array.isArray(resp.invoices)) ? resp.invoices :
      resp;

    const invoicesRaw = Array.isArray(payload) ? payload : [];
    const invoices = invoicesRaw.map(normalizeInvoiceFromApi);

    if (!invoices.length) {
      host.innerHTML = `<div class="text-xs text-slate-400">No drafts</div>`;
      return;
    }

    host.innerHTML = invoices.map(inv => {
      const st = String(inv.status || "").toLowerCase();
      const badge =
        st === "pending_approval"
          ? `<span class="ml-2 text-[10px] px-2 py-[2px] rounded bg-amber-50 text-amber-700 border border-amber-200">Pending</span>`
          : `<span class="ml-2 text-[10px] px-2 py-[2px] rounded bg-slate-50 text-slate-600 border border-slate-200">Draft</span>`;

      return `
        <button
          type="button"
          class="w-full text-left p-2 border rounded hover:bg-slate-50"
          data-inv-id="${inv.id}"
        >
          <div class="font-medium flex items-center">
            <span>${inv.customer_name || "Unnamed Customer"}</span>
            ${badge}
          </div>
          <div class="text-xs text-slate-500">
            #${inv.number || "Draft"} • ${inv.invoice_date || ""}
          </div>
        </button>
      `;
    }).join("");

    host.querySelectorAll("[data-inv-id]").forEach(btn => {
      btn.addEventListener("click", async () => {
        const id = parseInt(btn.dataset.invId, 10);
        await openInvoiceIntoForm(id, { mode: "edit" });
      });
    });

  } catch (err) {
    console.error(err);
    host.innerHTML = `<div class="text-xs text-red-500">Failed to load drafts</div>`;
  }
}

async function openInvoiceIntoForm(invoiceId, { mode = "view" } = {}) {
  const cid = getActiveCompanyId?.() || companyId?.();
  if (!cid) throw new Error("No active company.");

  const $ = (id) => document.getElementById(id);

  const modeNorm = String(mode || "view").toLowerCase();
  const isReview = ["view", "review", "approve"].includes(modeNorm);

  window._INV_LOADING = true;
  window._INV_TOTALS_LOCKED = isReview;
  window._INV_REVIEW_MODE = isReview;

  function applyVatColumnsVisibility() {
    const enabled = !!document.getElementById("invVatEnabled")?.checked;
    document.querySelectorAll(".vat-col").forEach((col) => {
      col.style.display = enabled ? "" : "none";
    });
    return enabled;
  }

  // ensure addLine + recalc exist
  if (typeof window.addLine !== "function") bindAR();

  if (!Array.isArray(window.REVENUE_ACCOUNTS_CACHE) || !window.REVENUE_ACCOUNTS_CACHE.length) {
    await loadRevenueAccountsForInvoice?.();
  }

  const raw = await apiFetch(`${ENDPOINTS.invoices(cid)}/${invoiceId}`, { method: "GET" });
  const inv = normalizeInvoiceFromApi(raw);

  function paintBackendTotals() {
    const sub = Number(inv.subtotal_amount ?? 0) || 0;
    const vat = Number(inv.vat_amount ?? 0) || 0;
    const tot = Number(inv.total ?? 0) || 0;

    $("sumSubtotal") && ($("sumSubtotal").textContent = sub.toFixed(2));
    $("sumVat") && ($("sumVat").textContent = vat.toFixed(2));
    $("sumTotal") && ($("sumTotal").textContent = tot.toFixed(2));

    const discAmt = Number(inv.discount_amount ?? 0) || 0;
    $("sumDiscount") && ($("sumDiscount").textContent = discAmt.toFixed(2));
    $("sumDiscountWrap") && ($("sumDiscountWrap").style.display = discAmt > 0 ? "" : "none");
  }

  // -------- header --------
  $("invId") && ($("invId").value = inv.id || "");
  $("invCustomerName") && ($("invCustomerName").value = inv.customer_name || "");
  $("invCustomerId") && ($("invCustomerId").value = inv.customer_id ? String(inv.customer_id) : "");

  $("invNumber") && ($("invNumber").value = inv.number || "");
  $("invDate") && ($("invDate").value = toIsoDateOnly(inv.invoice_date));
  $("invDueDate") && ($("invDueDate").value = toIsoDateOnly(inv.due_date));
  $("invTerms") && ($("invTerms").value = inv.terms || "Due on receipt");
  $("invCurrency") && ($("invCurrency").value = inv.currency || "ZAR");

  $("invDefaultVat") && ($("invDefaultVat").value = inv.default_vat_code || "STANDARD");

  // ✅ VAT checkbox: decide from payload (only set checkbox here)
  const vatCheckbox = $("invVatEnabled");

  const headerVat = Number(inv.vat_amount ?? 0) || 0;
  const linesVat = (inv.lines || []).reduce((s, ln) => s + (Number(ln.vat_amount ?? 0) || 0), 0);
  const hasVat = (headerVat > 0.000001) || (linesVat > 0.000001);

  const vatEnabledFromPayload =
    inv.vat_enabled === true ||
    (inv.vat_enabled == null && hasVat);

  if (vatCheckbox) {
    vatCheckbox.checked = vatEnabledFromPayload;
    vatCheckbox.disabled = isReview;
  }

  // ✅ Discount input is ALWAYS PERCENT in UI
  if ($("invDisc")) {
    const rate = Number(inv.discount_rate ?? 0) || 0;
    $("invDisc").value = String((rate * 100) || 0);
    $("invDisc").readOnly = isReview;
  }

  if ($("invOther")) {
    $("invOther").value = String(inv.other ?? 0);
    $("invOther").readOnly = isReview;
  }

  $("invMemo") && ($("invMemo").value = inv.notes || "");

  if ($("invoiceBankAccount") && inv.bank_account_id) {
    $("invoiceBankAccount").value = String(inv.bank_account_id);
  }

  if ($("invRevenueAccount")) {
    const headerRev = String(inv.revenue_account_code || "").trim();
    if (headerRev) $("invRevenueAccount").value = headerRev;
    $("invRevenueAccount").disabled = isReview;
  }

  $("invStatus") && ($("invStatus").textContent = inv.status || "draft");

  // -------- lines --------
  const tbody = document.querySelector("#invLines");
  if (tbody) tbody.innerHTML = "";

  (inv.lines || []).forEach((ln) => {
    window.addLine({
      itemName: ln.itemName || "",
      description: ln.description || "",
      quantity: ln.quantity ?? 1,
      unit_price: ln.unit_price ?? 0,
      vatCode: ln.vatCode || "STANDARD",
      account_code: ln.account_code || "",
      revenue_obligation_id: ln.revenue_obligation_id || null,
      vat_amount: ln.vat_amount,
      total_amount: ln.total_amount,
    });
  });

  // ✅ show/hide VAT columns ONCE (after rows exist)
  applyVatColumnsVisibility();

  // ✅ totals
  if (isReview) {
    paintBackendTotals();
    setTimeout(paintBackendTotals, 0);
    setTimeout(paintBackendTotals, 50);
  } else {
    window._INV_TOTALS_LOCKED = false;
    window.recalcInvoice?.({ force: true });
  }

  window._INV_LOADING = false;

  if (typeof lockInvoiceFormForReviewers === "function") {
    lockInvoiceFormForReviewers(inv.status, inv.id, modeNorm);
  }
}
window.openInvoiceIntoForm = openInvoiceIntoForm;


function normalizeInvoiceFromApi(raw) {
  // ✅ unwrap {ok:true, data:{...}} OR accept direct invoice payload
  const inv = (raw && typeof raw === "object" && raw.data && typeof raw.data === "object")
    ? raw.data
    : (raw || {});

  const toStr = (v) => (v === null || v === undefined ? "" : String(v));

  const toNum = (v, d = 0) => {
    const s = String(v ?? "").replace(/,/g, "").trim();
    if (s === "") return d;
    const n = Number(s);
    return Number.isFinite(n) ? n : d;
  };

  const upper = (v, d = "") => toStr(v || d).trim().toUpperCase();
  const trim  = (v) => toStr(v).trim();

  // ✅ VAT enabled (tri-state)
  const vatEnabledRaw = inv.vat_enabled ?? inv.vatEnabled ?? inv.vat;
  const vat_enabled =
    vatEnabledRaw === true ? true :
    vatEnabledRaw === false ? false :
    null;

  // ✅ pick lines from any backend shape
  const rawLines = Array.isArray(inv.lines)
    ? inv.lines
    : Array.isArray(inv.invoice_lines)
      ? inv.invoice_lines
      : Array.isArray(inv.items)
        ? inv.items
        : [];

  // ✅ totals (support both "total" and "total_amount")
  const subtotal_amount = toNum(inv.subtotal_amount ?? inv.subtotalAmount, 0);
  const vat_amount      = toNum(inv.vat_amount ?? inv.vatAmount, 0);
  const total_amount    = toNum(
    inv.total_amount ?? inv.totalAmount ?? inv.total ?? inv.total,
    0
  );

  // ✅ payment totals (prefer your SQL fields)
  const paid_amount = toNum(
    inv.paid_amount ??
    inv.paidAmount ??
    inv.amount_paid ??
    inv.amountPaid ??
    inv.allocated,
    0
  );

  // IMPORTANT:
  const outstanding_amount = (() => {
    const direct = toNum(
      inv.outstanding_amount ??
      inv.outstandingAmount ??
      inv.amount_due ??
      inv.amountDue ??
      inv.balance_due ??
      inv.balanceDue ??
      inv.outstanding,
      NaN
    );

    const inferred = Math.max(0, total_amount - paid_amount);

    // If backend didn't provide it, infer it
    if (!Number.isFinite(direct)) return inferred;

    // ✅ sanity checks (protect UI from bad backend fields)
    // 1) outstanding can't be bigger than total
    if (direct > total_amount + 0.00001) return inferred;

    // 2) if invoice is partially paid and direct equals paid, it's likely wrong
    if (
      paid_amount > 0.00001 &&
      paid_amount < total_amount - 0.00001 &&
      Math.abs(direct - paid_amount) < 0.00001
    ) {
      return inferred;
    }

    return Math.max(0, direct);
  })();

  // ✅ payment status (prefer backend computed field; else derive)
  const payment_status_raw = trim(inv.payment_status ?? inv.paymentStatus ?? "").toLowerCase();

  const payment_status = (() => {
    if (payment_status_raw) return payment_status_raw;

    const st = trim(inv.status ?? "").toLowerCase();
    if (st === "void") return "void";
    if (st === "written_off" || st === "written off") return "written_off";

    if (outstanding_amount <= 0.00001) return "paid";
    if (paid_amount > 0.00001) return "partial";
    return "unpaid";
  })();

  // ✅ discount (keep BOTH rate + amount)
  const discount_rate   = toNum(inv.discount_rate ?? inv.discountRate, 0);
  const discount_amount = toNum(inv.discount_amount ?? inv.discountAmount, 0);

  return {
    id: inv.id ?? null,

    customer_id: inv.customer_id ?? inv.customerId ?? null,
    customer_name: inv.customer_name ?? inv.customerName ?? "",

    customer_email: inv.customer_email ?? inv.customerEmail ?? "",
    customer_phone: inv.customer_phone ?? inv.customerPhone ?? "",
    customer_billing_address:
      inv.customer_billing_address ??
      inv.customer_address ??
      inv.billing_address ??
      "",
    customer_shipping_address:
      inv.customer_shipping_address ??
      inv.shipping_address ??
      "",

    customer_balance: toNum(
      inv.customer_balance ??
      inv.customerBalance ??
      inv.ar_balance ??
      inv.arBalance,
      0
    ),
    customer_open_invoices: toNum(
      inv.customer_open_invoices ??
      inv.customerOpenInvoices ??
      inv.open_invoices ??
      inv.openInvoices,
      0
    ),

    activity: Array.isArray(inv.activity) ? inv.activity : [],

    number: inv.number ?? "",

    invoice_date: toIsoDateOnly(inv.invoice_date ?? inv.invoiceDate ?? inv.date),
    due_date:     toIsoDateOnly(inv.due_date ?? inv.dueDate),

    terms: inv.terms ?? "Due on receipt",
    currency: inv.currency ?? "ZAR",

    vat_enabled,
    default_vat_code: upper(inv.default_vat_code ?? inv.defaultVatCode, "STANDARD"),

    // ✅ keep BOTH
    discount_rate,
    discount_amount,
    // legacy alias (amount)
    discount: discount_amount,

    other: toNum(inv.other ?? inv.other_charges ?? inv.otherCharges, 0),

    notes: inv.notes ?? inv.memo ?? "",

    bank_account_id: inv.bank_account_id ?? inv.bankAccountId ?? null,
    revenue_account_code: trim(inv.revenue_account_code ?? inv.revenueAccountCode ?? ""),

    // statuses
    status: trim(inv.status ?? "draft"),

    // totals
    subtotal_amount,
    vat_amount,
    total: total_amount,              // keep your existing key "total"
    total_amount: total_amount,       // ALSO expose explicit (helps other screens)

    // ✅ payment fields for viewer + list chips
    paid_amount,
    outstanding_amount,
    payment_status,

    // ✅ normalized lines
    lines: rawLines.map((ln) => {
      const vatRate = toNum(ln.vat_rate ?? ln.vatRate, 0);

      let vatCode = ln.vat_code ?? ln.vatCode ?? ln.vat ?? null;
      if (!vatCode) vatCode = vatRate === 15 ? "STANDARD" : "ZERO";

      const unit = toNum(ln.unit_price ?? ln.unitPrice ?? ln.price, 0);

      return {
        itemName: toStr(ln.item_name ?? ln.itemName ?? ln.item ?? ln.service ?? ""),
        description: toStr(ln.description ?? ln.desc ?? ln.memo ?? ""),
        quantity: toNum(ln.quantity ?? ln.qty, 1),

        unit_price: unit,
        unitPrice: unit,

        vat_rate: vatRate,
        vatCode: upper(vatCode, "STANDARD"),

        account_code: trim(
          ln.account_code ??
          ln.accountCode ??
          ln.revenue_account_code ??
          ln.revenueAccountCode ??
          ""
        ),

        discount_amount: toNum(ln.discount_amount ?? ln.discountAmount, 0),
        net_amount:      toNum(ln.net_amount ?? ln.netAmount, 0),
        vat_amount:      toNum(ln.vat_amount ?? ln.vatAmount, 0),
        total_amount:    toNum(ln.total_amount ?? ln.totalAmount, 0),
      };
    }),
  };
}

function toIsoDateOnly(v) {
  if (!v) return "";

  // already ISO date or ISO timestamp
  if (typeof v === "string" && /^\d{4}-\d{2}-\d{2}/.test(v)) {
    return v.slice(0, 10);
  }

  // parse "Fri, 28 Feb 2025 00:00:00 GMT" etc
  const d = new Date(v);
  if (!Number.isNaN(d.getTime())) return d.toISOString().slice(0, 10);

  return "";
}

// Use NEXT NUMBER endpoint ONLY when user is actually committing the invoice.
async function ensureInvoiceNumberOnCommit() {
  const cid = getActiveCompanyId?.();
  if (!cid) throw new Error("No active company.");

  const invId = parseInt(document.getElementById("invId")?.value || "0", 10);
  if (invId) return; // already saved invoice, number should exist

  const el = document.getElementById("invNumber");
  if (!el) throw new Error("Invoice number field not found.");

  // If already filled (maybe user typed manually), do nothing
  if (String(el.value || "").trim()) return;

  // ✅ Allocate ONLY now (consumes a number)
  const res = await apiFetch(ENDPOINTS.invoiceNextNumber(cid));
  if (res?.number) {
    el.value = res.number;
    return;
  }

  throw new Error("Could not allocate invoice number.");
}

window._INV_TOTALS_LOCKED = false;

function toISODateInput(v) {
  if (!v) return "";
  const s = String(v);

  // Already ISO-ish
  if (/^\d{4}-\d{2}-\d{2}/.test(s)) return s.slice(0, 10);

  // Try Date parsing (works for: "Tue, 06 May 2025 00:00:00 GMT")
  const d = new Date(s);
  if (!Number.isNaN(d.getTime())) return d.toISOString().slice(0, 10);

  return "";
}

function setSelectIfOptionExists(sel, value) {
  if (!sel || value == null || value === "") return false;
  const v = String(value);
  const opt = Array.from(sel.options || []).find(o => String(o.value) === v);
  if (!opt) return false;
  sel.value = v;
  return true;
}

async function loadInvoiceIntoForm(invoiceId) {
  const cid = getActiveCompanyId?.() || companyId?.();
  if (!cid) throw new Error("No active company selected.");

  window._INV_LOADING = true;
  window._INV_TOTALS_LOCKED = true;

  // ✅ use your endpoint style (singular)
  const res = await apiFetch(ENDPOINTS.invoice(cid, invoiceId), { method: "GET" });

  // ✅ unwrap {ok:true, data:{...}}
  const inv = res?.data || res || {};
  const $ = (id) => document.getElementById(id);

  // ---------- header ----------
  $("invId") && ($("invId").value = inv.id || "");
  $("invCustomerName") && ($("invCustomerName").value = inv.customer_name || "");
  $("invCustomerId") && ($("invCustomerId").value = inv.customer_id || "");

  $("invNumber") && ($("invNumber").value = inv.number || "");

  // ✅ FIX: proper date format
  const invDateISO = toISODateInput(inv.invoice_date);
  $("invDate") && ($("invDate").value = invDateISO);

  const dueISO = toISODateInput(inv.due_date);
  $("invDueDate") && ($("invDueDate").value = dueISO);

  $("invCurrency") && ($("invCurrency").value = inv.currency || "ZAR");
  $("invTerms") && ($("invTerms").value = inv.terms || $("invTerms").value || "Due on receipt");

  // ✅ Revenue account default (try stored field, else use first line revenue)
  const headerRevSel =
    $("invRevenueAccount") || $("invRevenue") || $("revenueAccount");

  const defaultRevCode =
    inv.revenue_account_code ||
    inv.default_revenue_account_code ||
    inv.lines?.[0]?.account_code ||
    "";

  setSelectIfOptionExists(headerRevSel, defaultRevCode);

  // ✅ Bank account selection:
  // 1) Prefer bank_account_id (if you store it)
  // 2) If null, try bank_id ONLY if your dropdown options match bank_id
  const bankSel = $("invoiceBankAccount");
  if (bankSel) {
    const ok1 = setSelectIfOptionExists(bankSel, inv.bank_account_id);
    if (!ok1) setSelectIfOptionExists(bankSel, inv.bank_id);
  }

  // discount fields (keep yours)
  if ($("invDisc")) {
    const rate = Number(inv.discount_rate ?? 0) || 0;
    $("invDisc").value = String(rate * 100 || 0);
    $("invDisc").readOnly = true;
  }

  if ($("invOther")) {
    $("invOther").value = String(inv.other ?? "0.00");
    $("invOther").readOnly = true;
  }

  $("invMemo") && ($("invMemo").value = inv.notes || "");
  $("invStatus") && ($("invStatus").textContent = inv.status || "draft");

  // ---------- lines ----------
  const tbody = document.querySelector("#invLines");
  if (tbody) tbody.innerHTML = "";

  (inv.lines || []).forEach((ln) => {
    window.addLine?.({
      item_name: ln.item_name,
      description: ln.description,
      quantity: ln.quantity,
      unit_price: ln.unit_price,

      // ✅ revenue account per line
      account_code: ln.account_code,
      revenue_obligation_id: ln.revenue_obligation_id || null,
      // ✅ vat fields (your addLine may expect vat_rate)
      vat_rate: ln.vat_rate,
      vatCode: ln.vat_code || ln.vatCode,

      // display amounts (optional)
      vat_amount: ln.vat_amount,
      total_amount: ln.total_amount,
    });
  });

  // ---------- totals ----------
  $("sumSubtotal") && ($("sumSubtotal").textContent = String(inv.subtotal_amount ?? "0.00"));
  $("sumVat") && ($("sumVat").textContent = String(inv.vat_amount ?? "0.00"));
  $("sumTotal") && ($("sumTotal").textContent = String(inv.total_amount ?? inv.total ?? "0.00"));

  const discAmt = Number(inv.discount_amount ?? 0) || 0;
  $("sumDiscount") && ($("sumDiscount").textContent = String(inv.discount_amount ?? "0.00"));
  $("sumDiscountWrap") && ($("sumDiscountWrap").style.display = discAmt > 0 ? "" : "none");

  window._INV_TOTALS_LOCKED = true;
  window._INV_LOADING = false;

  if (typeof lockInvoiceFormForReviewers === "function") {
    lockInvoiceFormForReviewers(inv.status, inv.id, "edit");
  }
  if (typeof updateInvoiceActionButtons === "function") {
    updateInvoiceActionButtons();
  }
}
window.loadInvoiceIntoForm = loadInvoiceIntoForm;

async function renderArCustomerList({ closeOnPick = true } = {}) {
  const host = document.getElementById("arCustomerList");
  if (!host) return;

  // Prefer cache if available (fast), else fetch
  let customers =
    (Array.isArray(window.CUSTOMERS) && window.CUSTOMERS.length
      ? window.CUSTOMERS
      : (store?.get?.(K.CUSTOMERS, []) || []))
      .filter(Boolean);

  if (!customers.length) {
    try {
      customers = await fetchCustomersFromBackend(true);
    } catch (e) {
      console.warn("[AR] fetchCustomersFromBackend failed:", e);
      customers = [];
    }
    window.CUSTOMERS = customers || [];
    if (Array.isArray(customers)) store?.set?.(K.CUSTOMERS, customers);
  }

  const active = (customers || []).filter((c) => c && c.is_active !== false);

  if (!active.length) {
    host.innerHTML = `
      <div class="text-xs text-slate-500 px-2 py-1">
        No active customers yet.
      </div>`;
    return;
  }

  // safer HTML escaping for attributes/text
  const escAttr = (s) =>
    String(s ?? "")
      .replaceAll("&", "&amp;")
      .replaceAll('"', "&quot;")
      .replaceAll("<", "&lt;")
      .replaceAll(">", "&gt;");

  const escText = (s) =>
    String(s ?? "")
      .replaceAll("&", "&amp;")
      .replaceAll("<", "&lt;")
      .replaceAll(">", "&gt;");

  host.innerHTML = active
    .map((c) => {
      const id = escAttr(c.id);
      const name = escAttr(c.name || "");
      const email = escText(c.email || "");
      const nameText = escText(c.name || "(No name)");
      return `
        <button
          type="button"
          class="w-full text-left px-2 py-1 text-xs hover:bg-slate-50 rounded"
          data-cust-id="${id}"
          data-cust-name="${name}"
        >
          <div class="font-medium">${nameText}</div>
          <div class="text-[11px] text-slate-500">${email}</div>
        </button>
      `;
    })
    .join("");

  function isQuotesMode() {
    // ✅ more reliable: quotes pane visible
    const quo = document.getElementById("arQuotesPane");
    return !!quo && !quo.classList.contains("hidden");
  }

  async function closeCustomerPicker() {
    if (!closeOnPick) return;
    const pane = document.getElementById("arCustomerPane");
    if (!pane) return;

    pane.classList.add("hidden");
    pane.classList.remove("finsage-floating", "finsage-floating-left");
    pane.setAttribute("aria-hidden", "true");

    // ✅ also hide overlay if your AR overlay is used for panels
    document.getElementById("arOverlay")?.classList.add("hidden");
  }

  // ✅ avoid rebinding multiple times if this function is called often
  if (host.dataset.bound === "1") return;
  host.dataset.bound = "1";

  // Use event delegation
  host.onclick = async (ev) => {
    const btn = ev.target.closest("[data-cust-id]");
    if (!btn) return;

    const custId = parseInt(btn.getAttribute("data-cust-id") || "0", 10) || null;
    const custName = (btn.getAttribute("data-cust-name") || "").trim();

    if (!custId) return;

    // full customer object
    const customerObj =
      (Array.isArray(window.CUSTOMERS) ? window.CUSTOMERS : [])
        .find((c) => String(c?.id) === String(custId)) || { id: custId, name: custName };

    // ✅ ROUTE based on active pane
    if (isQuotesMode()) {
      // fill QUOTE inputs
      const qNameInput = document.getElementById("quoteCustomerName");
      const qIdInput   = document.getElementById("quoteCustomerId");

      if (qNameInput) {
        qNameInput.value = custName;
        qNameInput.dataset.customerId = String(custId); // if you use dataset in other code
        qNameInput.dispatchEvent(new Event("input", { bubbles: true }));
        qNameInput.dispatchEvent(new Event("change", { bubbles: true }));
      }
      if (qIdInput) {
        qIdInput.value = String(custId);
        qIdInput.dispatchEvent(new Event("change", { bubbles: true }));
      }

      // ✅ open customer quotes list (NOT invoices)
      try {
        await window.openCustomerQuotesPane?.(custId, customerObj);
      } catch (e) {
        console.warn("[Quotes] openCustomerQuotesPane failed:", e);
      }

      qNameInput?.focus?.();
      await closeCustomerPicker();
      return;
    }

    // -------------------------
    // INVOICE MODE
    // -------------------------
    const nameInput = document.getElementById("invCustomerName");
    const idInput   = document.getElementById("invCustomerId");

    if (nameInput) {
      nameInput.value = custName;
      nameInput.dispatchEvent(new Event("input", { bubbles: true }));
      nameInput.dispatchEvent(new Event("change", { bubbles: true }));
    }
    if (idInput) {
      idInput.value = String(custId);
      idInput.dispatchEvent(new Event("change", { bubbles: true }));
    }

    try {
      console.log("[AR] customer picked => invoice mode, opening invoices pane", {
        custId,
        custName,
        hasFn: typeof window.openCustomerInvoicesPane,
      });
      await window.openCustomerInvoicesPane?.(custId, customerObj);
    } catch (e) {
      console.warn("[Invoices] openCustomerInvoicesPane failed:", e);
    }

    nameInput?.focus?.();
    await closeCustomerPicker();
  };
}

async function initReceivablesScreen() {
  const screen = document.getElementById("screen-ar");
  if (!screen) return;

  bindARPanels();

  if (screen.dataset.bound !== "1") {
    screen.dataset.bound = "1";

    bindAR();
    loadInvoiceItemCatalog();
    bindInvoiceLineButtons();
    bindInvoicePostingUI();
    bindCustomerInvoicesPane();
    wireCustomerInvoicesPaneHandlers();
    bindInvoiceViewerModal();
    bindInvoiceAllocatePaymentUI();
    bindInvoiceRecalcButton();

    // Quote
    wireQuotesScreen();

    // bind lookup once
    bindInvoiceCustomerLookup();
  }

  // ensure datalist exists + customers loaded
  await fillInvoiceCustomerList();

  // list pane
  await renderArCustomerList?.({ closeOnPick: true });

  await loadRevenueAccountsForInvoice?.();
  await renderDraftInvoiceList?.();

  updateInvoiceActionButtons();
}

let __custCreditWatchBound = false;

function bindCustomerCreditWatcher() {
  if (window.__custCreditWatchBound) return;
  window.__custCreditWatchBound = true;

  document.addEventListener("input", (e) => {
    const t = e.target;
    if (!t || !t.matches("#custCredit")) return;

    const cp = window.CURRENT_COMPANY?.credit_policy || {};
    const requested = Number(t.value || 0) || 0;

    const cap = Number(cp.clerk_request_cap ?? 0);
    const needsKyc = FS?.policy?.requireCustomerKyc
      ? FS.policy.requireCustomerKyc({ creditLimit: requested })
      : false;

    // Example: block clerks above cap (you can adjust your role test)
    if (cap > 0 && requested > cap && typeof userCanApproveCustomers === "function" && !userCanApproveCustomers()) {
      t.setCustomValidity(`Clerks can request up to ${cap}. Please submit for approval.`);
    } else {
      t.setCustomValidity("");
    }

    // If KYC required, you can prompt user:
    if (needsKyc && typeof openKycModal === "function") {
      // optional: openKycModal();
    }

    updateCustomerSubmitState?.();
  });
}

async function ensureInvoiceNumberAssigned() {
  const cid = getActiveCompanyId?.() || companyId?.();
  if (!cid) throw new Error("No active company.");

  const invIdEl = document.getElementById("invId");
  const invNoEl = document.getElementById("invNumber");

  const invId = parseInt(invIdEl?.value || "0", 10);
  const hasNumber = !!String(invNoEl?.value || "").trim();

  // already saved invoice OR already has number
  if (invId || hasNumber) return;

  // allocate only now
  const res = await apiFetch(ENDPOINTS.invoiceNextNumber(cid));
  if (res?.number) invNoEl.value = res.number;
}

function bindInvoiceViewPrint() {
  const btnView  = document.getElementById("btnViewInvoice");
  const btnPrint = document.getElementById("btnPrintInvoice");

  if (!btnView && !btnPrint) return;

  // prevent double binding
  if (btnView?.dataset.bound === "1") return;
  if (btnView)  btnView.dataset.bound = "1";
  if (btnPrint) btnPrint.dataset.bound = "1";

async function openView(print = false) {
  const cid   = getActiveCompanyId?.();
  const invId = parseInt(document.getElementById("invId")?.value || "0", 10);

  if (!cid || !invId) {
    alert("Open or save an invoice first.");
    return;
  }

  if (!print) {
    // ✅ View in SAME tab (A4 HTML view)
    window.location.href = ENDPOINTS.invoiceView(cid, invId);
    return;
  }

  // ✅ Print in NEW tab (prefer PDF, fallback to view)
  const url = ENDPOINTS.invoicePdf
    ? ENDPOINTS.invoicePdf(cid, invId)
    : ENDPOINTS.invoiceView(cid, invId);

  const w = window.open(url, "_blank");
  w?.addEventListener?.("load", () => w.print());
}

  btnView?.addEventListener("click", () => openView(false));
  btnPrint?.addEventListener("click", () => openView(true));
}


function bindInvoiceLineButtons() {
  const linesBody = document.getElementById("invLines");
  const addBtn = document.getElementById("invAddLine");
  const delBtn = document.getElementById("invDelLine");
  if (!linesBody) return;

  if (typeof window.addLine !== "function") {
    console.error("addLine() is not defined on window.");
    return;
  }

  if (addBtn && !addBtn.dataset.bound) {
    addBtn.dataset.bound = "1";
    addBtn.type = "button";
    addBtn.addEventListener("click", (e) => {
      e.preventDefault();
      window.addLine();
    });
  }

  if (delBtn && !delBtn.dataset.bound) {
    delBtn.dataset.bound = "1";
    delBtn.type = "button";
    delBtn.addEventListener("click", (e) => {
      e.preventDefault();
      const rows = linesBody.querySelectorAll("tr");
      if (rows.length) rows[rows.length - 1].remove();
      window.recalcInvoice?.();
    });
  }

  if (!linesBody.querySelector("tr")) window.addLine();
  
}

function bindInvoiceCustomerLookup() {
  const input  = document.getElementById("invCustomerName");
  const hidden = document.getElementById("invCustomerId");
  const dl     = document.getElementById("invCustomerList"); // ✅ your datalist
  if (!input || !hidden) return;

  // prevent double-binding
  if (input.dataset.bound === "1") return;
  input.dataset.bound = "1";

  let lastResolvedKey = "";
  let t = null;

  const norm = (s) => String(s || "").trim().toLowerCase();

  const getCustomers = () =>
    (Array.isArray(window._invoiceCustomers) && window._invoiceCustomers) ||
    (Array.isArray(window.CUSTOMERS) && window.CUSTOMERS) ||
    [];

  function findIdFromDatalist(rawLower) {
    if (!dl || !rawLower) return null;
    // ✅ match an option by value
    const opt = Array.from(dl.options || []).find(o => norm(o.value) === rawLower);
    const id = opt?.dataset?.id ? String(opt.dataset.id) : null;
    return id && id !== "undefined" ? id : null;
  }

  function findCustomerByRaw(rawLower, customers) {
    if (!rawLower) return null;

    // exact name match
    let match = customers.find(c => norm(c?.name) === rawLower);
    if (match) return match;

    // "Name (something)" => try name-only
    if (rawLower.includes("(")) {
      const nameOnly = rawLower.split("(")[0].trim().toLowerCase();
      match = customers.find(c => norm(c?.name) === nameOnly);
      if (match) return match;
    }

    // "Name - something" => try left side
    if (rawLower.includes(" - ")) {
      const left = rawLower.split(" - ")[0].trim().toLowerCase();
      match = customers.find(c => norm(c?.name) === left);
      if (match) return match;
    }

    return null;
  }

  async function resolveAndRefresh() {
    const rawLower = norm(input.value);

    if (!rawLower) {
      hidden.value = "";
      lastResolvedKey = "";
      return;
    }

    // ✅ 1) First try datalist option match (best for “clicked suggestion”)
    const idFromDl = findIdFromDatalist(rawLower);
    if (idFromDl) {
      hidden.value = idFromDl;
    } else {
      // ✅ 2) fallback to customer array matching (typing)
      const customers = getCustomers();
      if (!customers.length) {
        hidden.value = "";
        return;
      }
      const match = findCustomerByRaw(rawLower, customers);
      hidden.value = match ? String(match.id) : "";
    }

    const id = hidden.value ? Number(hidden.value) : 0;
    const key = `${rawLower}:${id}`;
    if (key === lastResolvedKey) return;
    lastResolvedKey = key;

    const customers = getCustomers();
    const customerObj = id ? (customers.find(c => Number(c.id) === id) || null) : null;
    console.log("bindInvoiceCustomerLookup: selected", customerObj);

    if (typeof renderCustomerHighlights === "function") {
      await renderCustomerHighlights(id);
    }

    if (id && typeof openCustomerInvoicesPane === "function") {
      await openCustomerInvoicesPane(id, customerObj);
    }
  }

  function scheduleResolve() {
    clearTimeout(t);
    t = setTimeout(resolveAndRefresh, 120);
  }

  input.addEventListener("input", scheduleResolve);
  input.addEventListener("change", resolveAndRefresh);
  input.addEventListener("blur", resolveAndRefresh);
  input.addEventListener("keydown", (e) => {
    if (e.key === "Enter") resolveAndRefresh();
  });

  // if input is prefilled (edit mode), resolve once
  setTimeout(resolveAndRefresh, 0);
}


async function saveInvoiceToBackend() {
  const cid = getActiveCompanyId();
  if (!cid) {
    alert("No active company – cannot save invoice.");
    return;
  }

  const payload = readInvoiceForm();

  if (!payload.customer_id) {
    alert("Please select a valid customer from the list.");
    return;
  }
  if (!payload.lines.length) {
    alert("Add at least one line item.");
    return;
  }

  try {
    const res = await apiFetch(ENDPOINTS.invoices(cid), {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload),
    });

    console.log("Invoice saved:", res);
    $("#invStatus") && ($("#invStatus").textContent = "Saved");

    if (res && res.number && $("#invNumber")) {
      $("#invNumber").value = res.number; // if backend generated a number
    }

    alert("Invoice saved to backend.");
  } catch (err) {
    console.error("saveInvoiceToBackend error:", err);
    alert("Error saving invoice. Check console / backend logs.");
  }
}

function syncInvoiceDueDateLabel() {
  const invDate = document.getElementById("invDate")?.value;   // YYYY-MM-DD
  const terms   = document.getElementById("invTerms")?.value;
  const out     = document.getElementById("invDueDateLabel");
  if (!out) return;

  if (!invDate) {
    out.textContent = "—";
    return;
  }

  const due = computeDueDate(invDate, terms);
  out.textContent = due || "—";
}

// bind once when invoice UI exists
function bindInvoiceTermsDueDate() {
  const invDate  = document.getElementById("invDate");
  const invTerms = document.getElementById("invTerms");
  if (!invDate || !invTerms) return;

  if (invTerms.dataset.boundDueLabel === "1") return;
  invTerms.dataset.boundDueLabel = "1";

  invDate.addEventListener("change", syncInvoiceDueDateLabel);
  invTerms.addEventListener("change", syncInvoiceDueDateLabel);
  syncInvoiceDueDateLabel();
}

function collectInvoiceFromForm() {
  const idInput   = document.getElementById("invId");
  const custInput = document.getElementById("invCustomerName");
  const dateInput = document.getElementById("invDate");
  const numInput  = document.getElementById("invNumber");
  const termsSel  = document.getElementById("invTerms");
  const currInput = document.getElementById("invCurrency");

  const vatChk  = document.getElementById("invVatEnabled");
  const vatSel  = document.getElementById("invDefaultVat");
  const discEl  = document.getElementById("invDisc");
  const otherEl = document.getElementById("invOther");
  const memoEl  = document.getElementById("invMemo");

  const bankSel = document.getElementById("invoiceBankAccount");
  const revSel  = document.getElementById("invRevenueAccount");
  const contractSel = document.getElementById("invRevenueContractId");

  const invoiceId    = idInput?.value ? parseInt(idInput.value, 10) : null;
  const customerName = custInput?.value?.trim() || "";
  const number       = numInput?.value?.trim() || "";

  const terms    = termsSel?.value || "on_receipt";   // on_receipt / 15 / 30
  const currency = currInput?.value || "ZAR";

  if (!customerName) throw new Error("Customer is required.");
  if (!number) throw new Error("Invoice number is required.");

    const dateRaw = dateInput?.value || "";
  const invoice_date = toIsoDateOnly(dateRaw);

  if (!invoice_date) {
    console.log("[collectInvoiceFromForm] invDate raw =", dateRaw, "normalized =", invoice_date);
    throw new Error("Invoice date is required.");
  }

  // ✅ always computed (no due-date input field)
  const due_date = computeDueDate(invoice_date, terms);

  // ✅ BLOCK future dates + due before invoice
  const todayIso = new Date().toISOString().slice(0, 10);
  if (String(invoice_date).slice(0, 10) > todayIso) {
    throw new Error(`Invoice date cannot be in the future (${invoice_date}).`);
  }
  if (due_date && String(due_date).slice(0, 10) < String(invoice_date).slice(0, 10)) {
    throw new Error("Due date cannot be earlier than invoice date.");
  }

  const customerId = resolveInvoiceCustomerId();
  if (!customerId) throw new Error("Please select a valid customer from the list.");

  const revenueCodeDefault = (revSel?.value || "").trim();
  if (!revenueCodeDefault) throw new Error("Please select a Revenue account.");

  const vatEnabled     = !!vatChk?.checked;
  const defaultVatCode = (vatSel?.value || "STANDARD").trim().toUpperCase();

  // ✅ Discount as percent: "5" / "5%" / "0.05" -> 0..1
  const totals = window.recalcInvoice?.() || {};

  const discount_rate =
    totals.discount_rate ?? parsePercent(discEl?.value || "0"); // 0..1

  const discount_amount =
    Number(totals.discount_amount) || 0;

  // legacy compatibility
  const discount = discount_rate;

  const other = parseFloat(otherEl?.value || "0") || 0;
  const memo  = memoEl?.value?.trim() || "";

  const bankAccountId = bankSel?.value ? parseInt(bankSel.value, 10) : null;
  const revenueContractId = contractSel?.value ? parseInt(contractSel.value, 10) : null;

  const rows = Array.from(document.querySelectorAll("#invLines tr"));

  const lines = rows
    .map((tr) => {
      // ✅ NEW item picker + meta
      const pickEl = tr.querySelector(".inv-item-pick");
      const typeEl = tr.querySelector(".inv-item-type");
      const idEl   = tr.querySelector(".inv-item-id");
      const codeEl = tr.querySelector(".inv-item-code");

      const descEl  = tr.querySelector(".inv-service");
      const acctEl  = tr.querySelector(".inv-acct");
      const oblEl   = tr.querySelector(".inv-obligation");
      const qtyEl   = tr.querySelector(".inv-qty");
      const priceEl = tr.querySelector(".inv-price");
      const vatEl   = tr.querySelector(".inv-vat-code");

      const itemPick = (pickEl?.value || "").trim();
      const desc     = (descEl?.value || "").trim();

      const qty  = parseFloat(qtyEl?.value || "0") || 0;
      const unit = parseFloat(priceEl?.value || "0") || 0;

      const vatCode = ((vatEl?.value || defaultVatCode) || "STANDARD")
        .trim()
        .toUpperCase();

      let vat_rate = null;
      if (vatCode === "CUSTOM") {
        const customEl = tr.querySelector(".inv-vat-custom");
        vat_rate = parseFloat(customEl?.value || "0") || 0; // percent
      }
      const account_code = ((acctEl?.value || "").trim() || revenueCodeDefault);
      const obligationIdRaw = (oblEl?.value || "").trim();
      const revenue_obligation_id = obligationIdRaw ? Number(obligationIdRaw) : null;

      // ✅ catalog meta (service | inventory | gl)
      const itemType = (typeEl?.value || "gl").trim().toLowerCase();
      const itemIdRaw = (idEl?.value || "").trim();
      const itemCode  = (codeEl?.value || "").trim();

      const itemId = itemIdRaw ? Number(itemIdRaw) : null;

      // ✅ same validation rule as before
      if (!(itemPick || desc) || !(qty || unit)) return null;

      return {
        // keep legacy fields if backend expects them
        item_name: itemPick,        // display text (what user sees)
        description: desc,
        quantity: qty,
        unit_price: unit,
        vatCode,
        vat_rate,
        account_code,
        revenue_obligation_id,

        // ✅ NEW meta fields (what backend can use to link to master records)
        item: itemPick,             // optional duplicate, but handy
        item_type: itemType,        // service | inventory | gl
        item_id: Number.isFinite(itemId) ? itemId : null,
        item_code: itemCode || null,
      };
    })
    .filter(Boolean);

  if (!lines.length) throw new Error("Invoice must have at least one valid line.");

  return {
    id: invoiceId,
    customer_id: customerId,
    customer_name: customerName,
    revenue_contract_id: revenueContractId,
    invoice_date,
    due_date,
    number,
    terms,
    currency,

    vat_enabled: vatEnabled,
    default_vat_code: defaultVatCode,

    // ✅ BOTH rate + amount
    discount_rate,
    discount_amount,
    discount,          // legacy (safe to keep)

    other,
    notes: memo,
    bank_account_id: bankAccountId,
    lines,
  };
}

function resetInvoiceForm() {
  console.log("resetInvoiceForm → clearing invoice fields");

  const $ = (sel) => document.querySelector(sel);

  // Hidden ID
  if ($("#invId")) $("#invId").value = "";

  // If you use hidden customer id, clear it too
  if ($("#invCustomerId")) $("#invCustomerId").value = "";

  // Header fields
  if ($("#invCustomerName")) $("#invCustomerName").value = "";
  if ($("#invNumber")) $("#invNumber").value = "";
  if ($("#invDate")) $("#invDate").value = "";
  if ($("#invTerms")) $("#invTerms").value = "Due on receipt";
  if ($("#invCurrency")) $("#invCurrency").value = "ZAR";

  // Bank account
  if ($("#invoiceBankAccount")) $("#invoiceBankAccount").selectedIndex = 0;

  // VAT controls
  if ($("#invVatEnabled")) $("#invVatEnabled").checked = false;
  if ($("#invDefaultVat")) $("#invDefaultVat").value = "STANDARD";

  // Totals inputs
  if ($("#invDisc"))  $("#invDisc").value  = "0.00";
  if ($("#invOther")) $("#invOther").value = "0.00";

  // ✅ Totals spans (these were not being reset before)
  if ($("#sumSubtotal")) $("#sumSubtotal").textContent = "0.00";
  if ($("#sumVat"))      $("#sumVat").textContent      = "0.00";
  if ($("#sumTotal"))    $("#sumTotal").textContent    = "0.00";

  // Status label
  if ($("#invStatus")) $("#invStatus").textContent = "Draft";

  // Memo
  if ($("#invMemo")) $("#invMemo").value = "";

  // Clear lines
  const tbody = document.querySelector("#invLines");
  if (tbody) tbody.innerHTML = "";

  // Add one empty line if you have a helper
  if (typeof addLine === "function") addLine();

  // Recalculate totals if you have this
  if (typeof recalcInvoice === "function") recalcInvoice();

  // Focus customer for next capture
  if ($("#invCustomerName")) $("#invCustomerName").focus();
}

let INVOICES_CACHE = null;

async function saveInvoiceDraft(statusOverride = "draft") {
  const cid = companyId();
  if (!cid) return alert("No active company selected.");

  // ✅ allocate number ONLY now (not on open)
  await ensureInvoiceNumberOnCommit();

  const inv = collectInvoiceFromForm();
  inv.status = statusOverride || "draft";

  try {
    let saved;

    if (inv.id) {
      saved = await apiFetch(`${ENDPOINTS.invoices(cid)}/${inv.id}`, {
        method: "PUT",
        body: JSON.stringify(inv),
      });
    } else {
      saved = await apiFetch(ENDPOINTS.invoices(cid), {
        method: "POST",
        body: JSON.stringify(inv),
      });
    }

    if (saved?.id && document.getElementById("invId")) {
      document.getElementById("invId").value = saved.id;
    }

    if (saved?.number && document.getElementById("invNumber")) {
      document.getElementById("invNumber").value = saved.number;
    }

    if (saved?.number && document.getElementById("invNumber")) {
      document.getElementById("invNumber").value = saved.number;
    }

    // ✅ refresh action buttons after save
    if (typeof updateInvoiceActionButtons === "function") {
      updateInvoiceActionButtons();
    }

    alert("Draft saved to backend ✅");
    await renderDraftInvoiceList();
    return saved;
  } catch (err) {
    console.error(err);
    alert(err.message || "Error saving invoice.");
  }
}

function wireInvoiceCustomerPicker() {
  const input = document.getElementById("invCustomerName");
  if (!input) return;

  if (input.dataset.pickerWired === "1") return; // ✅ prevent double-binding
  input.dataset.pickerWired = "1";

  input.addEventListener("change", () => {
    const typedRaw = (input.value || "").trim();
    const typed = typedRaw.toLowerCase();
    input.dataset.customerId = "";

    const list = Array.isArray(window.CUSTOMER_CACHE)
      ? window.CUSTOMER_CACHE
      : (Array.isArray(CUSTOMER_CACHE) ? CUSTOMER_CACHE : []);

    const hit = list.find((c) => {
      const name = String(c.name || "").trim();
      const email = String(c.email || "").trim();
      const idStr = String(c.id ?? "").trim();

      const nameLower = name.toLowerCase();
      const emailLower = email.toLowerCase();

      // ✅ old label support (backward compatible)
      const oldLabelLower = email ? `${nameLower} - ${emailLower}` : nameLower;

      return (
        typed === nameLower ||
        (emailLower && typed === emailLower) ||
        typed === oldLabelLower ||
        typed === idStr
      );
    });

    if (hit?.id) {
      input.dataset.customerId = String(hit.id);

      // ✅ FORCE DISPLAY TO NAME ONLY (your request)
      input.value = String(hit.name || "").trim();
    }
  });
}

async function approveInvoiceFromBackend(invoiceId) {
  const cid = getActiveCompanyId?.() || companyId?.();
  if (!cid) throw new Error("No active company.");
  if (!invoiceId) throw new Error("No invoice selected.");

  // 1) GET invoice full payload from backend
  const raw = await apiFetch(`${ENDPOINTS.invoices(cid)}/${invoiceId}`, { method: "GET" });
  const inv = normalizeInvoiceFromApi(raw);

  // hard guard: backend must have the date
  if (!inv.invoice_date) {
    throw new Error("Backend invoice is missing invoice_date. Please re-save the draft.");
  }

  // 2) Build payload exactly how backend expects (snake_case + lines)
  const payload = {
    id: inv.id,
    customer_id: inv.customer_id,
    customer_name: inv.customer_name,  // ok to include, backend can ignore extras

    number: inv.number,
    invoice_date: inv.invoice_date,
    due_date: inv.due_date || null,
    currency: inv.currency || "ZAR",
    terms: inv.terms || "Due on receipt",

    status: "approved",

    bank_account_id: inv.bank_account_id || null,
    notes: inv.notes || "",

    // IMPORTANT: backend invoice_lines wants:
    // description, account_code, quantity, unit_price, discount_amount, vat_rate, item_name
    lines: (inv.lines || []).map((ln) => ({
      item_name: ln.itemName || "",                // ✅ new column
      description: ln.description || "",
      account_code: ln.account_code || null,
      quantity: Number(ln.quantity || 0),
      unit_price: Number(ln.unit_price ?? ln.unitPrice ?? 0),
      discount_amount: Number(ln.discount_amount || 0),
      vat_rate: Number(ln.vat_rate || 0),
    })),
  };

  // 3) PUT update (status change + keep exact saved values)
  const saved = await apiFetch(`${ENDPOINTS.invoices(cid)}/${invoiceId}`, {
    method: "PUT",
    body: JSON.stringify(payload),
  });

  return saved || payload;
}

async function postCurrentInvoice() {
  const cid = getActiveCompanyId();
  const id = parseInt(document.getElementById("invId")?.value || "0", 10);
  if (!cid || !id) throw new Error("Open a saved invoice first.");

  const posted = await apiFetch(`${ENDPOINTS.invoices(cid)}/${id}/post`, {
    method: "POST",
  });

  // ✅ Return the posted invoice object (or at least {id})
  return posted || { id };
}


async function fetchInvoicesFromBackend(force = false) {
  const cid = getActiveCompanyId();
  if (!cid) return [];

  if (!force && Array.isArray(INVOICES_CACHE)) {
    return INVOICES_CACHE;
  }

  const data = await apiFetch(ENDPOINTS.invoices(cid));
  INVOICES_CACHE = data.invoices || [];
  return INVOICES_CACHE;
}
