function resolveCustomerIdFromInput(inputId, cacheList) {
  const input = document.getElementById(inputId);
  if (!input) return null;

  const typed = (input.value || "").trim();
  if (!typed) return null;

  // 1) stamped id from picker
  const stamped = input.dataset.customerId;
  if (stamped && /^\d+$/.test(stamped)) return parseInt(stamped, 10);

  // 2) numeric typed
  if (/^\d+$/.test(typed)) return parseInt(typed, 10);

  const needle = typed.toLowerCase();
  const list = Array.isArray(cacheList) ? cacheList : [];

  // 3) exact match first
  let hit = list.find(c => {
    const name = String(c.name || "").toLowerCase();
    const email = String(c.email || "").toLowerCase();
    return (
      name === needle ||
      email === needle ||
      `${name} - ${email}` === needle
    );
  });

  // 4) fallback: smart match (optional but UX-friendly)
  if (!hit) {
    hit = list.find(c => {
      const name = String(c.name || "").toLowerCase();
      return name.includes(needle); // partial match
    });
  }

  return hit?.id ? parseInt(hit.id, 10) : null;
}


