async function loadRevenueAccountsForQuotes() {
  const cid = getActiveCompanyId();
  if (!cid) return;

  try {
    const coa = await apiFetch(ENDPOINTS.coa(cid));
    const rows = Array.isArray(coa) ? coa : (coa?.accounts || coa?.rows || []);

    const norm = (v) => String(v || "").trim();
    const codeOf = (a) => norm(a.code || a.account_code);
    const nameOf = (a) => norm(a.name || a.account_name);
    const postingOf = (a) => (a.posting === undefined ? true : !!a.posting);

    const isRevenueCode = (code) => code.startsWith("PL_REV_");

    const revenueAccounts = rows.filter(a => {
      const code = codeOf(a);
      const name = nameOf(a);
      if (!code || !name) return false;
      if (!postingOf(a)) return false;
      if (!isRevenueCode(code)) return false;
      return true;
    });

    revenueAccounts.sort((a, b) => nameOf(a).localeCompare(nameOf(b)));

    window.REVENUE_ACCOUNTS_CACHE = revenueAccounts.map(a => ({
      code: codeOf(a),
      name: nameOf(a),
    }));

  } catch (e) {
    console.error("loadRevenueAccountsForQuotes failed:", e);
    window.REVENUE_ACCOUNTS_CACHE = [];
  }
}

