function isApprovalRequiredResponse(res) {
  // apiFetch may return json, or throw. We handle the json-success case here.
  return res && (
    res.status === "approval_required" ||
    res.approval_required === true ||
    res.approval_request_id != null
  );
}

function routeToApprovals({ requestId, module = "ar" } = {}) {
  try {
    if (requestId != null) store?.set?.("fs_last_approval_request_id", Number(requestId));
    store?.set?.("fs_approvals_default_status", "pending");
    store?.set?.("fs_approvals_default_module", module);
  } catch (e) {}

  // if you already have approvals screen name as "approvals", keep that
  switchScreen?.("approvals");

  // optional: if you want it to auto-open the specific request later, add that in approvals screen
}

async function issueQuote(id, { force = false } = {}) {
  const cid = FS.control.resolveCid();

  const res = await apiFetch(`/api/companies/${cid}/quotes/${id}/issue`, {
    method: "POST",
    body: JSON.stringify(force ? { force: true } : {}),
  });

  if (isApprovalRequiredResponse(res)) {
    routeToApprovals({ requestId: res.approval_request_id, module: "ar" });
    // Let caller know it didn't "issue" yet, it requested approval.
    return { ...res, _approval_flow: true };
  }

  return res;
}

async function acceptQuote(id, { force = false } = {}) {
  const cid = FS.control.resolveCid();

  const res = await apiFetch(`/api/companies/${cid}/quotes/${id}/accept`, {
    method: "POST",
    body: JSON.stringify(force ? { force: true } : {}),
  });

  if (isApprovalRequiredResponse(res)) {
    routeToApprovals({ requestId: res.approval_request_id, module: "ar" });
    return { ...res, _approval_flow: true };
  }

  return res;
}

