function wireQuoteValidity() {
  const elDate  = document.getElementById("quoteDate");
  const elDays  = document.getElementById("quoteValidDays");
  const elUntil = document.getElementById("quoteValidUntil");

  if (!elDate || !elDays || !elUntil) return;

  function recalc() {
    const qd = toIsoDateOnly(elDate.value);
    const vd = elDays.value;
    const vu = computeQuoteValidUntil(qd, vd);
    if (vu) elUntil.value = vu;
  }

  elDate.addEventListener("change", recalc);
  elDays.addEventListener("change", recalc);

  // default
  if (!elDate.value) elDate.value = new Date().toISOString().slice(0, 10);
  if (!elDays.value) elDays.value = "30";
  recalc();
}


function addDaysToISO(dateISO, days) {
  const d = new Date(String(dateISO).slice(0, 10) + "T00:00:00");
  d.setDate(d.getDate() + Number(days || 0));
  return d.toISOString().slice(0, 10);
}

// For now: dropdown only; later you can add "custom_date" option
function computeQuoteValidUntil(quote_date, validDays) {
  const days = parseInt(validDays, 10);
  if (!quote_date) return "";
  if (!Number.isFinite(days) || days <= 0) return "";
  return addDaysToISO(quote_date, days);
}

function collectQuoteFromForm() {
  const idInput   = document.getElementById("quoteId");
  const custInput = document.getElementById("quoteCustomerName");
  const dateInput = document.getElementById("quoteDate");
  const numInput  = document.getElementById("quoteNumber");
  const daysSel   = document.getElementById("quoteValidDays");
  const untilInput= document.getElementById("quoteValidUntil");
  const currInput = document.getElementById("quoteCurrency");

  const discEl  = document.getElementById("quoteDisc");
  const notesEl = document.getElementById("quoteNotes");
  const termsEl = document.getElementById("quoteTerms");

  const quoteId      = idInput?.value ? parseInt(idInput.value, 10) : null;
  const customerName = custInput?.value?.trim() || "";
  const number       = (numInput?.value || "").trim(); // draft-friendly (may be empty)
  const currency     = (currInput?.value || "ZAR").trim();

  if (!customerName) throw new Error("Customer is required.");

  const dateRaw = dateInput?.value || "";
  const quotation_date = toIsoDateOnly(dateRaw);
  if (!quotation_date) throw new Error("Quote date is required.");

  // ✅ block future quote date
  const todayIso = new Date().toISOString().slice(0, 10);
  if (String(quotation_date).slice(0, 10) > todayIso) {
    throw new Error(`Quote date cannot be in the future (${quotation_date}).`);
  }

  // Validity
  const validDays = (daysSel?.value || "30");
  let valid_until = toIsoDateOnly(untilInput?.value || "");

  // if field is empty, compute from dropdown
  if (!valid_until && validDays !== "custom") {
    valid_until = computeQuoteValidUntil(quotation_date, validDays);
  }

  // ✅ enforce valid_until >= quote_date (if present)
  if (valid_until && String(valid_until).slice(0, 10) < String(quotation_date).slice(0, 10)) {
    throw new Error("Valid until cannot be earlier than quote date.");
  }

  // Discount rate: store as 0..1 (same style as invoice)
  const discount_rate = parsePercent(discEl?.value || "0"); // 0..1

  const notes = notesEl?.value?.trim() || "";
  const terms = termsEl?.value?.trim() || "";

  const customerId = resolveQuoteCustomerId?.() || resolveInvoiceCustomerId?.();
  if (!customerId) throw new Error("Please select a valid customer from the list.");

  // Lines (mirror invoice, but use quote selectors)
  const rows = Array.from(document.querySelectorAll("#quoteLines tr"));

  const lines = rows
    .map((tr) => {
      const itemEl  = tr.querySelector(".q-item");
      const descEl  = tr.querySelector(".q-desc");
      const acctEl  = tr.querySelector(".q-acct");  // <select>
      const qtyEl   = tr.querySelector(".q-qty");
      const priceEl = tr.querySelector(".q-price");
      const vatEl   = tr.querySelector(".q-vat");
      const discEl  = tr.querySelector(".q-disc");  // only if you actually have it in the row

      const item_name   = (itemEl?.value || "").trim();
      const description = (descEl?.value || "").trim();

      const account_code = String(acctEl?.value || "").trim();   // ✅ from dropdown
      const quantity     = parseFloat(qtyEl?.value || "0") || 0;
      const unit_price = parseMoney(priceEl?.value || "0");
      const vat_rate     = parseFloat(vatEl?.value || "0") || 0;
      const discount_amount = parseFloat(discEl?.value || "0") || 0;

      // ignore empty rows
      if (!(item_name || description) || !(quantity || unit_price)) return null;

      return {
        item_name: item_name || null,
        description: description || item_name || "",
        account_code: account_code || null,          // ✅ keep required if backend requires it
        quantity,
        unit_price,
        vat_rate,
        discount_amount,
      };
    })
    .filter(Boolean);

  if (!lines.length) throw new Error("Quote must have at least one valid line.");

  for (let i = 0; i < lines.length; i++) {
    if (!String(lines[i].description || "").trim()) {
      throw new Error(`Line ${i + 1}: Missing description`);
    }
    if (!String(lines[i].account_code || "").trim()) {
      throw new Error(`Line ${i + 1}: Select a revenue account`);
    }
  }

  return {
    id: quoteId,
    customer_id: customerId,
    customer_name: customerName,

    number: number || null,         // draft-friendly
    quotation_date,
    valid_until: valid_until || null,

    currency,
    discount_rate,                  // 0..1

    notes,
    terms,

    lines,
  };
}

const moneyFmt = new Intl.NumberFormat(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 });

function formatMoneyInput(value) {
  const n = parseMoney(value);
  if (!Number.isFinite(n)) return "";
  return moneyFmt.format(n);
}

