function deleteSelectedQuoteLineRow() {
  const tbody = document.getElementById("quoteLines");
  if (!tbody) return;

  const radios = Array.from(tbody.querySelectorAll('input[type="radio"][name="qSel"]'));
  const picked = radios.find(r => r.checked);
  if (!picked) return;

  const tr = picked.closest("tr");
  tr?.remove();
}

function openQuoteIntoForm(q) {
  if (!q) return;

  document.getElementById("quoteId").value = q.id || "";
  document.getElementById("quoteStatus").textContent = (q.status || "draft");
  document.getElementById("quoteNumber").value = q.number || "";

  document.getElementById("quoteCustomerName").value = q.customer_name || "";
  // stamp dataset id for resolver
  const custInput = document.getElementById("quoteCustomerName");
  if (custInput && q.customer_id) custInput.dataset.customerId = String(q.customer_id);

  document.getElementById("quoteDate").value = (q.quotation_date || "").slice(0,10);
  document.getElementById("quoteValidUntil").value = (q.valid_until || "").slice(0,10);
  document.getElementById("quoteCurrency").value = q.currency || "ZAR";

  document.getElementById("quoteNotes").value = q.notes || "";
  document.getElementById("quoteTerms").value = q.terms || "";
  document.getElementById("quoteDisc").value = String((q.discount_rate || 0) * 100);

  // lines
  const tbody = document.getElementById("quoteLines");
  if (tbody) tbody.innerHTML = "";
  const lines = Array.isArray(q.lines) ? q.lines : [];
  if (!lines.length) addQuoteLineRow();

  lines.forEach(ln => {
    addQuoteLineRow();
    const tr = document.querySelector("#quoteLines tr:last-child");
    if (!tr) return;
    tr.querySelector(".q-item").value  = ln.item_name || "";
    tr.querySelector(".q-desc").value  = ln.description || "";
    tr.querySelector(".q-acct").value  = ln.account_code || "";
    tr.querySelector(".q-qty").value   = ln.quantity ?? 1;
    tr.querySelector(".q-price").value = ln.unit_price ?? 0;
    tr.querySelector(".q-vat").value   = ln.vat_rate ?? 0;
  });
}

