// Single source of truth for customers on the frontend
//let CUSTOMER_CACHE = [];
let CUSTOMER_CACHE = Array.isArray(window.CUSTOMER_CACHE) ? window.CUSTOMER_CACHE : [];

// 🔹 Ensure backend customer objects have the shape the UI expects
function normaliseCustomer(raw) {
  if (!raw || typeof raw !== "object") return null;

  return {
    // IDs
    id:
      raw.id ??
      raw.customer_id ??
      raw.customerId ??
      raw.pk ??
      null,

    // Basic info
    name:
      raw.name ??
      raw.customer_name ??
      raw.customerName ??
      "",
    email:
      raw.email ??
      raw.customer_email ??
      raw.customerEmail ??
      "",
    phone:
      raw.phone ??
      raw.customer_phone ??
      raw.customerPhone ??
      "",
    type:
      raw.type ??
      raw.customer_type ??
      "Company",

    // Addresses
    billAddr:
      raw.billAddr ??
      raw.bill_addr ??
      raw.billing_address ??
      "",
    billCountry:
      raw.billCountry ??
      raw.bill_country ??
      raw.billing_country ??
      "",
    shipAddr:
      raw.shipAddr ??
      raw.ship_addr ??
      raw.shipping_address ??
      "",

    // Tax & registration
    regNo:
      raw.regNo ??
      raw.registration_no ??
      raw.reg_no ??
      "",
    taxNo:
      raw.taxNo ??
      raw.tax_number ??
      raw.tax_no ??
      "",
    vatNo:
      raw.vatNo ??
      raw.vat_number ??
      raw.vat_no ??
      "",
    taxExempt:
      raw.taxExempt ??
      raw.tax_exempt ??
      "no",
    wht:
      raw.wht ??
      raw.withholding_tax ??
      "",

    // Terms / credit
    terms:
      raw.terms ??
      raw.payment_terms ??
      "Due on receipt",
    creditLimit:
      raw.creditLimit ??
      raw.credit_limit ??
      "",
    onHold:
      raw.onHold ??
      raw.on_hold ??
      "no",

    // Misc
    notes: raw.notes ?? "",
    tags: raw.tags ?? "",

    // Contacts (array)
    contacts: Array.isArray(raw.contacts) ? raw.contacts : [],

    // Active flag
    is_active:
      raw.is_active ??
      raw.active ??
      true,
  };
}

// 🔹 Global customer cache used by multiple screens

let customers        = [];   // used by bindCustomers
let currentId        = null; // currently selected customer id in UI
let currentFilter    = "active";
let currentKycRecord = null;

async function fetchCustomersFromBackend(forceFresh = false) {
  if (!forceFresh && CUSTOMER_CACHE.length) {
    return CUSTOMER_CACHE;
  }

  const cid = getActiveCompanyId();
  if (!cid) {
    console.warn("fetchCustomersFromBackend: no active company ID");
    return [];
  }

  const raw = await apiFetch(ENDPOINTS.customers(cid));

  const list = Array.isArray(raw)
    ? raw
    : Array.isArray(raw?.customers)
      ? raw.customers
      : Array.isArray(raw?.items)
        ? raw.items
        : [];

  CUSTOMER_CACHE = list
    .map(normaliseCustomer)
    .filter(c => c && c.id && c.name);

  // ✅ publish in window so invoice resolver can always find it
  window.CUSTOMER_CACHE = CUSTOMER_CACHE;

  // ✅ fast lookup by id + by name/email
  window.CUSTOMERS_BY_ID = new Map(
    CUSTOMER_CACHE.map(c => [String(c.id), c])
  );

  console.log("fetchCustomersFromBackend →", CUSTOMER_CACHE);
  return CUSTOMER_CACHE;
}

function bindInvoiceCustomerIdSync() {
  const nameEl = document.getElementById("invCustomerName");
  const idEl   = document.getElementById("invCustomerId");
  if (!nameEl || !idEl) return;

  // prevent double bind
  if (nameEl.dataset.bound === "1") return;
  nameEl.dataset.bound = "1";

  const sync = async () => {
    const typed = (nameEl.value || "").trim().toLowerCase();
    const customers = window._invoiceCustomers || [];

    const match = customers.find(c =>
      String(c?.name || "").trim().toLowerCase() === typed
    );

    const id = match ? Number(match.id) : null;

    // set form ID field
    idEl.value = id ? String(id) : "";

    // set global invoice state
    window.CURRENT_INVOICE_CUSTOMER_ID = id;
    window.CURRENT_INVOICE_CUSTOMER = match || null;

    if (id && typeof renderCustomerHighlights === "function") {
      renderCustomerHighlights(id);
    }

    // ✅ NEW: refresh revenue contract dropdown for selected customer
    await window.loadRevenueContractsForSelectedCustomer?.();

    // ✅ if customer changed, also clear obligation UI until contract is chosen
    window.toggleInvoiceObligationUI?.({
      hasRevenueContract: !!document.getElementById("invRevenueContractId")?.value,
      hasObligation: false,
    });
  };

  nameEl.addEventListener("input", sync);
  nameEl.addEventListener("change", sync);
  nameEl.addEventListener("blur", sync);
}

