    // ✅ Customer tabs (robust, no sibling dependency)
  (function bindCustomerTabs() {
    const screen = document.getElementById("screen-customers");
    const formHost = document.getElementById("custFormHost");
    if (!screen || !formHost) return;

    const tabButtons = screen.querySelectorAll("[data-tab]");
    if (!tabButtons.length) {
      console.warn("[Customers] No [data-tab] buttons found");
      return;
    }

    function showTab(tab) {
      // show/hide panes
      formHost.querySelectorAll("[data-pane]").forEach((p) => {
        const isActive = p.getAttribute("data-pane") === tab;
        p.classList.toggle("hidden", !isActive);
      });

      // ✅ shift to the tab’s form area (no leftover scroll from previous tab)
      formHost.scrollTop = 0;

      // optional active UI
      tabButtons.forEach((b) => b.classList.remove("ring-2", "ring-[var(--fs-teal)]"));
      const activeBtn = Array.from(tabButtons).find((b) => b.getAttribute("data-tab") === tab);
      activeBtn?.classList.add("ring-2", "ring-[var(--fs-teal)]");

      // ✅ optional: focus the first field inside the active pane
      const activePane = formHost.querySelector(`[data-pane="${tab}"]`);
      const firstField = activePane?.querySelector("input, select, textarea, button");
      firstField?.focus?.();
    }

    tabButtons.forEach((btn) => {
      btn.addEventListener("click", () => {
        const tab = btn.getAttribute("data-tab");
        if (!tab) return;
        showTab(tab);
      });
    });

    // ✅ Ensure a default tab is visible on load
    showTab("c-basics");
  })();

