function canApproveCustomerRequest(item) {
  const cid = FS?.control?.resolveCid?.() || null;
  const mode = FS?.control?.get ? FS.control.get(cid) : "owner_managed";

  const role = FS?.role?.normalize
    ? FS.role.normalize(getCurrentRole?.() || "")
    : String(getCurrentRole?.() || "").toLowerCase();

  const isOwner = FS?.policy?.isOwnerUser ? FS.policy.isOwnerUser() : false;

  // approval request must be pending
  if (String(item.status || "").toLowerCase() !== "pending") return false;

  // OWNER-MANAGED: owner approves, no KYC gating
  if (mode === "owner_managed") return isOwner || role === "owner" || role === "admin";

  // ASSISTED: only owner/admin approves, no KYC gating
  if (mode === "assisted") return isOwner || role === "owner" || role === "admin";

  // CONTROLLED: enforce KYC + allow manager/cfo/admin/owner
  if (mode === "controlled") {
    const kyc = item?.payload_json?.kyc || {};
    const docs = kyc.documents || [];
    const docsOk = !!docs.length;                 // or stricter: every doc uploaded
    const checksOk = kyc.checksOk !== false;      // default true unless explicitly false
    const kycOk = docsOk && checksOk;

    const canApprove = ["owner","admin","cfo","manager"].includes(role) || isOwner;
    return canApprove && kycOk;
  }

  return false;
}

function updateCustomerSaveButtonState() {
  const btn = document.getElementById("custSaveBtn");
  if (!btn) return;

  const cid = FS?.control?.resolveCid?.() || window.CURRENT_COMPANY_ID || null;
  const payload = window.fsCustomerForm?.read?.() || {};

  const canDirect = !!FS?.policy?.canDirectSaveCustomer?.(payload, cid);
  btn.dataset.canDirect = canDirect ? "1" : "0";
}

  async function maybeSubmitCreditProfileAfterCustomerSave(savedCustomer) {
  // Only do this if KYC was completed (or if credit limit > 0, etc.)
  if (!CURRENT_KYC_STATE?.completed) return;

  // Ensure docs are uploaded (optional: you may require docsOk)
  if (!CURRENT_KYC_STATE?.docsOk) return;

  // Upload docs if not uploaded yet (if approver flow doesn't upload)
  if (!Array.isArray(CURRENT_KYC_STATE.documents) || !CURRENT_KYC_STATE.documents.length) {
    const inc  = document.getElementById("doc-inc");
    const tax  = document.getElementById("doc-tax");
    const bank = document.getElementById("doc-bank");
    const id   = document.getElementById("doc-id");

    const docsMeta = await Promise.all([
      buildDocAndUpload(inc,  "doc-inc",  "Certificate of Incorporation"),
      buildDocAndUpload(tax,  "doc-tax",  "Tax documents / Tax clearance"),
      buildDocAndUpload(bank, "doc-bank", "Bank letter / bank statement"),
      buildDocAndUpload(id,   "doc-id",   "Director IDs & proof of address"),
    ]);

    CURRENT_KYC_STATE.documents = docsMeta;
    CURRENT_KYC_STATE.docsOk = docsMeta.every(d => d.status === "uploaded");
    if (!CURRENT_KYC_STATE.docsOk) return;
  }

  const createdBy =
    (window.currentUser && window.currentUser.email) ||
    localStorage.getItem("userEmail") ||
    "";

  const credit = parseFloat(savedCustomer.creditLimit || savedCustomer.credit_limit || "0") || 0;

  const profilePayload = {
    ...savedCustomer,
    requestedLimit: credit,
    createdBy,
    createdAt: new Date().toISOString(),
    status: "pending_senior", // or "draft" if you want drafts separate
    kyc: {
      ...CURRENT_KYC_STATE,
      documents: CURRENT_KYC_STATE.documents || [],
    },
  };

  const body = { customerId: savedCustomer.id, payload: profilePayload };

  // IMPORTANT: send JSON header to avoid silent empty request.get_json()
  await apiFetch(ENDPOINTS.credit.submit, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(body),
  });
}

async function loadDraftInvoices() {
  const cid = getActiveCompanyId();
  if (!cid) return;

  const list = document.getElementById("draftInvoiceList");
  if (!list) return;

  list.innerHTML = `<div class="text-xs text-slate-400">Loading…</div>`;

  try {
    const invoices = await apiFetch(
      `${ENDPOINTS.invoices(cid)}?status=draft`
    );

    if (!invoices.length) {
      list.innerHTML = `<div class="text-xs text-slate-400">No drafts</div>`;
      return;
    }

    list.innerHTML = invoices.map(inv => `
      <button
        class="w-full text-left p-2 border rounded hover:bg-slate-50"
        onclick="openDraftInvoice(${inv.id})"
      >
        <div class="font-medium">
          ${inv.customer_name || "Unnamed Customer"}
        </div>
        <div class="text-xs text-slate-500">
          #${inv.number || "Draft"} • ${inv.invoice_date}
        </div>
        <div class="text-xs text-slate-400">
          Total: ${inv.total || "—"}
        </div>
      </button>
    `).join("");

  } catch (err) {
    console.error("loadDraftInvoices error", err);
    list.innerHTML = `<div class="text-red-500 text-xs">Failed to load drafts</div>`;
  }
}

