function readInvoiceForm() {
  const customerName = document.getElementById("invCustomerName")?.value || "";
  const customerId   = document.getElementById("invCustomerId")?.value || null;
  
  const invoiceDate  = document.getElementById("invDate")?.value || "";
  const terms        = document.getElementById("invTerms")?.value || "Due on receipt";
  const dueDate      = document.getElementById("invDueDate")?.value || ""; // if you have it
  const number       = document.getElementById("invNumber")?.value || "";
  const currency     = document.getElementById("invCurrency")?.value || "ZAR";
  const notes        = document.getElementById("invMemo")?.value || "";

  const invId        = document.getElementById("invId")?.value || "";

  const linesBody = document.getElementById("invLines");
  const rows = Array.from(linesBody?.querySelectorAll("tr.inv-line-row, tr") || []);

  const vatEnabled = !!document.getElementById("invVatEnabled")?.checked;
  const defaultVatCode =
    (document.getElementById("invDefaultVat")?.value || "STANDARD").trim().toUpperCase();

  const lines = rows.map((row) => {
    const item = row.querySelector(".inv-desc")?.value || "";       // ✅ Item/Service
    const desc = row.querySelector(".inv-service")?.value || "";    // ✅ Description
    const acct = row.querySelector(".inv-acct")?.value || "";       // ✅ Revenue account
    const obligationIdRaw = row.querySelector(".inv-obligation")?.value || "";
    const revenue_obligation_id = obligationIdRaw ? Number(obligationIdRaw) : null;
    const qty  = parseFloat(row.querySelector(".inv-qty")?.value || "0") || 0;
    const unit = parseFloat(row.querySelector(".inv-price")?.value || "0") || 0;

    const code = ((row.querySelector(".inv-vat-code")?.value || defaultVatCode) + "")
      .trim()
      .toUpperCase();

    const net = Math.max(0, qty * unit);

    let vatRate = 0;
    let vatAmt  = 0;

    if (vatEnabled && code === "STANDARD") {
      vatRate = 15;
      vatAmt = +(net * 0.15).toFixed(2);
    } else {
      vatRate = 0;
      vatAmt = 0;
    }

    const total = +(net + vatAmt).toFixed(2);

    const itemClean = item.trim();
    const descClean = desc.trim();

    return {
      line_no: 0, // backend can set; optional
      item_name: itemClean,                              // ✅ maps to DB item_name
      description: (descClean || itemClean || "—"),      // ✅ maps to DB description (NOT NULL)
      account_code: acct || null,
      revenue_obligation_id,
      quantity: qty,
      unit_price: unit,
      net_amount: +net.toFixed(2),
      vat_rate: vatRate,                                 // ✅ numeric
      vat_amount: vatAmt,
      total_amount: total                                // ✅ DB column is total_amount
    };
  }).filter(l => (l.item_name || l.description) && l.net_amount >= 0);

  // header totals based on your recalcInvoice()
  const totals = window.recalcInvoice?.() || {};
  const disc = parseFloat(document.getElementById("invDisc")?.value || "0") || 0;
  const other = parseFloat(document.getElementById("invOther")?.value || "0") || 0;

  return {
    id: invId || null,
    customer_id: customerId ? Number(customerId) : null,
    customer_name: customerName,
    revenue_contract_id: document.getElementById("invRevenueContractId")?.value || null,
    number,
    invoice_date: invoiceDate,         // ✅ DB column
    due_date: dueDate || null,         // ✅ DB column
    currency,

    notes,

    discount_amount: +disc.toFixed(2), // ✅ DB column exists
    // "other" not in your invoices table; either store it in notes or add column
    subtotal_amount: +((totals.subtotalAfterDisc ?? 0)).toFixed(2),
    vat_amount: +((totals.vatTotal ?? 0)).toFixed(2),
    total_amount: +((totals.grandTotal ?? 0)).toFixed(2),

    status: "draft",
    lines
  };
}

  // 🔹 Global uploader used by the SAVE handler
  async function buildDocAndUpload(input, idBase, label) {
    if (!input || !input.files || input.files.length === 0) {
      return { id: idBase, label, status: "missing", versions: [] };
    }

    const file = input.files[0];

    // 1) Upload to backend
    const fd = new FormData();
    fd.append("file", file);

    const token =
      localStorage.getItem("fs_user_token") ||
      sessionStorage.getItem("fs_user_token");

    const resp = await fetch("http://127.0.0.1:5000/api/uploads/kyc", {
      method: "POST",
      headers: token ? { Authorization: `Bearer ${token}` } : {},
      body: fd,
    });

    if (!resp.ok) {
      throw new Error("Upload failed");
    }

    const info = await resp.json(); // { url, name, mime }

    // 2) Build metadata with SERVER URL
    return {
      id: idBase,
      label,
      status: "uploaded",
      versions: [
        {
          url: info.url,                         // e.g. "/uploads/kyc/company_1/file.pdf"
          name: info.name || file.name,
          mime: info.mime,
          uploadedAt: new Date().toISOString(),
          uploadedBy: getUploaderEmail(),
        },
      ],
    };
  }

  // ----- Risk bar function (same idea as earlier) -----
  function applyRiskScore(score) {
    const bar   = document.getElementById("riskBarFill");
    const label = document.getElementById("riskLabel");
    const scoreEl = document.getElementById("riskScore");

    if (!bar || !label || !scoreEl) return;

    score = Math.max(0, Math.min(100, Number(score) || 0));
    scoreEl.textContent = score;
    CURRENT_KYC_STATE.riskScore = score;

    let level, colorClass, textClass, width;
    if (score <= 30) {
      level = "low";
      colorClass = "bg-emerald-500";
      textClass = "text-emerald-600";
      width = "w-1/3";
    } else if (score <= 60) {
      level = "medium";
      colorClass = "bg-amber-500";
      textClass = "text-amber-600";
      width = "w-2/3";
    } else {
      level = "high";
      colorClass = "bg-red-500";
      textClass = "text-red-600";
      width = "w-full";
    }

    CURRENT_KYC_STATE.riskLevel = level;

    bar.className = `h-2 rounded-full ${colorClass} ${width}`;
    label.textContent = level === "low" ? "Low risk" : level === "medium" ? "Medium risk" : "High risk";
    label.className = `text-[11px] font-semibold ${textClass}`;
  }

// Simple doc check: all 4 doc inputs must have files
function checkKycDocs() {
  const inc  = document.getElementById("doc-inc");
  const tax  = document.getElementById("doc-tax");
  const bank = document.getElementById("doc-bank");
  const id   = document.getElementById("doc-id");

  const updateStatus = (input, labelId) => {
    const label = document.getElementById(labelId);
    if (!label) return;
    const has = !!(input && input.files && input.files.length > 0);
    label.textContent = has ? "Uploaded" : "Missing";
    label.className = has ? "text-[10px] text-emerald-600" : "text-[10px] text-slate-400";
  };

  updateStatus(inc,  "docStatus-inc");
  updateStatus(tax,  "docStatus-tax");
  updateStatus(bank, "docStatus-bank");
  updateStatus(id,   "docStatus-id");

  const docsOk =
    (inc?.files?.length || 0) > 0 &&
    (tax?.files?.length || 0) > 0 &&
    (bank?.files?.length || 0) > 0 &&
    (id?.files?.length || 0) > 0;

  window.CURRENT_KYC_STATE = window.CURRENT_KYC_STATE || {};
  window.CURRENT_KYC_STATE.docsOk = !!docsOk;
  return window.CURRENT_KYC_STATE.docsOk;
}

function recomputeKycRisk() {
  window.CURRENT_KYC_STATE = window.CURRENT_KYC_STATE || {};

  const modal = document.getElementById("kycModal");
  if (!modal) return { score: 20, level: "low", docsOk: false, checksOk: false };

  // ✅ Your checkbox IDs
  const CHECKS = [
    "kycCreditLimitChecked",
    "kycBankStatements",
    "kycTradeRefs",
    "kycDebtorDays",
    "kycRiskScoreGenerated",
    "kycAmlCheck",
    "kycPepCheck",
    "kycBusinessLicense",
    "kycTaxCompliance",
  ];

  const checksState = {};
  let checkedCount = 0;

  CHECKS.forEach((id) => {
    const el = document.getElementById(id);
    const ok = !!el?.checked;
    checksState[id] = ok;
    if (ok) checkedCount += 1;
  });

  const totalChecks = CHECKS.length;
  const checksOk = totalChecks ? checkedCount === totalChecks : true;

  // Docs from existing function
  const docsOk = !!window.CURRENT_KYC_STATE.docsOk;

  // Optional red flags input
  const redFlags = (document.getElementById("kycRedFlags")?.value || "").trim();

  // Credit affects risk
  const creditRaw = document.getElementById("custCredit")?.value || "0";
  const credit = parseFloat(creditRaw) || 0;

  // Start from a baseline
  let score = 10;

  // Missing docs is heavy risk
  if (!docsOk) score += 45;

  // Missing checks adds risk proportionally
  const missingChecks = totalChecks - checkedCount;
  if (missingChecks > 0) score += Math.min(35, missingChecks * 5);

  // Red flags bump risk
  if (redFlags.length > 0) score += 15;

  // Credit requested bump risk
  if (credit >= 50000) score += 20;
  else if (credit >= 25000) score += 10;
  else if (credit > 0) score += 5;

  // Clamp
  score = Math.max(0, Math.min(100, score));

  const level = score >= 70 ? "high" : score >= 40 ? "medium" : "low";

  // Save into state
  window.CURRENT_KYC_STATE.riskScore = score;
  window.CURRENT_KYC_STATE.riskLevel = level;
  window.CURRENT_KYC_STATE.checksOk = checksOk;
  window.CURRENT_KYC_STATE.redFlags = redFlags;

  // ✅ Update UI elements
  const scoreEl = document.getElementById("riskScore");
  if (scoreEl) scoreEl.textContent = String(score);

  const labelEl = document.getElementById("riskLabel");
  if (labelEl) labelEl.textContent = level === "high" ? "High risk" : level === "medium" ? "Medium risk" : "Low risk";

  const bar = document.getElementById("riskBarFill");
  if (bar) bar.style.width = `${score}%`;

  // Optional: keep input synced (unless user is typing)
  const input = document.getElementById("kycRiskScoreInput");
  if (input && document.activeElement !== input) input.value = String(score);

  return { score, level, docsOk, checksOk, checkedCount, totalChecks, credit, redFlags };
}

// Enable/disable customer save button based on KYC state
function updateCustomerSubmitState() {
  const saveBtn   = document.getElementById("custSaveBtn");
  const reqBtn    = document.getElementById("custRequestApprovalBtn"); // ✅ your real id
  const statusEl  = document.getElementById("kycStatusText");
  if (!saveBtn) return;

  const payload = window.fsCustomerForm?.read?.() || {};

  const cid = window.FS?.control?.resolveCid
    ? window.FS.control.resolveCid()
    : (typeof window.getActiveCompanyId === "function" ? window.getActiveCompanyId() : null);

  const setDisabled = (btn, msg) => {
    if (!btn) return;
    btn.disabled = true;
    btn.className =
      "inline-flex items-center px-4 py-2 rounded-lg text-sm font-semibold bg-slate-300 text-slate-600 cursor-not-allowed";
    if (msg != null && statusEl) statusEl.textContent = msg || "";
  };

  const setEnabled = (btn, msg) => {
    if (!btn) return;
    btn.disabled = false;
    btn.className =
      "inline-flex items-center px-4 py-2 rounded-lg text-sm font-semibold bg-[var(--fs-teal)] text-white hover:bg-[#00b3b3]";
    if (msg != null && statusEl) statusEl.textContent = msg || "";
  };

  // -----------------------------
  // No company selected
  // -----------------------------
  if (!cid) {
    setDisabled(saveBtn, "Select a company to continue.");
    setDisabled(reqBtn);
    return;
  }

  const mode = FS?.control?.get ? FS.control.get(cid) : "owner_managed";

  // Ensure KYC state exists (DO NOT reset here)
  window.CURRENT_KYC_STATE = window.CURRENT_KYC_STATE || {
    completed: false,
    docsOk: false,
    checksOk: true,
    riskScore: 20,
    riskLevel: "low",
  };

  const p = window.CURRENT_COMPANY?.credit_policy || {};

  // requested credit
  const rawRequested = payload.creditLimit ?? payload.credit_limit ?? "";
  const requested = Number(String(rawRequested).replace(/,/g, "").trim()) || 0;

  // role / cap
  const roleRaw =
    window.currentUser?.role ||
    window.currentUser?.user_role ||
    window.currentUser?.user_role_name ||
    "";
  const role = String(roleRaw).toLowerCase().trim();
  const clerkCap = Number(p.clerk_request_cap ?? 0) || 0;

  // owner?
  const ownerId = window.CURRENT_COMPANY?.owner_user_id;
  const meId = window.currentUser?.id;
  const isOwnerUser =
    ownerId != null && meId != null && String(ownerId) === String(meId);

  // can approve? (uses your FS.policy gate)
  const canApprove =
    FS?.policy?.canApproveCustomer
      ? FS.policy.canApproveCustomer(role, cid)
      : false;

  // KYC required?
  const kycThreshold = Number(p.kyc_threshold ?? 0) || 0;
  const kycForAny = !!p.require_kyc_for_any_credit;
  const kycRequired =
    (kycForAny && requested > 0) ||
    (kycThreshold > 0 && requested >= kycThreshold);

  const docsOk = !!window.CURRENT_KYC_STATE.docsOk;
  const completed = !!window.CURRENT_KYC_STATE.completed;
  const checksOk =
    window.CURRENT_KYC_STATE.checksOk === undefined
      ? true
      : !!window.CURRENT_KYC_STATE.checksOk;

  const kycOk = completed && docsOk && checksOk;

  // approval threshold (message only)
  const approvalThreshold = Number(p.approval_threshold ?? 0) || 0;
  const approvalRequired = approvalThreshold > 0 && requested > approvalThreshold;

  // default: Request approval should generally be available (it can save draft first)
  // only disable it when customer already approved or when we *must* block (controlled + KYC missing)
  if (reqBtn) {
    const st = String(payload.credit_status || payload.creditStatus || "draft").toLowerCase();
    const approved = st === "approved";
    reqBtn.disabled = approved;
    reqBtn.classList.toggle("opacity-50", reqBtn.disabled);
  }

  // -----------------------------
  // Owner-managed
  // -----------------------------
  if (mode === FS.control.MODES.OWNER || mode === "owner_managed") {
    setEnabled(saveBtn, "Owner-managed mode: ready to save.");
    // optional: keep request approval disabled (not used in this mode)
    setDisabled(reqBtn);
    return;
  }

  // -----------------------------
  // Clerk cap (hard stop for both Save and Request)
  // -----------------------------
  if (role === "clerk" && clerkCap > 0 && requested > clerkCap) {
    setDisabled(saveBtn, `Clerk limit exceeded. Max allowed credit is ${clerkCap}.`);
    setDisabled(reqBtn);
    return;
  }

  // -----------------------------
  // CONTROLLED
  // Rules you wanted:
  // - KYC must be completed BEFORE Request approval (and before Save for owners/approvers)
  // - Non-owner/non-approver: Save disabled, Request approval enabled only after KYC (if required)
  // -----------------------------
  if (mode === FS.control.MODES.CONTROLLED || mode === "controlled") {
    // If KYC required and not ok -> block both (KYC is the gate in controlled)
    if (kycRequired && !kycOk) {
      setDisabled(saveBtn, "Controlled mode: KYC required. Run KYC check and save it, then request approval.");
      // request approval should also be blocked until KYC is done
      setDisabled(reqBtn);
      return;
    }

    // KYC is OK (or not required)
    if (isOwnerUser || canApprove) {
      // Owner/approver can save (your choice)
      setEnabled(
        saveBtn,
        approvalRequired
          ? "Controlled: KYC complete. Saving will route for approval (above threshold)."
          : "Controlled: KYC complete. You can save."
      );
      // allow request approval too (optional)
      setEnabled(
        reqBtn,
        approvalRequired
          ? "Controlled: You can request approval (above threshold)."
          : "Controlled: You can request approval."
      );
    } else {
      // Non-approver in controlled: must request approval, never direct save
      setDisabled(saveBtn, "Controlled mode: use Request approval (Save disabled).");
      setEnabled(
        reqBtn,
        approvalRequired
          ? "Submit for approval (above threshold)."
          : "Submit for approval."
      );
    }
    return;
  }

  // -----------------------------
  // ASSISTED
  // Rules you wanted:
  // - Non-owner/non-approver: Save disabled, use Request approval
  // - KYC not enforced (warn only)
  // -----------------------------
  if (mode === FS.control.MODES.ASSISTED || mode === "assisted") {
    if (isOwnerUser || canApprove) {
      setEnabled(
        saveBtn,
        kycRequired && !kycOk
          ? "Assisted: KYC recommended (not required). You can save."
          : approvalRequired
            ? "Assisted: You can save. Above threshold will route for approval."
            : "Assisted: Ready to save."
      );
      setEnabled(reqBtn, "You can also request approval.");
    } else {
      setDisabled(saveBtn, "Assisted mode: use Request approval (Save disabled).");
      setEnabled(
        reqBtn,
        kycRequired && !kycOk
          ? "Assisted: KYC recommended. You can still request approval."
          : approvalRequired
            ? "Submit for approval (above threshold)."
            : "Submit for approval."
      );
    }
    return;
  }

  // fallback
  setDisabled(saveBtn, "This action requires review/approval.");
  setEnabled(reqBtn, "Request approval.");
}
  // Open/close modal helpers
  function openKycModal() {
    const modal = document.getElementById("kycModal");
    if (!modal) return;

    modal.classList.remove("hidden");
    modal.classList.add("flex");

    // prefill submitted by with current user email if available
    const submittedBy = document.getElementById("kycSubmittedBy");
    if (submittedBy && window.currentUser && window.currentUser.email) {
      submittedBy.value = window.currentUser.email;
    }

    // apply current risk state
    applyRiskScore(CURRENT_KYC_STATE.riskScore || 20);
  }

  function closeKycModal() {
    const modal = document.getElementById("kycModal");
    if (!modal) return;
    modal.classList.add("hidden");
    modal.classList.remove("flex");
  }

  window.userCanApproveCustomers = userCanApproveCustomers;

function bindCustomersKyc() {
  // ✅ Always ensure global state exists FIRST
  const currentCustId =
    window.fsCustomerForm?.read?.()?.id ?? null;

  if (window.__KYC_BOUND_FOR_CUSTOMER_ID !== currentCustId) {
    window.__KYC_BOUND_FOR_CUSTOMER_ID = currentCustId;

    window.CURRENT_KYC_STATE = {
      completed: false,
      docsOk: false,
      checksOk: false,
      riskScore: 20,
      riskLevel: "low",
      redFlags: "",
      submittedBy: "",
    };
  }

  // ✅ If you want KYC to reset per new customer, reset here:
  window.CURRENT_KYC_STATE.completed = false;
  window.CURRENT_KYC_STATE.docsOk = false;
  window.CURRENT_KYC_STATE.checksOk = false;

  if (typeof updateCustomerSubmitState === "function") updateCustomerSubmitState();

  const screen = document.getElementById("screen-customers");
  if (screen && screen.dataset.kycBound === "1") return;
  if (screen) screen.dataset.kycBound = "1";

  console.log("bindCustomersKyc: starting wiring");

  const openBtn = document.getElementById("openKycBtn");
  const saveBtn = document.getElementById("custSaveBtn");

  if (!openBtn) {
    console.warn("bindCustomersKyc: openKycBtn not found – nothing to wire");
    return;
  }

  function refreshKycSaveState() {
    const btn = document.getElementById("kycSaveBtn");
    const modal = document.getElementById("kycModal");
    if (!btn || !modal) return;

    // docsOk
    window.CURRENT_KYC_STATE.docsOk = !!checkKycDocs();

    // ✅ keep state in sync
    const checks = Array.from(modal.querySelectorAll('input[type="checkbox"]'));
    window.CURRENT_KYC_STATE.checksOk = checks.length ? checks.every((c) => c.checked) : true;

    const ok = !!(window.CURRENT_KYC_STATE.docsOk && window.CURRENT_KYC_STATE.checksOk);

    btn.disabled = !ok;
    btn.classList.toggle("opacity-50", !ok);
    btn.classList.toggle("cursor-not-allowed", !ok);
  }

  function bindKycModalControls() {
    const modal = document.getElementById("kycModal");
    if (!modal) return;

    if (modal.dataset.bound === "1") return;
    modal.dataset.bound = "1";

    const closeX = document.getElementById("kycCloseBtn");
    const closeBtn = document.getElementById("kycCancelBtn");

    const wireClose = (el) => el?.addEventListener("click", (e) => {
      e.preventDefault();
      e.stopPropagation();
      closeKycModal();
    });

    wireClose(closeX);
    wireClose(closeBtn);

    function refreshAll() {
      checkKycDocs();

      // ✅ FIX: compute checksOk from modal checkboxes
      const checks = Array.from(modal.querySelectorAll('input[type="checkbox"]'));
      window.CURRENT_KYC_STATE.checksOk = checks.length ? checks.every(cb => cb.checked) : true;

      recomputeKycRisk();

      if (typeof updateCustomerSubmitState === "function") updateCustomerSubmitState();
      if (typeof refreshKycSaveState === "function") refreshKycSaveState();
    }

    // Risk input: allow manual override but keep UI updated
    const riskInput = document.getElementById("kycRiskScoreInput");
    riskInput?.addEventListener("input", (e) => {
      const v = Math.max(0, Math.min(100, Number(e.target.value || 0)));
      window.CURRENT_KYC_STATE.riskScore = v;
      window.CURRENT_KYC_STATE.riskLevel = v >= 70 ? "high" : v >= 40 ? "medium" : "low";

      // Update UI quickly
      const scoreEl = document.getElementById("riskScore");
      if (scoreEl) scoreEl.textContent = String(v);

      const labelEl = document.getElementById("riskLabel");
      if (labelEl) labelEl.textContent = v >= 70 ? "High risk" : v >= 40 ? "Medium risk" : "Low risk";

      const bar = document.getElementById("riskBarFill");
      if (bar) bar.style.width = `${v}%`;
    });

    // Doc inputs
    ["doc-inc", "doc-tax", "doc-bank", "doc-id"].forEach((id) => {
      document.getElementById(id)?.addEventListener("change", refreshAll);
    });

    // All checkboxes inside modal
    modal.querySelectorAll('input[type="checkbox"]').forEach((cb) => {
      cb.addEventListener("change", refreshAll);
    });

    // Save KYC button
    const kycSave = document.getElementById("kycSaveBtn");
    kycSave?.addEventListener("click", (e) => {
      // ensure latest state
      refreshAll();

      // Require docs + checks before completing
      const ok = !!(window.CURRENT_KYC_STATE.docsOk && window.CURRENT_KYC_STATE.checksOk);
      if (!ok) {
        e.preventDefault();
        alert("Please complete all checks and upload all required documents before saving KYC.");
        return;
      }

      window.CURRENT_KYC_STATE.completed = true;

      if (typeof updateCustomerSubmitState === "function") updateCustomerSubmitState();
      closeKycModal();
    });

    // initial render
    refreshAll();
  }

    // ─────────────────────────────
    // 1) Open KYC modal from "Run KYC check"
    // ─────────────────────────────
    openBtn.addEventListener("click", (e) => {
      e.preventDefault();
      openKycModal();
      bindKycModalControls(); // binds once
    });

    // ─────────────────────────────
    // 3) Intercept SAVE button (company-aware, FS.policy based)
    // ─────────────────────────────
    if (saveBtn) {
      saveBtn.addEventListener(
        "click",
        async (e) => {
          const cid =
            (typeof getActiveCompanyId === "function" ? getActiveCompanyId() : null) ||
            (typeof CURRENT_COMPANY_ID !== "undefined" ? CURRENT_COMPANY_ID : null) ||
            null;

          // If no company selected yet, block (and let updateCustomerSubmitState show message)
          if (!cid) {
            e.preventDefault();
            e.stopPropagation();
            e.stopImmediatePropagation();
            alert("Please select a company before saving a customer.");
            return;
          }

          const baseCustomer =
            (window.fsCustomerForm && window.fsCustomerForm.read
              ? window.fsCustomerForm.read()
              : {}) || {};

          // Decide whether approval / KYC is required
          const needsApproval = !!FS?.policy?.requireCustomerApproval
            ? !!FS.policy.requireCustomerApproval(baseCustomer, cid)
            : true;

          const needsKyc = !!FS?.policy?.requireKycForCustomerSave
            ? !!FS.policy.requireKycForCustomerSave(baseCustomer, cid)
            : false;

          // ✅ If neither approval nor KYC is required, do NOT intercept (let normal Save run)
          if (!needsApproval && !needsKyc) return;

          // From here: assisted/controlled flow
          const role = typeof getCurrentRole === "function" ? getCurrentRole() : "";

          // 🔐 Clerks (or non-approvers): they submit to credit, must NOT call /customers directly
          if (typeof userCanApproveCustomers === "function" && !userCanApproveCustomers()) {
            e.preventDefault();
            e.stopPropagation();
            e.stopImmediatePropagation();

            // Enforce KYC completion before submit
            if (needsKyc) {
              if (!CURRENT_KYC_STATE.completed || !CURRENT_KYC_STATE.docsOk) {
                alert("KYC is required. Click 'Run KYC check' to complete it.");
                return;
              }
            }

            const createdBy =
              (window.currentUser && window.currentUser.email) ||
              localStorage.getItem("userEmail") ||
              "";

            // STEP 1: If brand-new customer (no id), create it first (still under the correct company)
            let workingCustomer = { ...baseCustomer };

            if (!workingCustomer.id) {
              try {
                const customerPayload = {
                  ...workingCustomer,
                  credit_status: "pending",
                };

                const created = await apiFetch(ENDPOINTS.customers(cid), {
                  method: "POST",
                  headers: { "Content-Type": "application/json" },
                  body: JSON.stringify(customerPayload),
                });

                if (created && created.id) {
                  workingCustomer.id = created.id;
                  console.log("New customer created for KYC:", created);
                } else {
                  alert("Customer could not be created – please try again.");
                  return;
                }
              } catch (err) {
                console.error("Error creating customer before KYC:", err);
                alert("Error creating customer. KYC was not submitted.");
                return;
              }
            }

            // STEP 1.5: Upload KYC docs
            try {
              const inc = document.getElementById("doc-inc");
              const tax = document.getElementById("doc-tax");
              const bank = document.getElementById("doc-bank");
              const id = document.getElementById("doc-id");

              const docsMeta = await Promise.all([
                buildDocAndUpload(inc, "doc-inc", "Certificate of Incorporation"),
                buildDocAndUpload(tax, "doc-tax", "Tax documents / Tax clearance"),
                buildDocAndUpload(bank, "doc-bank", "Bank letter / bank statement"),
                buildDocAndUpload(id, "doc-id", "Director IDs & proof of address"),
              ]);

              CURRENT_KYC_STATE.documents = docsMeta;
              CURRENT_KYC_STATE.docsOk = docsMeta.every((d) => d.status === "uploaded");
            } catch (uploadErr) {
              console.error("KYC upload error:", uploadErr);
              alert("Error uploading KYC documents. Please try again.");
              return;
            }

            const credit =
              parseFloat(
                workingCustomer.creditLimit || workingCustomer.credit_limit || "0"
              ) || 0;

            // STEP 2: Build KYC / credit profile payload
            const profilePayload = {
              ...workingCustomer,
              requestedLimit: credit,
              createdBy,
              createdAt: new Date().toISOString(),
              status: "pending_senior",
              kyc: {
                ...CURRENT_KYC_STATE,
                documents: CURRENT_KYC_STATE.documents || [],
              },
            };

            const body = {
              customerId: workingCustomer.id,
              payload: profilePayload,
            };

            console.log("Submitting KYC record to backend:", body);

            try {
              const saved = await apiFetch(ENDPOINTS.credit.submit, {
                method: "POST",
                body: JSON.stringify(body),
                // headers not needed – apiFetch adds JSON + Auth
              });

              if (typeof updateKycDashboardBadges === "function") {
                updateKycDashboardBadges();
              }
              if (typeof sendKycNotification === "function") {
                sendKycNotification("submitted", saved);
              }

              alert("Customer submitted for approval. It will be visible once approved.");
            } catch (err) {
              console.error("credit.submit error", err);
              alert("Error submitting KYC to backend.");
            }

            return; // do not fall through
          }

          // Approvers (senior/CFO/admin): let normal save handler run
          // (no preventDefault)
        },
        { capture: true }
      );
    }
  }

    // =====================================
    // Used by Credit Control "Review customer" button
    // → open the DOCUMENT VIEWER approval panel, not the clerk modal
    // =====================================
