    // ==============================
    // Document Preview Helpers
    // ==============================
    function openDocPreview(url, name) {
      if (!url) {
        alert("No document URL available for this record.");
        return;
      }

      const isBlob = url.startsWith("blob:");

      // If backend returns a relative path, serve it from Flask (5000)
      if (!isBlob && url.startsWith("/")) {
        url = `http://127.0.0.1:5000${url}`;
      }

      // Only attach token for real HTTP(S) URLs, NOT for blob:
      const isHttp = url.startsWith("http://") || url.startsWith("https://");
      if (isHttp) {
        const token =
          localStorage.getItem("fs_user_token") ||
          sessionStorage.getItem("fs_user_token");

        if (token) {
          const sep = url.includes("?") ? "&" : "?";
          url = `${url}${sep}token=${encodeURIComponent(token)}`;
        }
      }

      const modal = document.getElementById("docPreviewModal");
      const titleEl = document.getElementById("docPreviewTitle");
      const bodyEl = document.getElementById("docPreviewBody");
      const closeBtn = document.getElementById("docPreviewClose");

      if (!modal || !titleEl || !bodyEl || !closeBtn) {
        // fallback: open in new tab
        window.open(url, "_blank", "noopener");
        return;
      }

      titleEl.textContent = name || "Document preview";

      const lower = url.toLowerCase();
      const isPdf =
        lower.endsWith(".pdf") ||
        lower.includes(".pdf?") ||
        lower.includes(".pdf#");

      if (isPdf) {
        bodyEl.innerHTML = `<iframe src="${url}" class="w-full h-full border-0"></iframe>`;
      } else {
        bodyEl.innerHTML = `
          <div class="p-4 text-sm">
            <p class="mb-3">
              This file type cannot be previewed here.
              Click below to open/download it.
            </p>
            <a href="${url}" target="_blank" rel="noopener"
              class="inline-flex items-center px-3 py-1 rounded bg-blue-600 text-white text-xs hover:bg-blue-700">
              Open document in new tab
            </a>
          </div>
        `;
      }

      modal.classList.remove("hidden");

      const closeModal = () => {
        modal.classList.add("hidden");
        bodyEl.innerHTML = "";
      };

      closeBtn.onclick = closeModal;
      modal.onclick = (e) => {
        if (e.target === modal) closeModal();
      };
    }

    function closeDocPreview() {
      const modal = document.getElementById("docPreviewModal");
      const frame = document.getElementById("docPreviewFrame");
      if (!modal || !frame) return;

      frame.src = "about:blank";
      modal.classList.add("hidden");
      modal.classList.remove("flex");
    }

  // Wire close actions once DOM is ready
  window.addEventListener("load", () => {
    document.getElementById("docPreviewClose")?.addEventListener("click", closeDocPreview);

    document.getElementById("docPreviewModal")?.addEventListener("click", (e) => {
      if (e.target.id === "docPreviewModal") closeDocPreview();
    });
  }); // ✅ ADD THIS LINE (closes the load handler)

async function bindCustomerApprovals() {
  console.log("bindCustomerApprovals: loading from backend");

  const listHost = document.getElementById("custApprovalList");
  if (!listHost) {
    console.warn("bindCustomerApprovals: custApprovalList not found");
    return;
  }

  try {
    const items = await fetchPendingApprovals();  // 👈 use helper

    if (!items.length) {
      listHost.innerHTML = `
        <div class="text-sm text-slate-500">
          No pending customer approvals.
          <div class="text-[11px] text-slate-400 mt-1">
            When team members submit new customers for approval, 
            they will appear here for Credit Control / Senior review.
          </div>
        </div>`;
      return;
    }

    listHost.innerHTML = items.map((d) => `
      <button
        type="button"
        class="w-full text-left px-3 py-2 mb-2 border rounded hover:bg-slate-50"
        data-profile-id="${d.id}"
      >
        <div class="flex items-center justify-between">
          <div class="font-medium">
            ${d.customerName || d.name || "(No name)"}
          </div>
          <div class="text-[10px] px-2 py-0.5 rounded-full bg-amber-50 text-amber-700 border border-amber-100">
            ${(d.status || "pending").replace("_", " ")}
          </div>
        </div>
        <div class="text-xs text-slate-500">
          ${d.email || d.customerEmail || ""}
        </div>
        <div class="text-[11px] text-slate-400 mt-0.5">
          Submitted by ${d.createdBy || "unknown"}
          ${d.createdAt ? "· " + new Date(d.createdAt).toLocaleDateString() : ""}
        </div>
      </button>
    `).join("");

    listHost.querySelectorAll("[data-profile-id]").forEach((btn) => {
      btn.addEventListener("click", () => {
        const id = btn.getAttribute("data-profile-id");
        if (id) openApprovalFormForProfile(parseInt(id, 10));
      });
    });
  } catch (err) {
    console.error("bindCustomerApprovals error:", err);
    listHost.innerHTML =
      '<div class="text-xs text-red-500 mt-2">Error loading approvals.</div>';
  }
}

window.bindCustomerApprovals = bindCustomerApprovals;

