// Enable/disable Approve button based on doc decisions
function updateKycApproveButtonState() {
  const approveBtn = document.getElementById("kycApproveBtn");
  if (!approveBtn) return;

  const selects = Array.from(
    document.querySelectorAll("#kycDocTableBody .kyc-doc-decision")
  );

  // 🔒 If there are NO document rows, do NOT allow approval
  if (!selects.length) {
    approveBtn.disabled = true;
    approveBtn.classList.add("cursor-not-allowed", "bg-emerald-600/60");
    approveBtn.classList.remove("bg-emerald-600");
    return;
  }

  const allSelected = selects.every((s) => s.value);
  const allApproved = selects.every((s) => s.value === "approved");

  const canApprove = allSelected && allApproved;

  approveBtn.disabled = !canApprove;
  approveBtn.classList.toggle("cursor-not-allowed", !canApprove);
  approveBtn.classList.toggle("bg-emerald-600/60", !canApprove);
  approveBtn.classList.toggle("bg-emerald-600", canApprove);
}


// Render doc rows (with Preview link + decision + note)
function renderKycDocRows(docs) {
  const tbody = document.getElementById("kycDocTableBody");
  if (!tbody) return;

  tbody.innerHTML = "";

  // 📝 If there are no docs, show a friendly message row
  if (!docs || !docs.length) {
    tbody.innerHTML = `
      <tr>
        <td colspan="4" class="px-2 py-2 text-[11px] text-slate-400">
          No KYC documents are attached to this record.
        </td>
      </tr>
    `;
    updateKycApproveButtonState(); // will keep Approve disabled
    return;
  }

  docs.forEach((doc, index) => {
    const latest =
      (doc.versions && doc.versions[doc.versions.length - 1]) || null;

    const docId    = doc.id ?? (index + 1);
    const docLabel = doc.label || doc.type || ("Document " + (index + 1));

    const hasFile = !!(latest && latest.url);
    const url     = latest ? latest.url : null;
    const name    = latest ? (latest.name || docLabel) : docLabel;

    const tr = document.createElement("tr");
    tr.className = "border-b";
    tr.dataset.docId    = docId;
    tr.dataset.docLabel = docLabel;

    tr.innerHTML = `
      <td class="px-2 py-1 align-top">
        <div class="font-medium">${docLabel}</div>
        ${
          latest && latest.name
            ? `<div class="text-[10px] text-slate-500">${latest.name}</div>`
            : ""
        }
      </td>
      <td class="px-2 py-1 align-top">
        ${
          hasFile
            ? `<button type="button"
                       class="text-[11px] text-blue-600 underline"
                       data-doc-url="${url}"
                       data-doc-name="${name}">
                 Preview
               </button>`
            : `<span class="text-[11px] text-slate-400">No file</span>`
        }
      </td>
      <td class="px-2 py-1 align-top">
        <select
          class="kyc-doc-decision border rounded px-1 py-0.5 text-[11px]"
          data-doc-id="${docId}">
          <option value="">Select…</option>
          <option value="approved">Approve</option>
          <option value="rework">Return for rework</option>
          <option value="rejected">Reject</option>
        </select>
      </td>
      <td class="px-2 py-1 align-top">
        <input
          type="text"
          class="kyc-doc-note border rounded px-1 py-0.5 text-[11px] w-full"
          placeholder="Note (optional)" />
      </td>
    `;

    tbody.appendChild(tr);
  });

  // Wire Preview buttons
  tbody.querySelectorAll("[data-doc-url]").forEach((btn) => {
    btn.addEventListener("click", () => {
      const url = btn.getAttribute("data-doc-url");
      const name = btn.getAttribute("data-doc-name") || "Document";
      openDocPreview(url, name);
    });
  });

  // Re-evaluate Approve whenever a decision changes
  tbody.querySelectorAll(".kyc-doc-decision").forEach((sel) => {
    sel.addEventListener("change", updateKycApproveButtonState);
  });

  updateKycApproveButtonState();
}

