// Read per-document decisions from the approval table
function collectKycDocDecisionsFromTable() {
  const rows = document.querySelectorAll("#kycDocTableBody tr");
  return Array.from(rows).map((row, idx) => {
    const select = row.querySelector(".kyc-doc-decision");
    const note   = row.querySelector(".kyc-doc-note");

    const docId    = select?.dataset.docId || row.dataset.docId || (idx + 1);
    const docLabel = row.dataset.docLabel || "";

    return {
      document_id: docId,
      label: docLabel,
      decision: select ? select.value : "",
      note: note ? note.value.trim() : ""
    };
  });
}

function renderKycApprovalDetail(rec) {
  const panel = document.getElementById("custApprovalDetail");
  if (!panel) return;

  panel.classList.remove("hidden");

  const riskScore = rec.kyc?.riskScore ?? "—";
  const riskLevel = rec.kyc?.riskLevel ?? "—";
  const submittedBy =
    rec.kyc?.submittedBy || rec.createdBy || "";
  const submittedOn = rec.createdAt
    ? new Date(rec.createdAt).toLocaleDateString()
    : "";

  const requestedLimitRaw =
    rec.requestedLimit ?? rec.kyc?.requestedLimit ?? 0;
  const requestedLimitNumber = Number(requestedLimitRaw) || 0;

  const nameEl        = document.getElementById("kycCustName");
  const submittedByEl = document.getElementById("kycSubmittedByText");
  const riskScoreEl   = document.getElementById("kycRiskScoreText");
  const riskLevelEl   = document.getElementById("kycRiskLevelText");
  const limitEl       = document.getElementById("kycRequestedLimitText");

  // 🔹 NEW: identifier spans
  const regEl  = document.getElementById("kycRegNo");
  const taxEl  = document.getElementById("kycTaxNo");
  const vatEl  = document.getElementById("kycVatNo");

  if (nameEl)        nameEl.textContent        = rec.name || "(No name)";
  if (submittedByEl) submittedByEl.textContent = submittedBy || "unknown";
  if (riskScoreEl)   riskScoreEl.textContent   = riskScore;
  if (riskLevelEl)   riskLevelEl.textContent   = riskLevel;
  if (limitEl)       limitEl.textContent       = "ZAR " + requestedLimitNumber.toFixed(2);

  if (regEl) regEl.textContent = rec.regNo || "—";
  if (taxEl) taxEl.textContent = rec.taxNo || "—";
  if (vatEl) vatEl.textContent = rec.vatNo || "—";

  // Optional: submitted date text if you want it in HTML later
  const submittedOnEl = document.getElementById("kycSubmittedOnText");
  if (submittedOnEl) {
    submittedOnEl.textContent = submittedOn ? " on " + submittedOn : "";
  }

  // --- Documents ---
  const docs = rec.kyc?.documents || [];
  renderKycDocRows(docs);        // fill <tbody id="kycDocTableBody">

  // --- Buttons for this record ---
  const approveBtn = document.getElementById("kycApproveBtn");
  const reworkBtn  = document.getElementById("kycReturnBtn");
  const rejectBtn  = document.getElementById("kycRejectBtn");

  if (approveBtn) {
    approveBtn.onclick = () => finishCustomerKyc(rec, "approved");
  }
  if (reworkBtn) {
    reworkBtn.onclick = () => finishCustomerKyc(rec, "rework");
  }
  if (rejectBtn) {
    rejectBtn.onclick = () => finishCustomerKyc(rec, "rejected");
  }

  // Ensure Approve starts in correct disabled state
  updateKycApproveButtonState();
}

