// Optional: send receipt after payment
async function sendReceiptEmail(invoice, payment) {
  const cid = getActiveCompanyId();
  const toEmail =
    invoice.contact_email ||
    invoice.customer_email ||
    "";

  if (!toEmail) {
    console.warn("No email on invoice/customer, skipping receipt email.");
    return;
  }

  const ccEmail = invoice.company_email || "";

  await apiFetch(
    ENDPOINTS.invoiceEmailReceipt(cid, invoice.id),
    {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        payment_id: payment.id || null,
        to: toEmail,
        cc: ccEmail || undefined,
      }),
    }
  );
}

function formatNumberWithCommas(n) {
  const x = Number(String(n).replace(/,/g, ""));
  if (!Number.isFinite(x)) return "";
  return new Intl.NumberFormat("en-ZA", {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  }).format(x);
}

const AMT_SELECTOR = "#amt"; // ✅ CHANGE to your input selector

document.addEventListener("focusin", (e) => {
  const amtEl = e.target.closest?.(AMT_SELECTOR);
  if (!amtEl) return;
  amtEl.value = String(amtEl.value || "").replace(/,/g, "");
});

document.addEventListener("focusout", (e) => {
  const amtEl = e.target.closest?.(AMT_SELECTOR);
  if (!amtEl) return;
  amtEl.value = formatNumberWithCommas(amtEl.value);
});

document.addEventListener("input", (e) => {
  const amtEl = e.target.closest?.(AMT_SELECTOR);
  if (!amtEl) return;

  let v = String(amtEl.value || "").replace(/[^\d.]/g, "");
  const p = v.split(".");
  if (p.length > 2) v = p[0] + "." + p.slice(1).join("");
  const [a, b] = v.split(".");
  if (b != null) v = a + "." + b.slice(0, 2);
  amtEl.value = v;
});


