window.requestLeaseApproval = async function requestLeaseApproval({
  cid,
  lease_id,
  action,         // "lease_modify" | "lease_terminate" | "lease_pay"
  lease_name,
  amount = 0,
  currency = null,
  payload_json = {},

  // change ids (mods/terms)
  mod_id = null,
  term_id = null,
} = {}) {
  if (!cid) throw new Error("Missing cid");
  if (!lease_id) throw new Error("Missing lease_id");
  if (!window.ENDPOINTS?.approvals?.create) throw new Error("Missing ENDPOINTS.approvals.create");

  const leaseIdStr = String(lease_id);

  // ✅ Put payKey OUTSIDE the JSON body object
  const payKey =
    (payload_json && (payload_json.payment_id || payload_json.schedule_id || payload_json.payment_date)) || "";

  const mergedPayload = {
    ...(payload_json || {}),
    lease_id: Number(lease_id),
    mod_id: mod_id ? Number(mod_id) : null,
    term_id: term_id ? Number(term_id) : null,
  };

  return await apiFetch(ENDPOINTS.approvals.create(cid), {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      module: "ifrs16",
      action,
      entity_type: "lease",
      entity_id: leaseIdStr,
      entity_ref: lease_name || `Lease ${leaseIdStr}`,
      amount: Number(amount || 0),
      currency: currency || window.CURRENT_COMPANY?.base_currency || "ZAR",
      risk_level: "medium",

      // ✅ valid now
      dedupe_key: `ifrs16:lease:${leaseIdStr}:${action}:${String(payKey)}`,

      payload_json: mergedPayload,
    }),
  });
};

async function postLeaseMonthForPaymentIfNeeded(cid, lease_id, payment_date) {
  if (!cid || !lease_id || !payment_date) return null;

  // 1) Find current period for that lease "as_of" payment date
  const row = await fetchLeaseMonthPreviewForDate(cid, lease_id, payment_date);
  const periodNo = Number(row?.period_no || 0) || null;
  if (!periodNo) return null;

  // 2) Commit monthly posting (interest + depreciation)
  const out = await apiFetch(
    ENDPOINTS.leases.postMonth(cid, lease_id, periodNo),
    { method: "POST" }
  );

  // ✅ If review required, treat as a normal "created approval request" outcome
  if (out?.ok === false && String(out?.error || "").toUpperCase() === "REVIEW_REQUIRED") {
    return {
      ok: false,
      periodNo,
      row,
      review_required: true,
      approval_request: out?.approval_request || null,
      journal_id: null,
    };
  }

  // ✅ Success
  return {
    ok: true,
    periodNo,
    row,
    review_required: false,
    // try common ids your server may return
    journal_id: out?.journal_id || out?.posted_journal_id || out?.month_journal_id || null,
  };
}

async function renderApprovalsScreen(meta = {}) {
  const cid = getActiveCompanyId?.() || CURRENT_COMPANY_ID;
  if (!cid) return;

  if (!window.ENDPOINTS?.approvals) {
    const el0 = controlsPanel();
    if (el0) el0.innerHTML = `<div class="text-sm text-rose-600">Missing ENDPOINTS.approvals.*</div>`;
    return;
  }

  const el = controlsPanel();
  if (!el) return;

  el.innerHTML = `
    <div class="flex items-center justify-between mb-3">
      <div>
        <div class="text-sm font-semibold">Approvals</div>
        <div class="text-xs text-slate-500">Decide requests (approve/reject/cancel/comment)</div>
      </div>
      <div class="flex items-center gap-2">
        <select id="apprStatus" class="border rounded px-2 py-1 text-xs">
          <option value="pending">Pending</option>
          <option value="approved">Approved</option>
          <option value="rejected">Rejected</option>
          <option value="cancelled">Cancelled</option>
          <option value="">All</option>
        </select>
          <select id="apprModule" class="border rounded px-2 py-1 text-xs">
            <option value="">All modules</option>
            <option value="gl">GL</option>
            <option value="ap">AP</option>
            <option value="ar">AR</option>
            <option value="credit">Credit</option>
            <option value="leases">Leases</option>
            <option value="ppe">PPE</option>
            <option value="control_room">Control Room</option>
            <option value="loans">Loans</option>
            <option value="revenue">Revenue</option>
          </select>
        <button id="apprReload" class="px-3 py-1.5 text-xs rounded border">Reload</button>
      </div>
    </div>

    <div id="apprMsg" class="text-xs text-slate-500 mb-2"></div>
    <div id="apprList" class="space-y-2"></div>

    <!-- decide modal -->
    <div id="apprDecideModal" class="hidden fixed inset-0 z-[120] bg-black/30 items-center justify-center">
      <div class="bg-white w-[520px] max-w-[95vw] rounded-xl shadow-xl border p-4">
        <div class="flex items-center justify-between">
          <div class="text-sm font-semibold">Decide approval</div>
          <button id="apprDecideClose" class="text-xs px-2 py-1 border rounded">Close</button>
        </div>

        <div id="apprDecideBody" class="mt-3 text-xs"></div>

        <div class="mt-3 space-y-2">
          <label class="block text-xs text-slate-600">Decision</label>
          <select id="apprDecision" class="w-full border rounded px-2 py-1 text-xs">
            <option value="approve">Approve</option>
            <option value="reject">Reject</option>
            <option value="comment">Comment</option>
            <option value="cancel">Cancel</option>
            <option value="reassign">Reassign</option>
          </select>

          <label class="block text-xs text-slate-600">Note</label>
          <textarea id="apprNote" class="w-full border rounded px-2 py-1 text-xs" rows="3"></textarea>

          <div class="flex items-center justify-end gap-2 pt-2">
            <button id="apprDecideSave" class="px-3 py-1.5 text-xs rounded bg-[var(--fs-navy)] text-white">Save</button>
          </div>
          <div id="apprDecideMsg" class="text-xs text-rose-600"></div>
        </div>
      </div>
    </div>
  `;

  const statusEl = el.querySelector("#apprStatus");
  const moduleEl = el.querySelector("#apprModule");
  const listEl   = el.querySelector("#apprList");
  const msgEl    = el.querySelector("#apprMsg");

  if (meta.status != null) statusEl.value = meta.status;
  if (meta.module != null) moduleEl.value = meta.module;

  // history cache per request_id
  const histCache = new Map();

  async function load() {
    msgEl.textContent = "Loading…";
    listEl.innerHTML = "";

    const status = statusEl.value;
    const module = moduleEl.value;

    const data = await apiFetch(ENDPOINTS.approvals.list(cid, { status, module, limit: 50, offset: 0 }));
    const items = data?.items || [];

    msgEl.textContent = `${items.length} item(s)`;

    if (!items.length) {
      listEl.innerHTML = `<div class="text-xs text-slate-500">No approvals found.</div>`;
      return;
    }

    listEl.innerHTML = items.map(r => {
      const rid = r.id;

    // normalize values for easier comparisons 
    const mod = String(r.module || "").toLowerCase(); 
    const act = String(r.action || "").toLowerCase(); 
    const et = String(r.entity_type || "").toLowerCase();

    const isCustApproval =
      String(r.module || "").toLowerCase() === "ar" &&
      String(r.action || "").toLowerCase() === "approve_customer" &&
      String(r.entity_type || "").toLowerCase() === "customer";

    const isKycApproval =
      String(r.module || "").toLowerCase() === "credit" &&
      String(r.action || "").toLowerCase() === "kyc_customer" &&
      String(r.entity_type || "").toLowerCase() === "credit_profile";
      
    const isInvApproval =
      String(r.module || "").toLowerCase() === "ar" &&
      ["approve_post_invoice", "post_invoice"].includes(String(r.action || "").toLowerCase()) &&
      String(r.entity_type || "").toLowerCase() === "invoice";

    const isLeaseApproval =
      String(r.module || "").toLowerCase() === "ifrs16" &&
      ["lease_modify","lease_terminate"].includes(String(r.action || "").toLowerCase()) &&
      String(r.entity_type || "").toLowerCase() === "lease";

    const isLeasePayApproval =
      mod === "ifrs16" &&
      act === "lease_pay" &&
      et === "lease";
      
    const isQuoteIssueApproval =
      String(r.module || "").toLowerCase() === "ar" &&
      String(r.action || "").toLowerCase() === "quote_issue" &&
      String(r.entity_type || "").toLowerCase() === "quote";

    const isQuoteAcceptApproval =
      String(r.module || "").toLowerCase() === "ar" &&
      String(r.action || "").toLowerCase() === "quote_accept" &&
      String(r.entity_type || "").toLowerCase() === "quote";
      
    const isApAllocApproval =
      String(r.module || "").toLowerCase() === "ap" &&
      String(r.action || "").toLowerCase() === "allocate_bill_payment" &&
      String(r.entity_type || "").toLowerCase() === "bill";

    const isApReleaseApproval =
      String(r.module || "").toLowerCase() === "ap" &&
      String(r.action || "").toLowerCase() === "release_payment" &&
      ["vendor_payment","payment"].includes(String(r.entity_type || "").toLowerCase());

    const isPpeDeprBatchApproval =
      mod === "ppe" &&
      ["approve_depreciation","approve_post_depreciation_batch","post_depreciation_batch"].includes(act) &&
      et === "depreciation_batch";

    const isPpeDisposalApproval =
      mod === "ppe" && act.includes("disposal");

    const isPpeImpairmentApproval =
      mod === "ppe" && act.includes("impairment");

    const isPpeRevalApproval =
      mod === "ppe" && act.includes("revaluation");

    const isPpeHfsApproval =
      mod === "ppe" && (act.includes("hfs") || act.includes("held_for_sale"));

    const isPpeTransferApproval =
      mod === "ppe" && act.includes("transfer");

    const isLoanCreateApproval =
      mod === "loans" &&
      act === "create_loan" &&
      et === "loan";

    const isLoanPaymentApproval =
      mod === "loans" &&
      ["post_loan_payment", "release_loan_payment", "create_loan_payment"].includes(act) &&
      et === "loan_payment";

    const isLoanReclassApproval =
      mod === "loans" &&
      act === "post_loan_reclassification" &&
      et === "loan";

    const isLoanModificationApproval =
      mod === "loans" &&
      act === "post_loan_modification" &&
      et === "loan";

    const isLoanSettlementApproval =
      mod === "loans" &&
      act === "post_loan_settlement" &&
      et === "loan";
      
    const isRevenueRunApproval =
      mod === "revenue" &&
      ["post_recognition_run", "reverse_recognition_run"].includes(act) &&
      et === "revenue_run";

    const isRevenueContractApproval =
      mod === "revenue" &&
      ["create_contract", "approve_modification", "modify_contract"].includes(act) &&
      et === "revenue_contract";

      // ✅ decide which primary action button to show
      let actionBtn = `<button class="apprDecideBtn px-3 py-1.5 text-xs rounded border" data-id="${esc(rid)}">Decide</button>`;

      // Customer / Invoice approvals keep their special Review buttons
      if (isCustApproval || isInvApproval) {
        actionBtn = `
          <button class="${isInvApproval ? "apprReviewInv" : "apprReviewCust"} px-3 py-1.5 text-xs rounded bg-[var(--fs-navy)] text-white"
            data-id="${esc(rid)}"
            data-entity="${esc(r.entity_id)}"
          >Review</button>
        `;
      }

      else if (isKycApproval) {
        actionBtn = `
          <button class="apprOpenKyc px-3 py-1.5 text-xs rounded bg-[var(--fs-navy)] text-white"
            data-id="${esc(rid)}"
            data-profile-id="${esc(String(r.entity_id || ""))}"
          >Review</button>
        `;
      }

      // Lease modify / terminate approvals -> Open lease context
      else if (isLeaseApproval) {
        actionBtn = `
          <button class="apprOpenLease px-3 py-1.5 text-xs rounded bg-[var(--fs-navy)] text-white"
            data-approval-open="1"
            data-approval-action="${esc(String(r.action || ""))}"
            data-lease-id="${esc(String(r.entity_id || ""))}"
            data-mod-id="${esc(String(r.payload_json?.mod_id || ""))}"
            data-term-id="${esc(String(r.payload_json?.term_id || ""))}"
          >Review</button>
        `;
      }

      // Lease payment approvals -> Open payments screen / modal flow
      else if (isLeasePayApproval) {
        actionBtn = `
          <button class="apprDecideBtn px-3 py-1.5 text-xs rounded border"
            data-id="${esc(rid)}"
          >Decide</button>
        `;
      }
      
      // Quote issue approvals -> open quote viewer
      else if (isQuoteIssueApproval) {
        actionBtn = `
          <button class="apprOpenQuoteIssue px-3 py-1.5 text-xs rounded bg-[var(--fs-navy)] text-white"
            data-id="${esc(rid)}"
            data-quote-id="${esc(String(r.entity_id || ""))}"
          >Review</button>
        `;
      }

      // Quote accept approvals -> open quote viewer
      else if (isQuoteAcceptApproval) {
        actionBtn = `
          <button class="apprOpenQuoteAccept px-3 py-1.5 text-xs rounded bg-[var(--fs-navy)] text-white"
            data-id="${esc(rid)}"
            data-quote-id="${esc(String(r.entity_id || ""))}"
          >Review</button>
        `;
      }

      else if (isApAllocApproval) {
        const pj = r.payload_json || {};
        actionBtn = `
          <button class="apprReviewApAlloc px-3 py-1.5 text-xs rounded bg-[var(--fs-navy)] text-white"
            data-id="${esc(rid)}"
            data-bill-id="${esc(String(pj.bill_id || r.entity_id || ""))}"
            data-payment-id="${esc(String(pj.payment_id || ""))}"
            data-amount="${esc(String(pj.amount || ""))}"
          >Review</button>
        `;
      }

      else if (isApReleaseApproval) {
        actionBtn = `
          <button class="apprOpenApRelease px-3 py-1.5 text-xs rounded bg-[var(--fs-navy)] text-white"
            data-request-id="${esc(rid)}"
            data-payment-id="${esc(String(r.entity_id || ""))}"
          >Review</button>
        `;
      }

      else if (isPpeDeprBatchApproval) {
        const pj = r.payload_json || {};
        actionBtn = `
          <button class="apprReviewPpeDepr px-3 py-1.5 text-xs rounded bg-[var(--fs-navy)] text-white"
            data-request-id="${esc(rid)}"
            data-dep-ids="${esc(JSON.stringify(pj.dep_ids || []))}"
            data-period-end="${esc(String(pj.period_end || ""))}"
          >Review</button>
        `;
      }

      else if (
        isLoanCreateApproval ||
        isLoanPaymentApproval ||
        isLoanReclassApproval ||
        isLoanModificationApproval ||
        isLoanSettlementApproval
      ) {
        actionBtn = `
          <button class="apprOpenLoanReview px-3 py-1.5 text-xs rounded bg-[var(--fs-navy)] text-white"
            data-id="${esc(rid)}"
            data-loan-id="${esc(String(r.entity_id || ""))}"
            data-action="${esc(String(r.action || ""))}"
            data-ref="${esc(String(r.entity_ref || ""))}"
          >Review</button>
        `;
      }

      else if (isRevenueRunApproval || isRevenueContractApproval) {
        const pj = r.payload_json || {};
        actionBtn = `
          <button class="apprOpenRevenue px-3 py-1.5 text-xs rounded bg-[var(--fs-navy)] text-white"
            data-id="${esc(rid)}"
            data-run-id="${esc(String(pj.run_id || r.entity_id || ""))}"
            data-contract-id="${esc(String(pj.contract_id || (et === "revenue_contract" ? r.entity_id : "")))}"
            data-action="${esc(String(r.action || ""))}"
          >Review</button>
        `;
      }

      return `
        <div class="border rounded-lg p-3">
          <div class="flex items-start justify-between gap-3">
            <div>
              <div class="text-xs font-semibold">
                ${esc(r.module)} · ${esc(r.action)} · <span class="text-slate-500">${esc(r.status)}</span>
              </div>
              <div class="text-xs text-slate-600 mt-1">
                ${esc(r.entity_type)}:${esc(r.entity_id)} ${r.entity_ref ? `· ${esc(r.entity_ref)}` : ""}
              </div>
              <div class="text-xs text-slate-500 mt-1">
                Amount: ${esc(r.currency || "")} ${esc(r.amount || 0)} · Risk: ${esc(r.risk_level || "low")}
              </div>
            </div>
            <div class="flex flex-col items-end gap-2">
              ${actionBtn}
              <button class="apprViewHistory px-3 py-1.5 text-xs rounded border" data-id="${esc(rid)}">History</button>
            </div>
          </div>
          <div id="apprHist_${esc(rid)}" class="mt-2 hidden text-xs text-slate-600"></div>
        </div>
      `;
    }).join("");

    // Normal decide flow
    listEl.querySelectorAll(".apprDecideBtn").forEach(btn => {
      btn.addEventListener("click", async () => {
        const requestId = Number(btn.dataset.id || 0) || null;
        if (!requestId) return;

        const data = await apiFetch(ENDPOINTS.approvals.get(cid, requestId));
        const r = data?.item || {};

        const mod = String(r.module || "").toLowerCase();
        const act = String(r.action || "").toLowerCase();

        bodyEl.innerHTML = `
          <div class="space-y-1">
            <div><b>Module:</b> ${esc(String(r.module || ""))}</div>
            <div><b>Action:</b> ${esc(String(r.action || ""))}</div>
            <div><b>Entity:</b> ${esc(String(r.entity_ref || r.entity_id || ""))}</div>
            <div><b>Status:</b> ${esc(String(r.status || ""))}</div>
          </div>
        `;

        // ✅ ADD LOAN DETAILS RIGHT HERE
        if (
          mod === "loans" &&
          [
            "create_loan",
            "post_loan_payment",
            "release_loan_payment",
            "post_loan_reclassification",
            "post_loan_modification",
            "post_loan_settlement"
          ].includes(act)
        ) {
          const pj = r.payload_json || {};
          bodyEl.innerHTML += `
            <div class="mt-2 border rounded p-2 bg-white">
              <div class="text-xs font-semibold">Loan workflow details</div>
              <div class="mt-1 text-slate-600">
                <div><b>Loan:</b> ${esc(String(pj.loan_name || r.entity_ref || r.entity_id || ""))}</div>
                <div><b>Reference:</b> ${esc(String(pj.loan_reference || ""))}</div>
                <div><b>Lender:</b> ${esc(String(pj.lender_name || ""))}</div>
                <div><b>Amount:</b> ${esc(String(pj.principal_amount || pj.amount_paid || r.amount || ""))} ${esc(String(pj.currency || r.currency || ""))}</div>
                <div><b>Date:</b> ${esc(String(pj.start_date || pj.payment_date || pj.as_of_date || ""))}</div>
                <div><b>Bank:</b> ${esc(String(pj.bank_account_id || ""))}</div>
              </div>
            </div>
          `;
        }

        activeRequestId = requestId;
        showModal();
      });
    });

    // Customer review flow -> cust approvals screen
    listEl.querySelectorAll(".apprReviewCust").forEach(btn => {
      btn.addEventListener("click", async () => {
        const requestId = Number(btn.dataset.id);
        const customerId = Number(btn.dataset.entity);

        // persist handoff so screen-cust can auto-open
        store?.set?.("fs_cust_approval_request_id", requestId);
        store?.set?.("fs_cust_approval_customer_id", customerId);

        // route to existing cust approval screen
        switchScreen("cust-approvals"); // or "cust" if that's your canonical name
      });
    });

    listEl.querySelectorAll(".apprOpenKyc").forEach(btn => {
      btn.addEventListener("click", async () => {
        const requestId = Number(btn.dataset.id || 0) || null;
        const profileId = Number(btn.dataset.profileId || 0) || null;

        if (!requestId || !profileId) return;

        // Persist so the credit screen can auto-open the profile + approval request
        store?.set?.("fs_credit_approval_request_id", requestId);
        store?.set?.("fs_credit_profile_id", profileId);

        // Route to your credit/KYC screen (whatever your screen key is)
        await switchScreen?.("credit");

        // If you have a helper, call it (optional)
        try { await window.openCreditProfileForApproval?.(profileId, requestId); } catch (e) {}
      });
    });

    function waitForEl(selector, timeoutMs = 2500) {
      return new Promise((resolve, reject) => {
        const t0 = Date.now();
        const tick = () => {
          const el = document.querySelector(selector);
          if (el) return resolve(el);
          if (Date.now() - t0 > timeoutMs) return reject(new Error(`UI not ready: ${selector}`));
          requestAnimationFrame(tick);
        };
        tick();
      });
    }

    listEl.querySelectorAll(".apprReviewInv").forEach(btn => {
      btn.addEventListener("click", async () => {
        const requestId = Number(btn.dataset.id || 0) || null;

        // invoice id might be stored in different places, so we try several
        const invoiceId =
          Number(btn.dataset.entity || 0) ||
          Number(btn.getAttribute("data-invoice-id") || 0) ||
          null;

        if (!invoiceId) {
          alert("Missing invoice id on this approval item.");
          return;
        }

        // save context (optional)
        store?.set?.("fs_ar_approval_request_id", requestId);
        store?.set?.("fs_ar_approval_invoice_id", invoiceId);

        // go to AR screen
        await switchScreen?.("ar");

        // ✅ if your AR screen has panes, open invoices pane first (safe if it exists)
        try { window.showArPane?.("invoices"); } catch (e) {}

        // ✅ now load the invoice into the form
        try { await window.loadInvoiceIntoForm?.(invoiceId); } catch (e) {
          console.error(e);
          alert("Failed to load invoice into form: " + (e?.message || e));
        }
      });
    });

    listEl.querySelectorAll(".apprOpenLeasePay").forEach(btn => {
      btn.addEventListener("click", async () => {

        const leaseId =
          Number(btn.dataset.leaseId || 0) || null;

        const paymentId =
          Number(btn.dataset.paymentId || 0) || null;

        if (!leaseId) return;

        // ✅ Persist approval handoff context
        // (prevents TS unused warning + enables downstream usage)
        if (paymentId) {
          window.__LEASE_APPROVAL_PAYMENT_ID = paymentId;
        }

        window.__ACTIVE_LEASE_ID = leaseId;

        // Go to Lease Payments screen
        await switchScreen?.("lease-payments");

        // Fill Lease ID filter + auto-load
        setTimeout(() => {
          const leaseInp = document.getElementById("lpFilterLeaseId");
          if (leaseInp) leaseInp.value = String(leaseId);

          document.getElementById("btnLpLoad")?.click();

          // Optional UX highlight hook
          if (paymentId) {
            console.log("[Approval] Focus payment:", paymentId);
          }

        }, 50);

      });
    });

    // Quote approvals -> open quote viewer/screen with handoff
    listEl.querySelectorAll(".apprOpenQuoteIssue, .apprOpenQuoteAccept").forEach(btn => {
      btn.addEventListener("click", async () => {
        const requestId = Number(btn.dataset.id || 0) || null;
        const quoteId = Number(btn.dataset.quoteId || 0) || null;

        if (!quoteId) return;

        // ✅ persist context so your quote viewer can "know" it's from approvals
        store?.set?.("fs_quote_approval_request_id", requestId);
        store?.set?.("fs_quote_approval_quote_id", quoteId);

        // ✅ route to AR quotes area (adapt to your routing)
        await switchScreen?.("ar");
        window.showArPane?.("quotes");

        // ✅ open the quote in the form (you already have this)
        try { await window.openQuoteInForm?.(quoteId); } catch (e) {}

        // ✅ if you have a viewer modal opener, call it too (optional)
        // try { await window.openQuoteViewer?.(quoteId); } catch (e) {}
      });
    });

    listEl.querySelectorAll(".apprReviewApAlloc").forEach(btn => {
      btn.addEventListener("click", async () => {
        const requestId = Number(btn.dataset.id || 0) || 0;
        const billId    = Number(btn.dataset.billId || 0) || 0;
        if (!requestId || !billId) return;

        // 1) fetch full approval request
        const reqRes = await apiFetch(ENDPOINTS.approvals.get(cid, requestId));
        const req = reqRes?.item || {};
        const pj = req.payload_json || {};

        // 2) route + open bill viewer FIRST (because it may re-render the modal)
        await switchScreen?.("ap");
        await window.openBillViewer?.(billId, { preserveOpen: false });

        // 3) NOW get the modal again and apply dataset handoff
        const bv = document.getElementById("billViewerModal");
        if (!bv) return;

        bv.dataset.approvalRequestId   = String(requestId);
        bv.dataset.approvalAction      = String(req.action || "allocate_bill_payment");
        bv.dataset.approvalPaymentId   = String(pj.payment_id || "");
        bv.dataset.approvalAmount      = String(pj.amount || "");
        bv.dataset.approvalPayloadJson = JSON.stringify(pj || {});

        // 4) Open payment allocation panel (this should prefill + set payment id)
        setTimeout(() => {
          const modalNow = document.getElementById("billViewerModal");
          modalNow?.querySelector("#billViewAllocatePayment")?.click();
        }, 50);
      });
    });

    listEl.querySelectorAll(".apprReviewPpeDepr").forEach(btn => {
      btn.addEventListener("click", async () => {
        const requestId = Number(btn.dataset.requestId || 0) || null;
        const depIds = JSON.parse(btn.dataset.depIds || "[]") || [];
        const periodEnd = String(btn.dataset.periodEnd || "");

        if (!requestId) return;

        // Persist context so Fixed Assets screen can auto-open modal
        store?.set?.("fs_ppe_approval_request_id", requestId);
        store?.set?.("fs_ppe_dep_ids", depIds);
        store?.set?.("fs_ppe_dep_period_end", periodEnd);

        // ✅ Route to Fixed Assets screen
        await switchScreen?.("fixed-assets");

        // ✅ Once there, open the depreciation batch modal
        try {
          await window.openDepreciationBatchModal?.(requestId, depIds, periodEnd);
        } catch (e) {
          console.error("Depreciation modal not available:", e);
        }
      });
    });

    listEl.querySelectorAll(".apprOpenLoanReview").forEach(btn => {
      btn.addEventListener("click", async () => {
        const requestId = Number(btn.dataset.id || 0) || null;
        const loanId = Number(btn.dataset.loanId || 0) || null;
        const action = String(btn.dataset.action || "");

        store?.set?.("fs_loan_approval_request_id", requestId);
        store?.set?.("fs_loan_approval_loan_id", loanId);
        store?.set?.("fs_loan_approval_action", action);

        await switchScreen?.("loans");

        try {
          await window.ensureLoansScreenReady?.();
        } catch (_) {}

        if (loanId) {
          try { await window.loadLoanDetail?.(loanId); } catch (e) {
            console.error("[Approval] Failed to load loan detail", e);
          }
        } else {
          try { window.createNewLoan?.(); } catch (_) {}
        }

        // optional: route to exact tab by action
        if (action === "create_loan") {
          window.setLoanTab?.("loan-overview");
        } else if (["create_loan_payment", "post_loan_payment", "release_loan_payment"].includes(action)) {
          window.setLoanTab?.("loan-payments");
          if (window.openLoanPaymentModal) {
            setTimeout(() => window.openLoanPaymentModal(), 80);
          }
        } else {
          window.setLoanTab?.("loan-journal");
        }
      });
    });

    listEl.querySelectorAll(".apprOpenRevenue").forEach(btn => {
      btn.addEventListener("click", async () => {
        const requestId = Number(btn.dataset.id || 0) || null;
        const runId = Number(btn.dataset.runId || 0) || null;
        const contractId = Number(btn.dataset.contractId || 0) || null;

        if (requestId) store?.set?.("fs_revenue_approval_request_id", requestId);
        if (runId) store?.set?.("fs_revenue_run_id", runId);
        if (contractId) store?.set?.("fs_revenue_contract_id", contractId);

        await switchScreen?.("revenue");

        try {
          if (runId) {
            await window.openRevenueRunForApproval?.(runId, requestId);
          } else if (contractId) {
            await window.openRevenueContractForApproval?.(contractId, requestId);
          }
        } catch (e) {
          console.error("[Approval] Failed to open revenue review", e);
        }
      });
    });

    listEl.querySelectorAll(".apprViewHistory").forEach(btn => {
      btn.addEventListener("click", async () => toggleHistory(Number(btn.dataset.id)));
    });
  }

  // decide modal
  const modal = el.querySelector("#apprDecideModal");
  const closeBtn = el.querySelector("#apprDecideClose");
  const saveBtn  = el.querySelector("#apprDecideSave");
  const bodyEl   = el.querySelector("#apprDecideBody");
  const decisionEl = el.querySelector("#apprDecision");
  const noteEl = el.querySelector("#apprNote");
  const decideMsgEl = el.querySelector("#apprDecideMsg");

  let activeRequestId = null;

  function showModal() {
    modal.classList.remove("hidden");
    modal.classList.add("flex");
  }
  function hideModal() {
    modal.classList.add("hidden");
    modal.classList.remove("flex");
    activeRequestId = null;
    decideMsgEl.textContent = "";
    noteEl.value = "";
    decisionEl.value = "approve";
  }

  closeBtn.addEventListener("click", hideModal);
  modal.addEventListener("click", (e) => { if (e.target === modal) hideModal(); });

  async function openDecideModal(requestId) {
    activeRequestId = requestId;
    decideMsgEl.textContent = "";

    const data = await apiFetch(ENDPOINTS.approvals.get(cid, requestId));
    const r = data?.item || {};

    if (String(r.status || "").toLowerCase() !== "pending") {
      alert(`This request is not pending (${r.status}).`);
      await load();
      return;
    }

    // base summary
    bodyEl.innerHTML = `
      <div class="border rounded p-2 bg-slate-50">
        <div><b>${esc(r.module)}</b> · ${esc(r.action)} · <span>${esc(r.status)}</span></div>
        <div class="mt-1">${esc(r.entity_type)}:${esc(r.entity_id)} ${r.entity_ref ? `· ${esc(r.entity_ref)}` : ""}</div>
        <div class="mt-1 text-slate-600">Amount: ${esc(r.currency || "")} ${esc(r.amount || 0)} · Risk: ${esc(r.risk_level || "low")}</div>
      </div>
    `;

    // ✅ ADD EXTRA DETAILS FOR LEASE PAYMENT APPROVALS (INSIDE, where r exists)
    const mod = String(r.module || "").toLowerCase();
    const act = String(r.action || "").toLowerCase();

    if (mod === "leases" && ["post_lease_payment", "release_lease_payment"].includes(act)) {
      const pj = r.payload_json || {};
      bodyEl.innerHTML += `
        <div class="mt-2 border rounded p-2 bg-white">
          <div class="text-xs font-semibold">Lease payment details</div>
          <div class="mt-1 text-slate-600">
            <div><b>Lease:</b> ${esc(String(pj.lease_id || r.entity_id || ""))}</div>
            <div><b>Schedule:</b> ${esc(String(pj.schedule_id || ""))}</div>
            <div><b>Date:</b> ${esc(String(pj.payment_date || ""))}</div>
            <div><b>Amount:</b> ${esc(String(pj.amount || ""))} ${esc(String(pj.currency || r.currency || ""))}</div>
            <div><b>Bank:</b> ${esc(String(pj.bank_account_id || ""))}</div>
            <div><b>Ref:</b> ${esc(String(pj.reference || ""))}</div>
          </div>
        </div>
      `;
    }

    showModal();
  }

  saveBtn.addEventListener("click", async () => {
    decideMsgEl.textContent = "";
    if (!activeRequestId) return;

    const decision = String(decisionEl.value || "").toLowerCase().trim();
    if (!["approve", "reject", "comment", "cancel", "reassign"].includes(decision)) {
      decideMsgEl.textContent = "Invalid decision";
      return;
    }

    // Prevent double click duplicates
    const prevDisabled = saveBtn.disabled;
    saveBtn.disabled = true;

    // snapshot request id, because hideModal() clears it
    const requestId = activeRequestId;

    try {
      const out = await apiFetch(ENDPOINTS.approvals.decide(cid, requestId), {
        method: "POST",
        body: JSON.stringify({
          decision,
          note: noteEl.value || null,
          meta_json: {},
        }),
      });

      const req = out?.item || {};
      const ex  = out?.executed || {};

      const mod = String(req.module || "").toLowerCase();
      const act = String(req.action || "").toLowerCase();
      const pj  = req.payload_json || {};

      // close modal + refresh list
      histCache.delete(requestId);
      hideModal();
      await load();

      // only do post-approve UX when approving
      if (decision !== "approve") return;

      // server execution flag (reliable only when backend actually posts in the decide call)
      const executedOk = (ex?.ok === true) && (ex?.executed !== false);

      // ============================
      // CASE A: LEASE PAYMENT APPROVAL
      // ============================
      // IMPORTANT: include your real lease pay actions (release/post/etc)
      const isLeasePay =
        (mod === "leases" || mod === "ifrs16") &&
        ["lease_pay", "post_lease_payment", "release_lease_payment"].includes(act);

      if (isLeasePay) {
        if (!executedOk) {
          const msg = ex?.detail || "Approved, but nothing was posted.";
          try { msgEl.textContent = msg; } catch (_) {}
          return;
        }

        const lease_id =
          Number(pj.lease_id || req.entity_id || 0) || null;

        // Use payment_date/as_of for monthly_due preview
        const as_of =
          String(pj.payment_date || pj.as_of || "").slice(0, 10) ||
          String(new Date().toISOString()).slice(0, 10);

        // 1) If cash journal exists, you can open it first (optional)
        const cashJournalId =
          ex?.journal_id ||
          ex?.posted_journal_id ||
          ex?.cash_journal_id ||
          null;

        if (cashJournalId) {
          window.switchScreen?.("journal");
          window.fetchJournalDetail?.(cashJournalId);
        }

        // 2) NOW open Journal screen and load monthly IFRS preview lines
        // (This is the “non-monetary items” journal the user should post)
        if (lease_id) {
          try {
            await openLeaseMonthPreviewOnJournal(cid, lease_id, as_of);
          } catch (e) {
            console.warn("[Approvals] Failed to load monthly IFRS preview into journal:", e);
          }
        } else {
          console.warn("[Approvals] Missing lease_id for lease pay approval.");
        }

        return;
      }

      // =================================
      // CASE B: MONTHLY POSTING APPROVAL
      // =================================
      const isPostLeaseMonth =
        mod === "leases" &&
        act === "post_lease_month";

      if (isPostLeaseMonth) {
        const monthJournalId =
          ex?.journal_id ||
          ex?.posted_journal_id ||
          ex?.month_journal_id ||
          null;

        if (monthJournalId) {
          window.switchScreen?.("journal");
          window.fetchJournalDetail?.(monthJournalId);
          return;
        }

        // fallback: open journal with preview lines using monthly_due
        const lease_id = Number(pj.lease_id || 0) || null;
        const as_of = String(pj.period_end || pj.as_of || "").slice(0, 10);

        if (lease_id && as_of) {
          try {
            await openLeaseMonthPreviewOnJournal(cid, lease_id, as_of);
          } catch (e) {
            console.warn("[Approvals] Failed to load monthly preview into journal:", e);
          }
        }

        if (!executedOk) {
          const msg = ex?.detail || "Approved. Backend may not have executed the posting.";
          try { msgEl.textContent = msg; } catch (_) {}
        }

        return;
      }

      // other approvals: no special redirect
    } catch (e) {
      decideMsgEl.textContent = e?.message || "Failed to save decision";
      if ((e?.message || "").toLowerCase().includes("not pending")) {
        await load();
      }
    } finally {
      saveBtn.disabled = prevDisabled || false;
    }
  });

  async function toggleHistory(requestId) {
    const box = el.querySelector(`#apprHist_${CSS.escape(String(requestId))}`);
    if (!box) return;

    const isHidden = box.classList.contains("hidden");
    if (!isHidden) {
      box.classList.add("hidden");
      box.innerHTML = "";
      return;
    }

    box.classList.remove("hidden");
    box.innerHTML = "Loading history…";

    if (histCache.has(requestId)) {
      box.innerHTML = histCache.get(requestId);
      return;
    }

    const data = await apiFetch(ENDPOINTS.approvals.decisions(cid, requestId, { limit: 100, offset: 0 }));
    const rows = data?.items || [];

    if (!rows.length) {
      const html = `<div class="text-xs text-slate-500">No history.</div>`;
      histCache.set(requestId, html);
      box.innerHTML = html;
      return;
    }

    const html = rows.map(d => `
      <div class="border-t pt-2 mt-2">
        <div><b>${esc(d.decision)}</b> · ${esc(d.decided_at || "")}</div>
        ${d.note ? `<div class="text-slate-600">${esc(d.note)}</div>` : `<div class="text-slate-500">—</div>`}
      </div>
    `).join("");

    histCache.set(requestId, html);
    box.innerHTML = html;
  }

  el.querySelector("#apprReload").addEventListener("click", load);
  await load();
}
// ================================
// Audit Trail UI
// ================================
async function renderAuditTrailScreen(meta = {}) {
  const cid = getActiveCompanyId?.() || CURRENT_COMPANY_ID;
  if (!cid) return;

  if (!window.ENDPOINTS?.audit) {
    const el0 = controlsPanel();
    if (el0) el0.innerHTML = `<div class="text-sm text-rose-600">Missing ENDPOINTS.audit.*</div>`;
    return;
  }

  const el = controlsPanel();
  if (!el) return;

  el.innerHTML = `
    <div class="flex items-center justify-between mb-3">
      <div>
        <div class="text-sm font-semibold">Audit Trail</div>
        <div class="text-xs text-slate-500">Who did what, when (filters below)</div>
      </div>
      <div class="flex items-center gap-2">
        <button id="audReload" class="px-3 py-1.5 text-xs rounded border">Reload</button>
      </div>
    </div>

    <div class="grid grid-cols-2 md:grid-cols-4 gap-2 mb-3">
      <input id="audModule" class="border rounded px-2 py-1 text-xs" placeholder="module (ap/ar/gl)">
      <input id="audEntityType" class="border rounded px-2 py-1 text-xs" placeholder="entity_type (journal/bill)">
      <input id="audEntityId" class="border rounded px-2 py-1 text-xs" placeholder="entity_id (123)">
      <select id="audSeverity" class="border rounded px-2 py-1 text-xs">
        <option value="">all severities</option>
        <option value="info">info</option>
        <option value="warn">warn</option>
        <option value="critical">critical</option>
      </select>
    </div>

    <div class="grid grid-cols-2 md:grid-cols-4 gap-2 mb-3">
      <input id="audActor" class="border rounded px-2 py-1 text-xs" placeholder="actor_user_id">
      <input id="audFrom" type="date" class="border rounded px-2 py-1 text-xs">
      <input id="audTo" type="date" class="border rounded px-2 py-1 text-xs">
      <select id="audLimit" class="border rounded px-2 py-1 text-xs">
        <option value="50">50</option>
        <option value="100" selected>100</option>
        <option value="200">200</option>
        <option value="500">500</option>
      </select>
    </div>

    <div id="audMsg" class="text-xs text-slate-500 mb-2"></div>
    <div id="audList" class="space-y-2"></div>
  `;

  const moduleEl = el.querySelector("#audModule");
  const etEl = el.querySelector("#audEntityType");
  const eidEl = el.querySelector("#audEntityId");
  const sevEl = el.querySelector("#audSeverity");
  const actorEl = el.querySelector("#audActor");
  const fromEl = el.querySelector("#audFrom");
  const toEl = el.querySelector("#audTo");
  const limitEl = el.querySelector("#audLimit");

  if (meta.module) moduleEl.value = meta.module;
  if (meta.entity_type) etEl.value = meta.entity_type;
  if (meta.entity_id) eidEl.value = meta.entity_id;

  const msgEl = el.querySelector("#audMsg");
  const listEl = el.querySelector("#audList");

  async function load() {
    msgEl.textContent = "Loading…";
    listEl.innerHTML = "";

    const opts = {
      limit: Number(limitEl.value || 100),
      offset: 0,
      module: moduleEl.value.trim(),
      severity: sevEl.value.trim(),
      entity_type: etEl.value.trim(),
      entity_id: eidEl.value.trim(),
      actor_user_id: actorEl.value.trim(),
      from: fromEl.value || "",
      to: toEl.value || "",
    };

    const data = await apiFetch(ENDPOINTS.audit.list(cid, opts));
    const items = data?.items || [];

    msgEl.textContent = `${items.length} event(s)`;

    if (!items.length) {
      listEl.innerHTML = `<div class="text-xs text-slate-500">No audit events found.</div>`;
      return;
    }

    listEl.innerHTML = items.map(a => `
      <div class="border rounded-lg p-3">
        <div class="text-xs font-semibold">
          ${esc(a.module)} · ${esc(a.action)} · <span class="text-slate-500">${esc(a.severity)}</span>
        </div>
        <div class="text-xs text-slate-600 mt-1">
          ${esc(a.entity_type)}:${esc(a.entity_id)} ${a.entity_ref ? `· ${esc(a.entity_ref)}` : ""}
        </div>
        <div class="text-xs text-slate-500 mt-1">
          ${esc(a.occurred_at || a.created_at || "")} · actor: ${esc(a.actor_user_id)}
          ${a.amount ? ` · ${esc(a.currency || "")} ${esc(a.amount)}` : ""}
        </div>
        ${a.message ? `<div class="text-xs mt-2">${esc(a.message)}</div>` : ""}
      </div>
    `).join("");
  }

  el.querySelector("#audReload").addEventListener("click", load);
  [moduleEl, etEl, eidEl, sevEl, actorEl, fromEl, toEl, limitEl].forEach(x => {
    x.addEventListener("change", load);
  });

  await load();
}

