function setElHtml(id, html) {
  const el = document.getElementById(id);
  if (el) el.innerHTML = html;
}

function getCatalogMount() {
  return document.getElementById("catalogMount");
}

function cloneTemplate(tplId) {
  const tpl = document.getElementById(tplId);
  if (!tpl || !("content" in tpl)) return null;
  return tpl.content.cloneNode(true);
}

function setElText(id, text) {
  const el = document.getElementById(id);
  if (el) el.textContent = text;
}

function renderApiError(err) {
  const status = err?.status ? `HTTP ${err.status}` : "Request failed";
  const msg = err?.message || "Unknown error";
  return `<div class="text-xs text-red-600">${esc(status)} — ${esc(msg)}</div>`;
}


function setCatalogContextHeader() {
  const c = window.CURRENT_COMPANY || {};
  const p = window.COMPANY_PROFILE || {};
  const invMode = (c.inventory_mode ?? p.inventory_mode ?? "none");
  const valuation = (c.inventory_valuation ?? p.inventory_valuation ?? c.valuation_method ?? "—");

  const modeText = document.getElementById("catalogCompanyModeText");
  const valText  = document.getElementById("catalogValuationText");

  if (modeText) modeText.textContent = `Mode: ${String(invMode || "none")}`;
  if (valText)  valText.textContent  = `Valuation: ${String(valuation || "—")}`;
}

function isInventoryEnabledForCompany() {
  const c = window.CURRENT_COMPANY || {};
  const p = window.COMPANY_PROFILE || {};

  const mode = String(c.inventory_mode ?? p.inventory_mode ?? "none").trim().toLowerCase();
  const val  = String(c.inventory_valuation ?? p.inventory_valuation ?? "").trim().toLowerCase();

  // explicit OFF values
  const off = new Set(["none", "no", "false", "0", "off", "disabled", ""]);
  if (!off.has(val)) {
    // if valuation is present (fifo/avg/etc), inventory is enabled
    return true;
  }

  // modes that mean inventory is ON
  const onModes = new Set([
    "internal", "external", "perpetual", "periodic",
    "inventory", "retail", "enabled", "on", "warehouse"
  ]);

  return onModes.has(mode);
}
window.isInventoryEnabledForCompany = isInventoryEnabledForCompany;

function bindCatalogQuickTabs() {
  const root = document.getElementById("screen-inventory");
  if (!root || root.dataset.tabsBound === "1") return;
  root.dataset.tabsBound = "1";

  root.querySelectorAll("[data-nav]").forEach(btn => {
    btn.addEventListener("click", () => {
      const route = btn.getAttribute("data-nav");
      if (!route) return;

      // go through switchScreen so title + allowlist + permissions apply
      window.switchScreen?.(route);
    });
  });
}
window.bindCatalogQuickTabs = bindCatalogQuickTabs;

