function _invMetaFieldId(key) {
  return "invMeta_" + String(key || "").replace(/[^\w\-]/g, "_");
}

function makeInvMetaFieldEl(f, prefillMeta = {}) {
  const id = _invMetaFieldId(f.key);
  const label = f.label || f.key;

  const wrap = document.createElement("label");
  wrap.className = "text-xs";

  const requiredStar = f.required ? ' <span class="text-red-600">*</span>' : "";
  const val = prefillMeta?.[f.key];

  if (f.type === "checkbox") {
    wrap.innerHTML = `
      <div class="text-slate-600 mb-1">${esc(label)}${requiredStar}</div>
      <label class="flex items-center gap-2">
        <input id="${id}" type="checkbox" class="h-4 w-4" ${val ? "checked" : ""}>
        <span class="text-slate-500">Yes</span>
      </label>
    `;
    return wrap;
  }

  if (f.type === "select") {
    const opts = (f.options || []).map(o => {
      const sel = String(val || "") === String(o) ? "selected" : "";
      return `<option value="${esc(String(o))}" ${sel}>${esc(String(o))}</option>`;
    }).join("");

    wrap.innerHTML = `
      <div class="text-slate-600 mb-1">${esc(label)}${requiredStar}</div>
      <select id="${id}" class="w-full border rounded px-2 py-2 text-sm">
        ${opts}
      </select>
    `;
    return wrap;
  }

  const t = f.type === "number" ? "number" : "text";
  wrap.innerHTML = `
    <div class="text-slate-600 mb-1">${esc(label)}${requiredStar}</div>
    <input id="${id}" type="${t}" class="w-full border rounded px-2 py-2 text-sm"
      placeholder="${esc(f.placeholder || "")}"
      value="${esc(val == null ? "" : String(val))}">
  `;
  return wrap;
}

function renderInvItemIndustryFields(prefill = {}) {
  const industry = currentIndustry(); // you already have this
  const cfg = window.INV_ITEM_META_FIELDS?.[industry];

  const block = document.getElementById("invItemIndustryBlock");
  const wrap = document.getElementById("invItemIndustryFields");
  if (!block || !wrap) return;

  wrap.innerHTML = "";

  if (!cfg) {
    block.classList.add("hidden");
    return;
  }

  block.classList.remove("hidden");

  const prefillMeta = (prefill && typeof prefill.meta === "object" && prefill.meta) ? prefill.meta : {};

  // Optional item type selector
  if (cfg.itemTypes?.length) {
    const typeKey = "item_type";
    const typeId = _invMetaFieldId(typeKey);
    const currentType = prefillMeta[typeKey] || cfg.itemTypes[0];

    const typeEl = document.createElement("label");
    typeEl.className = "text-xs";
    typeEl.innerHTML = `
      <div class="text-slate-600 mb-1">Item type</div>
      <select id="${typeId}" class="w-full border rounded px-2 py-2 text-sm">
        ${cfg.itemTypes.map(t => `<option value="${esc(t)}" ${t===currentType ? "selected" : ""}>${esc(t)}</option>`).join("")}
      </select>
    `;
    wrap.appendChild(typeEl);

    const renderType = (t) => {
      // remove everything except the first (type selector)
      Array.from(wrap.children).slice(1).forEach(n => n.remove());
      (cfg.fieldsByType?.[t] || []).forEach(f => wrap.appendChild(makeInvMetaFieldEl(f, prefillMeta)));
    };

    setTimeout(() => {
      const sel = document.getElementById(typeId);
      if (sel) sel.addEventListener("change", () => renderType(sel.value));
    }, 0);

    renderType(currentType);
    return;
  }

  // Simple fields
  (cfg.fields || []).forEach(f => wrap.appendChild(makeInvMetaFieldEl(f, prefillMeta)));
}

function collectInvItemMetaFromUI() {
  const meta = {};
  document.querySelectorAll("[id^='invMeta_']").forEach(el => {
    const key = el.id.replace(/^invMeta_/, "");
    // reverse sanitize if you only used clean keys; here keys are already clean in config
    const realKey = key;
    if (el.type === "checkbox") meta[realKey] = !!el.checked;
    else meta[realKey] = (el.value ?? "").toString().trim();
  });

  // drop empty
  Object.keys(meta).forEach(k => {
    if (meta[k] === "") delete meta[k];
  });

  return meta;
}

