function bindReceiveModalOnce() {
  const m = document.getElementById("invReceiveModal");
  if (!m || m.dataset.bound === "1") return;
  m.dataset.bound = "1";

  // Overlay + close buttons
  document.getElementById("invReceiveOverlay")
    ?.addEventListener("click", closeReceiveModal);

  document.getElementById("invReceiveCloseBtn")
    ?.addEventListener("click", closeReceiveModal);

  document.getElementById("invReceiveCancelBtn")
    ?.addEventListener("click", closeReceiveModal);

  // Add line
  document.getElementById("invReceiveAddLineBtn")
    ?.addEventListener("click", (e) => {
      e.preventDefault?.();
      addReceiveLine();
    });

  // ✅ Save / Receive (prevent default submit + stop bubbling)
  document.getElementById("invReceiveSaveBtn")
    ?.addEventListener("click", async (e) => {
      e.preventDefault?.();
      e.stopPropagation?.();

      // keep modal open while submitting
      await submitReceiveStock(e);
    });

  // ESC key closes modal
  window.addEventListener("keydown", (e) => {
    if (e.key === "Escape" && !m.classList.contains("hidden")) {
      closeReceiveModal();
    }
  });
}
window.bindReceiveModalOnce = bindReceiveModalOnce;

function normalizeToISODate(v) {
  const s = String(v || "").trim();
  if (!s) return "";

  // already ISO YYYY-MM-DD (or YYYY-MM-DDTHH...)
  if (/^\d{4}-\d{2}-\d{2}/.test(s)) return s.slice(0, 10);

  // MM/DD/YYYY or DD/MM/YYYY
  const m = s.match(/^(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{4})$/);
  if (m) {
    let a = parseInt(m[1], 10);
    let b = parseInt(m[2], 10);
    const yyyy = String(m[3]);

    // Heuristic:
    // if first part > 12 => it's DD/MM/YYYY
    // else assume MM/DD/YYYY (you can flip this if your users are mostly DD/MM)
    let mm, dd;
    if (a > 12) {
      dd = a; mm = b;
    } else {
      mm = a; dd = b;
    }

    const MM = String(mm).padStart(2, "0");
    const DD = String(dd).padStart(2, "0");
    return `${yyyy}-${MM}-${DD}`;
  }

  // Try Date parse as last resort
  const d = new Date(s);
  if (!isNaN(d)) return d.toISOString().slice(0, 10);

  return "";
}

function readReceiveDateISO() {
  const el = document.getElementById("invReceiveDate");
  return normalizeToISODate(el?.value || "");
}

