window.openMovementDetail = openMovementDetail;

window._INV_ITEM_CACHE = window._INV_ITEM_CACHE || { loaded:false, items:[] };

async function ensureInvItemCache() {
  if (window._INV_ITEM_CACHE.loaded) return window._INV_ITEM_CACHE.items;

  const cid = getActiveCompanyId?.() || window.CURRENT_COMPANY_ID;
  if (!cid) return [];

  // pull a bigger limit so select has options
  const params = new URLSearchParams();
  params.set("limit", "500");
  params.set("offset", "0");
  params.set("active", "1");

  const data = await apiFetch(ENDPOINTS.inventory.items(cid, params.toString()));
  const items = (data?.rows || []).map(r => ({
    id: r.id,
    sku: r.sku || "",
    name: r.name || "",
  }));

  window._INV_ITEM_CACHE = { loaded:true, items };
  return items;
}

function fillReceiveVendorSelect(vendors, selectedId = "") {
  const el = document.getElementById("invReceiveVendor");
  if (!el) return;

  const sid = String(selectedId || "");
  el.innerHTML =
    `<option value="">— Select supplier —</option>` +
    (vendors || []).map(v => {
      const id = String(v.id ?? "");
      const name = (v.name || v.vendor_name || v.legal_name || v.full_name || `Vendor #${id}`).trim();
      const sel = (id && id === sid) ? "selected" : "";
      return `<option value="${esc(id)}" ${sel}>${esc(name)}</option>`;
    }).join("");
}
window.fillReceiveVendorSelect = fillReceiveVendorSelect;

async function openReceiveModal(prefill = {}) {
  const m = document.getElementById("invReceiveModal");
  if (!m) return;

  showReceiveMsg("");

  const iso = normalizeToISODate(prefill.tx_date) || new Date().toISOString().slice(0, 10);
  document.getElementById("invReceiveDate").value = iso;

  document.getElementById("invReceiveRef").value = prefill.ref || "";
  document.getElementById("invReceiveNotes").value = prefill.notes || "";

  const tbody = document.getElementById("invReceiveTbody");
  if (tbody) tbody.innerHTML = "";

  applyReceiveColumnPolicy();

  // ✅ load caches
  await ensureInvItemCache();
  await fetchVendorsFromBackend(false);
  fillReceiveVendorSelect(window.VENDORS_CACHE || [], prefill.vendor_id || "");

  addReceiveLine();

  m.classList.remove("hidden");
}
window.openReceiveModal = openReceiveModal;

function getReceiveColumnPolicy() {
  const ind = currentIndustry();

  if (ind === "private healthcare") return { showBatch: true, showExpiry: true };
  if (ind === "restaurant") return { showBatch: false, showExpiry: true };
  if (ind === "manufacturing") return { showBatch: true, showExpiry: false };
  if (ind === "agriculture") return { showBatch: true, showExpiry: true };

  return { showBatch: false, showExpiry: false };
}

function applyReceiveColumnPolicy() {
  const { showBatch, showExpiry } = getReceiveColumnPolicy();
  const m = document.getElementById("invReceiveModal");
  if (!m) return;

  m.querySelectorAll("[data-col='batch']").forEach(el => el.style.display = showBatch ? "" : "none");
  m.querySelectorAll("[data-col='expiry']").forEach(el => el.style.display = showExpiry ? "" : "none");

  m.querySelectorAll("[data-cell='batch']").forEach(el => el.style.display = showBatch ? "" : "none");
  m.querySelectorAll("[data-cell='expiry']").forEach(el => el.style.display = showExpiry ? "" : "none");
}

