window._STOCKTAKE = window._STOCKTAKE || {
  sessionId: null,
  asOf: null,
  items: [],          // from on_hand
  counted: new Map(), // item_id -> counted_qty
};

function bindStocktakeUI() {
  const btnNew = document.getElementById("stkNewBtn");
  if (btnNew && btnNew.dataset.bound !== "1") {
    btnNew.dataset.bound = "1";
    btnNew.addEventListener("click", () => startStocktakeFlow?.());
  }

  const btnRef = document.getElementById("stkRefreshBtn");
  if (btnRef && btnRef.dataset.bound !== "1") {
    btnRef.dataset.bound = "1";
    btnRef.addEventListener("click", () => {
      const mount = document.getElementById("stocktakeMount");
      if (mount) mount.innerHTML = `<div class="text-xs text-slate-500">Create a new stocktake to begin.</div>`;
      window._STOCKTAKE = { sessionId:null, asOf:null, items:[], counted:new Map() };
    });
  }

  const mount = document.getElementById("stocktakeMount");
  if (mount && !mount.innerHTML.trim()) {
    mount.innerHTML = `<div class="text-xs text-slate-500">Create a new stocktake to begin.</div>`;
  }
}
window.bindStocktakeUI = bindStocktakeUI;

async function startStocktakeFlow() {
  const cid = getActiveCompanyId?.() || window.CURRENT_COMPANY_ID;
  if (!cid) return;

  const mount = document.getElementById("stocktakeMount");
  if (mount) mount.innerHTML = `<div class="text-xs text-slate-500">Creating stocktake session…</div>`;

  try {
    const asOf = new Date().toISOString().slice(0, 10);

    // 1) create session
    const sess = await apiFetch(ENDPOINTS.inventory.stocktakeCreate(cid), {
      method: "POST",
      body: JSON.stringify({ title: `Stocktake ${asOf}`, as_of: asOf }),
    });

    const sessionId = sess?.id;
    if (!sessionId) throw new Error("No session id returned");

    // 2) load current on-hand snapshot
    const params = new URLSearchParams();
    params.set("as_of", asOf);

    const onhand = await apiFetch(ENDPOINTS.inventory.onHand(cid, params.toString()));
    const items = onhand?.items || [];

    // 3) init state
    window._STOCKTAKE = {
      sessionId,
      asOf,
      items,
      counted: new Map(items.map(r => [Number(r.item_id), Number(r.on_hand ?? 0)])), // default counted = system (editable)
    };

    renderStocktakeWorkspace();
  } catch (err) {
    if (mount) mount.innerHTML = renderApiError(err);
  }
}
window.startStocktakeFlow = startStocktakeFlow;

function renderStocktakeWorkspace() {
  const mount = document.getElementById("stocktakeMount");
  if (!mount) return;

  const st = window._STOCKTAKE || {};
  if (!st.sessionId) {
    mount.innerHTML = `<div class="text-xs text-slate-500">Create a new stocktake to begin.</div>`;
    return;
  }

  const mode = (document.querySelector('input[name="stocktakeMode"]:checked')?.value || "scan").toLowerCase();

  mount.innerHTML = `
    <div class="flex items-center justify-between mb-2">
      <div class="text-xs text-slate-600">
        Session <b>#${esc(String(st.sessionId))}</b> • As of <b>${esc(String(st.asOf || "—"))}</b>
      </div>

      <div class="flex items-center gap-2">
        <button id="stkSaveBtn" class="px-3 py-1 text-xs border rounded">Save Lines</button>
        <button id="stkCompareBtn" class="px-3 py-1 text-xs border rounded">Compare</button>
        <button id="stkPostBtn" class="px-3 py-1 text-xs bg-[var(--fs-navy)] text-white rounded">Post</button>
      </div>
    </div>

    <div id="stkMsg" class="mb-2 text-xs text-slate-500"></div>

    ${mode === "scan" ? renderStocktakeScanUI(st) : renderStocktakeSheetUI(st)}

    <div id="stkCompareOut" class="mt-3"></div>
  `;

  // mode toggle live refresh
  document.querySelectorAll('input[name="stocktakeMode"]').forEach(r => {
    if (r.dataset.bound === "1") return;
    r.dataset.bound = "1";
    r.addEventListener("change", () => renderStocktakeWorkspace());
  });

  document.getElementById("stkSaveBtn")?.addEventListener("click", saveStocktakeLines);
  document.getElementById("stkCompareBtn")?.addEventListener("click", runStocktakeCompare);
  document.getElementById("stkPostBtn")?.addEventListener("click", postStocktake);
}
window.renderStocktakeWorkspace = renderStocktakeWorkspace;

function renderStocktakeSheetUI(st) {
  const rows = (st.items || []).map(r => {
    const itemId = Number(r.item_id);
    const counted = st.counted?.get(itemId);
    return `
      <tr class="border-b">
        <td class="px-2 py-1">${esc(r.sku || "")}</td>
        <td class="px-2 py-1">${esc(r.name || "")}</td>
        <td class="px-2 py-1 text-right">${esc(r.on_hand ?? 0)}</td>
        <td class="px-2 py-1">
          <input
            class="w-28 border rounded px-2 py-1 text-xs text-right"
            type="number"
            step="0.0001"
            data-stk-item="${esc(String(itemId))}"
            value="${esc(String(counted ?? (r.on_hand ?? 0)))}"
          >
        </td>
      </tr>
    `;
  }).join("");

  return `
    <div class="overflow-auto border rounded">
      <table class="w-full text-xs">
        <thead class="bg-slate-50 border-b">
          <tr class="text-slate-600">
            <th class="text-left px-2 py-1">SKU</th>
            <th class="text-left px-2 py-1">Item</th>
            <th class="text-right px-2 py-1">System</th>
            <th class="text-left px-2 py-1">Counted</th>
          </tr>
        </thead>
        <tbody>${rows}</tbody>
      </table>
    </div>
  `;
}
window.renderStocktakeSheetUI = renderStocktakeSheetUI;

function renderStocktakeScanUI(st) {
  return `
    <div class="border rounded p-2">
      <div class="grid grid-cols-1 lg:grid-cols-3 gap-2 items-end">
        <label class="text-xs">
          <div class="text-slate-600 mb-1">Scan / Enter Barcode</div>
          <input id="stkScanBarcode" class="w-full border rounded px-2 py-2 text-sm" placeholder="Scan barcode…">
        </label>

        <label class="text-xs">
          <div class="text-slate-600 mb-1">Qty to add</div>
          <input id="stkScanQty" type="number" step="0.0001" value="1"
                 class="w-full border rounded px-2 py-2 text-sm text-right">
        </label>

        <button id="stkScanAddBtn" class="px-3 py-2 text-sm bg-[var(--fs-navy)] text-white rounded">
          Add
        </button>
      </div>

      <div class="text-[11px] text-slate-500 mt-2">
        Tip: Each scan updates counted qty. You can still Save/Compare/Post.
      </div>

      <div id="stkScanList" class="mt-3"></div>
    </div>
  `;
}
window.renderStocktakeScanUI = renderStocktakeScanUI;

async function saveStocktakeLines() {
  const cid = getActiveCompanyId?.() || window.CURRENT_COMPANY_ID;
  const st = window._STOCKTAKE || {};
  if (!cid || !st.sessionId) return;

  const msg = document.getElementById("stkMsg");
  if (msg) msg.textContent = "Saving…";

  // Read from inputs (sheet mode) if present, else use st.counted map (scan mode)
  const inputs = Array.from(document.querySelectorAll("[data-stk-item]"));
  if (inputs.length) {
    inputs.forEach(inp => {
      const itemId = Number(inp.getAttribute("data-stk-item"));
      const v = Number(inp.value);
      if (itemId && Number.isFinite(v)) st.counted.set(itemId, v);
    });
  }

  const lines = [];
  let lineNo = 0;

  for (const [item_id, counted_qty] of (st.counted?.entries() || [])) {
    if (!item_id) continue;
    lineNo += 1;
    lines.push({ item_id: Number(item_id), counted_qty: Number(counted_qty || 0) });
  }

  try {
    await apiFetch(ENDPOINTS.inventory.stocktakeLines(cid, st.sessionId), {
      method: "PUT",
      body: JSON.stringify({ lines }),
    });
    if (msg) msg.textContent = "Saved.";
  } catch (err) {
    if (msg) msg.textContent = "";
    showToast?.("Save failed", "error");
    const out = document.getElementById("stkCompareOut");
    if (out) out.innerHTML = renderApiError(err);
  }
}
window.saveStocktakeLines = saveStocktakeLines;

async function runStocktakeCompare() {
  const cid = getActiveCompanyId?.() || window.CURRENT_COMPANY_ID;
  const st = window._STOCKTAKE || {};
  if (!cid || !st.sessionId) return;

  const msg = document.getElementById("stkMsg");
  if (msg) msg.textContent = "Comparing…";

  // Always save first so compare uses latest
  await saveStocktakeLines();

  try {
    const cmp = await apiFetch(ENDPOINTS.inventory.stocktakeCompare(cid, st.sessionId));
    renderStocktakeCompare(cmp);
    if (msg) msg.textContent = "";
  } catch (err) {
    if (msg) msg.textContent = "";
    const out = document.getElementById("stkCompareOut");
    if (out) out.innerHTML = renderApiError(err);
  }
}
window.runStocktakeCompare = runStocktakeCompare;

function renderStocktakeCompare(cmp) {
  const out = document.getElementById("stkCompareOut");
  if (!out) return;

  const items = cmp?.items || [];
  if (!items.length) {
    out.innerHTML = `<div class="text-xs text-slate-500">No comparison rows.</div>`;
    return;
  }

  const row = (r) => `
    <tr class="border-b">
      <td class="px-2 py-1">${esc(r.sku || "")}</td>
      <td class="px-2 py-1">${esc(r.item_name || "")}</td>
      <td class="px-2 py-1 text-right">${esc(r.system_on_hand ?? 0)}</td>
      <td class="px-2 py-1 text-right">${esc(r.counted_qty ?? 0)}</td>
      <td class="px-2 py-1 text-right ${Number(r.variance || 0) !== 0 ? "font-semibold" : ""}">
        ${esc(r.variance ?? 0)}
      </td>
    </tr>
  `;

  out.innerHTML = `
    <div class="mt-2 font-semibold text-xs text-slate-700">
      Variance total: ${esc(String(cmp?.variance_total ?? 0))}
    </div>
    <div class="overflow-auto border rounded mt-2">
      <table class="w-full text-xs">
        <thead class="bg-slate-50 border-b">
          <tr class="text-slate-600">
            <th class="text-left px-2 py-1">SKU</th>
            <th class="text-left px-2 py-1">Item</th>
            <th class="text-right px-2 py-1">System</th>
            <th class="text-right px-2 py-1">Counted</th>
            <th class="text-right px-2 py-1">Variance</th>
          </tr>
        </thead>
        <tbody>${items.map(row).join("")}</tbody>
      </table>
    </div>
  `;
}
window.renderStocktakeCompare = renderStocktakeCompare;

async function postStocktake() {
  const cid = getActiveCompanyId?.() || window.CURRENT_COMPANY_ID;
  const st = window._STOCKTAKE || {};
  if (!cid || !st.sessionId) return;

  const msg = document.getElementById("stkMsg");

  // Always save first
  await saveStocktakeLines();

  if (!confirm("Post this stocktake? This will create a count movement.")) return;

  if (msg) msg.textContent = "Posting…";

  try {
    const out = await apiFetch(ENDPOINTS.inventory.stocktakePost(cid, st.sessionId), { method: "POST" });
    if (out?.ok) {
      if (msg) msg.textContent = `Posted ✔ Created tx #${out.posted_tx_id}`;
      loadInventoryMovements?.(); // refresh movements screen if needed
    } else {
      if (msg) msg.textContent = `Post failed.`;
    }
  } catch (err) {
    if (msg) msg.textContent = "";
    const cmpOut = document.getElementById("stkCompareOut");
    if (cmpOut) cmpOut.innerHTML = renderApiError(err);
  }
}
window.postStocktake = postStocktake; 

// --- Scan Mode handlers ---
document.addEventListener("click", async (e) => {
  if (e.target?.id !== "stkScanAddBtn") return;

  const cid = getActiveCompanyId?.() || window.CURRENT_COMPANY_ID;
  const st = window._STOCKTAKE || {};
  if (!cid || !st.sessionId) return;

  const barcode = (document.getElementById("stkScanBarcode")?.value || "").trim();
  const qtyAdd = Number(document.getElementById("stkScanQty")?.value || "1");
  const msg = document.getElementById("stkMsg");

  if (!barcode) return;
  if (!Number.isFinite(qtyAdd) || qtyAdd <= 0) return;

  try {
    if (msg) msg.textContent = "Looking up barcode…";

    // backend lookup endpoint exists
    const item = await apiFetch(ENDPOINTS.inventory.lookupByBarcode(cid, barcode));

    const itemId = Number(item?.id || item?.item_id || 0);
    if (!itemId) throw new Error("Barcode item has no id");

    // ensure item exists in list (if not, add to memory list)
    const exists = (st.items || []).some(r => Number(r.item_id) === itemId);
    if (!exists) {
      st.items.push({
        item_id: itemId,
        sku: item?.sku || "",
        name: item?.name || "",
        barcode: item?.barcode || barcode,
        on_hand: 0,
      });
    }

    // increment counted
    const current = Number(st.counted.get(itemId) || 0);
    st.counted.set(itemId, current + qtyAdd);

    if (msg) msg.textContent = `Added ${qtyAdd} to ${item?.sku || barcode}`;
    renderStocktakeScanList();
  } catch (err) {
    if (msg) msg.textContent = "";
    const out = document.getElementById("stkCompareOut");
    if (out) out.innerHTML = renderApiError(err);
  } finally {
    const inp = document.getElementById("stkScanBarcode");
    if (inp) { inp.value = ""; inp.focus(); }
  }
});

function renderStocktakeScanList() {
  const st = window._STOCKTAKE || {};
  const el = document.getElementById("stkScanList");
  if (!el) return;

  // only show items that have been counted (non-zero)
  const rows = [];
  for (const r of (st.items || [])) {
    const itemId = Number(r.item_id);
    const counted = Number(st.counted.get(itemId) || 0);
    if (!counted) continue;

    rows.push(`
      <tr class="border-b">
        <td class="px-2 py-1">${esc(r.sku || "")}</td>
        <td class="px-2 py-1">${esc(r.name || "")}</td>
        <td class="px-2 py-1">${esc(r.barcode || "")}</td>
        <td class="px-2 py-1 text-right">${esc(String(counted))}</td>
      </tr>
    `);
  }

  if (!rows.length) {
    el.innerHTML = `<div class="text-xs text-slate-500">No scans yet.</div>`;
    return;
  }

  el.innerHTML = `
    <div class="overflow-auto border rounded">
      <table class="w-full text-xs">
        <thead class="bg-slate-50 border-b">
          <tr class="text-slate-600">
            <th class="text-left px-2 py-1">SKU</th>
            <th class="text-left px-2 py-1">Item</th>
            <th class="text-left px-2 py-1">Barcode</th>
            <th class="text-right px-2 py-1">Counted</th>
          </tr>
        </thead>
        <tbody>${rows.join("")}</tbody>
      </table>
    </div>
  `;
}
window.renderStocktakeScanList = renderStocktakeScanList;

// =====================================================
// Tiny utilities (safe to include if you don't already have them)
// =====================================================

function debounce(fn, wait = 250) {
  let t = null;
  return (...args) => {
    clearTimeout(t);
    t = setTimeout(() => fn(...args), wait);
  };
}

