function bindInventoryValuationUI() {
  const run = document.getElementById("valRunBtn");
  if (run && run.dataset.bound !== "1") {
    run.dataset.bound = "1";
    run.addEventListener("click", () => loadInventoryValuation?.());
  }
}

async function loadInventoryValuation() {
  const cid = getActiveCompanyId?.() || window.CURRENT_COMPANY_ID;
  if (!cid) return;

  const asOf = document.getElementById("valAsOf")?.value || "";
  const el = document.getElementById("valuationTable");
  if (el) el.innerHTML = `<div class="text-xs text-slate-500">Loading valuation…</div>`;

  try {
    const params = new URLSearchParams();
    if (asOf) params.set("as_of", asOf);

    const data = await apiFetch(ENDPOINTS.inventory.valuation(cid, params.toString()));
    const items = data?.items || [];
    const total = Number(data?.total_value || 0);

    renderValuationTable(items, total, data?.as_of);
  } catch (err) {
    if (el) el.innerHTML = renderApiError(err);
  }
}

function renderValuationTable(items, totalValue, asOf) {
  const el = document.getElementById("valuationTable");
  if (!el) return;

  if (!items.length) {
    el.innerHTML = `<div class="text-xs text-slate-500">No valuation rows found.</div>`;
    return;
  }

  const row = (r) => `
    <tr class="border-b">
      <td class="px-2 py-2">${esc(r.sku || "")}</td>
      <td class="px-2 py-2">${esc(r.name || "")}</td>
      <td class="px-2 py-2 text-right">${esc(r.on_hand ?? 0)}</td>
      <td class="px-2 py-2 text-right">${fmtMoney(r.avg_cost || 0)}</td>
      <td class="px-2 py-2 text-right">${fmtMoney(r.value || 0)}</td>
    </tr>
  `;

  el.innerHTML = `
    <div class="flex items-center justify-between mb-2">
      <div class="text-xs text-slate-600">As of: <b>${esc(asOf || "—")}</b></div>
      <div class="text-xs text-slate-700">Total value: <b>${fmtMoney(totalValue || 0)}</b></div>
    </div>
    <div class="overflow-auto border rounded">
      <table class="w-full text-xs">
        <thead class="bg-slate-50 border-b">
          <tr class="text-slate-600">
            <th class="text-left px-2 py-2">SKU</th>
            <th class="text-left px-2 py-2">Item</th>
            <th class="text-right px-2 py-2">On-hand</th>
            <th class="text-right px-2 py-2">Avg cost</th>
            <th class="text-right px-2 py-2">Value</th>
          </tr>
        </thead>
        <tbody>${items.map(row).join("")}</tbody>
      </table>
    </div>
  `;
}

