// Stocktake (Minimal workable flow)
// =====================================================

function showReceiveMsg(text = "", kind = "info") {
  const el = document.getElementById("invReceiveMsg");
  if (!el) return;
  const cls =
    kind === "error" ? "text-red-600" :
    kind === "ok" ? "text-emerald-600" :
    "text-slate-600";
  el.className = `text-xs mb-3 ${cls}`;
  el.textContent = text || "";
}

function closeReceiveModal() {
  const m = document.getElementById("invReceiveModal");
  if (!m) return;
  m.classList.add("hidden");
}

function addReceiveLine(line = {}) {
  const tbody = document.getElementById("invReceiveTbody");
  if (!tbody) return;

  const items = window._INV_ITEM_CACHE?.items || [];

  const options = [`<option value="">Select item…</option>`].concat(
    items.map(it =>
      `<option value="${it.id}" data-sku="${esc(it.sku || "")}" data-name="${esc(it.name || "")}">
        ${esc(it.sku)} — ${esc(it.name)}
      </option>`
    )
  ).join("");

  const tr = document.createElement("tr");
  tr.className = "border-b";
  tr.innerHTML = `
    <!-- 1) SKU / Barcode -->
    <td class="px-2 py-2">
      <input
        class="w-full border rounded px-2 py-1 text-xs inv-rec-sku"
        placeholder="Scan / enter barcode"
        value="${esc(line.sku || "")}"
      />
    </td>

    <!-- 2) Item -->
    <td class="px-2 py-2">
      <select class="w-full border rounded px-2 py-1 text-xs inv-rec-item">
        ${options}
      </select>
    </td>

    <!-- 3) Qty -->
    <td class="px-2 py-2">
      <input type="number" step="0.0001"
        class="w-full border rounded px-2 py-1 text-xs text-right inv-rec-qty"
        placeholder="0" value="${esc(line.qty ?? "")}">
    </td>

    <!-- 4) Unit cost -->
    <td class="px-2 py-2">
      <input type="number" step="0.000001"
        class="w-full border rounded px-2 py-1 text-xs text-right inv-rec-cost"
        placeholder="0.000000" value="${esc(line.unit_cost ?? "")}">
    </td>

    <!-- ✅ 5) Batch (industry-controlled) -->
    <td class="px-2 py-2" data-cell="batch">
      <input
        class="w-full border rounded px-2 py-1 text-xs inv-rec-batch"
        placeholder="Optional"
        value="${esc(line.batch_no || "")}"
      />
    </td>

    <!-- ✅ 6) Expiry (industry-controlled) -->
    <td class="px-2 py-2" data-cell="expiry">
      <input type="date"
        class="w-full border rounded px-2 py-1 text-xs inv-rec-exp"
        value="${esc(line.expiry_date || "")}">
    </td>

    <!-- 7) Del -->
    <td class="px-2 py-2 text-right">
      <button class="text-xs underline text-red-600 inv-rec-del">Del</button>
    </td>
  `;

  const sel = tr.querySelector(".inv-rec-item");
  const skuInp = tr.querySelector(".inv-rec-sku");

  // Preselect item_id if provided
  if (line.item_id) sel.value = String(line.item_id);

  // When item changes, auto-fill SKU field
  sel.addEventListener("change", () => {
    const opt = sel.selectedOptions?.[0];
    const sku = opt?.getAttribute("data-sku") || "";
    if (skuInp && sku) skuInp.value = sku;
  });

  // When SKU entered/scanned, try auto-select matching item by sku
  skuInp?.addEventListener("change", () => {
    const sku = String(skuInp.value || "").trim();
    if (!sku) return;

    const match = items.find(it => String(it.sku || "").trim().toLowerCase() === sku.toLowerCase());
    if (match) sel.value = String(match.id);
  });

  tr.querySelector(".inv-rec-del")?.addEventListener("click", () => tr.remove());
  tbody.appendChild(tr);

  // ✅ ensure new row respects industry hide/show rules
  applyReceiveColumnPolicy();
}

async function submitReceiveStock() {
  const cid = getActiveCompanyId?.() || window.CURRENT_COMPANY_ID;
  if (!cid) return;

  showReceiveMsg("");

  // ✅ normalize date to ISO
  const tx_date = readReceiveDateISO();
  const ref     = (document.getElementById("invReceiveRef")?.value || "").trim() || null;
  const notes   = (document.getElementById("invReceiveNotes")?.value || "").trim() || null;

  // ✅ NEW: supplier (vendor) link
  const vendor_id_raw = (document.getElementById("invReceiveVendor")?.value || "").trim();
  const vendor_id = vendor_id_raw && /^\d+$/.test(vendor_id_raw) ? parseInt(vendor_id_raw, 10) : null;

  if (!tx_date) return showReceiveMsg("Date is required (use YYYY-MM-DD).", "error");
  if (!ref) return showReceiveMsg("Reference is required (GRN / Supplier Inv / PO #).", "error");
  if (!vendor_id) return showReceiveMsg("Supplier is required.", "error"); // ✅ ADD

  try { await ensureInvItemCache?.(); } catch (_) {}

  const pol = getReceiveColumnPolicy?.() || { showBatch:false, showExpiry:false };

  const tbody = document.getElementById("invReceiveTbody");
  const rows = Array.from(tbody?.querySelectorAll("tr") || []);

  const lines = [];
  let skipped = 0;
  const normSku = (s) => String(s || "").trim().toLowerCase();

  for (const tr of rows) {
    const item_id_raw =
      (tr.querySelector(".inv-rec-item")?.value || "").trim() ||
      (tr.querySelector(".inv-rec-itemid")?.value || "").trim();

    let item_id = item_id_raw && /^\d+$/.test(item_id_raw) ? parseInt(item_id_raw, 10) : null;

    const sku = (tr.querySelector(".inv-rec-sku")?.value || "").trim();
    if (!item_id && sku) {
      const match = (window._INV_ITEM_CACHE?.items || []).find(it => normSku(it.sku) === normSku(sku));
      if (match?.id) item_id = match.id;
    }

    const qty = Number(String(tr.querySelector(".inv-rec-qty")?.value || "0").replace(/,/g, ""));
    const unit_cost = Number(String(tr.querySelector(".inv-rec-cost")?.value || "0").replace(/,/g, ""));

    // ✅ normalize expiry date if enabled
    let expiry_date = null;
    if (pol.showExpiry) {
      const rawExp = (tr.querySelector(".inv-rec-exp")?.value || "").trim();
      expiry_date = rawExp ? normalizeToISODate(rawExp) : null;
      if (rawExp && !expiry_date) {
        skipped++;
        continue; // invalid expiry format
      }
    }

    const batch_no = pol.showBatch
      ? ((tr.querySelector(".inv-rec-batch")?.value || "").trim() || null)
      : null;

    const memo = (tr.querySelector(".inv-rec-memo")?.value || "").trim() || null;

    if (!item_id || !Number.isFinite(qty) || qty <= 0 || !Number.isFinite(unit_cost) || unit_cost < 0) {
      skipped++;
      continue;
    }

    lines.push({ item_id, qty, unit_cost, expiry_date, batch_no, memo });
  }

  if (!lines.length) {
    return showReceiveMsg(
      skipped ? "No valid lines. Select an item (or enter SKU) and ensure Qty > 0." : "Add at least one line.",
      "error"
    );
  }

  const btn = document.getElementById("invReceiveSaveBtn");
  const old = btn?.textContent || "Receive";
  if (btn) { btn.disabled = true; btn.textContent = "Saving…"; }

  try {
    await apiFetch(ENDPOINTS.inventory.receive(cid), {
      method: "POST",
      body: JSON.stringify({ tx_date, ref, notes, vendor_id, lines }), // ✅ KEEP vendor_id
    });

    showReceiveMsg("Received ✔", "ok");

    // ===============================
    // ✅ Reset header fields (partial)
    // ===============================

    // ❌ DO NOT change date
    // document.getElementById("invReceiveDate").value = tx_date;

    // ✅ Clear supplier dropdown (UI only — backend already saved vendor_id)
    const elVendor = document.getElementById("invReceiveVendor");
    if (elVendor) elVendor.value = "";

    // ✅ Clear reference + notes
    const elRef   = document.getElementById("invReceiveRef");
    const elNotes = document.getElementById("invReceiveNotes");

    if (elRef)   elRef.value = "";
    if (elNotes) elNotes.value = "";

    // ===============================
    // ✅ Reset lines but keep modal open
    // ===============================
    if (tbody) tbody.innerHTML = "";
    addReceiveLine?.();

    // Refresh movements grid
    loadInventoryMovements?.();

  } catch (err) {
    showReceiveMsg(err?.message || "Receive failed.", "error");

  } finally {
    if (btn) {
      btn.disabled = false;
      btn.textContent = old;
    }
  }
}
window.submitReceiveStock = submitReceiveStock;

async function ensureVendorsCache() {
  if (Array.isArray(window.VENDORS_CACHE) && window.VENDORS_CACHE.length) {
    return window.VENDORS_CACHE;
  }

  const cid = getActiveCompanyId?.() || window.CURRENT_COMPANY_ID;
  if (!cid) return [];

  // ⚠️ your helper expects res.data; some endpoints return {rows:...} or {items:...}
  const url = ENDPOINTS.vendors(cid);

  const res = await apiFetch(url, { method: "GET" });

  const rows =
    res?.data ||
    res?.rows ||
    res?.items ||
    res?.vendors ||
    (Array.isArray(res) ? res : []);

  window.VENDORS_CACHE = Array.isArray(rows) ? rows : [];
  return window.VENDORS_CACHE;
}

function renderReceiveVendorsSelect(vendors) {
  const sel = document.getElementById("invReceiveVendor");
  if (!sel) return;

  const prev = sel.value;

  sel.innerHTML = `<option value="">— Select supplier —</option>` + vendors.map(v => {
    const id = v.id ?? v.vendor_id ?? "";
    const name = v.name ?? v.vendor_name ?? v.company_name ?? v.full_name ?? `Vendor #${id}`;
    return `<option value="${String(id)}">${esc(String(name))}</option>`;
  }).join("");

  // keep previous selection if still exists
  if (prev && [...sel.options].some(o => o.value === prev)) sel.value = prev;
}

async function openReceiveModal(prefill = {}) {
  const m = document.getElementById("invReceiveModal");
  if (!m) return;

  showReceiveMsg("");

  const iso = normalizeToISODate(prefill.tx_date) || new Date().toISOString().slice(0, 10);
  document.getElementById("invReceiveDate").value = iso;

  document.getElementById("invReceiveRef").value = prefill.ref || "";
  document.getElementById("invReceiveNotes").value = prefill.notes || "";

  // ✅ NEW: load vendors + populate dropdown
  try {
    const vendors = await ensureVendorsCache();
    renderReceiveVendorsSelect(vendors);
    if (prefill.vendor_id) document.getElementById("invReceiveVendor").value = String(prefill.vendor_id);
  } catch (e) {
    console.warn("[Receive] vendors load failed", e);
  }

  const tbody = document.getElementById("invReceiveTbody");
  if (tbody) tbody.innerHTML = "";

  applyReceiveColumnPolicy();
  await ensureInvItemCache();
  addReceiveLine();

  m.classList.remove("hidden");
}
window.openReceiveModal = openReceiveModal;

(function () {
  const endpoints = window.endpoints; 
  const $ = (id) => document.getElementById(id);

  const F = (n) => {
    const x = Number(String(n ?? 0).replace(/,/g, "")) || 0;
    return x.toFixed(2);
  };

  const activeParamForStatus = (status) => {
    // backend: active=1 filters active only; anything else returns all
    status = String(status || "active").toLowerCase();
    return status === "active" ? "1" : "0";
  };

  let _svcRows = [];
  let _svcEditId = null;

  function ensureSvcModalMounted() {
    if (!$("svcItemModal")) {
      const tpl = document.getElementById("tpl-service-item-modal");
      if (!tpl || !tpl.content) return false;
      const modalsMount = $("modalsMount") || document.body;
      modalsMount.appendChild(tpl.content.cloneNode(true));
    }

    const m = $("svcItemModal");
    if (m && m.dataset.bound !== "1") {
      m.dataset.bound = "1";

      $("svcModalClose")?.addEventListener("click", () => showSvcModal(false));
      $("svcModalSave")?.addEventListener("click", () =>
        saveSvcModal().catch(e => ($("svcModalMsg").textContent = e.message))
      );
      $("svcModalArchive")?.addEventListener("click", () => {
        if (_svcEditId) archiveSvcItem(_svcEditId).catch(e => ($("svcModalMsg").textContent = e.message));
      });
    }

    return true;
  }

  function showSvcModal(open) {
    const m = $("svcItemModal");
    if (!m) return;
    if (open) {
      m.classList.remove("hidden");
      m.classList.add("flex");
    } else {
      m.classList.add("hidden");
      m.classList.remove("flex");
    }
  }

  function resetSvcModal() {
    _svcEditId = null;
    $("svcModalTitle").textContent = "New Service";
    $("svcModalMsg").textContent = "";

    $("svcFormCode").value = "";
    $("svcFormName").value = "";
    $("svcFormDesc").value = "";
    $("svcFormUnit").value = "";
    $("svcFormPrice").value = "0.00";
    $("svcFormVat").value = "";
    $("svcFormTaxable").checked = true;

    $("svcFormCode").disabled = false;
    $("svcModalArchive").classList.add("hidden");
  }

  function fillSvcModal(row) {
    _svcEditId = row?.id ?? null;
    $("svcModalTitle").textContent = `Edit Service: ${row?.code || ""}`;
    $("svcModalMsg").textContent = "";

    $("svcFormCode").value = row?.code || "";
    $("svcFormName").value = row?.name || "";
    $("svcFormDesc").value = row?.description || "";
    $("svcFormUnit").value = row?.unit || "";
    $("svcFormPrice").value = F(row?.price ?? 0);
    $("svcFormVat").value = row?.vat_code || "";
    $("svcFormTaxable").checked = !!row?.is_taxable;

    // usually code should not change once used
    $("svcFormCode").disabled = true;

    $("svcModalArchive").classList.toggle("hidden", !row?.is_active);
  }

  function renderSvcRows() {
    const tbody = $("svcItemsTbody");
    const msg = $("svcItemsMsg");
    const status = String($("svcStatus")?.value || "active").toLowerCase();

    let rows = _svcRows;
    if (status === "active") rows = rows.filter(r => !!r.is_active);
    if (status === "inactive") rows = rows.filter(r => !r.is_active);

    if (!rows.length) {
      tbody.innerHTML = `<tr><td colspan="5" class="px-2 py-3 text-slate-500">No service items found.</td></tr>`;
      msg.textContent = "";
      return;
    }

    tbody.innerHTML = rows.map(r => {
      const inactiveBadge = r.is_active ? "" : `<span class="ml-2 text-[10px] px-2 py-0.5 border rounded text-slate-500">Inactive</span>`;
      return `
        <tr class="border-t">
          <td class="px-2 py-2"><div class="font-semibold">${esc(r.code || "")}</div></td>
          <td class="px-2 py-2">${esc(r.name || "")}${inactiveBadge}</td>
          <td class="px-2 py-2 text-right">${F(r.price)}</td>
          <td class="px-2 py-2">${esc((r.vat_code || "") || "-")}</td>
          <td class="px-2 py-2 text-right whitespace-nowrap">
            <button class="svc-edit px-2 py-1 text-[11px] border rounded" data-id="${r.id}">Edit</button>
            ${r.is_active ? `<button class="svc-archive ml-1 px-2 py-1 text-[11px] border rounded" data-id="${r.id}">Archive</button>` : ""}
          </td>
        </tr>
      `;
    }).join("");

    msg.textContent = `${rows.length} item(s)`;
  }

window.loadServiceItems = async function loadServiceItems() {
  const cid = getActiveCompanyId?.();
  if (!cid) return;

  const tbodyEl = $("svcItemsTbody");
  const msgEl   = $("svcItemsMsg");

  // ✅ If template not mounted, don't run UI renderer
  if (!tbodyEl || !msgEl) {
    console.warn("[ServiceItems] UI not mounted; skipping loadServiceItems()");
    return;
  }

  const q = String($("svcSearch")?.value || "").trim();
  const status = String($("svcStatus")?.value || "active").toLowerCase();

  msgEl.textContent = "Loading…";
  tbodyEl.innerHTML = `<tr><td colspan="5" class="px-2 py-3 text-slate-500">Loading…</td></tr>`;

  try {
    const rows = await window.apiFetch(window.endpoints.services.listItems(cid, {
      q,
      active: activeParamForStatus(status),
      limit: 200,
      offset: 0,
    }));

    _svcRows = Array.isArray(rows) ? rows : [];
    renderSvcRows();
  } catch (e) {
    console.warn("[ServiceItems] load failed", e);
    tbodyEl.innerHTML = `<tr><td colspan="5" class="px-2 py-3 text-red-600">Failed: ${esc(e.message || "error")}</td></tr>`;
    msgEl.textContent = "";
  }
};

let _svcSaving = false;

async function saveSvcModal() {
  const cid = getActiveCompanyId?.();
  if (!cid) return;

  if (_svcSaving) return;              // ✅ block double-submit
  _svcSaving = true;

  const btn = document.getElementById("btnSvcSave"); // use your real save button id
  if (btn) btn.disabled = true;

  try {
    const payload = {
      code: String($("svcFormCode").value || "").trim(),
      name: String($("svcFormName").value || "").trim(),
      description: String($("svcFormDesc").value || "").trim(),
      unit: String($("svcFormUnit").value || "").trim(),
      price: Number(String($("svcFormPrice").value || "0").replace(/,/g, "")) || 0,
      vat_code: String($("svcFormVat").value || "").trim(),
      is_taxable: !!$("svcFormTaxable").checked,
      is_active: true,
    };

    if (!payload.code) return void ($("svcModalMsg").textContent = "Code is required.");
    if (!payload.name) return void ($("svcModalMsg").textContent = "Name is required.");

    $("svcModalMsg").textContent = "Saving…";

    if (_svcEditId) {
      await apiFetch(endpoints.services.updateItem(cid, _svcEditId), {
        method: "PATCH",
        body: JSON.stringify(payload),
      });
    } else {
      await apiFetch(endpoints.services.createItem(cid), {
        method: "POST",
        body: JSON.stringify(payload),
      });
    }

    // ✅ keep modal open
    $("svcModalMsg").textContent = "Saved ✅ Refreshing…";
    await window.loadServiceItems?.();   // refresh list on the services screen
    $("svcModalMsg").textContent = "Saved ✅";

  } catch (e) {
    // ✅ show duplicate nicely
    const msg = e?.message || String(e);
    if ((e?.status === 400 || e?.status === 409) && /already exists|duplicate/i.test(msg)) {
      $("svcModalMsg").textContent = "That code already exists. Use a new code (e.g., SVC-006).";
    } else {
      $("svcModalMsg").textContent = `Save failed: ${msg}`;
    }
    console.error(e);
  } finally {
    _svcSaving = false;
    if (btn) btn.disabled = false;
  }
}

  async function archiveSvcItem(id) {
    const cid = getActiveCompanyId?.();
    if (!cid || !id) return;

    // If your backend archives via DELETE, keep this.
    // If it archives via PATCH {is_active:false}, tell me and I’ll adjust.
    await window.apiFetch(endpoints.services.archiveItem(cid, id), { method: "DELETE" });
    await window.loadServiceItems();
  }

  window.bindServiceItemsUI = function bindServiceItemsUI() {
    const mount = document.getElementById("catalogMount");
    if (!mount) return;

    // modal (mounts modal once if missing)
    ensureSvcModalMounted();

    const btnNew    = $("svcItemNewBtn");
    const btnRef    = $("svcItemRefreshBtn");
    const elQ       = $("svcSearch");
    const elStatus  = $("svcStatus");
    const tbody     = $("svcItemsTbody");

    const mClose    = $("svcModalClose");
    const mSave     = $("svcModalSave");
    const mArchive  = $("svcModalArchive");

    // debounce loader (recreated on each render is fine)
    let t = null;
    const schedule = () => {
      clearTimeout(t);
      t = setTimeout(() => window.loadServiceItems?.(), 250);
    };

    // helper: bind once per element instance
    const bindOnce = (el, fn) => {
      if (!el) return;
      if (el.dataset.bound === "1") return;
      el.dataset.bound = "1";
      fn();
    };

    bindOnce(btnRef, () => {
      btnRef.addEventListener("click", () => window.loadServiceItems?.());
    });

    bindOnce(btnNew, () => {
      btnNew.addEventListener("click", () => {
        resetSvcModal();
        showSvcModal(true);
      });
    });

    bindOnce(elQ, () => {
      elQ.addEventListener("input", schedule);
    });

    bindOnce(elStatus, () => {
      elStatus.addEventListener("change", () => window.loadServiceItems?.());
    });

    // modal buttons (modal persists, so bind-once is important)
    bindOnce(mClose, () => {
      mClose.addEventListener("click", () => showSvcModal(false));
    });

    bindOnce(mSave, () => {
      mSave.addEventListener("click", () =>
        saveSvcModal().catch(e => ($("svcModalMsg").textContent = e.message))
      );
    });

    bindOnce(mArchive, () => {
      mArchive.addEventListener("click", () => {
        if (_svcEditId) {
          archiveSvcItem(_svcEditId).catch(e => ($("svcModalMsg").textContent = e.message));
        }
      });
    });

    // table actions
    bindOnce(tbody, () => {
      tbody.addEventListener("click", (ev) => {
        const btn = ev.target.closest("button");
        if (!btn) return;

        const id = btn.getAttribute("data-id");
        const row = _svcRows.find(r => String(r.id) === String(id));
        if (!row) return;

        if (btn.classList.contains("svc-edit")) {
          resetSvcModal();
          fillSvcModal(row);
          showSvcModal(true);
        }

        if (btn.classList.contains("svc-archive")) {
          archiveSvcItem(id).catch(e => alert(e.message || "Archive failed"));
        }
      });
    });
  };
})();

function bindVendors() {
  const screen = document.getElementById("screen-vendors");
  if (!screen || screen.dataset.bound === "1") return;
  screen.dataset.bound = "1";

  const listHost = document.getElementById("vendList");
  const searchEl = document.getElementById("vendSearch");
  const btnNew   = document.getElementById("vendNewBtn");
  const btnSave  = document.getElementById("vendSaveBtn");
  const btnArch  = document.getElementById("vendArchiveBtn");
  const formHost = document.getElementById("vendFormHost");

  // ✅ Right panel (new)
  const rightPanel = document.getElementById("vendRightPanel");

  if (!listHost || !formHost) return;

  const cid =
    (typeof companyId === "function" ? companyId() : null) ||
    (typeof getActiveCompanyId === "function" ? getActiveCompanyId() : null) ||
    window.CURRENT_COMPANY_ID;

  if (!cid) return console.warn("[Vendors] No company id found");

  // ✅ endpoints (use your pattern)
  const ENDPOINTS = window.ENDPOINTS || {};
  if (typeof ENDPOINTS.vendors !== "function" || typeof ENDPOINTS.vendor !== "function") {
    console.warn("[Vendors] ENDPOINTS.vendors/vendor not configured");
    return;
  }

  // -------------------
  // State
  // -------------------
  let vendors = [];
  let currentId = null;
  let filterMode = "active"; // active | archived | all

  // -------------------
  // Right panel helpers
  // -------------------
  function showRightPanel(show) {
    if (!rightPanel) return;
    rightPanel.classList.toggle("hidden", !show);
  }

  function writeProfile(v = {}) {
    const emailEl  = document.getElementById("vendProfileEmail");
    const phoneEl  = document.getElementById("vendProfilePhone");
    const statusEl = document.getElementById("vendProfileStatus");

    if (emailEl)  emailEl.textContent  = v.email || "—";
    if (phoneEl)  phoneEl.textContent  = v.phone || "—";
    if (statusEl) statusEl.textContent = (v.is_active === false ? "Archived" : "Active");
  }

  // -------------------
  // Tabs
  // -------------------
  function showTab(tab) {
    formHost.querySelectorAll("[data-pane]").forEach(p => {
      p.classList.toggle("hidden", p.getAttribute("data-pane") !== tab);
    });
    formHost.scrollTop = 0;
  }

  (function bindTabs() {
    screen.querySelectorAll("[data-tab]").forEach(btn => {
      btn.addEventListener("click", () => showTab(btn.getAttribute("data-tab")));
    });
    showTab("v-basics");
  })();

  // -------------------
  // Contacts (template)
  // -------------------
  function addVendorContactRow(prefill = {}) {
    const host = document.getElementById("vendContacts");
    const tpl  = document.getElementById("vendContactTpl");
    if (!host || !tpl) return;

    const node = tpl.content.firstElementChild.cloneNode(true);

    node.querySelector(".vendCName").value  = prefill.name || prefill.full_name || "";
    node.querySelector(".vendCRole").value  = prefill.role || "";
    node.querySelector(".vendCEmail").value = prefill.email || "";
    node.querySelector(".vendCPhone").value = prefill.phone || "";

    node.querySelector(".vendContactRemove")?.addEventListener("click", () => node.remove());
    host.appendChild(node);
  }

  function readVendorContacts() {
    return Array.from(document.querySelectorAll("#vendContacts .border.rounded-lg"))
      .map(box => ({
        name:  box.querySelector(".vendCName")?.value?.trim()  || "",
        role:  box.querySelector(".vendCRole")?.value?.trim()  || "",
        email: box.querySelector(".vendCEmail")?.value?.trim() || "",
        phone: box.querySelector(".vendCPhone")?.value?.trim() || "",
      }))
      .filter(c => c.name || c.email || c.phone || c.role);
  }

  function writeVendorContacts(list = []) {
    const host = document.getElementById("vendContacts");
    if (!host) return;
    host.innerHTML = "";
    const arr = Array.isArray(list) ? list : [];
    (arr.length ? arr : [{}]).forEach(c => addVendorContactRow(c));
  }

  document.getElementById("vendAddContact")?.addEventListener("click", () => addVendorContactRow({}));

  // -------------------
  // Form read/write
  // -------------------
  function readForm() {
    const clean = (id) => {
      const v = (document.getElementById(id)?.value || "").trim();
      return v === "" ? null : v; // ✅ empty => NULL
    };

    return {
      id: currentId ? Number(currentId) : null,

      externalCode: clean("vendExternalCode"),
      name: (document.getElementById("vendName")?.value || "").trim(), // required
      email: clean("vendEmail"),
      phone: clean("vendPhone"),

      remitAddr: clean("vendRemitAddr"),
      country: clean("vendCountry"),
      regNo: clean("vendRegNo"),

      bankName: clean("vendBankName"),
      branchCode: clean("vendBranchCode"),
      accountName: clean("vendAccountName"),
      accountNumber: clean("vendAccountNumber"),
      accountType: clean("vendAccountType"),
      bankCurrency: clean("vendBankCurrency"),
      swiftCode: clean("vendSwiftCode"),

      complianceStatus: document.getElementById("vendComplianceStatus")?.value || "draft",
      complianceRequired: document.getElementById("vendComplianceRequired")?.checked || false,
      missingDocs: window.fsVendorCompliance?.getMissingDocs?.() || [],

      pay_method: clean("vendPayMethod"), // UI-only
      service: clean("vendService"),       // UI-only

      taxNo: clean("vendTaxNo"),
      vatNo: clean("vendVatNo"),
      wht: clean("vendWht"),

      vendorStatus: clean("vendStatusSelect") || "active",
      terms: clean("vendTerms") || "Due on receipt",
      onHold: clean("vendOnHold") || "no",

      notes: clean("vendNotes") || "",
      tags: clean("vendTags") || "",

      is_active: (document.getElementById("vendIsActive")?.value || "1") === "1",
      contacts: readVendorContacts(),
    };
  }

  function writeForm(v = {}) {
    const isExisting = !!v.id;
    const isActive = v.is_active !== false;

    // ✅ right panel only for existing vendor
    showRightPanel(isExisting);
    if (isExisting) writeProfile(v);

    const setVal = (id, val) => {
      const el = document.getElementById(id);
      if (el) el.value = val ?? "";
    };

    setVal("vendExternalCode", v.external_code || v.externalCode || "");
    setVal("vendName", v.name || "");
    setVal("vendEmail", v.email || "");
    setVal("vendPhone", v.phone || "");

    setVal("vendRemitAddr", v.remit_address || v.remitAddr || "");
    setVal("vendCountry", v.country || ""); // ✅ don’t force ZA
    setVal("vendRegNo", v.registration_no || v.regNo || "");

    setVal("vendBankName", v.bank_name || v.bankName || "");
    setVal("vendBranchCode", v.branch_code || v.branchCode || "");
    setVal("vendAccountName", v.account_name || v.accountName || "");
    setVal("vendAccountNumber", v.account_number || v.accountNumber || "");
    setVal("vendAccountType", v.account_type || v.accountType || "");
    setVal("vendBankCurrency", v.bank_currency || v.bankCurrency || "");
    setVal("vendSwiftCode", v.swift_code || v.swiftCode || "");

    setVal("vendPayMethod", v.pay_method || "Bank Transfer");
    setVal("vendService", v.service || "");

    setVal("vendTaxNo", v.tax_number || v.taxNo || "");
    setVal("vendVatNo", v.vat_number || v.vatNo || "");
    setVal("vendWht", (v.wht_percent ?? v.wht ?? ""));

    setVal("vendStatusSelect", v.vendor_status || v.vendorStatus || "active");
    setVal("vendTerms", v.payment_terms || v.terms || "Due on receipt");
    setVal("vendOnHold", v.on_hold || v.onHold || "no");

    setVal("vendComplianceStatus", v.compliance_status || v.complianceStatus || "draft");
    const req = (v.compliance_required ?? v.complianceRequired) === true;
    const reqEl = document.getElementById("vendComplianceRequired");
    if (reqEl) reqEl.checked = !!req;

    window.fsVendorCompliance?.writeChecklistFromVendor?.(v);
    window.fsVendorCompliance?.refreshBadge?.(v);

    setVal("vendNotes", v.notes || "");
    setVal("vendTags", v.tags || "");

    setVal("vendIsActive", isActive ? "1" : "0");

    writeVendorContacts(v.contacts || []);
    window.fsComplianceTemplateApply?.();

    const pill = document.getElementById("vendStatus");
    if (pill) pill.textContent = v.id ? (isActive ? "Saved" : "Archived") : "New";

    if (btnArch) {
      btnArch.textContent = isActive ? "Archive" : "Restore";
      btnArch.dataset.mode = isActive ? "archive" : "restore";
    }
  }

  window.fsVendorForm = { read: readForm, write: writeForm };

  const draft = bindVendorDraftAutosave({
    cid,
    getCurrentId: () => currentId,   // currentId in your state
    readForm,
    writeForm
  });

  window.fsVendorCompliance = window.fsVendorCompliance || {};
  const fsVendorCompliance = window.fsVendorCompliance;


  fsVendorCompliance.getMissingDocs = function () {
    const checked = new Set(
      Array.from(document.querySelectorAll(".vendDocChk:checked"))
        .map(x => x.getAttribute("data-doc"))
    );

    const required = [
      "cipc", "bank_proof", "tax_pin",
      // vat_cert is optional in real life; keep it required only if VAT number is filled
    ];

    const vatNo = (document.getElementById("vendVatNo")?.value || "").trim();
    if (vatNo) required.push("vat_cert");

    const missing = required.filter(k => !checked.has(k));
    const txt = document.getElementById("vendMissingDocsText");
    if (txt) txt.value = missing.join(", ");
    return missing;
  };

 (function bindComplianceTemplateUI(){
  const tpl = document.getElementById("vendComplianceTemplate");
  const hint = document.getElementById("vendComplianceTemplateHint");
  const rowBbbee = document.getElementById("vendDocRowBbbee");
  const rowGS = document.getElementById("vendDocRowGoodStanding");

  function vendorCountryGuess(){
    const c = (document.getElementById("vendCountry")?.value || "").trim().toUpperCase();
    if (c === "ZA" || c.includes("SOUTH AFRICA")) return "ZA";
    return "";
  }

  function applyTemplate(){
    const v = (tpl?.value || "auto").toLowerCase();
    const resolved = v === "auto" ? (vendorCountryGuess() || "GLOBAL") : (v.toUpperCase());

    if (hint) {
      hint.textContent =
        `Using template: ${
          v === "auto"
            ? "Auto (based on vendor country)"
            : (resolved === "GLOBAL" ? "Standard (Global)" : resolved)
        }`;
    }

    const isZA = resolved === "ZA";
    rowBbbee?.classList.toggle("hidden", !isZA);
    rowGS?.classList.toggle("hidden", !isZA);

    // if switching away from ZA, optionally uncheck ZA-only items
    if (!isZA) {
      document
        .querySelectorAll('.vendDocChk[data-doc="bbbee"], .vendDocChk[data-doc="good_standing"]')
        .forEach(chk => (chk.checked = false));
    }

    // ✅ now it exists (because you placed this after getMissingDocs)
    window.fsVendorCompliance?.getMissingDocs?.();
  }

  // expose so writeForm() can trigger it after loading vendor
  window.fsComplianceTemplateApply = applyTemplate;

  tpl?.addEventListener("change", applyTemplate);
  document.getElementById("vendCountry")?.addEventListener("input", () => {
    if ((tpl?.value || "auto") === "auto") applyTemplate();
  });

  applyTemplate();
})();

  fsVendorCompliance.writeChecklistFromVendor = function (v) {
    const missing = v.missing_docs || v.missingDocs || [];
    const missingSet = new Set(missing);

    document.querySelectorAll(".vendDocChk").forEach(chk => {
      const k = chk.getAttribute("data-doc");
      chk.checked = !missingSet.has(k); // ✅ if missing -> unchecked
    });

    fsVendorCompliance.getMissingDocs(); // refresh textarea
  };

  fsVendorCompliance.refreshBadge = function (v) {
    const badge = document.getElementById("vendComplianceBadge");
    if (!badge) return;

    const st = (v.compliance_status || v.complianceStatus || "draft").toLowerCase();
    const missing = (v.missing_docs || v.missingDocs || []);
    const label =
      st === "verified" ? "Verified" :
      st === "blocked" ? "Blocked" :
      missing.length ? "Missing docs" :
      st === "pending" ? "Pending" : "Draft";

    badge.textContent = label;
  };

  // -------------------
  // Filtering (simple)
  // -------------------
  function passFilter(v) {
    const archived = v.is_active === false;

    if (filterMode === "active" && archived) return false;
    if (filterMode === "archived" && !archived) return false;

    const q = (searchEl?.value || "").trim().toLowerCase();
    if (!q) return true;

    const hay = [
      v.name,
      v.email,
      v.external_code,
      v.phone,
    ].filter(Boolean).join(" ").toLowerCase();

    return hay.includes(q);
  }

  function renderList() {
    const items = vendors.filter(passFilter);

    listHost.innerHTML =
      items.map(v => {
        const archived = v.is_active === false;
        const archivedBadge = archived
          ? `<span class="ml-1 text-[10px] px-1.5 py-0.5 rounded-full bg-slate-100 text-slate-500 border border-slate-200">Archived</span>`
          : "";

        // ✅ Approval/Credit badge (safe even if field doesn't exist)
        const status = String(v.credit_status || v.creditStatus || v.approval_status || v.status || "").toLowerCase();
        let creditBadge = "";
        if (status) {
          creditBadge = (status === "approved")
            ? `<span class="ml-1 text-[10px] px-1.5 py-0.5 rounded-full bg-emerald-50 text-emerald-700 border border-emerald-200">Approved</span>`
            : `<span class="ml-1 text-[10px] px-1.5 py-0.5 rounded-full bg-amber-50 text-amber-700 border border-amber-200">Needs approval</span>`;
        }

        return `
          <button type="button"
            class="w-full text-left px-2 py-1 rounded text-sm border hover:bg-slate-50 ${archived ? "opacity-60 italic bg-slate-50" : ""}"
            data-vend-id="${v.id}">
            <div class="font-medium flex items-center gap-1">
              ${v.name || "(No name)"} ${archivedBadge} ${creditBadge}
            </div>
            <div class="text-xs text-slate-500">${v.email || ""}</div>
          </button>
        `;
      }).join("") ||
      `<div class="text-xs text-slate-400 mt-2">No vendors found.</div>`;

    listHost.querySelectorAll("[data-vend-id]").forEach(btn => {
      btn.addEventListener("click", () => {
        currentId = btn.getAttribute("data-vend-id");
        renderCurrent();
      });
    });
  }

  function renderCurrent() {
    if (!currentId) {
      const blank = { id: null, contacts: [], is_active: true, credit_status: "draft" };
      writeForm(blank);
      window.renderCustomerApprovalUI(blank); // ✅ shows Draft badge + disables request button until saved
      $("#custStatus") && ($("#custStatus").textContent = "New");
      return;
    }

    const c = customers.find((x) => String(x.id) === String(currentId));
    if (!c) {
      const blank = { id: null, contacts: [], is_active: true, credit_status: "draft" };
      writeForm(blank);
      window.renderCustomerApprovalUI(blank);
      $("#custStatus") && ($("#custStatus").textContent = "New");
      return;
    }

    writeForm(c);

    // ✅ Ensure the approval bar updates when switching customers
    window.renderCustomerApprovalUI(c);

    $("#custStatus") && ($("#custStatus").textContent = "Saved");
  }

  // -------------------
  // Backend
  // -------------------
  async function loadVendors() {
    const res = await apiFetch(ENDPOINTS.vendors(cid) + "?include_inactive=1");
    vendors = res?.data || res || [];
    if (!Array.isArray(vendors)) vendors = [];

    renderList();

    if (!currentId && vendors.length) {
      currentId = String(vendors[0].id);
      renderCurrent();
    }
    if (!vendors.length) {
      currentId = null;
      showRightPanel(false);
      writeForm({ id: null, contacts: [], is_active: true, vendor_status: "active", country: "ZA" });
    }
  }

  async function saveVendor() {
    const formPayload = /** @type {any} */ (readForm());
    if (!formPayload.name) return alert("Vendor name is required.");

    const roleRaw = (typeof getCurrentRole === "function" ? getCurrentRole() : "");

    if (FS.policy.vendorSaveSetsPendingIfClerk?.(cid, roleRaw)) {
      formPayload.complianceStatus = formPayload.complianceStatus || "pending";
      formPayload.compliance_status = formPayload.complianceStatus;
    }

    // 🔁 UI → API mapping (camelCase → snake_case)
    function toVendorApiPayload(p) {
      return {
        id: p.id,

        external_code: p.externalCode,
        name: p.name,
        email: p.email,
        phone: p.phone,

        remit_address: p.remitAddr,
        country: p.country,
        registration_no: p.regNo,

        bank_name: p.bankName,
        branch_code: p.branchCode,
        account_name: p.accountName,
        account_number: p.accountNumber,
        account_type: p.accountType,
        bank_currency: p.bankCurrency,
        swift_code: p.swiftCode,

        compliance_status: p.complianceStatus,
        compliance_required: p.complianceRequired,
        missing_docs: p.missingDocs,

        tax_number: p.taxNo,
        vat_number: p.vatNo,

        // ✅ WHT FIX (this was not saving before)
        wht_percent: p.wht,

        vendor_status: p.vendorStatus,
        payment_terms: p.terms,
        on_hold: p.onHold,

        notes: p.notes,
        tags: p.tags,

        is_active: p.is_active,
        contacts: p.contacts,
      };
    }

    const apiPayload = toVendorApiPayload(formPayload);

    let res;
    if (apiPayload.id) {
      res = await apiFetch(ENDPOINTS.vendor(cid, apiPayload.id), {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(apiPayload),
      });
    } else {
      res = await apiFetch(ENDPOINTS.vendors(cid), {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(apiPayload),
      });
    }

    const saved = res?.data || res;
    await loadVendors();
    currentId = String(saved?.id || currentId || "");
    renderCurrent();
    alert("Vendor saved.");
  }

  async function archiveOrRestore() {
    const v = vendors.find(x => String(x.id) === String(currentId));
    if (!v) return alert("No vendor selected.");

    const mode = btnArch?.dataset.mode || "archive";
    const makeActive = mode === "restore";

    if (!confirm(makeActive ? `Restore "${v.name}"?` : `Archive "${v.name}"?`)) return;

    await apiFetch(ENDPOINTS.vendor(cid, v.id), {
      method: "PUT",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ is_active: makeActive }),
    });

    await loadVendors();
    currentId = String(v.id);
    renderCurrent();
  }

  // -------------------
  // Filter buttons wiring
  // -------------------
  const fA = document.getElementById("vendFilterActive");
  const fR = document.getElementById("vendFilterArchived");
  const fAll = document.getElementById("vendFilterAll");

  function setFilter(mode) {
    filterMode = mode;
    [fA, fR, fAll].forEach(b => b?.classList.remove("ring-2", "ring-[var(--fs-teal)]"));
    if (mode === "active") fA?.classList.add("ring-2", "ring-[var(--fs-teal)]");
    if (mode === "archived") fR?.classList.add("ring-2", "ring-[var(--fs-teal)]");
    if (mode === "all") fAll?.classList.add("ring-2", "ring-[var(--fs-teal)]");
    renderList();
  }

  fA?.addEventListener("click", () => setFilter("active"));
  fR?.addEventListener("click", () => setFilter("archived"));
  fAll?.addEventListener("click", () => setFilter("all"));
  setFilter("active");

  // -------------------
  // Events
  // -------------------
  searchEl?.addEventListener("input", renderList);
  btnSave?.addEventListener("click", () => saveVendor().catch(e => alert(e?.message || "Save failed")));
  btnArch?.addEventListener("click", () => archiveOrRestore().catch(e => alert(e?.message || "Update failed")));

  btnNew?.addEventListener("click", () => {
    currentId = null;
    draft.clearDraft(null); // wipes "new" draft
    writeForm({ id: null, contacts: [], is_active: true, vendor_status: "active", country: "ZA" });
    showTab("v-basics");
  });

  // ✅ Compliance buttons (PUT THEM HERE)
  document.getElementById("vendRecalcCompliance")?.addEventListener("click", () => {
    window.fsVendorCompliance?.getMissingDocs?.();
  });

  document.getElementById("vendSetPending")?.addEventListener("click", () => {
    const el = document.getElementById("vendComplianceStatus");
    if (el) el.value = "pending";
    window.fsVendorCompliance?.getMissingDocs?.();
  });

  document.getElementById("vendSetVerified")?.addEventListener("click", () => {
    const roleRaw = (typeof getCurrentRole === "function" ? getCurrentRole() : "");
    const can = FS.policy.canApproveVendor?.(roleRaw, cid);

    if (!can) {
      alert("Only an approver (Manager/CFO) can mark a vendor as Verified in this mode.");
      return;
    }

    const el = document.getElementById("vendComplianceStatus");
    if (el) el.value = "verified";

    window.fsVendorCompliance?.getMissingDocs?.();
  });

  // init
  showRightPanel(false); // start hidden
  loadVendors().catch(e => console.warn("loadVendors failed:", e));
}

function vendorsDraftKey(cid, vendorId) {
  const v = vendorId ? `vend:${vendorId}` : "new";
  return `fs:vendors:draft:${cid}:${v}`;
}

function debounce(fn, ms = 250) {
  let t = null;
  return (...args) => {
    clearTimeout(t);
    t = setTimeout(() => fn(...args), ms);
  };
}

function bindVendorDraftAutosave({ cid, getCurrentId, readForm, writeForm }) {
  const saveDraft = debounce(() => {
    const key = vendorsDraftKey(cid, getCurrentId());
    const payload = readForm();

    // optional: don’t store big arrays if you don’t want
    // payload.contacts = payload.contacts || [];

    localStorage.setItem(key, JSON.stringify(payload));
  }, 250);

  // capture typing changes in the form area
  const host = document.getElementById("vendFormHost");
  if (host) {
    host.addEventListener("input", saveDraft, true);
    host.addEventListener("change", saveDraft, true);
  }

  function restoreDraft() {
    const key = vendorsDraftKey(cid, getCurrentId());
    const raw = localStorage.getItem(key);
    if (!raw) return false;

    try {
      const data = JSON.parse(raw);
      // only restore if it matches the same vendor/new draft
      writeForm(data);
      return true;
    } catch {
      return false;
    }
  }

  function clearDraft(vendorId = null) {
    const key = vendorsDraftKey(cid, vendorId);
    localStorage.removeItem(key);
  }

  return { restoreDraft, clearDraft };
}

function bindBillVendorGuards() {
  const vendEl = document.getElementById("billVendor");
  if (!vendEl || vendEl.dataset.grniBound === "1") return;

  vendEl.dataset.grniBound = "1";

  vendEl.addEventListener("change", () => {
    // ✅ prevent recursion when clearBillForm triggers change events
    if (window._BILL_CLEARING) return;

    // ✅ don't clear links while applyGrniToBillForm is auto-setting vendor
    if (window._AP_APPLYING_GRNI) {
      if (Array.isArray(window._BILL_GRNI_LINKS) && window._BILL_GRNI_LINKS.length) {
        console.log("[GRNI] Vendor changed during apply; skip clearing");
      }
      return;
    }

    // 🧹 clear linked GRNs if vendor changes (user-driven)
    window._BILL_GRNI_LINKS = [];

    // ✅ also clear hidden json so readBillForm doesn't re-load old link
    const hid = document.getElementById("billGrniLinksJson");
    if (hid) hid.value = "[]";

    // ✅ clear the bill form so a new GRN can fill it cleanly
    window._BILL_CLEARING = true;
    try {
      window.clearBillForm?.({ keepCurrency: true });
    } finally {
      window._BILL_CLEARING = false;
    }

    console.log("[GRNI] Cleared links + cleared bill due to vendor change");
  });
}

function bindAP() {
  const linesBody = document.getElementById("billLines");
  const addBtn    = document.getElementById("billAddLine");
  const delBtn    = document.getElementById("billDelLine");
  const screen    = document.getElementById("screen-ap");

  if (!linesBody || !addBtn || !delBtn || !screen) return;

  // ✅ RESTORED (old behavior): don't exit the whole bindAP on second call
  // bind-once only for buttons/hotkeys
  const firstBind = screen.dataset.apBound !== "1";
  if (firstBind) screen.dataset.apBound = "1";

  // =========================
  // Helpers
  // =========================
  const F = (n) => {
    const x = Number(String(n ?? 0).replace(/,/g, "")) || 0;
    if (typeof window.fmt === "function") return window.fmt(x);
    return x.toFixed(2);
  };

  const cid = (typeof window.getActiveCompanyId === "function")
    ? window.getActiveCompanyId()
    : (window.cid || "0");

  const DRAFT_KEY = `fs:apBillDraft:${cid || "0"}`;

  const toNum = (v, d = 0) => {
    const n = Number(String(v ?? "").replace(/,/g, ""));
    return Number.isFinite(n) ? n : d;
  };

  // =========================
  // Active root helpers (fix duplicate IDs)
  // =========================
  function getBillRoot() {
    const candidates = [
      document.querySelector("#billModal:not(.hidden)"),
      document.querySelector("#billEditor:not(.hidden)"),
      document.getElementById("screen-ap"),
      document
    ].filter(Boolean);

    // pick the first candidate that actually contains a vendorId input
    for (const c of candidates) {
      const hid = c.querySelector?.("#billVendorId");
      if (hid) return c;
    }

    return candidates[0] || document;
  }
  window.getBillRoot = getBillRoot;

  function getFirstNonEmptyValue(root, id) {
    // Search inside the visible root first
    const els = Array.from(root?.querySelectorAll?.(`#${id}`) || []);
    for (const el of els) {
      const v = (el?.value ?? el?.getAttribute?.("value") ?? "").toString().trim();
      if (v !== "") return v;
    }

    // Fallback to document (in case the input lives outside root)
    const el2 = document.getElementById(id);
    const v2 = (el2?.value ?? el2?.getAttribute?.("value") ?? "").toString().trim();
    return v2;
  }

  function refreshBillAccountDropdowns() {
    const list = Array.isArray(window.BILL_ACCOUNTS_CACHE) ? window.BILL_ACCOUNTS_CACHE : [];
    if (!list.length) return;

    document.querySelectorAll("#billLines .bill-acct").forEach(sel => {
      const keep = sel.value || "";
      sel.innerHTML =
        `<option value="">(Default)</option>` +
        list.map(a =>
          `<option value="${escapeHtml(String(a.code))}">${escapeHtml(String(a.name || a.code))}</option>`
        ).join("");
      if (keep) sel.value = keep;
    });
  }

  // ✅ Load accounts for bill lines once (new version kept)
  window._BILL_ACCTS_READY =
    window._BILL_ACCTS_READY || window.loadBillAccountsForLines?.();

  window._BILL_ACCTS_READY?.then(() => {
    refreshBillAccountDropdowns();
    if (!document.querySelector("#billLines tr"))
      addBillLine();
  });

  // Lock flags
  window._BILL_LOADING       = window._BILL_LOADING ?? false;
  window._BILL_TOTALS_LOCKED = window._BILL_TOTALS_LOCKED ?? false;
  window._BILL_REVIEW_MODE   = window._BILL_REVIEW_MODE ?? false;

  // =========================
  // VAT helpers
  // =========================
  const vatEnabledEl = document.getElementById("apBillVatEnabled");
  const vatModeEl    = document.getElementById("apBillVatMode");

  const normalizeVatCode = (raw) => {
    let s = String(raw || "").trim().toUpperCase();
    if (!s) return "STANDARD";
    s = s.split("(")[0].trim();
    s = s.split(" ")[0].trim();
    if (s === "STD") s = "STANDARD";
    if (s === "NONE") s = "EXEMPT";
    return s || "STANDARD";
  };

  const getVatRateFromCode = (raw) => {
    const code = normalizeVatCode(raw);
    if (code === "STANDARD") return 15;
    if (code === "CUSTOM") return null; // per-line custom (read from input)
    return 0; // ZERO / EXEMPT
  };

  function setVatUIVisible(enable) {
    document.querySelectorAll("#screen-ap .bill-vat-code").forEach(sel => {
      sel.disabled = !enable;
      sel.classList.toggle("opacity-50", !enable);
      sel.classList.toggle("cursor-not-allowed", !enable);
    });

    document.querySelectorAll("#screen-ap .bill-vat-custom").forEach(inp => {
      if (!enable) inp.classList.add("hidden");
      inp.disabled = !enable;
    });

    document.querySelectorAll("#screen-ap td.vat-col, #screen-ap th.vat-col").forEach(el => {
      el.classList.toggle("opacity-50", !enable);
    });
  }

  function applyVatVisibility() {
    const enable = !!vatEnabledEl?.checked;
    setVatUIVisible(enable);

    if (!enable) {
      document.querySelectorAll("#screen-ap .bill-vat-code").forEach(sel => {
        sel.value = "STANDARD";
      });
    }

    window.recalcBill?.({ force: true });
    window.saveBillDraftToLocal?.();
  }

  if (vatEnabledEl && vatEnabledEl.dataset.bound !== "1") {
    vatEnabledEl.dataset.bound = "1";
    vatEnabledEl.addEventListener("change", applyVatVisibility);
  }

  if (vatModeEl && vatModeEl.dataset.bound !== "1") {
    vatModeEl.dataset.bound = "1";
    vatModeEl.addEventListener("change", () => {
      window.recalcBill?.({ force: true });
      window.saveBillDraftToLocal?.();
    });
  }

  applyVatVisibility();

  // ✅ RESTORED (old behavior): old version also recalced right after VAT init
  window.recalcBill?.({ force: true });

  // =========================
  // Discount helper
  // =========================
  function parseDiscountRate(raw) {
    let s = String(raw ?? "").trim();
    if (!s) return 0;

    const hasPct = s.includes("%");
    s = s.replace("%", "").trim();

    const n = parseFloat(s);
    if (!Number.isFinite(n)) return 0;

    if (hasPct || n > 1) return Math.max(0, n / 100);
    return Math.max(0, n);
  }

  // =========================
  // Recalc Bill (kept)
  // =========================
  function recalcBill({ force = false } = {}) {
    const vatMode = (document.getElementById("apBillVatMode")?.value || "exclusive").toLowerCase();

    if (window._BILL_REVIEW_MODE && !force) return null;
    if (window._BILL_LOADING && !force) return null;
    if (window._BILL_TOTALS_LOCKED && !force) return null;

    const body = document.getElementById("billLines");
    if (!body) return null;

    const rows = Array.from(body.querySelectorAll("tr"));
    const vatEnabled = !!document.getElementById("apBillVatEnabled")?.checked;

    let subtotalRawNet   = 0;
    let subtotalRawGross = 0;
    let vatTotalRaw      = 0;

    const vatableByRateNet   = {};
    const vatableByRateGross = {};

    rows.forEach(row => {
      const qtyEl     = row.querySelector(".bill-qty");
      const priceEl   = row.querySelector(".bill-price");
      const codeEl    = row.querySelector(".bill-vat-code");
      const customEl  = row.querySelector(".bill-vat-custom");

      const vatSpan   = row.querySelector(".bill-vat-amt");
      const totalSpan = row.querySelector(".bill-line-total");

      let qty = Math.max(0, toNum(qtyEl?.value, 0));
      if (qtyEl) qtyEl.value = String(qty);

      const price = Math.max(0, toNum(priceEl?.value, 0));
      const gross = qty * price;

      const code = normalizeVatCode(codeEl?.value || "STANDARD");

      let rate = 0;
      if (vatEnabled) {
        if (code === "CUSTOM") rate = Math.max(0, toNum(customEl?.value, 0));
        else rate = getVatRateFromCode(code) || 0;
      }

      let lineNet = 0, lineVat = 0, lineTotal = 0;

      if (!vatEnabled || rate <= 0) {
        lineTotal = gross;
        lineNet   = gross;
        lineVat   = 0;
      } else if (vatMode === "inclusive") {
        lineTotal = gross;
        lineNet   = gross / (1 + rate / 100);
        lineVat   = lineTotal - lineNet;
      } else {
        lineNet   = gross;
        lineVat   = lineNet * (rate / 100);
        lineTotal = lineNet + lineVat;
      }

      subtotalRawNet   += lineNet;
      subtotalRawGross += lineTotal;
      vatTotalRaw      += lineVat;

      if (vatEnabled && rate > 0) {
        if (vatMode === "inclusive") {
          vatableByRateGross[rate] = (vatableByRateGross[rate] || 0) + lineTotal;
        } else {
          vatableByRateNet[rate] = (vatableByRateNet[rate] || 0) + lineNet;
        }
      }

      if (vatSpan)   vatSpan.textContent   = F(lineVat);
      if (totalSpan) totalSpan.textContent = F(lineTotal);
    });

    const root = getBillRoot();
    const discRaw = getFirstNonEmptyValue(root, "billDisc");
    const othRaw  = getFirstNonEmptyValue(root, "billOther");
    const discRate = parseDiscountRate(discRaw);
    const other    = toNum(othRaw, 0);

    const discBase = (vatMode === "inclusive") ? subtotalRawGross : subtotalRawNet;
    let discAmt = Math.min(Math.max(0, discBase * discRate), discBase);

    let vatAfterDisc = 0;
    if (vatEnabled && discAmt > 0) {
      if (vatMode === "inclusive") {
        const baseGross = subtotalRawGross || 0;
        Object.keys(vatableByRateGross).forEach(k => {
          const rate = Number(k);
          const grossBase = vatableByRateGross[rate] || 0;
          const share = baseGross > 0 ? (grossBase / baseGross) : 0;
          const grossAfter = Math.max(0, grossBase - (discAmt * share));
          const netAfter = grossAfter / (1 + rate / 100);
          vatAfterDisc += (grossAfter - netAfter);
        });
      } else {
        const baseNet = subtotalRawNet || 0;
        Object.keys(vatableByRateNet).forEach(k => {
          const rate = Number(k);
          const netBase = vatableByRateNet[rate] || 0;
          const share = baseNet > 0 ? (netBase / baseNet) : 0;
          const netAfter = Math.max(0, netBase - (discAmt * share));
          vatAfterDisc += netAfter * (rate / 100);
        });
      }
    } else {
      vatAfterDisc = vatEnabled ? vatTotalRaw : 0;
    }

    const netDiscAmt = (vatMode === "inclusive")
      ? (subtotalRawGross > 0 ? (discAmt * (subtotalRawNet / subtotalRawGross)) : 0)
      : discAmt;

    const netAfterDisc = Math.max(0, subtotalRawNet - netDiscAmt);
    const subtotalDisplay = Math.max(0, netAfterDisc + other);
    const vatDisplay      = Math.max(0, vatAfterDisc);
    const totalDisplay    = Math.max(0, subtotalDisplay + vatDisplay);

    if (!window._BILL_TOTALS_LOCKED || force) {
      const subEl = root.querySelector("#billSubtotal");
      const vatEl = root.querySelector("#billVat");
      const totEl = root.querySelector("#billTotal");

      if (subEl) subEl.textContent = F(subtotalDisplay);
      if (vatEl) vatEl.textContent = F(vatDisplay);
      if (totEl) totEl.textContent = F(totalDisplay);

      const wrap = root.querySelector("#billDiscountWrap");
      const amt  = root.querySelector("#billDiscountAmt");

      if (wrap && amt) {
        const show = netDiscAmt > 0.000001;
        wrap.classList.toggle("hidden", !show);
        amt.textContent = F(netDiscAmt);
      }
    }

    return {
      subtotal_amount: subtotalDisplay,
      discount_amount: netDiscAmt,
      discount_rate: discRate,
      vat_amount: vatDisplay,
      total_amount: totalDisplay,
      other,
      vat_mode: vatMode,
      _raw_subtotal_net: subtotalRawNet,
      _raw_subtotal_gross: subtotalRawGross,
      _discount_amount_gross_basis: discAmt,
    };
  }
  window.recalcBill = recalcBill;

  (function bindTotalsInputs() {
    const root = getBillRoot();
    const ids = ["billDisc", "billOther", "apBillVatEnabled", "apBillVatMode"];

    ids.forEach((id) => {
      const els = Array.from(root.querySelectorAll(`#${id}`));
      els.forEach((el) => {
        if (el.dataset.recalcBound === "1") return;
        el.dataset.recalcBound = "1";

        const handler = () => {
          window.recalcBill?.({ force: true });
          window.saveBillDraftToLocal?.();
        };

        el.addEventListener("input", handler);
        el.addEventListener("change", handler);
      });
    });
  })();

  // =========================
  // Add Bill Line
  // =========================
  function addBillLine(data = {}) {
    const body = document.getElementById("billLines");
    if (!body) return null;

    const row = document.createElement("tr");
    row.className = "bill-line-row";
    row.innerHTML = `
      <td class="px-2 py-1 text-xs">
        <input class="w-full border rounded px-1 py-0.5 text-xs bill-item" placeholder="Item / Service">
      </td>
      <td class="px-2 py-1 text-xs">
        <input class="w-full border rounded px-1 py-0.5 text-xs bill-desc" placeholder="Description" required>
      </td>
      <td class="px-2 py-1 text-xs">
        <select class="w-full border rounded px-1 py-0.5 text-xs bill-acct">
          <option value="">(Default)</option>
        </select>
      </td>
      <td class="px-2 py-1 text-xs text-right">
        <input type="number" step="0.01" class="w-full border rounded px-1 py-0.5 text-right text-xs bill-qty" value="1">
      </td>
      <td class="px-2 py-1 text-xs text-right">
        <input type="number" step="0.01" class="w-full border rounded px-1 py-0.5 text-right text-xs bill-price" value="0.00">
      </td>
      <td class="px-2 py-1 text-xs vat-col">
        <div class="flex items-center justify-end gap-2">
          <select class="border rounded px-2 py-1 text-xs bill-vat-code">
            <option value="STANDARD">STANDARD (15%)</option>
            <option value="ZERO">ZERO (0%)</option>
            <option value="EXEMPT">EXEMPT (0%)</option>
            <option value="CUSTOM">CUSTOM</option>
          </select>
          <input type="number" min="0" step="0.01"
            class="hidden w-[110px] border rounded px-2 py-1 text-xs bill-vat-custom"
            placeholder="Custom %" inputmode="decimal" />
        </div>
      </td>
      <td class="px-2 py-1 text-xs text-right vat-col"><span class="bill-vat-amt">0.00</span></td>
      <td class="px-2 py-1 text-xs text-right"><span class="bill-line-total">0.00</span></td>
      <td class="px-2 py-1 text-xs">
        <button type="button" class="btn bill-del-row">×</button>
      </td>
    `;

    body.appendChild(row);

    // Prefill
    row.querySelector(".bill-item").value  = String(data.item_name ?? data.itemName ?? data.item ?? "");
    row.querySelector(".bill-desc").value  = String(data.description ?? data.desc ?? data.memo ?? "");
    row.querySelector(".bill-qty").value   = String(data.quantity ?? data.qty ?? 1);
    row.querySelector(".bill-price").value = String(data.unit_price ?? data.unitPrice ?? data.price ?? 0);

    const acctSel = row.querySelector(".bill-acct");
    if (acctSel) {
      const list = Array.isArray(window.BILL_ACCOUNTS_CACHE) ? window.BILL_ACCOUNTS_CACHE : [];
      acctSel.innerHTML =
        `<option value="">(Default)</option>` +
        list.map(a => `<option value="${escapeHtml(String(a.code))}">${escapeHtml(String(a.name || a.code))}</option>`).join("");
      const acctVal = data.account_code ?? data.accountCode ?? "";
      if (acctVal) acctSel.value = String(acctVal);
    }

    // row VAT controls
    const codeSel   = row.querySelector(".bill-vat-code");
    const customEl  = row.querySelector(".bill-vat-custom");

    const vatRate = toNum(data.vat_rate ?? data.vatRate, 0);
    let vatCode = String(data.vatCode ?? data.vat_code ?? data.vat ?? "").trim().toUpperCase();
    if (!vatCode) {
      if (vatRate === 15) vatCode = "STANDARD";
      else if (vatRate === 0) vatCode = "ZERO";
      else if (vatRate > 0) vatCode = "CUSTOM";
      else vatCode = "ZERO";
    }
    if (codeSel) codeSel.value = vatCode || "STANDARD";
    if (customEl) {
      if (vatCode === "CUSTOM" && vatRate > 0) customEl.value = String(vatRate);
      else if (!String(customEl.value || "").trim()) customEl.value = "15";
    }

    function syncCustomUI() {
      const vatEnabled = !!document.getElementById("apBillVatEnabled")?.checked;
      const v = normalizeVatCode(codeSel?.value);

      if (!vatEnabled) {
        customEl?.classList.add("hidden");
        if (customEl) customEl.disabled = true;
        return;
      }

      if (customEl) customEl.disabled = false;

      if (v === "CUSTOM") {
        customEl?.classList.remove("hidden");
        if (!String(customEl?.value || "").trim()) customEl.value = "15";
      } else {
        customEl?.classList.add("hidden");
      }
    }

    syncCustomUI();

    codeSel?.addEventListener("change", () => {
      syncCustomUI();
      window.recalcBill?.({ force: true });
      window.saveBillDraftToLocal?.();
    });

    customEl?.addEventListener("input", () => {
      window.recalcBill?.({ force: true });
      window.saveBillDraftToLocal?.();
    });

    row.querySelector(".bill-del-row")?.addEventListener("click", () => {
      row.remove();
      if (!document.querySelector("#billLines tr")) addBillLine();
      window.recalcBill?.({ force: true });
      window.saveBillDraftToLocal?.();
    });

    if (!window._BILL_LOADING && !window._BILL_TOTALS_LOCKED) {
      row.querySelectorAll("input,select").forEach(el => {
        el.addEventListener("input", () => { window.recalcBill?.({ force: true }); window.saveBillDraftToLocal?.(); });
        el.addEventListener("change", () => { window.recalcBill?.({ force: true }); window.saveBillDraftToLocal?.(); });
      });
    }

    window.recalcBill?.({ force: true });
    return row;
  }
  window.addBillLine = addBillLine;

  // Reads GRNI links from hidden JSON field
  window.readBillGrniLinks = function () {
    try {
      const raw = document.getElementById("billGrniLinksJson")?.value || "[]";
      const arr = JSON.parse(raw);
      return Array.isArray(arr) ? arr : [];
    } catch (e) {
      console.error("Failed to parse GRNI links JSON:", e);
      return [];
    }
  };

  // Writes GRNI links to hidden JSON field
  window.writeBillGrniLinks = function (links) {
    const clean = (Array.isArray(links) ? links : []).map(x => ({
      receipt_tx_id: parseInt(x.receipt_tx_id || x.tx_id || 0, 10) || 0,
      amount: Number(x.amount || 0) || 0,
    })).filter(x => x.receipt_tx_id > 0 && x.amount > 0);

    const el = document.getElementById("billGrniLinksJson");
    if (el) el.value = JSON.stringify(clean);
  };

  // =========================
  // Read/Write Bill Form (kept)
  // =========================
  function readBillForm() {
    const root = getBillRoot();

    window.syncDueDateFromTerms?.({ force: true });

    const unwrapVal = (v) => {
      if (!v) return "";
      if (typeof v === "object" && v instanceof HTMLElement && "value" in v) return String(v.value || "").trim();
      if (typeof v === "object" && "value" in v) return String(v.value || "").trim();
      if (v instanceof Date && !isNaN(v)) return v.toISOString().slice(0, 10);
      return String(v || "").trim();
    };

    const toISODate = (v) => {
      const s = unwrapVal(v);
      if (!s) return "";
      if (/^\d{4}-\d{2}-\d{2}/.test(s)) return s.slice(0, 10);

      const m = s.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
      if (m) return `${m[3]}-${String(m[1]).padStart(2, "0")}-${String(m[2]).padStart(2, "0")}`;

      return "";
    };

    const billDateEls = Array.from(root.querySelectorAll("#billDate"));
    const rawBillDate = billDateEls
      .map(el => (el.value || el.getAttribute("value") || "").trim())
      .find(Boolean) || "";
    const billDateISO = toISODate(rawBillDate);

    const dueEls = Array.from(root.querySelectorAll("#billDue"));
    const rawDue = dueEls
      .map(el => (el.value || el.getAttribute("value") || "").trim())
      .find(Boolean) || "";
    const dueISO = toISODate(rawDue) || null;

    // ---- Vendor (supports <select> OR <input>) ----
    const vendorEl = root.querySelector("#billVendor");
    const vendorIdEl = root.querySelector("#billVendorId");

    let vendorName = "";
    let vendorId = (vendorIdEl?.value || "").trim();

    if (vendorEl) {
      if (vendorEl.tagName === "SELECT") {
        // select stores id
        vendorId = vendorId || String(vendorEl.value || "").trim();
        // optional: try display name
        const opt = vendorEl.selectedOptions?.[0];
        vendorName = (opt?.textContent || "").trim();
      } else {
        // input stores name
        vendorName = String(vendorEl.value || "").trim();
      }
    }

    if (!vendorId && vendorName) {
      const v = (typeof resolveVendorByTypedValue === "function")
        ? resolveVendorByTypedValue(vendorName)
        : null;

      if (v?.id) {
        vendorId = String(v.id);
        if (vendorIdEl) vendorIdEl.value = vendorId;
      }
    }

    // ✅ read GRNI links json (hidden)
    // ✅ GRNI links (prefer hidden json if it exists, fallback to window var)
    let grni_links = [];
    try {
      const el = root.querySelector("#billGrniLinksJson");
      if (el?.value) grni_links = JSON.parse(el.value);
    } catch (_) {}

    if (!Array.isArray(grni_links) || !grni_links.length) {
      grni_links = Array.isArray(window._BILL_GRNI_LINKS) ? window._BILL_GRNI_LINKS : [];
    }

    // ✅ normalize (backend usually expects numbers + correct keys)
    grni_links = (grni_links || [])
      .map(x => ({
        receipt_tx_id: Number(x?.receipt_tx_id || 0),
        amount: Number(String(x?.amount ?? 0).replace(/,/g, "")) || 0,
      }))
      .filter(x => x.receipt_tx_id > 0 && x.amount > 0);

    const rows = Array.from(root.querySelectorAll("#billLines tr"));
    const lines = rows.map((row, i) => {
      const item    = row.querySelector(".bill-item")?.value || "";
      const desc    = row.querySelector(".bill-desc")?.value || "";
      const acct    = row.querySelector(".bill-acct")?.value || "";
      const qty     = toNum(row.querySelector(".bill-qty")?.value, 0);
      const price   = toNum(row.querySelector(".bill-price")?.value, 0);
      const vatCode = normalizeVatCode(row.querySelector(".bill-vat-code")?.value || "STANDARD");
      const customRate = toNum(row.querySelector(".bill-vat-custom")?.value, 0);

      return {
        line_no: i + 1,
        item_name: item,
        description: desc,
        account_code: acct || null,
        quantity: qty,
        unit_price: price,
        vat_code: vatCode,
        vat_rate: vatCode === "CUSTOM" ? customRate : getVatRateFromCode(vatCode),
      };
    });

    const totals = window.recalcBill?.({ force: true }) || {};

    return {
      id: (root.querySelector("#billId")?.value || "").trim() || null,
      vendorName,
      vendor_id: (/^\d+$/.test(vendorId) ? parseInt(vendorId, 10) : null),
      grni_links,
      number: (root.querySelector("#billNumber")?.value || "").trim() || null,
      bill_date: billDateISO,
      due_date: dueISO,
      currency: (root.querySelector("#billCurrency")?.value || "").trim() || null,
      vat_enabled: !!root.querySelector("#apBillVatEnabled")?.checked,
      discount_rate: parseDiscountRate(root.querySelector("#billDisc")?.value),
      other_amount: toNum(root.querySelector("#billOther")?.value, 0),
      notes: (root.querySelector("#billMemo")?.value || "").trim(),
      lines,
      totals,
      status: (root.querySelector("#billStatus")?.textContent || "draft").toLowerCase(),
    };
  }
  window.readBillForm = readBillForm;

  function writeBillForm(b = {}) {
    window._BILL_LOADING = true;

    const root = getBillRoot();

    const setVal = (id, val) => {
      const els = Array.from(root.querySelectorAll(`#${id}`));
      if (!els.length) return;

      if (val && typeof val === "object" && "value" in val) val = val.value;
      const v = (val ?? "");

      els.forEach(el => {
        el.value = v;
        el.setAttribute("value", v);
      });
    };

    const unwrapVal = (v) => {
      if (!v) return "";
      if (typeof v === "object" && v instanceof HTMLElement && "value" in v) return v.value || "";
      if (typeof v === "object" && "value" in v) return v.value || "";
      if (v instanceof Date && !isNaN(v)) return v.toISOString().slice(0, 10);
      return String(v || "").trim();
    };

    const toISODate = (v) => {
      const s = unwrapVal(v);
      if (!s) return "";
      if (/^\d{4}-\d{2}-\d{2}/.test(s)) return s.slice(0, 10);

      const m = s.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
      if (m) return `${m[3]}-${String(m[1]).padStart(2, "0")}-${String(m[2]).padStart(2, "0")}`;

      return "";
    };

    const billId = b.id || "";
    const billDate = toISODate(b.bill_date) || new Date().toISOString().slice(0, 10);
    const dueDate  = toISODate(b.due_date);

    setVal("billId", billId);
    // ---- Vendor (supports <select> OR <input>) ----
    const vendorEl = root.querySelector("#billVendor");
    const vendorIdEl = root.querySelector("#billVendorId");

    const vId = (b.vendor_id ?? b.vendorId ?? "").toString();
    const vName = (b.vendorName || b.vendor_name || "").toString();

    if (vendorIdEl) vendorIdEl.value = vId;

    if (vendorEl) {
      if (vendorEl.tagName === "SELECT") {
        vendorEl.value = vId;
        vendorEl.dispatchEvent(new Event("change", { bubbles: true }));
      } else {
        vendorEl.value = vName;
        vendorEl.dispatchEvent(new Event("input", { bubbles: true }));
        vendorEl.dispatchEvent(new Event("change", { bubbles: true }));
      }
    }
    setVal("billNumber", b.number || "");
    setVal("billDate", billDate);
    setVal("billDue", dueDate);
    setVal("billCurrency", b.currency || (window.CURRENT_COMPANY?.currency || "ZAR"));

    // ✅ NEW: store GRNI links on the form (hidden)
    try {
      const links = Array.isArray(b.grni_links) ? b.grni_links : [];
      const el = root.querySelector("#billGrniLinksJson") || document.getElementById("billGrniLinksJson");
      if (el) el.value = JSON.stringify(links);
    } catch {}

    window._BILL_LOADING = false;
    window.syncDueDateFromTerms?.({ force: true });
    window.recalcBill?.({ force: true });
  }
  window.writeBillForm = writeBillForm;

  // =========================
  // Local draft save/load (kept)
  // =========================
  window.saveBillDraftToLocal = function saveBillDraftToLocal() {
    try {
      window.syncDueDateFromTerms?.({ force: true });
      const form = (typeof window.readBillForm === "function") ? window.readBillForm() : null;
      if (!form) return;

      localStorage.setItem(DRAFT_KEY, JSON.stringify({
        saved_at: new Date().toISOString(),
        form,
      }));
    } catch (e) {
      console.warn("[AP] saveBillDraftToLocal failed:", e);
    }
  };

  async function saveBillDraft(status = "draft") {
    const cid2 = window.FS?.control?.resolveCid?.();
    if (!cid2) throw new Error("No company selected.");

    // ✅ force vendor sync BEFORE readBillForm()
    await window._forceSyncBillVendor?.();

    const form = (typeof window.readBillForm === "function") ? window.readBillForm() : null;
    if (!form) throw new Error("Bill form not available.");

    const rootDbg = (typeof getBillRoot === "function") ? getBillRoot() : document;
    const domVendorId =
      (rootDbg.querySelector("#billVendorId")?.value || document.getElementById("billVendorId")?.value || "").trim();

    console.log("[DEBUG saveBillDraft]", {
      form_vendor_id: form.vendor_id,
      form_vendorName: form.vendorName,
      domVendorId,
      domVendorName: (rootDbg.querySelector("#billVendor")?.value || document.getElementById("billVendor")?.value || "").trim(),
    });

    // ✅ HARD FIX: if DOM has vendor id, force it onto the form
    if (!form.vendor_id || Number(form.vendor_id) <= 0) {
      const v = String(domVendorId || "").trim();
      if (/^\d+$/.test(v)) form.vendor_id = parseInt(v, 10);
    }

    // ✅ fallback read from hidden input
    if (!form.vendor_id) {
      const root = (typeof getBillRoot === "function") ? getBillRoot() : document;
      const v = (getFirstNonEmptyValue(root, "billVendorId") || "").trim();
      if (/^\d+$/.test(v)) form.vendor_id = parseInt(v, 10);
    }

    if (!form.vendor_id) throw new Error("Vendor is required.");
    if (!form.bill_date) throw new Error("Bill date is required.");
    if (!Array.isArray(form.lines) || !form.lines.length) throw new Error("Add at least one line.");

    window.syncDueDateFromTerms?.({ force: true });

    const root = (typeof getBillRoot === "function") ? getBillRoot() : document;
    const dueISO = (root.querySelector("#billDue")?.value || "").slice(0, 10) || null;

    const toNum = (x, d = 0) => {
      try {
        if (x == null) return d;
        if (typeof x === "string") x = x.replace(/,/g, "").trim();
        const n = Number(x);
        return Number.isFinite(n) ? n : d;
      } catch {
        return d;
      }
    };

    const toDiscRate = (x) => {
      let r = toNum(x, 0);
      if (r > 1) r = r / 100;   // allow 5 => 0.05
      return Math.max(0, Math.min(1, r));
    };

    const lines = (form.lines || []).map((l) => {
      const vat_code = normalizeVatCode(l.vat_code || "STANDARD");
      let vat_rate =
        vat_code === "CUSTOM"
          ? toNum(l.vat_rate, 0)
          : toNum(getVatRateFromCode(vat_code), 0);

      // if custom rate came as 0.15, convert to 15
      if (vat_code === "CUSTOM" && vat_rate > 0 && vat_rate <= 1) vat_rate = vat_rate * 100;

      return { ...l, vat_code, vat_rate };
    });

    const t = form.totals || {};

    const header = {
      vendor_id: form.vendor_id,
      bill_date: form.bill_date,
      due_date: dueISO,
      currency: form.currency || null,
      number: form.number || null,
      notes: form.notes || null,
      status,

      discount_rate: toDiscRate(form.discount_rate),
      discount_amount: toNum(t.discount_amount, 0),
      other_amount: toNum(t.other, toNum(form.other_amount, 0)),

      subtotal_amount: toNum(t.subtotal_amount, 0),
      vat_amount: toNum(t.vat_amount, 0),
      total_amount: toNum(t.total_amount, 0),
    };

    const billId = parseInt(root.querySelector("#billId")?.value || "0", 10) || 0;

    // ✅ GRNI links (goods receipt matching)
    // Prefer: form.grni_links (if you store it on form / hidden input)
    // Fallback: window._BILL_GRNI_LINKS (set when user clicks GRN row)
    const rawLinks =
      (Array.isArray(form.grni_links) && form.grni_links.length ? form.grni_links : null) ||
      (Array.isArray(window._BILL_GRNI_LINKS) && window._BILL_GRNI_LINKS.length ? window._BILL_GRNI_LINKS : null) ||
      (Array.isArray(window.readBillGrniLinks?.()) ? window.readBillGrniLinks() : []);

    const grni_links = (rawLinks || [])
      .map(x => ({
        receipt_tx_id: parseInt(x.receipt_tx_id || x.tx_id || x.receiptTxId || 0, 10) || 0,
        amount: toNum(x.amount ?? x.remaining ?? 0, 0),
      }))
      .filter(x => x.receipt_tx_id > 0 && x.amount > 0);

    console.log("[DEBUG grni_links]", grni_links);

    let res;
    if (billId && window.ENDPOINTS?.bill) {
      res = await window.apiFetch(window.ENDPOINTS.bill(cid2, billId), {
        method: "PUT",
        body: JSON.stringify({ header, lines, grni_links }),
      });
    } else {
      res = await window.apiFetch(window.ENDPOINTS.bills(cid2), {
        method: "POST",
        body: JSON.stringify({ header, lines, grni_links }),
      });
    }

    const saved = res?.data || res;
    window.writeBillForm?.(saved);

    // ✅ if you want to immediately clear for a new bill:
    //window.clearBillForm?.({ keepCurrency: true });

    return saved;
  }
  window.saveBillDraft = saveBillDraft;

  function clearBillForm({ keepCurrency = true } = {}) {
    const root = (typeof getBillRoot === "function") ? getBillRoot() : document;

    // ✅ prevent vendor guards/watchers recursion
    window._BILL_CLEARING = true;
    window._BILL_LOADING = true;

    const setVal = (id, val) => {
      const els = Array.from(root.querySelectorAll(`#${id}`));
      if (!els.length) return;
      const v = (val ?? "");
      els.forEach(el => {
        el.value = v;
        el.setAttribute("value", v);
        // ❌ DO NOT dispatch input/change here during clear
      });
    };

    // Header fields
    setVal("billId", "");
    setVal("billVendor", "");
    setVal("billVendorId", "");
    setVal("billNumber", "");

    const today = new Date().toISOString().slice(0, 10);
    setVal("billDate", today);
    setVal("billDue", "");

    if (!keepCurrency) {
      setVal("billCurrency", window.CURRENT_COMPANY?.currency || "ZAR");
    }

    setVal("billNotes", "");
    setVal("billMemo", "");

    const hid = root.querySelector("#billGrniLinksJson");
    if (hid) hid.value = "[]";
    window._BILL_GRNI_LINKS = [];

    const linesBody = root.querySelector("#billLines");
    if (linesBody) linesBody.innerHTML = "";

    if (typeof window.addBillLine === "function") {
      window.addBillLine();
    }

    window._BILL_LOADING = false;
    window._BILL_CLEARING = false;

    // Now do recalcs once, manually
    window.syncDueDateFromTerms?.({ force: true });
    window.recalcBill?.({ force: true });
  }
  window.clearBillForm = clearBillForm;

  window.loadBillDraftFromLocal = function loadBillDraftFromLocal() {
    try {
      const raw = localStorage.getItem(DRAFT_KEY);
      if (!raw) return false;
      const obj = JSON.parse(raw);
      const form = obj?.form || null;
      if (!form) return false;
      window.writeBillForm?.(form);
      return true;
    } catch (e) {
      return false;
    }
  };

  // ✅ RESTORED (old block): Header autosave
  const headerIds = [
    "billVendor","billVendorId","billNumber","billDate","billDue","billCurrency",
    "billDisc","billOther","billMemo","apBillVatEnabled"
  ];

  headerIds.forEach(id => {
    const el = document.getElementById(id);
    if (!el) return;
    if (el.dataset.apDraftBound === "1") return;
    el.dataset.apDraftBound = "1";
    el.addEventListener("input", () => window.saveBillDraftToLocal?.());
    el.addEventListener("change", () => window.saveBillDraftToLocal?.());
  });

  // =========================
  // Buttons (bind once)  ✅ RESTORED old "only bind once" behavior
  // =========================
  if (firstBind && addBtn.dataset.bound !== "1") {
    addBtn.dataset.bound = "1";
    addBtn.addEventListener("click", () => {
      addBillLine();
      window.saveBillDraftToLocal?.();
    });
  }

  if (firstBind && delBtn.dataset.bound !== "1") {
    delBtn.dataset.bound = "1";
    delBtn.addEventListener("click", () => {
      const rows = Array.from(document.querySelectorAll("#billLines tr"));
      const last = rows[rows.length - 1];
      if (last) last.remove();
      if (!document.querySelector("#billLines tr")) addBillLine();
      window.recalcBill?.({ force: true });
      window.saveBillDraftToLocal?.();
    });
  }

  // posting UI
  window.applyBillButtonsByMode?.();
  window.bindBillPostingUI?.();

  // ✅ RESTORED (old block): Edit button binding
  const btnEdit = document.getElementById("billEdit");
  if (btnEdit && btnEdit.dataset.bound !== "1") {
    btnEdit.dataset.bound = "1";
    btnEdit.type = "button";
    btnEdit.addEventListener("click", (e) => {
      e.preventDefault();
      window.unlockBillForEditing?.();
      window.applyBillButtonsByMode?.();
    });
  }

  // ✅ RESTORED (old block): Hotkeys
  if (firstBind && !document.body.dataset.apHotkeysBound) {
    document.body.dataset.apHotkeysBound = "1";
    document.addEventListener("keydown", async (e) => {
      const inAP = !!document.getElementById("screen-ap")?.classList.contains("active");
      if (!inAP) return;

      if ((e.ctrlKey || e.metaKey) && e.key.toLowerCase() === "s") {
        e.preventDefault();
        try {
          await window.commitBill?.("draft");
        } catch (err) {
          console.warn("[AP] Ctrl+S failed:", err);
          alert(err?.message || "Failed to save draft");
        } finally {
          window.applyBillButtonsByMode?.();
        }
        return;
      }

      if ((e.ctrlKey || e.metaKey) && e.key === "Enter") {
        e.preventDefault();
        try {
          await window.commitBill?.("approve_post");
        } catch (err) {
          console.warn("[AP] Ctrl+Enter failed:", err);
          alert(err?.message || "Failed to approve/post bill");
        } finally {
          window.applyBillButtonsByMode?.();
        }
      }
    });
  }

  // ensure at least one row
  if (!document.querySelector("#billLines tr")) addBillLine();
  window.recalcBill?.({ force: true });
  bindBillVendorGuards();   // 👈 add here
}
window.bindAP = bindAP;


async function loadBillIntoForm(billId, { mode = "review" } = {}) {
  const cid = FS.control.resolveCid();
  if (!cid) throw new Error("No active company.");

  // 🔒 lock immediately to avoid recalc flicker
  window._BILL_LOADING = true;
  window._BILL_TOTALS_LOCKED = true;
  window._BILL_REVIEW_MODE = (mode === "review");

  const res = await apiFetch(ENDPOINTS.bill(cid, billId), { method: "GET" });
  const bill = res?.data || res;
  if (!bill || !bill.id) throw new Error("Invalid bill payload.");

  // ---------------------------
  // 1) Write backend values exactly
  // ---------------------------
  window.writeBillForm?.(bill);

  // ---------------------------
  // 2) Optional: update bill date when EDITING a draft
  // ---------------------------
  if (mode === "edit" && String(bill.status).toLowerCase() === "draft") {
    const today = new Date().toISOString().slice(0, 10);

    const billDateEl = document.getElementById("billDate");
    if (billDateEl) billDateEl.value = today;

    // also re-sync due date from terms if you already support this
    window.syncDueDateFromTerms?.({ force: true });
  }

  // ---------------------------
  // 3) Lock / unlock based on mode
  // ---------------------------
  if (mode === "review") {
    lockBillFormForReviewers(bill.status, bill.id);
    window._BILL_TOTALS_LOCKED = true;
  } else {
    unlockBillForEditing();
    window._BILL_TOTALS_LOCKED = false;
  }

  // ---------------------------
  // 4) Done
  // ---------------------------
  window._BILL_LOADING = false;
  window._BILL_REVIEW_MODE = (mode === "review");

  return bill;
}

window.loadBillIntoForm = loadBillIntoForm;

function lockGrniAccount(tr) {
  if (!tr) return;

  const acctEl = tr.querySelector(".bill-acct");
  if (!acctEl) return;

  const code  = window.GRNI_CLEARING_ACCOUNT_CODE || "BS_CL_2215";
  const label = window.GRNI_CLEARING_ACCOUNT_LABEL || "GRNI Control (Clearing)";

  // Set code as the real value, but show friendly label
  if (acctEl.tagName === "SELECT") {
    // ensure a dedicated option exists
    let opt = [...acctEl.options].find(o => o.value === code);
    if (!opt) {
      opt = document.createElement("option");
      opt.value = code;
      acctEl.insertBefore(opt, acctEl.firstChild);
    }

    // ✅ what user sees
    opt.textContent = label;

    // ✅ actual saved value (posting / validation uses this)
    acctEl.value = code;
  } else {
    // if it's an input, show label but store code separately
    acctEl.value = label;
    acctEl.dataset.value = code; // keep code for your guard if needed
  }

  acctEl.disabled = true;
  acctEl.dataset.locked = "grni";
  acctEl.classList.add("bg-slate-100", "text-slate-500", "cursor-not-allowed");
  acctEl.title = label;
}
window.lockGrniAccount = lockGrniAccount;

// ✅ this applies selection into the bill form (NO GRN reposting)
async function applyGrniToBillForm(grnRow) {
  console.log("[GRNI] applyGrniToBillForm called", grnRow);

  // ✅ guard flag to prevent "vendor change" handlers from clearing links while we are applying GRNI
  window._AP_APPLYING_GRNI = true;

  try {
    const cid = getActiveCompanyId?.() || CURRENT_COMPANY_ID;

    const vendorId =
      window._AP_VENDOR_ID ||
      Number(document.getElementById("billVendorId")?.value || 0) ||
      Number(grnRow?.vendor_id || grnRow?.receipt_vendor_id || 0) ||
      null;

    const txId = Number(grnRow?.receipt_tx_id || 0);

    console.log("[GRNI] ids", { cid, vendorId, txId, rowReceiptTxId: grnRow?.receipt_tx_id });

    if (!cid || !vendorId || !txId) {
      console.warn("[GRNI] abort: missing cid/vendorId/txId", { cid, vendorId, txId });
      return;
    }

    // 1) keep vendor id + vendor name (may trigger vendor-change listeners)
    const vendIdEl = document.getElementById("billVendorId");
    if (vendIdEl) vendIdEl.value = String(vendorId);

    const vendInput = document.getElementById("billVendor"); // datalist input (name)
    const vendObj = (Array.isArray(window.VENDORS) ? window.VENDORS : [])
      .find(v => String(v?.id) === String(vendorId));
    if (vendInput && vendObj?.name) vendInput.value = vendObj.name;

    // 2) optional: set bill date from GRN date
    const billDateEl = document.getElementById("billDate");
    if (billDateEl && billDateEl.type === "date") {
      const d = new Date(grnRow?.tx_date || "");
      if (!isNaN(d)) billDateEl.value = d.toISOString().slice(0, 10);
    }

    // 3) fetch receipt tx details (THIS gives you lines)
    let tx;
    try {
      tx = await apiFetch(ENDPOINTS.inventory.txOne(cid, txId), { method: "GET" });
    } catch (e) {
      console.warn("[GRNI] txOne failed", e);
      return;
    }

    const lines = tx?.lines || [];
    console.log("[GRNI] txOne result", { txId, lines_count: lines.length, tx });

    const body = document.getElementById("billLines");
    if (!body) {
      console.warn("[GRNI] abort: #billLines not found");
      return;
    }

    // 4) clear existing bill lines
    body.innerHTML = "";

    // 5) add lines into bill form
    const addRow = () => {
      if (typeof window.addBillLine === "function") return window.addBillLine({});

      const tr = document.createElement("tr");
      tr.className = "bill-line-row";
      tr.innerHTML = `
        <td class="px-3 py-2"><input class="w-full border rounded px-2 py-1 bill-item"></td>
        <td class="px-3 py-2"><input class="w-full border rounded px-2 py-1 bill-desc"></td>
        <td class="px-3 py-2"><input class="w-full border rounded px-2 py-1 bill-acct"></td>
        <td class="px-3 py-2 text-right"><input class="w-full border rounded px-2 py-1 text-right bill-qty"></td>
        <td class="px-3 py-2 text-right"><input class="w-full border rounded px-2 py-1 text-right bill-price"></td>
        <td class="px-3 py-2 text-right vat-col">
          <select class="w-full border rounded px-2 py-1 bill-vat-code">
            <option value="STANDARD">STANDARD</option>
            <option value="ZERO">ZERO</option>
            <option value="EXEMPT">EXEMPT</option>
            <option value="CUSTOM">CUSTOM</option>
          </select>
        </td>
        <td class="px-3 py-2 text-right vat-col"><input class="w-full border rounded px-2 py-1 text-right bill-vat-custom"></td>
        <td class="px-3 py-2 text-right"><span class="bill-line-total">0.00</span></td>
        <td class="px-3 py-2"></td>
      `;
      body.appendChild(tr);
      return tr;
    };

    (lines || []).forEach(l => {
      const tr = addRow();
      if (!tr) return;

      tr.querySelector(".bill-item").value  = l.item_name || l.sku || "";
      tr.querySelector(".bill-desc").value  = l.memo || "";
      tr.querySelector(".bill-qty").value   = String(Number(l.qty || 0) || 0);
      tr.querySelector(".bill-price").value = String(Number(l.unit_cost || 0) || 0);

      const vatSel = tr.querySelector(".bill-vat-code");
      if (vatSel) vatSel.value = "STANDARD";

      // ✅ lock to GRNI Control
      lockGrniAccount(tr);
    });

    // ✅ compute receipt total from lines (this worked for you: 315000)
    const computedTotal = (lines || []).reduce(
      (s, l) => s + (Number(l.qty || 0) * Number(l.unit_cost || 0)),
      0
    );

    const amt = Number(
      String(grnRow?.open_amount ?? grnRow?.receipt_total ?? computedTotal ?? 0).replace(/,/g, "")
    ) || 0;

    console.log("[GRNI] amounts", {
      open_amount: grnRow?.open_amount,
      receipt_total: grnRow?.receipt_total,
      computed_from_lines: computedTotal,
      amt_chosen: amt,
    });

    // ✅ STORE GRNI LINK so readBillForm() can send it
    window._BILL_GRNI_LINKS = (amt > 0)
      ? [{ receipt_tx_id: txId, amount: amt }]
      : [];

    console.log("[GRNI] set links", window._BILL_GRNI_LINKS);

    const hid = document.getElementById("billGrniLinksJson");
    if (hid) {
      hid.value = JSON.stringify(window._BILL_GRNI_LINKS);
      console.log("[GRNI] wrote #billGrniLinksJson", hid.value);
    } else {
      console.warn("[GRNI] #billGrniLinksJson not found (links stored in window var only)");
    }

    // 6) recalc totals
    window.recalcBill?.({ force: true });

    console.log("[GRNI] done applyGrniToBillForm");
  } finally {
    // ✅ always clear guard flag
    window._AP_APPLYING_GRNI = false;
  }
}
window.applyGrniToBillForm = applyGrniToBillForm;

function writeGrnIntoBillRef(grnRef) {
  const el = document.getElementById("billNumber");
  if (!el) return;

  el.value = String(grnRef || "").trim();
  el.dispatchEvent(new Event("input", { bubbles: true }));
  el.dispatchEvent(new Event("change", { bubbles: true }));
}

function writeGrnIntoBillMemo(grnRef) {
  const memo = document.getElementById("billMemo");
  if (!memo) return;

  const ref = String(grnRef || "").trim();
  if (!ref) return;

  const tag = `GRN: ${ref}`;

  const cur = String(memo.value || "").trim();
  // avoid duplicates
  if (cur.split("\n").some(line => line.trim() === tag)) return;

  memo.value = cur ? `${cur}\n${tag}` : tag;
  memo.dispatchEvent(new Event("input", { bubbles: true }));
  memo.dispatchEvent(new Event("change", { bubbles: true }));
}
window.writeGrnIntoBillMemo = writeGrnIntoBillMemo;

function lockBillFormForReviewers(status, billId) {
  const isDraft = String(status || "").toLowerCase() === "draft";

  // store current opened bill id (useful for approve/post)
  const idEl = document.getElementById("billId");
  if (idEl && billId != null) idEl.value = String(billId);

  // disable all inputs except action buttons
  document
    .querySelectorAll("#screen-ap input, #screen-ap select, #screen-ap textarea")
    .forEach(el => {
      // allow action buttons
      if (el.id === "billApprove" || el.id === "billRecalc" || el.id === "billEdit") return;

      el.disabled = true;
      el.classList.add("opacity-60", "cursor-not-allowed");
    });

  // disable add/delete lines
  setBtnDisabled(document.getElementById("billAddLine"), true);
  setBtnDisabled(document.getElementById("billDelLine"), true);

  // show status clearly
  const pill = document.getElementById("billStatus");
  if (pill) pill.textContent = String(status || "DRAFT").toUpperCase();

  // use isDraft: in review mode, only drafts can be edited (typical rule)
  const editBtn = document.getElementById("billEdit");
  if (editBtn) {
    editBtn.classList.toggle("hidden", !isDraft);  // hide edit if not draft
    setBtnDisabled(editBtn, !isDraft);
    editBtn.dataset.billId = billId != null ? String(billId) : "";
  }
}
window.lockBillFormForReviewers = lockBillFormForReviewers;


function unlockBillForEditing() {
  window._BILL_TOTALS_LOCKED = false;
  window._BILL_REVIEW_MODE = false;

  document
    .querySelectorAll("#screen-ap input, #screen-ap select, #screen-ap textarea")
    .forEach(el => {
      el.disabled = false;
      el.classList.remove("opacity-60", "cursor-not-allowed");
    });

  setBtnDisabled(document.getElementById("billAddLine"), false);
  setBtnDisabled(document.getElementById("billDelLine"), false);

  // optional: hide the edit button once already editing
  const editBtn = document.getElementById("billEdit");
  if (editBtn) editBtn.classList.add("hidden");

  window.recalcBill?.({ force: true });
}
window.unlockBillForEditing = unlockBillForEditing;

window.syncDueDateFromTerms = function syncDueDateFromTerms({ force = false } = {}) {
  const billDate = (document.getElementById("billDate")?.value || "").slice(0, 10);
  const termSel  = document.getElementById("billDueTerm");
  const daysEl   = document.getElementById("billDueDays");
  const dueEl    = document.getElementById("billDue"); // hidden

  if (!billDate || !termSel || !dueEl) return null;

  // ✅ helper (now actually USED)
  function clampInt(v, d = 0) {
    const n = parseInt(String(v ?? ""), 10);
    return Number.isFinite(n) ? Math.max(0, n) : d;
  }

  const term = String(termSel.value || "30").toUpperCase();

  let days;

  if (term === "CUSTOM") {
    daysEl?.classList.remove("hidden");
    days = clampInt(daysEl?.value, 30);     // ✅ uses clampInt
    if (daysEl) daysEl.value = String(days);
  } else {
    daysEl?.classList.add("hidden");
    if (daysEl) daysEl.value = "";
    days = clampInt(term, 30);              // ✅ uses clampInt
  }

  // ✅ Add days in LOCAL time (no toISOString timezone shift)
  const base = new Date(billDate + "T00:00:00");
  if (isNaN(base.getTime())) return null;

  base.setDate(base.getDate() + days);

  const y = base.getFullYear();
  const m = String(base.getMonth() + 1).padStart(2, "0");
  const d = String(base.getDate()).padStart(2, "0");
  const iso = `${y}-${m}-${d}`;

  dueEl.value = iso;
  return iso;
};


// ✅ bind once
(function bindDueTermsOnce() {
  const wrap = document.getElementById("screen-ap");
  if (!wrap || wrap.dataset.dueTermsBound === "1") return;
  wrap.dataset.dueTermsBound = "1";

  const billDateEl = document.getElementById("billDate");
  const termSel    = document.getElementById("billDueTerm");
  const daysEl     = document.getElementById("billDueDays");

  billDateEl?.addEventListener("change", () => {
    window.syncDueDateFromTerms?.({ force: true });
    window.recalcBill?.();
    window.saveBillDraftToLocal?.(); // ✅ safe
  });

  termSel?.addEventListener("change", () => {
    if (String(termSel.value).toUpperCase() === "CUSTOM" && (!daysEl.value || daysEl.value === "0")) {
      daysEl.value = "30";
    }
    window.syncDueDateFromTerms?.({ force: true });
    window.recalcBill?.();
    window.saveBillDraftToLocal?.(); // ✅ local (recommended)
    // OR if you really want API save here (not recommended):
    // window.saveBillDraft?.("draft");
  });

  daysEl?.addEventListener("input", () => {
    window.syncDueDateFromTerms?.({ force: true });
    window.recalcBill?.();
    window.saveBillDraftToLocal?.(); // ✅ safe
  });

  window.syncDueDateFromTerms?.({ force: true });
})();


