// ✅ define money formatter safely (don't redeclare if already exists)
window.moneyFmt = window.moneyFmt || new Intl.NumberFormat(undefined, {
  minimumFractionDigits: 2,
  maximumFractionDigits: 2,
});

// ✅ safe number parser for amounts
function toNum(v, d = 0) {
  const n = Number(String(v ?? "").replace(/,/g, ""));
  return Number.isFinite(n) ? n : d;
}

// ✅ the ONE loader your bindAPPanels calls
// ✅ Draft Bills Pane loader (single source of truth)
window.loadDraftBillsPane = async function loadDraftBillsPane() {
  const cid = FS.control.resolveCid();
  if (!cid) return;

  const listEl = document.getElementById("draftBillList");
  if (!listEl) return;

  const status = document.getElementById("apDraftFilter")?.value || "draft";
  const q = (document.getElementById("apDraftSearch")?.value || "").trim().toLowerCase();

  const params = new URLSearchParams();
  if (status && status !== "all") params.append("status", status);

  const url = `${ENDPOINTS.bills(cid)}?${params.toString()}`;

  listEl.innerHTML = `<div class="text-xs text-slate-400">Loading…</div>`;

  let res;
  try {
    res = await apiFetch(url);
  } catch (e) {
    console.warn("[AP] loadDraftBillsPane fetch failed:", e);
    listEl.innerHTML = `<div class="text-xs text-red-500">Failed to load bills.</div>`;
    return;
  }

  let rows = Array.isArray(res) ? res : (res?.data || []);
  if (!Array.isArray(rows)) rows = [];

  if (q) {
    rows = rows.filter(b => String(b.number || b.id || "").toLowerCase().includes(q));
  }

  if (!rows.length) {
    listEl.innerHTML = `<div class="text-xs text-slate-400">No bills found.</div>`;
    return;
  }

  listEl.innerHTML = rows.map(b => {
    const num  = b.number || `BILL-${b.id}`;
    const vend = b.vendor_name || b.vendorName || `Vendor #${b.vendor_id || ""}`;

    const rawAmt = Number(String(b.total_amount ?? 0).replace(/,/g, ""));
    const safeAmt = Number.isFinite(rawAmt) ? rawAmt : 0;

    const amt = (typeof window.fmt === "function")
      ? window.fmt(safeAmt)
      : (window.moneyFmt?.format ? window.moneyFmt.format(safeAmt) : String(safeAmt));

    const st = String(b.status || "").toUpperCase();
    const dt = String(b.bill_date || "").slice(0, 10);

    return `
      <button type="button"
        class="w-full text-left border rounded-lg p-2 hover:bg-slate-50"
        data-bill-id="${b.id}">
        <div class="flex items-center justify-between">
          <div class="font-semibold text-sm">${escapeHtml(num)}</div>
          <div class="text-xs text-slate-500">${escapeHtml(st)}</div>
        </div>
        <div class="text-xs text-slate-600 truncate">${escapeHtml(vend)}</div>
        <div class="text-xs text-slate-500">${escapeHtml(dt)} • ${escapeHtml(amt)}</div>
      </button>
    `;
  }).join("");

  // ✅ IMPORTANT: remove any previous inline onclick behavior
  listEl.querySelectorAll("[data-bill-id]").forEach(btn => {
    btn.onclick = null;

    btn.addEventListener("click", async (e) => {
      e.preventDefault();
      e.stopPropagation();

      const id = parseInt(btn.dataset.billId || "0", 10);
      if (!id) return;

      try {
        // ✅ Load into the AP bill form (review/locked mode)
        if (typeof window.loadBillIntoForm === "function") {
          await window.loadBillIntoForm(id, { mode: "review" });
        } else {
          // fallback: fetch then write form
          document.getElementById("billGrniLinksJson")?.value
          const bill = one?.data || one;
          window.writeBillForm?.(bill);
        }
      } catch (err) {
        console.warn("[AP] load bill into form failed:", err);
        alert(err?.message || "Failed to open bill");
        return;
      }

      // ✅ close the pane
      document.getElementById("apDraftPane")?.classList.add("hidden");
      const vendHidden = document.getElementById("apVendorPane")?.classList.contains("hidden");
      if (vendHidden) document.getElementById("apOverlay")?.classList.add("hidden");
    }, { passive: false });
  });
};

async function openApVendorPicker({ closeOnPick = true, reason = "" } = {}) {
  if (reason) window.showToast?.(reason, "warning");

  const hasVendors =
    (Array.isArray(window.VENDORS) && window.VENDORS.length) ||
    (Array.isArray(window.vendors) && window.vendors.length);

  if (!hasVendors) {
    try { await fetchVendorsFromBackend?.(true); } catch {}
  }

  const list =
    (Array.isArray(window.VENDORS) && window.VENDORS.length)
      ? window.VENDORS
      : (Array.isArray(window.vendors) ? window.vendors : []);

  if (!list.length) {
    window.showToast?.("No vendors found. Please add a vendor first.", "warning");
    window.switchScreen?.("vendors");
    return;
  }

  const pane = document.getElementById("apVendorPane");
  const ovl  = document.getElementById("apOverlay");
  pane?.classList.remove("hidden");
  ovl?.classList.remove("hidden");

  await renderApVendorList({ closeOnPick });
}
window.openApVendorPicker = openApVendorPicker;

// ================================
// bindAPPanels (ONLY place that opens/closes panes)
// ================================
function bindAPPanels() {
  const wrap = document.getElementById("screen-ap");
  if (!wrap || wrap.dataset.apPanelsBound === "1") return;
  wrap.dataset.apPanelsBound = "1";

  const overlay   = document.getElementById("apOverlay");
  const vendPane  = document.getElementById("apVendorPane");
  const billsPane = document.getElementById("apDraftPane");

  // ✅ legacy (keep safe): if you still have GRNI pane/button in DOM, we won't use them
  const grniPane  = document.getElementById("apGrniPane");
  const btnGrni   = document.getElementById("btnToggleGRNIPane");
  const btnCloseGrni = document.getElementById("btnCloseGrniPane");

  const btnVendors = document.getElementById("btnToggleVendorsAP");
  const btnBills   = document.getElementById("btnToggleBillDrafts");
  const btnCloseVendors = document.getElementById("btnCloseVendorsAP");
  const btnCloseBills   = document.getElementById("btnCloseBillDrafts");

  if (!overlay || !vendPane || !billsPane || !btnVendors || !btnBills) {
    console.warn("[AP] bindAPPanels missing nodes", { overlay, vendPane, billsPane, btnVendors, btnBills });
    return;
  }

  const showOverlay = () => overlay.classList.remove("hidden");
  const hideOverlay = () => overlay.classList.add("hidden");

  // ✅ Tabs exist INSIDE apDraftPane now
  const tabBills = document.getElementById("apTabBills");
  const tabGrni  = document.getElementById("apTabGrni");

  const billsControls = document.getElementById("apBillsControls");
  const grniControls  = document.getElementById("apGrniControls");
  const billsMount    = document.getElementById("draftBillList");
  const grniMount     = document.getElementById("apGrniMount");
  const titleEl       = document.getElementById("apRightPaneTitle");
  const grniSearch    = document.getElementById("apGrniSearch");

  async function setRightTab(tab) {
    // tab: "bills" | "grni"
    const isBills = tab === "bills";
    window._AP_RIGHT_TAB = tab;

    if (titleEl) titleEl.textContent = isBills ? "Bills" : "GRN / GRNI";

    // active styling (simple)
    tabBills?.classList.toggle("bg-slate-100", isBills);
    tabGrni?.classList.toggle("bg-slate-100", !isBills);

    billsControls?.classList.toggle("hidden", !isBills);
    billsMount?.classList.toggle("hidden", !isBills);

    grniControls?.classList.toggle("hidden", isBills);
    grniMount?.classList.toggle("hidden", isBills);

    // ============================
    // Load content for the tab
    // ============================
    if (isBills) {
      const vid =
        window._AP_VENDOR_ID ||
        (parseInt(document.getElementById("billVendorId")?.value || "0", 10) || null);

      // No vendor selected -> force vendor pick
      if (!vid) {
        if (billsMount) {
          billsMount.innerHTML = `
            <div class="text-xs text-slate-500 px-2 py-1">
              Pick a vendor to view bills.
            </div>`;
        }

        // open vendor picker
        showOverlay?.();
        vendPane?.classList.remove("hidden");
        billsPane?.classList.add("hidden");

        // load vendor list
        if (typeof window.renderApVendorList === "function") {
          await window.renderApVendorList({ closeOnPick: true });
        }
        return;
      }

      // Vendor selected -> show ONLY that vendor’s bills (modal flow)
      if (typeof window.renderApBillsList === "function") {
        await window.renderApBillsList({ vendor_id: vid, unpaidOnly: true });
      } else {
        console.warn("[AP] renderApBillsList is missing");
      }

    } else {
      // GRNI tab
      const q = (grniSearch?.value || "").trim();
      window.loadOpenGrniPane?.({ q, limit: 200, offset: 0 });
    }
  }

  // expose for vendor click handler to refresh correctly
  window.setApRightPaneTab = setRightTab;

  function closeAll() {
    vendPane.classList.add("hidden");
    billsPane.classList.add("hidden");

    // ✅ if old GRNI pane exists, hide it too (doesn't break)
    grniPane?.classList.add("hidden");

    hideOverlay();
  }

  overlay.addEventListener("click", closeAll);
  document.addEventListener("keydown", (e) => { if (e.key === "Escape") closeAll(); });

  // Vendors pane (left)
  btnVendors.addEventListener("click", async (e) => {
    e.preventDefault();
    const isHidden = vendPane.classList.contains("hidden");
    if (isHidden) {
      showOverlay();
      vendPane.classList.remove("hidden");

      // ✅ keep right pane hidden when opening vendor list
      billsPane.classList.add("hidden");
      grniPane?.classList.add("hidden");

      await window.renderApVendorList?.({ closeOnPick: true });
    } else {
      vendPane.classList.add("hidden");
      if (billsPane.classList.contains("hidden")) hideOverlay();
    }
  });

  btnCloseVendors?.addEventListener("click", (e) => {
    e.preventDefault();
    vendPane.classList.add("hidden");
    if (billsPane.classList.contains("hidden")) hideOverlay();
  });

  // Right pane (Bills / GRNI tabs)
  btnBills.addEventListener("click", async (e) => {
    e.preventDefault();
    const isHidden = billsPane.classList.contains("hidden");
    if (isHidden) {
      showOverlay();
      billsPane.classList.remove("hidden");
      vendPane.classList.add("hidden");

      // ✅ default tab
    await setRightTab(window._AP_RIGHT_TAB || "bills");
    } else {
      billsPane.classList.add("hidden");
      if (vendPane.classList.contains("hidden")) hideOverlay();
    }
  });

  btnCloseBills?.addEventListener("click", (e) => {
    e.preventDefault();
    billsPane.classList.add("hidden");
    if (vendPane.classList.contains("hidden")) hideOverlay();
  });

  // ✅ Tabs (inside apDraftPane)
  tabBills?.addEventListener("click", async (e) => {
    e.preventDefault();
   await setRightTab("bills");
  });

  tabGrni?.addEventListener("click", async (e) => {
    e.preventDefault();
    await setRightTab("grni");
  });

  // ✅ GRNI search (only triggers when GRNI tab is active)
  if (grniSearch && grniSearch.dataset.bound !== "1") {
    grniSearch.dataset.bound = "1";
    grniSearch.addEventListener("input", () => {
      if (window._AP_RIGHT_TAB !== "grni") return;
      const q = (grniSearch.value || "").trim();
      window.loadOpenGrniPane?.({ q, limit: 200, offset: 0 });
    });
  }

  // existing filters (Bills)
  document.getElementById("apDraftFilter")?.addEventListener("change", () => {
    if (window._AP_RIGHT_TAB === "bills") window.loadDraftBillsPane?.();
  });
  document.getElementById("apDraftSearch")?.addEventListener("input", () => {
    if (window._AP_RIGHT_TAB === "bills") window.loadDraftBillsPane?.();
  });

  // ✅ LEGACY: if you still have old GRNI pane/button, clicking it just opens right pane + GRNI tab
  btnGrni?.addEventListener("click", (e) => {
    e.preventDefault();
    showOverlay();
    billsPane.classList.remove("hidden");
    vendPane.classList.add("hidden");
    setRightTab("grni");
  });

  btnCloseGrni?.addEventListener("click", (e) => {
    e.preventDefault();
    // old close just closes right pane
    billsPane.classList.add("hidden");
    if (vendPane.classList.contains("hidden")) hideOverlay();
  });

  window.apCloseAllPanels = closeAll;

  // ✅ set initial tab
  if (!window._AP_RIGHT_TAB) window._AP_RIGHT_TAB = "bills";
}
window.bindAPPanels = bindAPPanels;

function setApRightPaneTab(tab) {
  const title = document.getElementById("apRightPaneTitle");
  const tabBills = document.getElementById("apTabBills");
  const tabGrni  = document.getElementById("apTabGrni");

  const billsControls = document.getElementById("apBillsControls");
  const grniControls  = document.getElementById("apGrniControls");

  const billsMount = document.getElementById("draftBillList");
  const grniMount  = document.getElementById("apGrniMount");

  const isBills = tab === "bills";

  if (title) title.textContent = isBills ? "Bills" : "GRN / GRNI";

  // simple active styling
  if (tabBills) tabBills.classList.toggle("bg-slate-100", isBills);
  if (tabGrni)  tabGrni.classList.toggle("bg-slate-100", !isBills);

  billsControls?.classList.toggle("hidden", !isBills);
  billsMount?.classList.toggle("hidden", !isBills);

  grniControls?.classList.toggle("hidden", isBills);
  grniMount?.classList.toggle("hidden", isBills);

  // load the right content
  if (isBills) {
    window.loadDraftBillsPane?.();
  } else {
    const q = (document.getElementById("apGrniSearch")?.value || "").trim();
    window.loadOpenGrniPane?.({ q, limit: 200, offset: 0 });
  }

  window._AP_RIGHT_TAB = tab;
}
window.setApRightPaneTab = setApRightPaneTab;

// ✅ IMPORTANT:
// Remove/disable any other addEventListener bindings for:
// btnToggleBillDrafts, btnCloseBillDrafts, apOverlay, apDraftFilter, apDraftSearch
// so only bindAPPanels controls the panes.

window.bindAPDraftClose = function bindAPDraftClose() {
  const wrap = document.getElementById("screen-ap");
  if (!wrap || wrap.dataset.apDraftCloseBound === "1") return;
  wrap.dataset.apDraftCloseBound = "1";

  const overlay = document.getElementById("apOverlay");
  const pane = document.getElementById("apDraftPane");
  const btnClose = document.getElementById("btnCloseBillDrafts");

  const close = () => {
    pane?.classList.add("hidden");
    // hide overlay only if vendor pane also hidden
    const vendHidden = document.getElementById("apVendorPane")?.classList.contains("hidden");
    if (vendHidden) overlay?.classList.add("hidden");
  };

  btnClose?.addEventListener("click", (e) => { e.preventDefault(); close(); });
  overlay?.addEventListener("click", close);
};

function openApPane(paneId) {
  document.getElementById("apOverlay")?.classList.remove("hidden");
  document.getElementById(paneId)?.classList.remove("hidden");
}
function closeApPane(paneId) {
  document.getElementById("apOverlay")?.classList.add("hidden");
  document.getElementById(paneId)?.classList.add("hidden");
}

function bindBillVendorLookup() {
  const nameEl = document.getElementById("billVendor");
  const idEl   = document.getElementById("billVendorId");
  const dl     = document.getElementById("vendDataList");
  if (!nameEl || !idEl || !dl) return;

  if (nameEl.dataset.bound === "1") return;
  nameEl.dataset.bound = "1";

  function resolveVendorIdFromName(name) {
    name = (name || "").trim().toLowerCase();
    if (!name) return null;

    // prefer cache (faster + reliable)
    const list = Array.isArray(window.VENDORS_CACHE) ? window.VENDORS_CACHE : [];
    const hit = list.find(v => String(v.name || "").trim().toLowerCase() === name);
    return hit ? Number(hit.id) : null;
  }

  function updateVendorSummary(v) {
    const email = document.getElementById("apVendSummary")?.querySelector("span");
    // you can expand this later (open bills, last payment)
    // for now just show basic in summary area
    const host = document.getElementById("apVendSummary");
    if (!host) return;
    host.innerHTML = `
      <div>Email: <span>${escapeHtml(v?.email || "—")}</span></div>
      <div>Phone: <span>${escapeHtml(v?.phone || "—")}</span></div>
      <div>Status: <span>${escapeHtml(v?.vendor_status || "—")}</span></div>
    `;
  }

  function onPick() {
    const typed = nameEl.value || "";
    const vid = resolveVendorIdFromName(typed);

    if (!vid) {
      idEl.value = "";
      return;
    }

    idEl.value = String(vid);

    // load vendor object from cache and update summary
    const list = Array.isArray(window.VENDORS_CACHE) ? window.VENDORS_CACHE : [];
    const v = list.find(x => Number(x.id) === Number(vid));
    if (v) updateVendorSummary(v);
  }

  nameEl.addEventListener("change", onPick);
  nameEl.addEventListener("blur", onPick);

  // Optional: as user types, clear id until they match
  nameEl.addEventListener("input", () => {
    idEl.value = "";
  });
}

function bindBillVendorIdSync() {
  const input = document.getElementById("billVendor");
  const hidden = document.getElementById("billVendorId");

  if (!input || !hidden) return;
  if (input.dataset.bound === "1") return;
  input.dataset.bound = "1";

  function syncVendor() {
    const name = input.value.trim();
    const list = window._AP_VENDOR_CACHE || [];

    const match = list.find(v =>
      (v.name || "").toLowerCase() === name.toLowerCase()
    );

    hidden.value = match ? String(match.id) : "";
  }

  input.addEventListener("change", syncVendor);
  input.addEventListener("blur", syncVendor);
}

window.VENDORS_CACHE = window.VENDORS_CACHE || [];

async function fetchVendorsFromBackend(includeInactive = false) {
  const cid = getActiveCompanyId?.() || CURRENT_COMPANY_ID;
  const url = ENDPOINTS.vendors(cid) + (includeInactive ? "?include_inactive=1" : "");
  const res = await apiFetch(url, { method: "GET" });
  const rows = res?.data || [];
  window.VENDORS_CACHE = Array.isArray(rows) ? rows : [];
  return window.VENDORS_CACHE;
}

function normalizeVendorLabel(s) {
  return String(s || "").trim();
}

// Finds vendor by matching either "Name" or "Name (email)"
function resolveVendorByTypedValue(typed) {
  const t = normalizeVendorLabel(typed);
  if (!t) return null;

  const vendors = Array.isArray(window.VENDORS_CACHE) ? window.VENDORS_CACHE : [];
  // match label "Name (email)" or just name
  return vendors.find(v => {
    const name = String(v?.name || "").trim();
    const email = String(v?.email || "").trim();
    const label = email ? `${name} (${email})` : name;
    return label === t || name === t;
  }) || null;
}

function bindBillVendorIdSync() {
  const root = (typeof getBillRoot === "function") ? getBillRoot() : document;
  const inp = root.querySelector("#billVendor");
  const hid = root.querySelector("#billVendorId");
  if (!inp || !hid) return;
  if (inp.dataset.bound === "1") return;
  inp.dataset.bound = "1";

  const setCurrencyDefault = () => {
    // prefer company context currency if you have it
    const curEl = document.getElementById("billCurrency");
    if (!curEl) return;
    const companyCur =
      (window.CURRENT_COMPANY?.currency || window.CURRENT_COMPANY?.base_currency || "").trim();
    if (!curEl.value && companyCur) curEl.value = companyCur;
  };

  const sync = async () => {
    // ensure cache exists
    if (!Array.isArray(window.VENDORS_CACHE) || window.VENDORS_CACHE.length === 0) {
      await fetchVendorsFromBackend(false);
    }

    // expose a forced sync function that saveBillDraft can call
    window._forceSyncBillVendor = async () => {
      await sync();
    };
    
    const v = resolveVendorByTypedValue(inp.value);
    hid.value = v ? String(v.id) : "";

    // ✅ currency rule: do NOT force vendor bank currency on bill
    // Use company currency as default (what you said you want).
    setCurrencyDefault();

    // Optional: update sidebar summary if you want later
    // renderAPVendorSummary?.(v);
  };

  inp.addEventListener("input", sync);   // ✅ important
  inp.addEventListener("change", sync);
  inp.addEventListener("blur", sync);
}
window.bindBillVendorIdSync = bindBillVendorIdSync;

window._forceSyncBillVendor = async function () {
  const root = window.getBillRoot?.() || document;
  const inp = root.querySelector("#billVendor");
  const hid = root.querySelector("#billVendorId");
  if (!inp || !hid) return;

  if (!Array.isArray(window.VENDORS_CACHE) || window.VENDORS_CACHE.length === 0) {
    await window.fetchVendorsFromBackend?.(false);
  }

  const v = window.resolveVendorByTypedValue?.(inp.value);
  hid.value = v?.id ? String(v.id) : hid.value;
};

async function renderApVendorList({ closeOnPick = true } = {}) {
  const host = document.getElementById("apVendorList");
  if (!host) return;

  // cache first
  let vendors =
    (Array.isArray(window.VENDORS) && window.VENDORS.length
      ? window.VENDORS
      : (store?.get?.(K.VENDORS, []) || []))
      .filter(Boolean);

  // fetch if empty
  if (!vendors.length) {
    try {
      vendors = await fetchVendorsFromBackend(true);
    } catch (e) {
      console.warn("[AP] fetchVendorsFromBackend failed:", e);
      vendors = [];
    }
    window.VENDORS = vendors || [];
    if (Array.isArray(vendors)) store?.set?.(K.VENDORS, vendors);
  }

  const active = (vendors || []).filter(v => v && v.is_active !== false);

  if (!active.length) {
    host.innerHTML = `<div class="text-xs text-slate-500 px-2 py-1">No active vendors yet.</div>`;
    return;
  }

  const escAttr = (s) =>
    String(s ?? "")
      .replaceAll("&", "&amp;")
      .replaceAll('"', "&quot;")
      .replaceAll("<", "&lt;")
      .replaceAll(">", "&gt;");

  const escText = (s) =>
    String(s ?? "")
      .replaceAll("&", "&amp;")
      .replaceAll("<", "&lt;")
      .replaceAll(">", "&gt;");

  // ✅ render first
  host.innerHTML = active.map(v => {
    const id = escAttr(v.id);
    const name = escAttr(v.name || "");
    const email = escText(v.email || "");
    const phone = escText(v.phone || "");
    const nameText = escText(v.name || "(No name)");

    return `
      <button
        type="button"
        class="w-full text-left px-2 py-1 text-xs hover:bg-slate-50 rounded"
        data-vendor-id="${id}"
        data-vendor-name="${name}"
      >
        <div class="font-medium">${nameText}</div>
        <div class="text-[11px] text-slate-500">${email}${email && phone ? " • " : ""}${phone}</div>
      </button>
    `;
  }).join("");

  async function closeVendorPicker() {
    if (!closeOnPick) return;
    document.getElementById("apVendorPane")?.classList.add("hidden");
    // only hide overlay if no other panes are open
    if (document.getElementById("apDraftPane")?.classList.contains("hidden")) {
      document.getElementById("apOverlay")?.classList.add("hidden");
    }
  }

  // ✅ bind once (delegate)
  if (host.dataset.bound === "1") return;
  host.dataset.bound = "1";

  host.onclick = async (ev) => {
    const btn = ev.target.closest("[data-vendor-id]");
    if (!btn) return;

    const vendorId = parseInt(btn.getAttribute("data-vendor-id") || "0", 10) || null;
    const vendorName = (btn.getAttribute("data-vendor-name") || "").trim();
    if (!vendorId) return;

    // ✅ global selection (used by bills + GRNI)
    window._AP_VENDOR_ID = vendorId;

    // ✅ fill bill form: NAME + ID (not ID in name field)
    const nameInput = document.getElementById("billVendor");   // visible field (name)
    const idInput   = document.getElementById("billVendorId"); // hidden/real id

    if (nameInput) {
      nameInput.value = vendorName; // ✅ name goes here
      nameInput.dispatchEvent(new Event("input", { bubbles: true }));
      nameInput.dispatchEvent(new Event("change", { bubbles: true }));
    }

    if (idInput) {
      idInput.value = String(vendorId); // ✅ id goes here
      idInput.dispatchEvent(new Event("change", { bubbles: true }));
    }

    // ✅ open + load vendor bills pane (this is what stopped happening)
    window._AP_RIGHT_TAB = "bills";
    if (typeof window.openVendorBillsPane === "function") {
      await window.openVendorBillsPane(vendorId, { id: vendorId, name: vendorName });
    } else {
      console.warn("[AP] openVendorBillsPane missing — cannot show vendor bills pane");
    }

    // ✅ close ONLY the vendor picker pane (don’t close everything)
    if (closeOnPick) {
      document.getElementById("apVendorPane")?.classList.add("hidden");
      // keep overlay if bills pane is open; otherwise hide it
      const billsPane = document.getElementById("apDraftPane");
      if (billsPane?.classList.contains("hidden")) {
        document.getElementById("apOverlay")?.classList.add("hidden");
      }
    }
  };
}
window.renderApVendorList = renderApVendorList;


function bindBillVendorIdSync() {
  const nameEl = document.getElementById("billVendor");
  const idEl   = document.getElementById("billVendorId");
  if (!nameEl || !idEl) return;

  if (nameEl.dataset.bound === "1") return;
  nameEl.dataset.bound = "1";

  function sync() {
    const name = (nameEl.value || "").trim().toLowerCase();
    const list = Array.isArray(window._billVendors) ? window._billVendors : (window.VENDORS || []);
    const found = list.find(v => (v?.name || "").trim().toLowerCase() === name);

    if (found?.id) idEl.value = String(found.id);
    else idEl.value = ""; // clear if no exact match
  }

  nameEl.addEventListener("input", sync);
  nameEl.addEventListener("change", sync);
}

