async function loadBillAccountsForLines() {
  const cid = getActiveCompanyId?.() || CURRENT_COMPANY_ID;
  if (!cid) return;

  try {
    const raw = await apiFetch(ENDPOINTS.coa(cid));
    const rows = Array.isArray(raw) ? raw : (raw?.rows || raw?.accounts || []);

    const lower = (s) => String(s || "").toLowerCase().trim();
    const codeOf = (a) => String(a.code || a.account_code || a.template_code || "").trim();
    const nameOf = (a) => String(a.name || a.account_name || "").trim();
    const postingOf = (a) => (a.posting === undefined ? true : !!a.posting);

    // ---------- DENY LISTS ----------
    const denyCategoryContains = [
      "cash", "equivalent", "bank", "petty",
      "accumulated depreciation", "accumulated amort",
      "depreciation & amortization",
      "finance costs",
      "tax expense",
      "other adjustments",
      "non-operating adjustments",
      "revenue adjustments",
      "retained earnings",
      "capital",
      "equity",
      "payables",          // optional: keeps control accounts out
      "receivables",       // optional: keeps control accounts out
      "vat",               // keeps VAT Input/Output out
    ];

    // keywords in NAME to exclude (you asked “things like salaries”)
    const denyNameContains = [
      "salary", "salaries", "wages", "payroll",
      "paye", "withholding",
      "depreciation", "amortization", "amortisation",
      "interest", "finance cost",
      "income tax",
      "adjustment", "reclassification",
      "bank charges", // optional (keep if you want)
    ];

    // codes to exclude by prefix (strongest guard)
    const denyCodeStarts = [
      "BS_CA_", "BS_CL_", "BS_NCA_", "BS_NCL_", "BS_EQ_", // optional: removes ALL balance sheet accounts
      "PL_OI_",        // other income (not an expense)
      "PL_REV_",       // revenue
      "PL_REV_ADJ_",   // contra revenue
      "PL_OPEX_ADJ_",  // if you ever have this family
    ];

    // ✅ If you DO want assets for capex on bills, remove BS_* from denyCodeStarts
    // and rely on category/name exclusions instead.

    // ---------- ALLOW RULES ----------
    const isAllowedFamily = (code) =>
      code.startsWith("PL_OPEX_") || code.startsWith("PL_COS_") || code.startsWith("BS_NCA_") || code.startsWith("BS_CA_");

    const isDenied = (a) => {
      const code = codeOf(a);
      const nm = lower(nameOf(a));
      const cat = lower(a.category || "");
      const sec = lower(a.section || "");

      if (!code) return true;
      if (!postingOf(a)) return true;

      // If you want “only known families”, enforce this:
      // if (!isAllowedFamily(code)) return true;

      if (denyCodeStarts.some(p => code.startsWith(p))) return true;

      if (denyCategoryContains.some(x => cat.includes(x))) return true;
      if (denyNameContains.some(x => nm.includes(x))) return true;

      // Extra: exclude adjustment section always
      if (sec.includes("adjust")) return true;

      return false;
    };

    // Base allow: Expenses + COGS + (optional) Assets
    const baseAllow = (a) => {
      const code = codeOf(a);
      const sec = lower(a.section || "");
      const cat = lower(a.category || "");

      const isExpense = sec === "expense" || cat.includes("operating expenses") || code.startsWith("PL_OPEX_");
      const isCogs    = cat.includes("cost of sales") || cat.includes("cost of revenue") || code.startsWith("PL_COS_");
      const isAsset   = sec === "asset" || code.startsWith("BS_NCA_") || code.startsWith("BS_CA_");

      // ✅ choose what you want:
      return isExpense || isCogs || isAsset; // keep assets (capex)
      // return isExpense || isCogs;          // hide assets completely
    };

    const allowed = rows.filter(a => baseAllow(a) && !isDenied(a));

    // Sort A→Z by name
    allowed.sort((a, b) => nameOf(a).localeCompare(nameOf(b)));

    // Build cache for line dropdowns
    const seen = new Set();
    window.BILL_ACCOUNTS_CACHE = allowed
      .map(a => ({ code: codeOf(a), name: nameOf(a) || codeOf(a) }))
      .filter(x => x.code && !seen.has(x.code) && (seen.add(x.code), true));

  } catch (e) {
    console.warn("[AP] loadBillAccountsForLines error:", e);
    window.BILL_ACCOUNTS_CACHE = [];
  }
}
window.loadBillAccountsForLines = loadBillAccountsForLines;

async function loadAPPostingAccounts() {
  const cid = getActiveCompanyId?.() || CURRENT_COMPANY_ID;
  if (!cid) {
    window.AP_POSTING_ACCOUNTS_CACHE = [];
    return [];
  }

  try {
    const raw = await apiFetch(ENDPOINTS.coa(cid));
    const payload = (typeof unwrapApi === "function") ? unwrapApi(raw) : raw;

    const rows = Array.isArray(payload)
      ? payload
      : (payload?.rows || payload?.accounts || payload?.coa || payload?.data || []);

    const norm = (v) => String(v || "").trim();
    const lower = (v) => norm(v).toLowerCase();
    const codeOf = (a) => norm(a.code || a.account_code || a.template_code);
    const nameOf = (a) => norm(a.name || a.account_name || a.label);
    const sectionOf = (a) => lower(a.section || "");
    const categoryOf = (a) => lower(a.category || "");
    const cfBucketOf = (a) => lower(a.cf_bucket || "");
    const postingOf = (a) => (a.posting === undefined ? true : !!a.posting);

    // ✅ Cash / Bank accounts for payment posting
    const isCashOrBank = (a) => {
      if (!postingOf(a)) return false;
      const code = codeOf(a);
      const cat = categoryOf(a);
      const sec = sectionOf(a);
      const name = lower(nameOf(a));
      const bucket = cfBucketOf(a);

      if (!code) return false;

      // strongest: metadata bucket/category
      if (bucket === "cash") return true;
      if (cat.includes("cash") || cat.includes("equivalent")) return true;

      // fallback keywords
      if (name.includes("bank") || name.includes("cash") || name.includes("petty cash")) return true;

      // allow only Assets for these
      if (sec && !sec.includes("asset")) return false;

      return false;
    };

    // ✅ Accounts Payable control (optional for allocations / AP ledger)
    const isApControl = (a) => {
      if (!postingOf(a)) return false;
      const code = codeOf(a);
      const name = lower(nameOf(a));
      const cat = categoryOf(a);
      const sec = sectionOf(a);
      const bucket = cfBucketOf(a);

      if (!code) return false;

      // your COA example: BS_CL_2200 Accounts Payable
      if (bucket === "payables") return true;
      if (cat.includes("payable")) return true;
      if (name.includes("accounts payable") || name.includes("ap")) return true;

      // typically liability
      if (sec && !sec.includes("liab")) return false;

      return false;
    };

    const bankAccounts = rows.filter(isCashOrBank);
    const apAccounts = rows.filter(isApControl);

    // sort nicely
    bankAccounts.sort((a, b) => nameOf(a).localeCompare(nameOf(b)));
    apAccounts.sort((a, b) => nameOf(a).localeCompare(nameOf(b)));

    // caches
    const seen = new Set();

    window.AP_BANK_ACCOUNTS_CACHE = bankAccounts
      .map((a) => ({ code: codeOf(a), name: nameOf(a) }))
      .filter((x) => x.code && x.name && !seen.has("B:" + x.code) && (seen.add("B:" + x.code), true));

    const seen2 = new Set();
    window.AP_CONTROL_ACCOUNTS_CACHE = apAccounts
      .map((a) => ({ code: codeOf(a), name: nameOf(a) }))
      .filter((x) => x.code && x.name && !seen2.has("A:" + x.code) && (seen2.add("A:" + x.code), true));

    // main combined cache (if you want one list)
    window.AP_POSTING_ACCOUNTS_CACHE = [
      ...window.AP_BANK_ACCOUNTS_CACHE.map((x) => ({ ...x, kind: "bank" })),
      ...window.AP_CONTROL_ACCOUNTS_CACHE.map((x) => ({ ...x, kind: "ap" })),
    ];

    // ✅ fill the bill viewer bank dropdown if it exists
    const sel = document.getElementById("billViewPayBank");
    if (sel) {
      sel.innerHTML =
        `<option value="">-- Select bank/cash account --</option>` +
        window.AP_BANK_ACCOUNTS_CACHE
          .map((a) => `<option value="${escapeHtml(a.code)}">${escapeHtml(a.name)}</option>`)
          .join("");
    }

    return window.AP_POSTING_ACCOUNTS_CACHE;
  } catch (err) {
    console.error("loadAPPostingAccounts error:", err);
    window.AP_BANK_ACCOUNTS_CACHE = [];
    window.AP_CONTROL_ACCOUNTS_CACHE = [];
    window.AP_POSTING_ACCOUNTS_CACHE = [];
    const sel = document.getElementById("billViewPayBank");
    if (sel) sel.innerHTML = `<option value="">Failed to load bank accounts</option>`;
    return [];
  }
}
window.loadAPPostingAccounts = loadAPPostingAccounts;

function applyBillButtonsByMode() {
  const cid = FS.control.resolveCid();

  const btnDraft   = document.getElementById("billSaveDraft");
  const btnApprove = document.getElementById("billApprove");
  const btnPost    = document.getElementById("billPost");

  if (!cid || (!btnDraft && !btnApprove && !btnPost)) return;

  const mode = FS.control.get(cid);
  const role = FS.role.normalize(getCurrentRole?.() || "");
  const canApprove = !!FS.policy.canApproveBill?.(role, cid);

  // ✅ reset defaults every time
  if (btnDraft) {
    btnDraft.textContent = "Save Draft (Ctrl+S)";
    setBtnDisabled(btnDraft, false);
  }

  if (btnApprove) {
    btnApprove.textContent = "Approve (Ctrl+Enter)";
    setBtnDisabled(btnApprove, false);
  }

  if (btnPost) btnPost.classList.remove("hidden");

  // ---------------------------
  // OWNER MODE
  // ---------------------------
  if (mode === FS.control.MODES.OWNER) {
    if (btnDraft) {
      setBtnDisabled(btnDraft, true, "Drafts are disabled in owner-managed mode");
    }

    if (btnApprove) {
      btnApprove.textContent = "Save & Post (Ctrl+Enter)";
      // optional: make it look primary
      btnApprove.classList.add("bg-[var(--fs-navy)]", "text-white");
    }

    if (btnPost) btnPost.classList.add("hidden");
    return;
  }

  // ---------------------------
  // ASSISTED / CONTROLLED
  // ---------------------------
  if (btnApprove) {
    btnApprove.textContent = "Approve (Ctrl+Enter)";
    setBtnDisabled(btnApprove, !canApprove, "You don’t have approval rights.");
    // remove primary styling if previously applied
    btnApprove.classList.remove("bg-[var(--fs-navy)]", "text-white");
  }
}
window.applyBillButtonsByMode = applyBillButtonsByMode;

async function loadOpenGRNIForVendor(vendorId, { q = "", limit = 50, offset = 0 } = {}) {
  const cid = getActiveCompanyId?.() || window.CURRENT_COMPANY_ID;
  if (!cid || !vendorId) return { items: [], limit, offset };

  const params = new URLSearchParams();
  params.set("vendor_id", String(vendorId));
  params.set("q", String(q || ""));
  params.set("limit", String(limit));
  params.set("offset", String(offset));

  const res = await apiFetch(ENDPOINTS.ap.grniOpen(cid, params.toString()));
  return {
    items: Array.isArray(res?.items) ? res.items : [],
    limit: Number(res?.limit ?? limit),
    offset: Number(res?.offset ?? offset),
  };
}
window.loadOpenGRNIForVendor = loadOpenGRNIForVendor;

function getSelectedApVendorId() {
  // 1) if your vendor picker sets one of these, use it
  const candidates = [
    window._AP_VENDOR_ID,
    window.AP_ACTIVE_VENDOR_ID,
    window.SELECTED_VENDOR_ID,
    window._SELECTED_VENDOR_ID,
    window._BILL_VENDOR_ID,
  ];
  for (const v of candidates) {
    const n = Number(v);
    if (Number.isFinite(n) && n > 0) return n;
  }

  // 2) try bill form vendor dropdown (adjust id if yours differs)
  const el =
    document.getElementById("billVendor") ||
    document.getElementById("apBillVendor") ||
    document.getElementById("vendor_id");

  const id = Number(el?.value || 0);
  if (Number.isFinite(id) && id > 0) return id;

  return 0;
}

async function loadOpenGrniPane({ q = "", limit = 200, offset = 0 } = {}) {
  const cid = getActiveCompanyId?.() || CURRENT_COMPANY_ID;
  const vendorId = window._AP_VENDOR_ID || getSelectedApVendorId?.();
  const mount = document.getElementById("apGrniMount");
  if (!cid || !mount) return;

  if (!vendorId) {
    mount.innerHTML = `<div class="text-xs text-slate-500">Select a vendor first, then open GRN/GRNI.</div>`;
    return;
  }

  const params = new URLSearchParams();
  params.set("vendor_id", String(vendorId));
  if (q) params.set("q", q);
  params.set("limit", String(limit));
  params.set("offset", String(offset));

  mount.innerHTML = `<div class="text-xs text-slate-500">Loading GRNs…</div>`;

  let data;
  try {
    data = await apiFetch(ENDPOINTS.ap.grniOpen(cid, params.toString()));
  } catch (err) {
    mount.innerHTML = renderApiError?.(err) || `<div class="text-xs text-red-600">Failed to load GRNs.</div>`;
    return;
  }

  const items = Array.isArray(data?.items) ? data.items : [];
  if (!items.length) {
    mount.innerHTML = `<div class="text-xs text-slate-500">No open GRNs for this vendor.</div>`;
    return;
  }

  const pack = (obj) => encodeURIComponent(JSON.stringify(obj || {}));

  mount.innerHTML = `
    <div class="overflow-auto border rounded">
      <table class="w-full text-xs">
        <thead class="bg-slate-50 border-b">
          <tr class="text-slate-600">
            <th class="text-left px-2 py-2">GRN</th>
          </tr>
        </thead>
        <tbody>
          ${items.map(r => {
            const payload = pack({
              receipt_tx_id: r.receipt_tx_id,
              tx_date: r.tx_date,
              ref: r.ref,
              notes: r.notes,
              remaining: r.remaining,
            });

            return `
              <tr class="border-b hover:bg-slate-50 cursor-pointer" data-grn="${payload}">
                <td class="px-2 py-2 font-medium">${esc(r.ref || "")}</td>
              </tr>
            `;
          }).join("")}
        </tbody>
      </table>
    </div>
    <div class="mt-2 text-[11px] text-slate-500">${items.length} open receipt(s)</div>
  `;

  // click => apply (NO modal)
  mount.onclick = async (ev) => {
    const tr = ev.target.closest("tr[data-grn]");
    if (!tr) return;

    let row = null;
    try { row = JSON.parse(decodeURIComponent(tr.getAttribute("data-grn") || "%7B%7D")); } catch (_) {}
    if (!row?.receipt_tx_id) return; // ✅ use receipt_tx_id (not ref)

    // ✅ Write GRN into memo only
    const memo = document.getElementById("billMemo");
    if (memo) memo.value = (memo.value ? memo.value + "\n" : "") + `GRN: ${row.ref || row.receipt_tx_id}`;

    // ✅ store link for backend posting later
    window._BILL_GRNI_LINKS = [{
      receipt_tx_id: Number(row.receipt_tx_id || 0),
      amount: Number(String(row.remaining ?? 0).replace(/,/g, "")) || 0,
    }];

    // ✅ this MUST be the function that fills lines
    await window.applyGrniToBillForm?.(row);
  };
}
window.loadOpenGrniPane = loadOpenGrniPane;



async function postBill(billId) {
  const cid = getActiveCompanyId?.() || CURRENT_COMPANY_ID;
  if (!billId) throw new Error("Missing billId");

  const res = await apiFetch(ENDPOINTS.billPost(cid, billId), { method: "POST" });
  if (!res?.ok) throw new Error(res?.error || "Post bill failed");
  return res;
}

function bindBillPostingUI() {
  const btnDraft = document.getElementById("billSaveDraft");
  const btnApprove = document.getElementById("billApprove");
  if (!btnDraft && !btnApprove) return;

  const refreshDraftPaneIfOpen = async () => {
    const pane = document.getElementById("apDraftPane");
    const isOpen = pane && !pane.classList.contains("hidden");
    if (isOpen) await window.loadDraftBillsPane?.();
  };

  if (btnDraft && btnDraft.dataset.bound !== "1") {
    btnDraft.dataset.bound = "1";
    btnDraft.type = "button";
    btnDraft.addEventListener("click", async (e) => {
      e.preventDefault();
      try {
        await commitBill("draft");

        // ✅ refresh drafts pane list if it’s open
        await refreshDraftPaneIfOpen();
      } catch (err) {
        console.error("Bill draft error:", err);
        alert(err?.message || "Could not save bill draft.");
      } finally {
        applyBillButtonsByMode?.();
      }
    });
  }

  if (btnApprove && btnApprove.dataset.bound !== "1") {
    btnApprove.dataset.bound = "1";
    btnApprove.type = "button";
    btnApprove.addEventListener("click", async (e) => {
      e.preventDefault();
      try {
        await commitBill("approve_post");
        await renderCashFlow?.(CURRENT_PERIOD_KEY);

        // ✅ refresh drafts pane list if it’s open
        await refreshDraftPaneIfOpen();
      } catch (err) {
        console.error("Bill approve/post error:", err);
        alert(err?.message || "Could not approve/post bill.");
      } finally {
        applyBillButtonsByMode?.();
      }
    });
  }

  applyBillButtonsByMode?.();
}
window.bindBillPostingUI = bindBillPostingUI;

// ✅ Vendor invoice number enforcement (not system-generated)
window.ensureBillNumberOnCommit = function ensureBillNumberOnCommit() {
  const numberEl = document.getElementById("billNumber");
  const vendorEl = document.getElementById("billVendor");

  const num = (numberEl?.value || "").trim();

  if (!num) {
    const vend = (vendorEl?.value || "the vendor").trim();
    alert(`Vendor invoice number is required before posting.\n\nPlease capture the invoice number on ${vend}'s invoice.`);
    numberEl?.focus();
    numberEl?.classList.add("ring-2", "ring-red-400");
    return false;
  }

  numberEl?.classList.remove("ring-2", "ring-red-400");
  return true;
};

async function commitBill(action) {
  const cid = FS.control.resolveCid();
  if (!cid) throw new Error("No company selected.");

  const role = FS.role.normalize(getCurrentRole?.() || "");
  const mode = FS.control.get(cid);
  const isOwnerMode = (mode === FS.control.MODES.OWNER);
  const canApprove = !!FS.policy.canApproveBill?.(role, cid);

  // ---------------------------
  // Helpers
  // ---------------------------
  const getRoot = () => (typeof window.getBillRoot === "function" ? window.getBillRoot() : document);

  function requireExpenseAccounts(root) {
    const rows = Array.from(root.querySelectorAll("#billLines tr"));
    const missing = [];

    rows.forEach((row, idx) => {
      const acct = (row.querySelector(".bill-acct")?.value || "").trim();
      if (!acct) missing.push(idx + 1);
    });

    if (missing.length) {
      throw new Error(`Select an expense account for line(s): ${missing.join(", ")}`);
    }
  }

  async function ensureBillRowExistsForPosting({ statusToSave = "draft" } = {}) {
    const root = getRoot();

    // 1) Ensure vendor field has synced hidden vendorId
    await window._forceSyncBillVendor?.();

    // 2) Require vendor invoice number
    const ok = window.ensureBillNumberOnCommit?.();
    if (ok === false) throw new Error("Vendor invoice number is required.");

    // 3) Require at least 1 line + each line has an expense account
    //    (we validate DOM here so we catch it even if form-building bugs happen)
    const anyLine = !!root.querySelector("#billLines tr");
    if (!anyLine) throw new Error("Add at least one line.");
    requireExpenseAccounts(root);

    // 4) Save ONCE (creates id if missing, updates if present)
    const saved = await window.saveBillDraft(statusToSave);

    // 5) Ensure billId is on DOM (some flows rely on it)
    const billId = saved?.id || parseInt(root.querySelector("#billId")?.value || "0", 10) || 0;
    if (billId) {
      const idEl = root.querySelector("#billId") || document.getElementById("billId");
      if (idEl) idEl.value = String(billId);
    }

    if (!billId) throw new Error("Could not create bill.");
    return { billId, saved };
  }

  // ---------------------------
  // SAVE DRAFT
  // ---------------------------
  if (action === "draft") {
    // Save once (and validate accounts too)
    const { saved } = await ensureBillRowExistsForPosting({ statusToSave: "draft" });

    // Owner-managed: auto post after saving
    if (isOwnerMode) {
      const billId = saved?.id || parseInt(document.getElementById("billId")?.value || "0", 10) || 0;
      if (!billId) throw new Error("Could not create bill.");
      await postBillAccordingToPolicy(billId);
      return { ok: true, flow: "save_and_post_owner", billId };
    }

    return { ok: true, flow: "draft_only", billId: saved?.id || null };
  }

  // ---------------------------
  // POST / APPROVE
  // ---------------------------
  if (action === "post" || action === "approve_post") {
    if (!canApprove && !isOwnerMode) {
      throw new Error("You are not allowed to post bills.");
    }

    // Save once + preflight checks
    const { billId } = await ensureBillRowExistsForPosting({ statusToSave: "draft" });

    // Backend decides status + journals
    await postBillAccordingToPolicy(billId);

    return { ok: true, flow: "post", billId };
  }

  throw new Error("Unknown action: " + action);
}

window.commitBill = commitBill;

async function refreshVendorGrniPaneAfterPost({ cid, billId, vendorId }) {
  try {
    console.log("[GRNI] refresh after post start", { cid, billId, vendorId });

    // 1) Best: re-fetch the bill FULL (if it includes grni_open_receipts)
    // If you have an endpoint like ENDPOINTS.billOne / ENDPOINTS.billFull use it.
    if (ENDPOINTS.billOne) {
      const full = await apiFetch(ENDPOINTS.billOne(cid, billId) + `?_=${Date.now()}`, { method: "GET" });

      const open = full?.grni_open_receipts || full?.open_receipts || [];
      if (Array.isArray(open) && typeof window.renderGrniPane === "function") {
        window.renderGrniPane(open);
        console.log("[GRNI] refreshed via billOne()", { count: open.length });
        return;
      }
    }

    // 2) Next best: dedicated open receipts endpoint for this vendor
    if (ENDPOINTS.grniOpenReceipts) {
      const open = await apiFetch(ENDPOINTS.grniOpenReceipts(cid, vendorId) + `?_=${Date.now()}`, {
        method: "GET",
      });

      const rows = Array.isArray(open) ? open : (open?.rows || open?.data || []);
      window._GRNI_OPEN_RECEIPTS = rows;

      if (typeof window.renderGrniPane === "function") {
        window.renderGrniPane(rows);
      }

      console.log("[GRNI] refreshed via grniOpenReceipts()", { count: rows.length });
      return;
    }

    // 3) Last resort: if your vendor picker/pane loader exists, call it
    if (typeof window.openApVendorPicker === "function") {
      console.log("[GRNI] fallback: reopening vendor picker to force reload");
      await window.openApVendorPicker({ closeOnPick: true });
    }
  } catch (e) {
    console.warn("[GRNI] refresh after post failed", e);
  }
}

async function postBillAccordingToPolicy(billId) {
  const cid = FS.control.resolveCid();
  if (!cid) throw new Error("No company selected.");
  if (!billId) throw new Error("Bill ID missing.");

  const mode = FS.control.get(cid);
  const shouldAutoPost = !!FS.policy.billAutoPosts?.(cid);

  if (!shouldAutoPost && mode !== FS.control.MODES.OWNER) {
    // still allow manual post
  }

  if (ENDPOINTS.billPost) {
    const out = await apiFetch(ENDPOINTS.billPost(cid, billId), {
      method: "POST",
      body: JSON.stringify({}),
    });

    const saved = out?.data || out;

    if (typeof writeBillForm === "function") writeBillForm(saved);

    // ✅ refresh GRN pane (do NOT rely on browser refresh)
    const vendorId =
      Number(saved?.vendor_id || 0) ||
      Number(document.getElementById("billVendorId")?.value || 0) ||
      Number(window._AP_VENDOR_ID || 0) ||
      null;

    await refreshVendorGrniPaneAfterPost({ cid, billId, vendorId });

    console.log("[BILL] posted ok, refreshed vendor pane", { cid, billId, vendorId });
    return saved;
  }

  if (mode === FS.control.MODES.OWNER) {
    const saved = await saveBillDraft("posted");
    return saved;
  }

  throw new Error("Posting endpoint not available. Add POST /bills/:id/post.");
}

window.postBillAccordingToPolicy = postBillAccordingToPolicy;
window.refreshVendorGrniPaneAfterPost = refreshVendorGrniPaneAfterPost;

async function initPayablesScreen() {
  const screen = document.getElementById("screen-ap");
  if (!screen) return;

  // Panels/toggles also usually bind once, but if bindAPPanels() already guards itself, ok.
  bindAPPanels?.();

  if (screen.dataset.bound !== "1") {
    screen.dataset.bound = "1";

    bindAP?.();                 // big bindAP (lines+totals+save)
    bindBillVendorLookup?.();   // ✅ vendor picker pane -> set vendor + open bills list
    bindBillVendorIdSync?.();   // ✅ input+datalist sync -> hidden vendor_id
    bindBillViewerModal?.();    // ✅ modal allocate payment + close buttons
    // bindApBillsFlow?.();      // optional (if you split vendor->bills->viewer)
  }

  // ---- Data loads / caches (can rerun safely) ----
  await loadBillAccountsForLines?.();  // ✅ builds BILL_ACCOUNTS_CACHE + maybe prefill selects
  await fillBillVendorList?.();        // ✅ datalist for billVendor input
  await loadAPPostingAccounts?.();     // ✅ AP_POSTING_ACCOUNTS_CACHE (for payment/posting)
  await renderApVendorList?.({ closeOnPick: true }); // ✅ left pane vendors
}

function renderBillViewerSidePane(bill, modalEl) {
  if (!modalEl || !bill) return;

  // ✅ modal-scoped lookup (prevents duplicate-id conflicts elsewhere)
  const $ = (id) => modalEl.querySelector(`#${id}`);

  const toNum = (x, d = 0) => {
    const n = Number(String(x ?? "").replace(/,/g, ""));
    return Number.isFinite(n) ? n : d;
  };
  const fmt2 = (x) => toNum(x, 0).toFixed(2);

  // -----------------------------
  // Aging / Outstanding
  // -----------------------------
  const outstanding = (() => {
    const out0 = toNum(bill.outstanding_amount ?? bill.outstanding ?? 0, 0);
    if (out0 > 0) return out0;

    const total = toNum(
      bill.total_amount ?? bill.total ?? bill.amount_total ?? bill.grand_total ?? 0,
      0
    );
    const paid = toNum(
      bill.paid_amount ?? bill.paid ?? bill.allocated_total ?? bill.total_paid ?? 0,
      0
    );

    const out = total - paid;
    return out > 0 ? out : 0;
  })();

  const dueDate =
    bill.due_date ||
    bill.dueDate ||
    bill.due ||
    bill.payment_due ||
    "";

  const status =
    bill.status ||
    bill.bill_status ||
    "";

  const isPaid = outstanding <= 0;

  const agingBadgeText = isPaid ? "Paid" : "Unpaid";

  const elAgingBadge = $("billAgingBadge");
  const elOut        = $("billAgingOutstanding");
  const elDue        = $("billAgingDueDate");
  const elStatus     = $("billAgingStatus");

  if (elAgingBadge) elAgingBadge.textContent = agingBadgeText;
  if (elOut) elOut.textContent = isPaid ? "0.00" : fmt2(outstanding);
  if (elDue) elDue.textContent = String(dueDate || "—");
  if (elStatus) elStatus.textContent = String(status || (isPaid ? "paid" : "unpaid"));

  // -----------------------------
  // Activity feed
  // -----------------------------
  // supports:
  // - bill.activity[]
  // - bill.events[]
  // - bill.history[]
  // - bill.audit_trail[]
  // - bill.payments[] (mapped)
  // - bill.allocations[] (mapped)
  const rawActivity =
    (Array.isArray(bill.activity) && bill.activity) ||
    (Array.isArray(bill.events) && bill.events) ||
    (Array.isArray(bill.history) && bill.history) ||
    (Array.isArray(bill.audit_trail) && bill.audit_trail) ||
    [];

  const payments = Array.isArray(bill.payments) ? bill.payments : [];
  const allocations = Array.isArray(bill.allocations) ? bill.allocations : [];

  const mappedPayments = payments.map(p => ({
    type: "payment",
    date: p.date || p.payment_date || p.created_at || p.createdAt || "",
    label: `Payment${p.reference ? ` (${p.reference})` : ""}`,
    amount: p.amount ?? p.paid_amount ?? p.value,
    status: p.status || p.state || "",
  }));

  const mappedAlloc = allocations.map(a => ({
    type: "allocation",
    date: a.date || a.allocated_at || a.created_at || a.createdAt || "",
    label: `Allocated${a.payment_reference ? ` (${a.payment_reference})` : ""}`,
    amount: a.amount ?? a.value,
    status: a.status || "",
  }));

  // Normalize raw activity shape
  const normalizedRaw = rawActivity.map(ev => {
    const when =
      ev.date ||
      ev.created_at ||
      ev.createdAt ||
      ev.timestamp ||
      "";

    const label =
      ev.label ||
      ev.description ||
      ev.message ||
      ev.event ||
      ev.type ||
      "Event";

    const amount =
      ev.amount ?? ev.value ?? null;

    const st =
      ev.status || ev.state || "";

    return { date: when, label, amount, status: st, type: ev.type || ev.event_type || "" };
  });

  // Combine + sort newest first (best-effort)
  const activity = [...normalizedRaw, ...mappedPayments, ...mappedAlloc]
    .filter(x => x && (x.label || x.date || x.amount != null))
    .sort((a, b) => {
      const da = Date.parse(a.date || "") || 0;
      const db = Date.parse(b.date || "") || 0;
      return db - da;
    });

  const host  = $("billActivityModal");
  const badge = $("billActivityBadge");

  if (badge) badge.textContent = activity.length ? String(activity.length) : "";

  if (!host) return;

  if (!activity.length) {
    host.innerHTML = `<div class="text-xs text-slate-400">No activity.</div>`;
    return;
  }

  host.innerHTML = activity.slice(0, 20).map(ev => {
    const when = ev.date ? String(ev.date) : "—";
    const label = ev.label ? String(ev.label) : "Event";
    const st = ev.status ? String(ev.status) : "";
    const hasAmt = ev.amount !== undefined && ev.amount !== null && String(ev.amount).trim() !== "";
    const amt = hasAmt ? fmt2(ev.amount) : "";

    return `
      <div class="border rounded-lg p-2 bg-white">
        <div class="flex items-center justify-between gap-2">
          <div class="min-w-0">
            <div class="text-xs font-semibold text-slate-700 truncate">${escapeHtml(label)}</div>
            <div class="text-[11px] text-slate-500 truncate">
              ${escapeHtml(when)}${st ? ` • ${escapeHtml(st)}` : ""}
            </div>
          </div>
          ${amt ? `<div class="text-xs font-semibold tabular-nums">${escapeHtml(amt)}</div>` : ""}
        </div>
      </div>
    `;
  }).join("");
}

window.renderBillViewerSidePane = renderBillViewerSidePane;

function safeJsonBody(payload) {
  // if it's already a string, make sure it's not double-stringified
  if (typeof payload === "string") {
    const s = payload.trim();

    // If it's a JSON string literal, JSON.parse will return a string
    // e.g. "\"{...}\"" -> "{...}"
    try {
      const parsed = JSON.parse(s);
      if (typeof parsed === "string") {
        // remove one layer
        return parsed;
      }
      // parsed is object/array -> original string is fine
      return s;
    } catch {
      // not JSON - treat as raw
      return s;
    }
  }

  // normal object -> stringify once
  return JSON.stringify(payload ?? {});
}
window.safeJsonBody = safeJsonBody;

function bindBillViewerModal() {
  const modal = document.getElementById("billViewerModal");
  if (!modal || modal.dataset.bound === "1") return;
  modal.dataset.bound = "1";

  // ✅ Scope selectors to THIS modal to avoid ID mismatches / duplicates
  const $ = (id) => modal.querySelector(`#${id}`);

  const btnClose  = $("billViewClose");
  const btnOpen   = $("billViewAllocatePayment");

  const panel     = $("billViewPayPanel");
  const btnCancel = $("billViewPayCancel");
  const btnSave   = $("billViewPaySave");

  const btnApprove = $("billViewApprovePayment");
  const btnRelease = $("billViewReleasePayment");

  const elDate = $("billViewPayDate");
  const elAmt  = $("billViewPayAmount");
  const elBank = $("billViewPayBank");
  const elRef  = $("billViewPayRef");
  const elDesc = $("billViewPayDesc");
  const elMsg  = $("billViewPayMsg");
  const elCcy  = $("billViewPayCurrency");
  const elOut  = $("billViewOutstanding");

  // WHT
  const elWhtEnabled = $("billViewWhtEnabled");
  const elWhtWrap    = $("billViewWhtWrap");
  const elWhtRate    = $("billViewWhtRate");
  const elWhtAmount  = $("billViewWhtAmount");
  const elWhtLedger  = $("billViewWhtLedger");
  const elWhtReason  = $("billViewWhtReason");

  const elPaymentId  = $("billViewPaymentId");

  const toNum = (x, d = 0) => {
    const n = Number(String(x ?? "").replace(/,/g, ""));
    return Number.isFinite(n) ? n : d;
  };
  const fmt2 = (x) => (Number(x || 0)).toFixed(2);

  function hidePayPanel() { billViewerSetPayPanelOpen(modal, false); }
  function showPayPanel() { billViewerSetPayPanelOpen(modal, true); }

  // ✅ Always start hidden (older behavior)
  hidePayPanel();

  // ✅ Hide panel ONLY when viewer becomes OPEN (robust to class toggles in 2 steps)
  let wasOpen = false;
  const isModalOpen = () => !modal.classList.contains("hidden");

  const mo = new MutationObserver(() => {
    const openNow = isModalOpen();

    if (openNow && !wasOpen) {
      hidePayPanel();
      if (elMsg) elMsg.textContent = "";

      if (modal.dataset.approvalRequestId) {
        // ✅ simulate real click flow
        btnOpen?.click();
      } else {
        if (elPaymentId) elPaymentId.value = "";
        setReviewModeLock(false); // ensure not stuck in lock mode
      }
    }

    wasOpen = openNow;
  });

  mo.observe(modal, { attributes: true, attributeFilter: ["class"] });

  // =========================
  // Mode / Role / Policy helpers
  // =========================
  function getRole() {
    return (typeof getCurrentRole === "function" ? getCurrentRole() : "") || "";
  }

  function setBtnState(btn, ok, why = "") {
    if (!btn) return;
    btn.disabled = !ok;
    btn.classList.toggle("opacity-50", !ok);
    btn.classList.toggle("cursor-not-allowed", !ok);
    btn.title = ok ? "" : why;
  }

  async function getVendor() {
    const { cid, bill, vendorId } = getCtx();
    if (bill?.vendor && typeof bill.vendor === "object") return bill.vendor;
    if (bill?._vendor && typeof bill._vendor === "object") return bill._vendor;

    const vId = Number(vendorId || 0) || 0;
    if (!cid || !vId) return null;

    try {
      if (typeof ENDPOINTS?.vendor === "function") {
        const res = await apiFetch(ENDPOINTS.vendor(cid, vId));
        const out = (typeof unwrapApi === "function") ? unwrapApi(res) : res;
        return out?.data || out || null;
      }

      const res = await apiFetch(`${API_BASE}/api/companies/${cid}/vendors/${vId}`);
      const out = (typeof unwrapApi === "function") ? unwrapApi(res) : res;
      return out?.data || out || null;
    } catch (e) {
      console.warn("[AP] vendor fetch failed:", e);
      return null;
    }
  }

  function setReviewModeLock(on) {
    const lock = !!on;

    [elDate, elAmt, elBank, elDesc, elWhtEnabled, elWhtRate, elWhtAmount, elWhtLedger, elWhtReason]
      .forEach(el => { if (el) el.disabled = lock; });

    // keep reference editable (per your rule)
    if (elRef) elRef.disabled = false;
  }

    // ✅ unlock button (optional override)
    const btnEdit = $("billViewPayEdit");
    btnEdit?.addEventListener("click", () => {
      setReviewModeLock(false);
    }); 

  function applyPaymentPermissions() {
    const { cid } = getCtx();
    const roleRaw = getRole();

    const canCreate = FS?.policy?.canCreatePayment?.(roleRaw, cid) !== false;
    const canAlloc  = FS?.policy?.canAllocatePayment?.(roleRaw, cid) !== false;
    const canAppr   = FS?.policy?.canApprovePayment?.(roleRaw, cid) !== false;
    const canRel    = FS?.policy?.canReleasePayment?.(roleRaw, cid) !== false;

    const approvalRequestId = Number(modal.dataset.approvalRequestId || 0) || 0;
    const approvalAction = String(modal.dataset.approvalAction || "").toLowerCase();

    const fromApprovals = approvalRequestId > 0;

    // default (normal AP workflow)
    let allowCreateAllocate = canCreate && canAlloc;
    let allowApprove = canAppr;
    let allowRelease = canRel;

    // ✅ Approvals-review mode overrides
    if (fromApprovals) {
      // When reviewing an allocation request, you are NOT creating a new one
      if (approvalAction === "allocate_bill_payment") {
        allowCreateAllocate = false;   // avoid creating another payment
        allowRelease = false;          // release is not part of this approval
        // approve stays true/false based on permission
      }

      // If you later add inbox review for release_payment approvals:
      if (approvalAction === "release_payment") {
        allowCreateAllocate = false;   // already have payment
        // approve might be disabled if you want Release-only flows
        // allowRelease remains canRel
      }
    }

    setBtnState(btnSave, allowCreateAllocate, "No permission to create/allocate payments in this mode.");
    setBtnState(btnApprove, allowApprove, "No permission to approve payments in this mode.");
    setBtnState(btnRelease, allowRelease, "No permission to release payments in this mode.");

    // Optional: hide buttons completely instead of disabling
    // if (btnRelease) btnRelease.classList.toggle("hidden", fromApprovals && approvalAction === "allocate_bill_payment");
    // if (btnSave) btnSave.classList.toggle("hidden", fromApprovals && approvalAction === "allocate_bill_payment");
  }

  function isVendorComplianceEnforced(cid) {
    return FS?.policy?.vendorPaymentRequiresVerified?.(cid) === true;
  }

  // ✅ scope gate selectors to modal too (prevents wrong elements)
  function setComplianceGateUI({ vendor, cid }) {
    const wrap   = $("billVendComplianceGate");
    const badge  = $("billVendComplianceBadge");
    const text   = $("billVendComplianceText");
    const fixBtn = $("billVendFixBtn");
    const bypass = $("billVendBypassBtn");

    if (!wrap || !vendor) return;

    const mode = FS.control.get(cid);
    const status = String(vendor.compliance_status || vendor.complianceStatus || "draft").toLowerCase();
    const missing = FS.policy.vendorMissingDocs?.(vendor) || [];

    const verified = status === "verified" && missing.length === 0;

    wrap.classList.toggle("hidden", verified);

    if (badge) {
      badge.textContent = verified ? "Verified" : status.charAt(0).toUpperCase() + status.slice(1);
    }

    if (text) {
      let msg = "";
      if (!verified) {
        msg += `This vendor is not fully compliant.\n`;
        if (missing.length) msg += `Missing: ${missing.join(", ")}.\n`;

        if (mode === FS.control.MODES.CONTROLLED) {
          msg += "Controlled mode: requirements must be satisfied before payment release.";
        } else if (mode === FS.control.MODES.ASSISTED) {
          msg += FS.control.isReviewEnabled?.(cid)
            ? "Assisted mode (review enabled): compliance is enforced before release."
            : "Assisted mode: compliance is recommended but not enforced.";
        } else {
          msg += "Owner-managed mode: compliance is advisory only.";
        }
      }
      text.textContent = msg.trim();
    }

    const allowBypass = mode === FS.control.MODES.OWNER;
    if (bypass) {
      bypass.classList.toggle("hidden", !allowBypass);
      bypass.onclick = () => {
        wrap.classList.add("hidden");
        if (elMsg) elMsg.textContent = "Proceeding without vendor compliance (owner-managed mode).";
      };
    }

    fixBtn?.addEventListener("click", () => {
      const vendorId = vendor.id || vendor.vendor_id;
      window.location.hash = `#vendors?vendor_id=${vendorId}&tab=compliance`;
    });
  }

  async function enforceVendorComplianceOrThrow() {
    const { cid } = getCtx();
    if (!isVendorComplianceEnforced(cid)) return;

    const vendor = await getVendor();
    if (!vendor) return;

    const status = String(vendor.compliance_status || vendor.complianceStatus || "draft").toLowerCase();
    const missing = FS?.policy?.vendorMissingDocs?.(vendor) || vendor.missing_docs || vendor.missingDocs || [];

    const isOk = status === "verified" && Array.isArray(missing) && missing.length === 0;
    if (isOk) return;

    throw new Error(
      `Vendor compliance not verified (${status}).\n` +
      (missing?.length ? `Missing: ${missing.join(", ")}` : "Missing required documents.")
    );
  }

  function getCtx() {
    const cid = getActiveCompanyId?.();
    const billId = Number(modal?.dataset?.billId || 0) || 0;

    const bill =
      window._OPEN_BILL_OBJ ||
      window._OPEN_BILL ||
      window.openBill ||
      (window.BILLS_BY_ID && billId ? window.BILLS_BY_ID[billId] : null) ||
      {};

    const vendorId = Number(bill.vendor_id || bill.vendorId || 0) || 0;
    return { cid, billId, bill, vendorId };
  }

  // Endpoints (match your backend)
  const urlCreateVendorPayment = (cid) => `${API_BASE}/api/companies/${cid}/ap/vendor_payments`;
  const urlAllocateBill = (cid, billId) => `${API_BASE}/api/companies/${cid}/ap/bills/${billId}/allocate_payment`;
  const urlApprovePayment = (cid, paymentId) => `${API_BASE}/api/companies/${cid}/ap/vendor_payments/${paymentId}/approve`;
  const urlReleasePayment = (cid, paymentId) => `${API_BASE}/api/companies/${cid}/ap/vendor_payments/${paymentId}/release`;

  function close() {
    modal.classList.add("hidden");
    modal.classList.remove("flex");
    hidePayPanel();
    if (elMsg) elMsg.textContent = "";
    if (elPaymentId) elPaymentId.value = "";

    delete modal.dataset.approvalRequestId;
    delete modal.dataset.approvalAction;
    delete modal.dataset.approvalPaymentId;
    delete modal.dataset.approvalAmount;
    delete modal.dataset.approvalPayloadJson;
  }

  function pruneBankSelectOptions() {
    if (!elBank) return;
    const badCodes = new Set(["PL_OPEX_6105"]);
    [...elBank.options].forEach(opt => {
      const code = String(opt.value || "").trim();
      if (code && badCodes.has(code)) opt.remove();
    });
  }

  function computeOutstanding(bill) {
    const out0 = toNum(bill.outstanding_amount ?? bill.outstanding ?? 0, 0);
    if (out0 > 0) return out0;

    const total = toNum(bill.total_amount ?? bill.total ?? bill.amount_total ?? bill.grand_total ?? 0, 0);
    const paid  = toNum(bill.paid_amount ?? bill.paid ?? bill.allocated_total ?? bill.total_paid ?? 0, 0);
    const out = total - paid;
    return out > 0 ? out : 0;
  }

  async function loadBanks() {
    if (!elBank) return;

    // keep your existing safety prune (even though we won't be using COA options anymore)
    pruneBankSelectOptions?.();

    const { cid } = getCtx();
    if (!cid) return;

    // ✅ Correct endpoint: company bank accounts (used to pay vendors)
    const url =
      (typeof ENDPOINTS?.bankAccounts === "function")
        ? ENDPOINTS.bankAccounts(cid)
        : `${API_BASE}/api/companies/${cid}/bank_accounts`;

    try {
      const keep = String(elBank.value || "");

      // optional: show loading state
      elBank.innerHTML = `<option value="">Loading bank accounts…</option>`;

      const raw = await apiFetch(url, { method: "GET" });
      const payload = (typeof unwrapApi === "function") ? unwrapApi(raw) : raw;

      // Your Flask route returns jsonify(accounts) => likely an array
      const rows =
        Array.isArray(payload) ? payload :
        Array.isArray(payload?.data) ? payload.data :
        Array.isArray(payload?.accounts) ? payload.accounts :
        [];

      // rebuild select
      elBank.innerHTML = `<option value="">-- Select bank account --</option>`;

      if (!rows.length) {
        elBank.insertAdjacentHTML(
          "beforeend",
          `<option value="" disabled>(No bank accounts found)</option>`
        );
        return;
      }

      // ✅ Normalize bank accounts into options
      // Value: prefer bank_account_code / posting code if it exists, else fall back to id
      rows.forEach(b => {
        const id = b.id ?? b.bank_account_id ?? b.bankAccountId ?? null;

        const value =
          b.bank_account_code ||
          b.account_code ||
          b.gl_code ||
          b.posting_account_code ||
          (id ? String(id) : "");

        if (!value) return;

        const bankName =
          b.bank_name || b.bankName || b.name || "Bank";

        const acctName =
          b.account_name || b.accountName || b.label || "";

        const acctNo =
          b.account_number || b.accountNumber || "";

        const ccy =
          b.currency || b.bank_currency || "";

        const label = [
          bankName,
          acctName,
          acctNo ? `(${acctNo})` : "",
          ccy ? `• ${ccy}` : "",
        ].filter(Boolean).join(" ").trim();

        elBank.insertAdjacentHTML(
          "beforeend",
          `<option value="${escapeHtml(String(value))}">${escapeHtml(label || String(value))}</option>`
        );
      });

      // restore selection if still valid
      if (keep) elBank.value = keep;

    } catch (e) {
      console.warn("[AP] loadBanks failed:", url, e);
      elBank.innerHTML = `<option value="" disabled>(Failed to load bank accounts)</option>`;
    } finally {
      // keep your prune hook
      pruneBankSelectOptions?.();
    }
  }

  function bindWhtToggle() {
    if (!elWhtEnabled || !elWhtWrap) return;
    if (elWhtEnabled.dataset.bound === "1") return;
    elWhtEnabled.dataset.bound = "1";

    const sync = async () => {
      const on = !!elWhtEnabled.checked;
      elWhtWrap.classList.toggle("hidden", !on);

      // ✅ prefill only when turning ON, and only if user hasn’t typed
      if (on && elWhtLedger && String(elWhtLedger.value || "").trim() === "") {
        const def = await getDefaultWhtLedgerCode();
        if (def) elWhtLedger.value = def;
      }
    };

    elWhtEnabled.addEventListener("change", () => {
      elWhtEnabled.dataset.touched = "1";
      sync();
    });

    elWhtLedger?.addEventListener("input", () => (elWhtLedger.dataset.touched = "1"));

    // initial
    sync();
  }

  function prefillFromApprovalPayloadIfAny() {
    if (!modal.dataset.approvalRequestId) return;

    let pj = {};
    try { pj = JSON.parse(modal.dataset.approvalPayloadJson || "{}"); } catch (e) {}

    // Payment id
    if (elPaymentId && pj.payment_id) elPaymentId.value = String(pj.payment_id);

    // Core fields
    if (elDate && pj.payment_date && !elDate.value) elDate.value = String(pj.payment_date);
    if (elAmt && pj.amount && !String(elAmt.value || "").trim()) elAmt.value = String(pj.amount);

    // Bank (must happen AFTER loadBanks)
    if (elBank && pj.bank_account_id) elBank.value = String(pj.bank_account_id);

    // Description / reference (reference may be editable)
    if (elDesc && pj.description && !String(elDesc.value || "").trim()) elDesc.value = String(pj.description);
    if (elRef && pj.reference && !String(elRef.value || "").trim()) elRef.value = String(pj.reference);

    // WHT
    const whtOn = String(pj.wht_rate || pj.wht_amount || pj.wht_ledger_code || "").trim() !== "";
    if (elWhtEnabled) elWhtEnabled.checked = whtOn;
    if (elWhtWrap) elWhtWrap.classList.toggle("hidden", !whtOn);

    if (elWhtRate && pj.wht_rate) elWhtRate.value = String(pj.wht_rate);
    if (elWhtAmount && pj.wht_amount) elWhtAmount.value = String(pj.wht_amount);
    if (elWhtLedger && pj.wht_ledger_code) elWhtLedger.value = String(pj.wht_ledger_code);
    if (elWhtReason && pj.wht_reason) elWhtReason.value = String(pj.wht_reason);
  } 

  function toNumSafe(x, d = 0) {
    const n = Number(String(x ?? "").replace(/,/g, ""));
    return Number.isFinite(n) ? n : d;
  }

  // Auto-calc WHT when payment amount changes
  (function bindWhtAutocalc() {
    if (!elAmt || elAmt.dataset.whtBound === "1") return;
    elAmt.dataset.whtBound = "1";

    elAmt.addEventListener("input", () => {
      if (!elWhtEnabled?.checked) return;

      const rate = toNumSafe(elWhtRate?.value || "", 0);
      const payAmt = toNumSafe(elAmt.value || "", 0);

      const whtAmtStr = String(elWhtAmount?.value || "").trim();
      const userTypedAmt = whtAmtStr.length > 0;

      if (rate > 0 && payAmt > 0 && !userTypedAmt && elWhtAmount) {
        elWhtAmount.value = fmt2((payAmt * rate) / 100);
      }
    });
  })();

  async function getDefaultWhtLedgerCode() {
    const cid = getActiveCompanyId?.();
    if (!cid) return "";

    // cache per company
    window._WHT_LEDGER_CACHE = window._WHT_LEDGER_CACHE || {};
    if (window._WHT_LEDGER_CACHE[cid]) return window._WHT_LEDGER_CACHE[cid];

    try {
      const raw = await apiFetch(`${API_BASE}/api/companies/${cid}/account_settings`);
      const out = unwrapApi?.(raw) ?? raw;
      const code = String(out?.wht_payable_code || "").trim();

      window._WHT_LEDGER_CACHE[cid] = code;
      return code;
    } catch (e) {
      return "";
    }
  }

  function prefillWhtFromVendorIfAny() {
    const { cid, bill } = getCtx();
    if (!elWhtEnabled || !elWhtWrap || !elWhtRate || !elAmt) return;

    const vendor = bill?.vendor || bill?.vendor_obj || bill?._vendor || null;

    const billHasAny = [
      bill?.wht_rate, bill?.withholding_tax_rate,
      bill?.wht_amount, bill?.withholding_tax_amount,
      bill?.wht_ledger_code, bill?.withholding_tax_ledger_code,
      bill?.wht_reason, bill?.withholding_tax_reason,
    ].some(v => String(v ?? "").trim());
    if (billHasAny) return;

    const uiHasAny = [
      elWhtRate?.value, elWhtAmount?.value, elWhtLedger?.value, elWhtReason?.value,
    ].some(v => String(v ?? "").trim());
    if (uiHasAny) return;

    const rateRaw =
      vendor?.wht_percent ?? vendor?.wht ??
      bill?.vendor_wht_percent ?? bill?.wht_percent ?? null;

    const rate = toNumSafe(rateRaw, 0);
    if (!(rate > 0)) return;

    const ledger =
      vendor?.wht_ledger_code ??
      vendor?.withholding_tax_ledger_code ??
      FS?.policy?.whtControlLedgerCode?.(cid) ??
      "";

    elWhtEnabled.checked = true;
    elWhtWrap.classList.remove("hidden");
    elWhtRate.value = String(rate);

    const payAmt = toNumSafe(elAmt.value || "", 0);
    const userTypedWhtAmt = String(elWhtAmount?.value || "").trim().length > 0;

    if (payAmt > 0 && elWhtAmount && !userTypedWhtAmt) {
      elWhtAmount.value = fmt2((payAmt * rate) / 100);
    }

    if (elWhtLedger && String(ledger).trim()) elWhtLedger.value = String(ledger);
    if (elWhtReason) elWhtReason.value = "";
  }

  function prefillFromBill() {
    const { bill } = getCtx();
    const ccy = bill.currency || "";
    if (elCcy) elCcy.textContent = ccy;

    if (elDate && !elDate.value) elDate.value = new Date().toISOString().slice(0, 10);

    const outstanding = computeOutstanding(bill);
    if (elOut) elOut.textContent = fmt2(outstanding);

    if (elAmt && !String(elAmt.value || "").trim() && outstanding > 0) {
      elAmt.value = fmt2(outstanding);
    }

    if (elDesc && !String(elDesc.value || "").trim()) {
      const num = bill.number || bill.bill_no || bill.reference || bill.invoice_no || `BILL-${bill.id || ""}`;
      elDesc.value = `Payment for bill ${num}`;
    }

    const wht_rate = bill.wht_rate ?? bill.withholding_tax_rate ?? "";
    const wht_amount = bill.wht_amount ?? bill.withholding_tax_amount ?? "";
    const wht_ledger = bill.wht_ledger_code ?? bill.withholding_tax_ledger_code ?? "";
    const wht_reason = bill.wht_reason ?? bill.withholding_tax_reason ?? "";

    const hasAny = String(wht_rate || wht_amount || wht_ledger || wht_reason).trim() !== "";
    if (elWhtEnabled) elWhtEnabled.checked = !!hasAny;
    if (elWhtRate) elWhtRate.value = String(wht_rate || "");
    if (elWhtAmount) elWhtAmount.value = String(wht_amount || "");
    if (elWhtLedger && wht_ledger) elWhtLedger.value = String(wht_ledger);
    if (elWhtReason && wht_reason) elWhtReason.value = String(wht_reason);

    if (elPaymentId) {
      const apPayId = Number(modal.dataset.approvalPaymentId || 0) || 0;
      // ✅ only override when approvals handed off a payment id
      if (apPayId) elPaymentId.value = String(apPayId);
      // otherwise: leave whatever is already in the input alone
    }
    prefillWhtFromVendorIfAny();
  }

  async function createPaymentDraft() {
    const { cid, vendorId } = getCtx();
    if (!cid) throw new Error("Missing company id.");
    if (!vendorId) throw new Error("Bill missing vendor_id.");

    const amount = String(elAmt?.value || "").trim();
    if (!amount) throw new Error("Amount is required.");

    // ✅ bank account selected in dropdown (now from /bank_accounts)
    const bank_account_id = Number(String(elBank?.value || "").trim() || 0) || 0;
    if (!bank_account_id) throw new Error("Bank account is required.");

    const payload = {
      vendor_id: Number(vendorId),
      amount: Number(String(elAmt?.value || "").replace(/,/g, "")) || 0,
      payment_date: (String(elDate?.value || "").trim() || null),  // "YYYY-MM-DD" or null
      bank_account_id: Number(bank_account_id),
      reference: String(elRef?.value || "").trim() || null,
      description: String(elDesc?.value || "").trim() || null,
    };
    if (!payload.amount) throw new Error("Amount is required.");

    // WHT optional
    const whtOn = !!elWhtEnabled?.checked;
    if (whtOn) {
      const rate = String(elWhtRate?.value || "").trim();
      const wam  = String(elWhtAmount?.value || "").trim();
      const led  = String(elWhtLedger?.value || "").trim();
      const rea  = String(elWhtReason?.value || "").trim();

      if (rate) payload.wht_rate = rate;
      if (wam)  payload.wht_amount = wam;
      if (led)  payload.wht_ledger_code = led || null;
      if (rea)  payload.wht_reason = rea || null;
    }

    const body = (typeof payload === "string") ? payload : JSON.stringify(payload);

    const res = await apiFetch(urlCreateVendorPayment(cid), {
      method: "POST",
      body,
    });

    const out = (typeof unwrapApi === "function") ? unwrapApi(res) : res;
    const data = out?.data || out || {};
    const paymentId = Number(data.payment_id || data.id || 0) || 0;

    if (!paymentId) throw new Error("Payment created but payment id not returned.");
    if (elPaymentId) elPaymentId.value = String(paymentId);

    return { paymentId, amount };
  }

  async function allocateToBill(paymentId, amount) {
    const { cid, billId } = getCtx();
    if (!cid || !billId) throw new Error("Missing bill context.");

    const res = await apiFetch(urlAllocateBill(cid, billId), {
      method: "POST",
      body: JSON.stringify({ payment_id: paymentId, amount }),
    });

    return (typeof unwrapApi === "function") ? unwrapApi(res) : res;
  }

  function prefillFromApprovalHandoff() {
    const payId = Number(modal.dataset.approvalPaymentId || 0) || 0;
    const amt   = String(modal.dataset.approvalAmount || "").trim();

    if (payId && elPaymentId) elPaymentId.value = String(payId);

    // only set amount if user hasn’t typed
    if (amt && elAmt && !String(elAmt.value || "").trim()) {
      elAmt.value = String(amt);
    }

    // If review came from approvals, we want panel open
    if (modal.dataset.approvalRequestId) {
      showPayPanel();
    }
  }

  async function approvePayment(paymentId) {
    const { cid } = getCtx();
    if (!cid) throw new Error("Missing company id.");
    const res = await apiFetch(urlApprovePayment(cid, paymentId), { method: "POST" });
    return (typeof unwrapApi === "function") ? unwrapApi(res) : res;
  }

  async function releasePayment(paymentId) {
    const { cid } = getCtx();
    if (!cid) throw new Error("Missing company id.");
    const res = await apiFetch(urlReleasePayment(cid, paymentId), { method: "POST" });
    return (typeof unwrapApi === "function") ? unwrapApi(res) : res;
  }

  // =========================
  // Events (bind ONCE each)
  // =========================
  btnClose?.addEventListener("click", close);
  btnCancel?.addEventListener("click", hidePayPanel);

  btnOpen?.addEventListener("click", async () => {
    showPayPanel();
    if (!panel) return;

    applyPaymentPermissions();

    if (elMsg) elMsg.textContent = "Loading…";
    bindWhtToggle();

    // ✅ carry approval payment id into input ASAP
    const apPayId = Number(modal.dataset.approvalPaymentId || 0) || 0;
    if (apPayId && elPaymentId) elPaymentId.value = String(apPayId);

    const billId = Number(modal.dataset.billId || 0) || 0;
    if ((!window._OPEN_BILL_OBJ || !window._OPEN_BILL_OBJ.id) && billId) {
      await window.openBillViewer?.(billId, { preserveOpen: true });
    }

    const { cid } = getCtx();

    const vendor = await getVendor();
    const ctx = getCtx();
    if (vendor && ctx.bill) {
      ctx.bill.vendor = vendor;
      window._OPEN_BILL_OBJ = ctx.bill;
    }

    const enforce = isVendorComplianceEnforced(cid);
    if (vendor) {
      setComplianceGateUI({ vendor, cid });
    } else {
      const wrap  = $("billVendComplianceGate");
      const badge = $("billVendComplianceBadge");
      const text  = $("billVendComplianceText");

      if (wrap) wrap.classList.toggle("hidden", !enforce);
      if (badge) badge.textContent = "Check required";
      if (text) text.textContent =
        "Vendor requirements may be enforced before Release, but vendor details could not be loaded.";
    }

    prefillFromBill();
    await loadBanks();
    pruneBankSelectOptions?.();

    // ✅ must be AFTER loadBanks
    prefillFromApprovalPayloadIfAny();
    setReviewModeLock(!!modal.dataset.approvalRequestId);
    btnEdit.style.display = modal.dataset.approvalRequestId ? "inline-block" : "none";
    
    if (elMsg) elMsg.textContent = "";
    elAmt?.focus?.();
  });

  btnSave?.addEventListener("click", async () => {
    const { billId, cid } = getCtx();
    if (!billId) return;

    try {
      // optional warning-only check (don’t block)
      if (isVendorComplianceEnforced(cid)) {
        try { await enforceVendorComplianceOrThrow(); }
        catch (e) { console.warn("[AP] compliance warning:", e); }
      }

      if (elMsg) elMsg.textContent = "Creating payment…";
      const { paymentId, amount } = await createPaymentDraft();

      if (elMsg) elMsg.textContent = "Allocating to bill…";
      const allocRes = await allocateToBill(paymentId, amount);

      // ✅ approval-required guard (backend returns 202)
      const approvalReq =
        allocRes?.approval_request ||
        allocRes?.approvalRequest ||
        allocRes?.data?.approval_request ||
        allocRes?.data?.approvalRequest ||
        null;

      const approvalRequired =
        (allocRes?.error === "APPROVAL_REQUIRED") ||
        (allocRes?.ok === false && !!approvalReq);

      if (approvalRequired) {
        if (elMsg) elMsg.textContent = "Sent for approval ✅ (check Approvals inbox)";
        try { await switchScreen?.("approvals"); } catch (e) {}
        return;
      }

      // ✅ only say allocated if we truly allocated
      if (elMsg) elMsg.textContent = `Allocated ✅ (Payment #${paymentId})`;
      await window.openBillViewer?.(billId, { preserveOpen: true });

    } catch (e) {
      console.warn("[AP] create+allocate failed:", e);
      if (elMsg) elMsg.textContent = "Failed.";
      alert(e?.message || "Failed to allocate payment");
    }
  });

  btnApprove?.addEventListener("click", async () => {
    const { cid, billId } = getCtx();
    if (!cid) return;

    const approvalRequestId = Number(modal.dataset.approvalRequestId || 0) || 0;
    const paymentId = Number(elPaymentId?.value || 0) || 0;

    try {
      if (elMsg) elMsg.textContent = "Approving…";

      // ✅ If launched from inbox: decide the approval request
      if (approvalRequestId > 0) {
        await apiFetch(ENDPOINTS.approvals.decide(cid, approvalRequestId), {
          method: "POST",
          body: JSON.stringify({
            decision: "approve",
            note: null,
            meta_json: {},   // keep for future
          }),
        });

        // clear handoff (prevents accidental reuse)
        modal.dataset.approvalRequestId = "";
        modal.dataset.approvalAction = "";

        if (elMsg) elMsg.textContent = "Approved ✅";
        await switchScreen?.("approvals");  // optional: go back to inbox
        return;
      }

      // fallback (non-inbox flow)
      if (!paymentId) return alert("Create a payment first.");
      await approvePayment(paymentId);

      if (elMsg) elMsg.textContent = "Approved ✅";
      await window.openBillViewer?.(billId, { preserveOpen: true });

    } catch (e) {
      if (elMsg) elMsg.textContent = "Approve failed.";
      alert(e?.message || "Failed to approve");
    }
  });

  btnRelease?.addEventListener("click", async () => {
    const { cid, billId } = getCtx();
    if (!cid) return;

    const approvalRequestId = Number(modal.dataset.approvalRequestId || 0) || 0;
    const approvalAction = String(modal.dataset.approvalAction || "");

    // ✅ inbox flow for release_payment approvals
    if (approvalRequestId > 0 && approvalAction === "release_payment") {
      await apiFetch(ENDPOINTS.approvals.decide(cid, approvalRequestId), {
        method: "POST",
        body: JSON.stringify({ decision: "approve", note: null, meta_json: {} }),
      });
      modal.dataset.approvalRequestId = "";
      modal.dataset.approvalAction = "";
      if (elMsg) elMsg.textContent = "Released ✅";
      await switchScreen?.("approvals");
      return;
    }

    // fallback normal release flow (non-inbox)
    const paymentId = Number(elPaymentId?.value || 0) || 0;
    if (!paymentId) return alert("Create a payment first (Create & Allocate).");

    const ok = confirm(`Release payment #${paymentId}? This will post the journal.`);
    if (!ok) return;

    try {
      await enforceVendorComplianceOrThrow();
      if (elMsg) elMsg.textContent = "Releasing…";
      await releasePayment(paymentId);
      if (elMsg) elMsg.textContent = "Released ✅";
      await window.openBillViewer?.(billId, { preserveOpen: true });
      hidePayPanel();
    } catch (e) {
      if (elMsg) elMsg.textContent = "Release failed.";
      alert(e?.message || "Failed to release payment");
    }
  });
}

window.bindBillViewerModal = bindBillViewerModal;

// ==============================
// 3) AP CONTROL RECON
// ==============================
async function renderAPRecon() {
  const companyId = CURRENT_COMPANY_ID;
  const asAt0 = isoToday();

  const mount = getControlsMount();
  if (!mount) return;

  mount.innerHTML = `
    <div class="card shadow-sage p-3">
      <div style="display:flex; align-items:center; justify-content:space-between; gap:12px;">
        <div>
          <div style="font-weight:700; color:var(--fs-navy); font-size:18px;">AP Control Reconciliation</div>
          <div style="color:var(--fs-muted); font-size:12px;">Control vs subledger (vendors) as at a date</div>
        </div>
        <div style="display:flex; gap:10px; align-items:center;">
          <input id="apReconAsAt" type="date" value="${asAt0}" class="pill" />
          <button id="btnRunApRecon" class="btn btn-highlight">Run</button>
        </div>
      </div>

      <div id="apReconOut" style="margin-top:14px;"></div>
    </div>
  `;

  const out = mount.querySelector("#apReconOut");
  const btn = mount.querySelector("#btnRunApRecon");

  async function run() {
    const asAt = (mount.querySelector("#apReconAsAt")?.value || asAt0).slice(0, 10);
    out.innerHTML = `<div class="pill">Loading…</div>`;

    try {
      if (!ENDPOINTS?.apRecon) {
        out.innerHTML = `<div class="pill" style="border-color:#fca5a5;">Missing ENDPOINTS.apRecon</div>`;
        return;
      }

      const res = await apiFetch(ENDPOINTS.apRecon(companyId, asAt), { method: "GET" });
      const data = res.data || res;

      const vendors = (data.vendors || data.rows || []).slice(0, 300);

      out.innerHTML = `
        <div class="grid grid-cols-3 gap-8" style="margin-top:10px;">
          <div class="card p-3">
            <div class="uppercase tracking-widest text-slate-400" style="font-size:11px;">AP account</div>
            <div style="font-weight:700; color:var(--fs-navy); margin-top:6px;">${esc(data.ap_account || data.ap_ledger_code || "")}</div>
            <div class="text-slate-600" style="font-size:12px; margin-top:6px;">As at: <span class="tabular-nums">${esc(asAt)}</span></div>
          </div>

          <div class="card p-3">
            <div class="uppercase tracking-widest text-slate-400" style="font-size:11px;">Control balance</div>
            <div style="font-weight:800; font-size:20px; margin-top:6px;" class="tabular-nums">${money(data.control_balance)}</div>
            <div class="text-slate-600" style="font-size:12px; margin-top:6px;">From ledger (credit - debit or debit-credit depending on your AP convention)</div>
          </div>

          <div class="card p-3">
            <div class="uppercase tracking-widest text-slate-400" style="font-size:11px;">Subledger vs control</div>
            <div class="text-slate-600" style="font-size:12px; margin-top:6px;">Subledger total: <b class="tabular-nums">${money(data.subledger_total)}</b></div>
            <div class="text-slate-600" style="font-size:12px; margin-top:6px;">Difference: <b class="tabular-nums">${money(data.difference)}</b></div>
            <div style="margin-top:8px;">
              <span class="pill" style="border-color:${data.is_balanced ? 'rgba(0,200,200,.35)' : '#fca5a5'};">
                ${data.is_balanced ? "Balanced ✅" : "Not balanced ⚠️"}
              </span>
            </div>
          </div>
        </div>

        <div style="margin-top:16px; display:flex; align-items:center; justify-content:space-between;">
          <div style="font-weight:700; color:var(--fs-navy);">Vendors</div>
          <span class="pill">Showing ${vendors.length} vendors</span>
        </div>

        <div style="margin-top:10px; overflow:auto;">
          <table class="border-collapse" style="width:100%;">
            <thead>
              <tr>
                <th align="left">Vendor</th>
                <th align="left">Vendor ID</th>
                <th align="right">Balance</th>
              </tr>
            </thead>
            <tbody>
              ${vendors.map(r => `
                <tr>
                  <td>${esc(r.vendor_name || "")}</td>
                  <td class="tabular-nums">${esc(String(r.vendor_id ?? ""))}</td>
                  <td align="right" class="tabular-nums">${money(r.balance)}</td>
                </tr>
              `).join("")}
            </tbody>
          </table>
        </div>
      `;
    } catch (e) {
      console.error("AP recon failed", e);
      out.innerHTML = `<div class="pill" style="border-color:#fca5a5;">Error: ${esc(e.message || e)}</div>`;
    }
  }

  btn.onclick = run;
  run();
}
window.renderAPRecon = renderAPRecon;

// ==============================
// 4) VENDOR STATEMENTS (ledger-based)
// ==============================
async function renderAPStatements() {
  const companyId = CURRENT_COMPANY_ID;

  const mount = getControlsMount();
  if (!mount) return;

  mount.innerHTML = `
    <div class="card shadow-sage p-3">
      <div style="display:flex; align-items:center; justify-content:space-between; gap:12px;">
        <div>
          <div style="font-weight:700; color:var(--fs-navy); font-size:18px;">Vendor Statement</div>
          <div style="color:var(--fs-muted); font-size:12px;">From ledger (AP control line items)</div>
        </div>
        <div style="display:flex; gap:10px; align-items:center; flex-wrap:wrap;">
          <input id="stmtVendorId" placeholder="Vendor ID" class="pill" style="width:160px;" />
          <input id="stmtFrom" type="date" value="${isoMonthStart()}" class="pill" />
          <input id="stmtTo" type="date" value="${isoToday()}" class="pill" />
          <button id="btnRunVendorStmt" class="btn btn-highlight">Run</button>
        </div>
      </div>

      <div id="stmtOut" style="margin-top:14px;"></div>
    </div>
  `;

  const out = mount.querySelector("#stmtOut");
  const btn = mount.querySelector("#btnRunVendorStmt");

  // -----------------------
  // UI helpers (mirrors AR)
  // -----------------------
  function renderActionsBox() {
    return `
      <div class="card p-3" style="margin-top:14px;">
        <div style="font-weight:700; color:var(--fs-navy);">Bill actions</div>
        <div style="color:var(--fs-muted); font-size:12px; margin-top:4px;">
          Reverse = undo wrong posting. Write-off = vendor waived / dispute settled / duplicate posted.
        </div>

        <div style="display:flex; gap:10px; align-items:center; margin-top:10px; flex-wrap:wrap;">
          <input id="revBillId" placeholder="Bill ID" class="pill" style="width:140px;" />
          <input id="revReason" placeholder="Reason (optional)" class="pill" style="width:320px;" />
          <input id="revDate" type="date" value="${isoToday()}" class="pill" />
          <button id="btnReverseBill" class="btn">Reverse</button>
          <button id="btnWriteoffBill" class="btn">Write-off</button>
        </div>

        <div id="revOut" style="margin-top:10px;"></div>

        <div id="writeoffPanel" class="card p-3" style="margin-top:12px; display:none;">
          <div style="font-weight:700; color:var(--fs-navy);">Write-off bill</div>
          <div style="color:var(--fs-muted); font-size:12px; margin-top:4px;">
            Choose the write-off account (e.g. supplier discounts / other income / expense reduction).
          </div>

          <div style="display:flex; gap:10px; align-items:center; margin-top:10px; flex-wrap:wrap;">
            <select id="writeoffAccount" class="pill" style="min-width:320px;"></select>
            <input id="writeoffDate" type="date" value="${isoToday()}" class="pill" />
            <input id="writeoffReason" placeholder="Write-off reason (optional)" class="pill" style="width:320px;" />
            <button id="btnConfirmWriteoff" class="btn btn-highlight">Confirm write-off</button>
            <button id="btnCancelWriteoff" class="btn">Cancel</button>
          </div>

          <div id="writeoffOut" style="margin-top:10px;"></div>
        </div>
      </div>
    `;
  }

  function loadWriteoffAccounts() {
    const sel = mount.querySelector("#writeoffAccount");
    if (!sel) return;

    // ✅ AP write-off is usually "other income / supplier discounts / adjustments"
    fillSelectFromCurrentCOA(sel, {
      placeholder: "Select write-off account…",
      filterFn: (a) => {
        const cat  = String(a.category || a.section || "").toLowerCase();
        const nm   = String(a.name || "").toLowerCase();
        const code = String(a.code || "").toLowerCase();

        // Adjustments bucket
        if (cat.includes("adjust")) return true;

        // Income-ish buckets (if your COA uses them)
        if (cat.includes("other income")) return true;
        if (cat.includes("income")) return true;

        // Keywords
        if (nm.includes("supplier") && nm.includes("discount")) return true;
        if (nm.includes("discount")) return true;
        if (nm.includes("rebate")) return true;
        if (nm.includes("write") && nm.includes("off")) return true;
        if (nm.includes("waived")) return true;

        // Fallback: allow 82xx adjustments if you use that convention
        if (code.startsWith("82") || code.includes("8200")) return true;

        return false;
      },
      labelFn: (a) => (a?.name || "").toString().trim(),
    });
  }

  function unwrapStatement(res) {
    // handles:
    // - {ok:true,data:{...}}
    // - {data:{...}}
    // - direct payload {...}
    if (res && typeof res === "object") {
      if (res.ok === true && res.data && typeof res.data === "object") return res.data;
      if (res.data && typeof res.data === "object") return res.data;
      return res;
    }
    return {};
  }

  function rowsFromPayload(p) {
    if (Array.isArray(p?.rows)) return p.rows;
    if (Array.isArray(p?.transactions)) return p.transactions;
    // in case backend returns "data" with rows nested (some endpoints do)
    if (Array.isArray(p?.data?.rows)) return p.data.rows;
    if (Array.isArray(p?.data?.transactions)) return p.data.transactions;
    return [];
  }

  async function run() {
    const vendorId = mount.querySelector("#stmtVendorId").value.trim();
    const from = mount.querySelector("#stmtFrom").value;
    const to = mount.querySelector("#stmtTo").value;

    if (!vendorId) {
      out.innerHTML = `<div class="pill" style="border-color:#fca5a5;">Enter a Vendor ID.</div>`;
      return;
    }

    out.innerHTML = `<div class="pill">Loading…</div>`;

    try {
      const res = await apiFetch(ENDPOINTS.apStatement(companyId, vendorId, from, to), { method: "GET" });
      const data = unwrapStatement(res);
      const rows = rowsFromPayload(data).slice(0, 800);

      out.innerHTML = `
        <div class="grid grid-cols-3 gap-8">
          <div class="card p-3">
            <div class="uppercase tracking-widest text-slate-400" style="font-size:11px;">Opening</div>
            <div style="font-weight:900; font-size:18px; margin-top:6px;" class="tabular-nums">${money(data.opening_balance)}</div>
            <div class="text-slate-600" style="font-size:12px; margin-top:6px;">AP: ${esc(data.ap_account || "")}</div>
          </div>
          <div class="card p-3">
            <div class="uppercase tracking-widest text-slate-400" style="font-size:11px;">Closing</div>
            <div style="font-weight:900; font-size:18px; margin-top:6px;" class="tabular-nums">${money(data.closing_balance)}</div>
            <div class="text-slate-600" style="font-size:12px; margin-top:6px;">${esc(data.from)} → ${esc(data.to)}</div>
          </div>
          <div class="card p-3">
            <div class="uppercase tracking-widest text-slate-400" style="font-size:11px;">Vendor</div>
            <div style="font-weight:700; color:var(--fs-navy); margin-top:6px;">#${esc(vendorId)}</div>
            <div class="text-slate-600" style="font-size:12px; margin-top:6px;">Ledger-based statement</div>
          </div>
        </div>

        <div style="margin-top:14px; overflow:auto;">
          <table class="border-collapse" style="width:100%;">
            <thead>
              <tr>
                <th align="left">Date</th>
                <th align="left">Ref</th>
                <th align="left">Memo</th>
                <th align="right">Debit</th>
                <th align="right">Credit</th>
                <th align="right">Movement</th>
                <th align="right">Balance</th>
              </tr>
            </thead>
            <tbody>
              ${
                rows.length
                  ? rows.map(r => `
                      <tr>
                        <td class="tabular-nums">${esc(r.date)}</td>
                        <td>${esc(r.ref || "")}</td>
                        <td>${esc(r.memo || "")}</td>
                        <td align="right" class="tabular-nums">${money(r.debit)}</td>
                        <td align="right" class="tabular-nums">${money(r.credit)}</td>
                        <td align="right" class="tabular-nums">${money(r.movement)}</td>
                        <td align="right" class="tabular-nums"><b>${money(r.balance)}</b></td>
                      </tr>
                    `).join("")
                  : `<tr><td colspan="7" style="padding:10px; color:var(--fs-muted);">No ledger movements in this date range.</td></tr>`
              }
            </tbody>
          </table>
        </div>

        ${renderActionsBox()}
      `;

      // -----------------------
      // Actions wiring (mirror)
      // -----------------------
      const btnReverse = mount.querySelector("#btnReverseBill");
      const btnWriteoff = mount.querySelector("#btnWriteoffBill");
      const revOut = mount.querySelector("#revOut");

      const writeoffPanel = mount.querySelector("#writeoffPanel");
      const btnConfirmWriteoff = mount.querySelector("#btnConfirmWriteoff");
      const btnCancelWriteoff = mount.querySelector("#btnCancelWriteoff");
      const writeoffOut = mount.querySelector("#writeoffOut");

      // ✅ REVERSE BILL (endpoint optional)
      btnReverse.onclick = async () => {
        const billId = mount.querySelector("#revBillId").value.trim();
        const reason = mount.querySelector("#revReason").value.trim();
        const dateStr = (mount.querySelector("#revDate").value || isoToday()).slice(0, 10);

        if (!billId) {
          revOut.innerHTML = `<div class="pill" style="border-color:#fca5a5;">Enter a bill ID.</div>`;
          return;
        }

        revOut.innerHTML = `<div class="pill">Reversing…</div>`;

        try {
          await assertNotLocked(dateStr, "ap");

          if (!ENDPOINTS?.ap?.reverseBill && !ENDPOINTS?.apReverseBill) {
            throw new Error("Missing ENDPOINTS.ap.reverseBill (or ENDPOINTS.apReverseBill)");
          }

          const reverseUrl =
            (ENDPOINTS?.ap?.reverseBill ? ENDPOINTS.ap.reverseBill(companyId, billId) : ENDPOINTS.apReverseBill(companyId, billId));

          const resp = await apiFetch(reverseUrl, {
            method: "POST",
            body: JSON.stringify({ reason, date: dateStr }),
          });

          const rid = resp.reversal_journal_id || resp.data?.reversal_journal_id;

          revOut.innerHTML = `
            <div class="pill" style="border-color:rgba(0,200,200,.35);">
              ✅ Bill reversed<br>
              Journal ID: ${esc(String(rid || ""))}
            </div>
          `;

          await run();
        } catch (e) {
          console.error("Reverse bill failed:", e);
          revOut.innerHTML = `<div class="pill" style="border-color:#fca5a5;">${esc(e.message || e)}</div>`;
        }
      };

      // ✅ OPEN WRITE-OFF PANEL
      btnWriteoff.onclick = () => {
        writeoffPanel.style.display = "block";
        loadWriteoffAccounts();
        writeoffOut.innerHTML = "";
      };

      // ✅ CANCEL WRITE-OFF
      btnCancelWriteoff.onclick = () => {
        writeoffPanel.style.display = "none";
      };

      // ✅ CONFIRM WRITE-OFF (endpoint expected: /ap/bills/:id/writeoff)
      btnConfirmWriteoff.onclick = async () => {
        const billId = mount.querySelector("#revBillId").value.trim();
        const acct = mount.querySelector("#writeoffAccount").value.trim();
        const dateStr = (mount.querySelector("#writeoffDate").value || isoToday()).slice(0, 10);
        const reason = mount.querySelector("#writeoffReason").value.trim();

        if (!billId) {
          writeoffOut.innerHTML = `<div class="pill" style="border-color:#fca5a5;">Enter bill ID above.</div>`;
          return;
        }
        if (!acct) {
          writeoffOut.innerHTML = `<div class="pill" style="border-color:#fca5a5;">Select a write-off account.</div>`;
          return;
        }

        writeoffOut.innerHTML = `<div class="pill">Writing off…</div>`;

        try {
          await assertNotLocked(dateStr, "ap");

          if (!ENDPOINTS?.ap?.writeoffBill && !ENDPOINTS?.apWriteoffBill) {
            throw new Error("Missing ENDPOINTS.ap.writeoffBill (or ENDPOINTS.apWriteoffBill)");
          }

          const woUrl =
            (ENDPOINTS?.ap?.writeoffBill ? ENDPOINTS.ap.writeoffBill(companyId, billId) : ENDPOINTS.apWriteoffBill(companyId, billId));

          const resp = await apiFetch(woUrl, {
            method: "POST",
            body: JSON.stringify({
              writeoff_account_code: acct,
              date: dateStr,
              reason,
            }),
          });

          const jid = resp.writeoff_journal_id || resp.data?.writeoff_journal_id;

          writeoffOut.innerHTML = `
            <div class="pill" style="border-color:rgba(0,200,200,.35);">
              ✅ Bill written off<br>
              Journal ID: ${esc(String(jid || ""))}
            </div>
          `;

          writeoffPanel.style.display = "none";
          await run();
        } catch (e) {
          console.error("Write-off bill failed:", e);
          writeoffOut.innerHTML = `<div class="pill" style="border-color:#fca5a5;">${esc(e.message || e)}</div>`;
        }
      };

    } catch (e) {
      console.error("Vendor statement failed", e);
      out.innerHTML = `<div class="pill" style="border-color:#fca5a5;">Error: ${esc(e.message || e)}</div>`;
    }
  }

  btn.onclick = run;
}
window.renderAPStatements = renderAPStatements;


// ==============================
// 5) AP AGING (30/60/90 style)
// ==============================
async function renderAPAging() {
  const companyId = CURRENT_COMPANY_ID;
  const asAt0 = isoToday();

  const mount = getControlsMount();
  if (!mount) return;

  mount.innerHTML = `
    <div class="card shadow-sage p-3">
      <div style="display:flex; align-items:center; justify-content:space-between; gap:12px; flex-wrap:wrap;">
        <div>
          <div style="font-weight:700; color:var(--fs-navy); font-size:18px;">AP Aging (30/60/90)</div>
          <div style="color:var(--fs-muted); font-size:12px;">Outstanding bills bucketed by days overdue</div>
        </div>

        <div style="display:flex; gap:10px; align-items:center; flex-wrap:wrap;">
          <input id="agingAsAt" type="date" value="${asAt0}" class="pill" />
          <input id="agingVendorId" placeholder="Vendor ID (optional)" class="pill" style="width:180px;" />
          <button id="btnRunApAging" class="btn btn-highlight">Run</button>
        </div>
      </div>

      <div id="agingOut" style="margin-top:14px;"></div>
    </div>
  `;

  const out = mount.querySelector("#agingOut");
  const btn = mount.querySelector("#btnRunApAging");

  async function run() {
    const asAt = (mount.querySelector("#agingAsAt")?.value || asAt0).slice(0, 10);
    const vendRaw = (mount.querySelector("#agingVendorId")?.value || "").trim();
    const vendorId = vendRaw ? vendRaw : null;

    out.innerHTML = `<div class="pill">Loading…</div>`;

    try {
      if (!ENDPOINTS?.apAging) {
        out.innerHTML = `<div class="pill" style="border-color:#fca5a5;">Missing ENDPOINTS.apAging</div>`;
        return;
      }

      const res = await apiFetch(ENDPOINTS.apAging(companyId, asAt, vendorId), { method: "GET" });
      const data = res.data || res;

      // Expect backend similar to AR:
      // data.totals + data.vendors OR data.bills
      const totals = data.totals || {};
      const vendors = (data.vendors || []).slice(0, 400);

      const tCur = totals["current"] ?? 0;
      const t030 = totals["1_30"] ?? totals["0_30"] ?? 0;
      const t3160 = totals["31_60"] ?? 0;
      const t6190 = totals["61_90"] ?? 0;
      const t91 = totals["91_plus"] ?? totals["91+"] ?? 0;
      const tTotal = totals["total"] ?? 0;

      out.innerHTML = `
        <div class="grid grid-cols-3 gap-8">
          <div class="card p-3">
            <div class="uppercase tracking-widest text-slate-400" style="font-size:11px;">Current</div>
            <div style="font-weight:800; font-size:18px; margin-top:6px;" class="tabular-nums">${money(tCur)}</div>
          </div>
          <div class="card p-3">
            <div class="uppercase tracking-widest text-slate-400" style="font-size:11px;">1 - 30</div>
            <div style="font-weight:800; font-size:18px; margin-top:6px;" class="tabular-nums">${money(t030)}</div>
          </div>
          <div class="card p-3">
            <div class="uppercase tracking-widest text-slate-400" style="font-size:11px;">31 - 60</div>
            <div style="font-weight:800; font-size:18px; margin-top:6px;" class="tabular-nums">${money(t3160)}</div>
          </div>
          <div class="card p-3">
            <div class="uppercase tracking-widest text-slate-400" style="font-size:11px;">61 - 90</div>
            <div style="font-weight:800; font-size:18px; margin-top:6px;" class="tabular-nums">${money(t6190)}</div>
          </div>
          <div class="card p-3">
            <div class="uppercase tracking-widest text-slate-400" style="font-size:11px;">91+</div>
            <div style="font-weight:800; font-size:18px; margin-top:6px;" class="tabular-nums">${money(t91)}</div>
          </div>
          <div class="card p-3">
            <div class="uppercase tracking-widest text-slate-400" style="font-size:11px;">Total</div>
            <div style="font-weight:900; font-size:20px; margin-top:6px;" class="tabular-nums">${money(tTotal)}</div>
          </div>
        </div>

        <div style="margin-top:16px; display:flex; align-items:center; justify-content:space-between;">
          <div style="font-weight:700; color:var(--fs-navy);">Vendors</div>
          <span class="pill">Showing ${vendors.length} rows</span>
        </div>

        <div style="margin-top:10px; overflow:auto;">
          <table class="border-collapse" style="width:100%;">
            <thead>
              <tr>
                <th align="left">Vendor</th>
                <th align="left">Vendor ID</th>
                <th align="right">Current</th>
                <th align="right">1-30</th>
                <th align="right">31-60</th>
                <th align="right">61-90</th>
                <th align="right">91+</th>
                <th align="right">Total</th>
              </tr>
            </thead>
            <tbody>
              ${vendors.map(v => `
                <tr>
                  <td>${esc(v.vendor_name || "")}</td>
                  <td class="tabular-nums">${esc(String(v.vendor_id ?? ""))}</td>
                  <td align="right" class="tabular-nums">${money(v.current || 0)}</td>
                  <td align="right" class="tabular-nums">${money(v["1_30"] || 0)}</td>
                  <td align="right" class="tabular-nums">${money(v["31_60"] || 0)}</td>
                  <td align="right" class="tabular-nums">${money(v["61_90"] || 0)}</td>
                  <td align="right" class="tabular-nums">${money(v["91_plus"] || 0)}</td>
                  <td align="right" class="tabular-nums"><b>${money(v.total || 0)}</b></td>
                </tr>
              `).join("")}
            </tbody>
          </table>
        </div>
      `;
    } catch (e) {
      console.error("AP aging failed", e);
      out.innerHTML = `<div class="pill" style="border-color:#fca5a5;">Error: ${esc(e.message || e)}</div>`;
    }
  }

  btn.onclick = run;
  run();
}
window.renderAPAging = renderAPAging;

  /* ==============================
   * Dashboard render helpers
   * ============================== */



async function renderMonthEndClose(periodKey = "this_month") {
  const tag = $("#closeStatusTag");
  const bar = $("#closeProgress");
  const list = $("#closeChecklist");
  if (!tag || !bar || !list) return;

  try {
    const snap = await getDashboardData(periodKey);
    const aging = snap?.aging || {};
    const bs = snap?.balanceSheet || {};
    const counts = snap?.counts || {};

    const arTotal = Number(aging?.ar?.total || 0);
    const apTotal = Number(aging?.ap?.total || 0);
    const bsCheck = Number(bs?.check || 0);
    const customers = Number(counts?.customers || 0);
    const vendors = Number(counts?.vendors || 0);

    const steps = [
      { label: "Customers loaded", done: customers > 0 },
      { label: "Vendors loaded", done: vendors > 0 },
      { label: "Receivables reviewed", done: arTotal >= 0 },
      { label: "Payables reviewed", done: apTotal >= 0 },
      { label: "Balance Sheet reviewed", done: Math.abs(bsCheck) <= 1 },
    ];

    const total = steps.length;
    const done = steps.filter(s => s.done).length;
    const pct = total ? Math.round((done / total) * 100) : 0;

    tag.textContent = pct === 100 ? "Closed" : (pct >= 60 ? "In Progress" : "Not started");
    bar.style.width = `${pct}%`;

    list.innerHTML = steps
      .map(s => `<li>${s.done ? "☑" : "☐"} ${s.label}</li>`)
      .join("");
  } catch (e) {
    console.error("renderMonthEndClose error:", e);
  }
}
window.renderMonthEndClose = renderMonthEndClose;

async function renderARAgingSnapshot(periodKey = "this_month") {
  const hostAR = $("#agingAR");
  const hostAP = $("#agingAP");
  if (!hostAR || !hostAP) return;

  try {
    const snap = await getDashboardData(periodKey);
    const ar = snap?.aging?.ar || {};
    const ap = snap?.aging?.ap || {};

    const arBuckets = {
      "0-30": Number(ar["0_30"] || 0),
      "31-60": Number(ar["31_60"] || 0),
      "61-90": Number(ar["61_90"] || 0),
      "91-120": Number(ar["91_120"] || 0),
      "121+": Number(ar["121_plus"] || 0),
    };

    const apBuckets = {
      "Current": Number(ap["current"] || 0),
      "1-30": Number(ap["1_30"] || 0),
      "31-60": Number(ap["31_60"] || 0),
      "61-90": Number(ap["61_90"] || 0),
      "91+": Number(ap["91_plus"] || 0),
    };

    function renderAgingRows(host, buckets) {
      const max = Math.max(...Object.values(buckets), 0);

      host.innerHTML = Object.entries(buckets)
        .map(([bucket, value]) => {
          const width = max ? Math.max(8, (value / max) * 100) : 0;
          return `
            <div class="flex items-center gap-2">
              <span class="w-16">${bucket}</span>
              <div class="flex-1 h-1.5 bg-slate-100 rounded">
                <div class="h-1.5 rounded bg-[var(--fs-teal)]" style="width:${width}%"></div>
              </div>
              <span class="w-24 text-right">${money(value)}</span>
            </div>
          `;
        })
        .join("");
    }

    renderAgingRows(hostAR, arBuckets);
    renderAgingRows(hostAP, apBuckets);
  } catch (e) {
    console.error("renderARAgingSnapshot error:", e);
    hostAR.innerHTML = `<div>No receivables yet.</div>`;
    hostAP.innerHTML = `<div>No payables yet.</div>`;
  }
}
window.renderARAgingSnapshot = renderARAgingSnapshot;
window.renderAPAgingSnapshot = renderARAgingSnapshot;

async function renderFixedAssetsSnapshot(periodKey = "this_month") {
  const elBook = $("#faBookValue");
  const elDep = $("#faDep");
  const elNet = $("#faNet");
  const elPend = $("#faPending");
  if (!elBook || !elDep || !elNet || !elPend) return;

  try {
    const snap = await getDashboardData(periodKey);
    const fa = snap?.fixedAssets || {};

    const book = Number(fa.bookValue || 0);
    const dep = Number(fa.accumDep || 0);
    const net = Number(fa.netBookValue != null ? fa.netBookValue : (book - dep));
    const pending = Number(fa.pendingCount || 0);

    elBook.textContent = money(book);
    elDep.textContent = money(dep);
    elNet.textContent = money(net);
    elPend.textContent = String(pending);
  } catch (e) {
    console.error("renderFixedAssetsSnapshot error:", e);
    elBook.textContent = money(0);
    elDep.textContent = money(0);
    elNet.textContent = money(0);
    elPend.textContent = "0";
  }
}
window.renderFixedAssetsSnapshot = renderFixedAssetsSnapshot;

async function renderInventorySnapshot(periodKey = "this_month") {
  const v = $("#invValue");
  const s = $("#invSkus");
  const d = $("#invDays");
  const a = $("#invAlerts");
  if (!v || !s || !d || !a) return;

  try {
    const snap = await getDashboardData(periodKey);
    const inv = snap?.inventory || {};

    const value = Number(inv.value || 0);
    const skus = Number(inv.skus || 0);
    const days = Number(inv.days || 0);
    const alerts = Number(inv.alerts || 0);

    v.textContent = money(value);
    s.textContent = String(skus);
    d.textContent = String(days);
    a.textContent = String(alerts);
  } catch (e) {
    console.error("renderInventorySnapshot error:", e);
    v.textContent = money(0);
    s.textContent = "0";
    d.textContent = "0";
    a.textContent = "0";
  }
}
