  function renderServices() {
    // Left list (service jobs)
    const jobsHost   = $("#svcJobsList");
    const detailHost = $("#svcJobDetail");
    const totalHost  = $("#svcBillTotal");
    const statusHost = $("#svcBillStatus");

    if (!jobsHost) return; // screen not on this page

    // For now this is demo-only; later we can read from store.get("fs_service_jobs", [])
    const demoJobs = [
      {
        id: "JOB-001",
        title: "Monthly bookkeeping - March",
        customer: "Acme Trading (Pty) Ltd",
        status: "In progress",
        amount: 4500,
      },
      {
        id: "JOB-002",
        title: "Year-end financial statements",
        customer: "Sunrise Clinic",
        status: "Not started",
        amount: 12000,
      },
    ];

    // ─────────────────────────────────────
    // 1) Render service jobs list
    // ─────────────────────────────────────
    if (!demoJobs.length) {
      jobsHost.innerHTML =
        `<div class="text-xs text-slate-400 mt-2">No service jobs yet.</div>`;
    } else {
      jobsHost.innerHTML = demoJobs
        .map(
          (j) => `
          <button
            type="button"
            class="w-full text-left px-2 py-1 mb-1 rounded border hover:bg-slate-50 text-xs"
            data-svc-id="${j.id}"
          >
            <div class="flex items-center justify-between">
              <span class="font-medium">${j.title}</span>
              <span class="text-[10px] text-slate-500">${j.status}</span>
            </div>
            <div class="text-[11px] text-slate-500">
              ${j.customer} · ${money(j.amount || 0)}
            </div>
          </button>
        `
        )
        .join("");
    }

    // Default detail text
    if (detailHost) {
      detailHost.innerHTML =
        `<div class="text-xs text-slate-600">
          Select a job to preview notes and billing information.
        </div>`;
    }

    // ─────────────────────────────────────
    // 2) When you click a job:
    //    - show detail
    //    - pre-fill Quick Billing with that job
    // ─────────────────────────────────────
    jobsHost.querySelectorAll("[data-svc-id]").forEach((btn) => {
      btn.addEventListener("click", () => {
        const id = btn.getAttribute("data-svc-id");
        const job = demoJobs.find((j) => j.id === id);
        if (!job || !detailHost) return;

        detailHost.innerHTML = `
          <div class="space-y-1 text-xs">
            <div class="font-semibold text-slate-800">${job.title}</div>
            <div class="text-slate-500">${job.customer}</div>
            <div>Status: <span class="font-medium">${job.status}</span></div>
            <div>Est. billable: <span class="font-medium">${money(job.amount || 0)}</span></div>
            <div class="mt-2 text-[11px] text-slate-500">
              This is a demo service job. Later we’ll store time, notes,
              and push it directly into an invoice or recurring billing.
            </div>
          </div>
        `;

        // Push job amount into Quick Billing as a starting point
        const qtyEl  = $("#svcBillQty");
        const rateEl = $("#svcBillRate");
        const descEl = $("#svcBillDesc");
        if (qtyEl && rateEl) {
          qtyEl.value  = "1";
          rateEl.value = String(job.amount || 0);
        }
        if (descEl) {
          descEl.value = job.title;
        }
        recomputeServiceBillingTotal();
      });
    });

    // ─────────────────────────────────────
    // 3) Quick Billing logic (re-usable)
    // ─────────────────────────────────────
    const qtyEl  = $("#svcBillQty");
    const rateEl = $("#svcBillRate");
    const vatEl  = $("#svcBillVatCode");

    function recomputeServiceBillingTotal() {
      if (!totalHost) return;
      const qty     = parseFloat(qtyEl?.value || "0") || 0;
      const rate    = parseFloat(rateEl?.value || "0") || 0;
      const vatCode = vatEl?.value || "STANDARD";

      const base = qty * rate;
      let vatAmt = 0;
      if (vatCode === "STANDARD") {
        vatAmt = base * 0.15;
      }
      const total = base + vatAmt;
      totalHost.textContent = money(total || 0);
    }

    // Expose so you can call it from elsewhere if needed
    window.recomputeServiceBillingTotal = recomputeServiceBillingTotal;

    qtyEl && qtyEl.addEventListener("input", recomputeServiceBillingTotal);
    rateEl && rateEl.addEventListener("input", recomputeServiceBillingTotal);
    vatEl && vatEl.addEventListener("change", recomputeServiceBillingTotal);

    // ─────────────────────────────────────
    // 4) Send to Invoice → AR
    //    This is the "reusable" part: it *feeds* AR, not its own invoice system
    // ─────────────────────────────────────
    const sendBtn = $("#svcBillToInvoice");
    sendBtn &&
      sendBtn.addEventListener("click", () => {
        const customer = $("#svcBillCustomer")?.value || "";
        const desc     = $("#svcBillDesc")?.value || "";
        const qty      = parseFloat($("#svcBillQty")?.value || "0") || 0;
        const rate     = parseFloat($("#svcBillRate")?.value || "0") || 0;
        const vatCode  = $("#svcBillVatCode")?.value || "STANDARD";

        if (!customer || !desc || !qty || !rate) {
          if (statusHost) {
            statusHost.textContent =
              "Customer, description, qty and rate are required.";
            setTimeout(() => (statusHost.textContent = ""), 3000);
          }
          return;
        }

        // 🔹 This is the "draft invoice" payload AR will pick up
        const draft = {
          fromService: true,
          customer,
          desc,
          qty,
          rate,
          vatCode,
        };

        localStorage.setItem(
          "fs_service_invoice_draft",
          JSON.stringify(draft)
        );

        if (statusHost) {
          statusHost.textContent = "Draft sent to Accounts Receivable…";
          setTimeout(() => (statusHost.textContent = ""), 3000);
        }

        // Jump into AR screen (where bindAR will read the draft)
        switchScreen("ar");
      });

      // Ensure initial total is computed
      recomputeServiceBillingTotal();
    }
    
