  // Company profile flags (from /api/auth/me)
  // ==============================
  function updateCompanyProfileFromUser(me) {
    // If nothing to work with, try restore from localStorage and bail
    if (!me || !me.company) {
      const saved = store.get("fs_company_profile", null);
      if (saved && typeof saved === "object") {
        COMPANY_PROFILE = { ...COMPANY_PROFILE, ...saved };
      }
      return;
    }

    // ✅ use backend company object
    CURRENT_COMPANY = me.company;

    // Backend can send something like:
    //   me.company_profile = {
    //     is_service_only: true,
    //     uses_inventory: false,
    //     uses_cogs: false,
    //     default_inventory_mode: "none",
    //     default_valuation: null,
    //   }
    //
    // or flags under me.company.flags / me.company.features.
    const flags =
      me.company_profile ||
      me.company.flags ||
      me.company.features ||
      {};

    const industryRaw =
      me.company.industry ||
      me.industry ||
      localStorage.getItem("fs_industry") ||
      "";
    const industry = String(industryRaw).toLowerCase();

    // Start from current defaults and override with backend / heuristics
    COMPANY_PROFILE = {
      ...COMPANY_PROFILE,
      key: me.company.id || me.company.key || null,

      // If backend gives us explicit booleans, use them.
      // Otherwise: basic heuristic by industry.
      is_service_only:
        flags.is_service_only ??
        flags.service_only ??
        (
          industry.includes("service") ||
          industry.includes("consult") ||
          industry.includes("professional") ||
          industry.includes("legal") ||
          industry.includes("clinic")
        ),

      uses_inventory:
        flags.uses_inventory ??
        flags.has_inventory ??
        !(
          industry.includes("service") ||
          industry.includes("consult") ||
          industry.includes("professional") ||
          industry.includes("legal") ||
          industry.includes("clinic")
        ),

      uses_cogs:
        flags.uses_cogs ??
        flags.has_cogs ??
        true,

      default_inventory_mode: flags.default_inventory_mode || "none",
      default_valuation: flags.default_valuation || null,
    };

    // Persist so next reload can still gate nav before /me finishes
    store.set("fs_company_profile", COMPANY_PROFILE);
  }

  async function restoreAuthUI() {
    console.log("restoreAuthUI: starting");

    const token =
      localStorage.getItem(TOKEN_KEY) || sessionStorage.getItem(TOKEN_KEY);

    if (!token) {
      console.log("restoreAuthUI: no token in storage");
      return null;
    }

    try {
      const me = await apiFetch(ENDPOINTS.auth.me);
      window.currentUser = me;
      console.log("restoreAuthUI: currentUser =", me);

      console.log(
        "restoreAuthUI: me.company_id =",
        me.company_id,
        "local company_id before =",
        localStorage.getItem(COMPANY_KEY)
      );

      // ✅ set CURRENT_COMPANY for any UI that needs it
      CURRENT_COMPANY = me.company || null;

      // 🔥 normalise role using normalizeRole()
      const rawRole =
        (me && (me.user_role || me.role || me.system_role)) ||
        localStorage.getItem("userRole") ||
        window.FS_USER_ROLE ||
        "viewer";

      const appRole = normalizeRole(rawRole);
      localStorage.setItem("userRole", appRole);
      window.FS_USER_ROLE = appRole;

      // ✅ Store company id from backend
      if (me.company_id != null) {
        localStorage.setItem(COMPANY_KEY, String(me.company_id));
        sessionStorage.setItem(COMPANY_KEY, String(me.company_id));
      } else {
        // shared demo / default
        localStorage.setItem(COMPANY_KEY, "1");
        sessionStorage.setItem(COMPANY_KEY, "1");
      }

      // 🔁 IMPORTANT: now that COMPANY_KEY is final, re-point the companyStore
      refreshCompanyStore();

      // ✅ hydrate feature flags for nav (service vs inventory)
      updateCompanyProfileFromUser(me);
      console.log("restoreAuthUI: COMPANY_PROFILE =", COMPANY_PROFILE);

      // ✅ Ensure email stored for avatar / header
      if (me.email) {
        // was: localStorage.setItem("userEmail", me.email);
        store.set("userEmail", me.email);        // <- this is the new line you asked about

        // optional: keep this for backward-compat if you still read from localStorage anywhere
        localStorage.setItem("userEmail", me.email);
      }

      // ✅ header / user badges, etc.
      applyAuthUI(me);

      return me;
    } catch (err) {
      console.warn("restoreAuthUI: token invalid, clearing", err);
      localStorage.removeItem(TOKEN_KEY);
      sessionStorage.removeItem(TOKEN_KEY);
      window.currentUser = null;
      return null;
    }
  }

  window.__debugShowDrafts = function () {
    console.log("store drafts (global):", store.get(K.CUST_DRAFTS, []));
    console.log(
      "store drafts (companyStore):",
      companyStore.get(K.CUST_DRAFTS, [])
    );
  };

