// ==============================
// Full app bootstrap (heavy init)
// ==============================
async function bootstrapApp(currentUser) {
  console.log("bootstrapApp: starting for user", currentUser?.email);

  // ------------------------------------------------------------
  // 0) Load cached company profile (fallback only)
  // ------------------------------------------------------------
  if (!COMPANY_PROFILE || !COMPANY_PROFILE.key) {
    const savedProfile = store.get("fs_company_profile", null);
    if (savedProfile && typeof savedProfile === "object") {
      COMPANY_PROFILE = { ...COMPANY_PROFILE, ...savedProfile };
    }
  }

  // ------------------------------------------------------------
  // 1) Resolve company id + access mode
  // ------------------------------------------------------------
  let tokenPayload = null;
  try {
    const token = window.getToken?.();
    if (token) {
      const parts = String(token).split(".");
      if (parts.length >= 2) {
        tokenPayload = JSON.parse(atob(parts[1]));
      }
    }
  } catch (e) {
    console.warn("bootstrapApp: failed to decode token payload", e);
    tokenPayload = null;
  }

  const tokenAccessScope = String(tokenPayload?.access_scope || "").toLowerCase();
  const tokenSaysDelegated =
    !!tokenPayload?.is_delegated_company_access ||
    tokenAccessScope === "delegated_workspace";

  const postingCtx = tokenSaysDelegated
    ? (
        window.FS_DELEGATED_WORKSPACE?.restorePostingContext?.() ||
        window.restorePostingContext?.() ||
        null
      )
    : null;

  try {
    const token = window.getToken?.();
    if (token) {
      const parts = String(token).split(".");
      if (parts.length >= 2) {
        tokenPayload = JSON.parse(atob(parts[1]));
      }
    }
  } catch (e) {
    console.warn("bootstrapApp: failed to decode token payload", e);
    tokenPayload = null;
  }

  const accessScope = String(
    tokenPayload?.access_scope ||
    currentUser?.token_access_scope ||
    currentUser?.access_scope ||
    ""
  ).toLowerCase();

  const tokenDelegated =
    !!tokenPayload?.is_delegated_company_access ||
    !!currentUser?.is_delegated_company_access ||
    accessScope === "delegated_workspace";

  const delegatedPostingCompanyId =
    Number(
      postingCtx?.targetCompanyId ||
      postingCtx?.companyId ||
      tokenPayload?.target_company_id ||
      currentUser?.target_company_id ||
      tokenPayload?.company_id ||
      currentUser?.company_id ||
      0
    ) || null;

  const isDelegatedPosting =
    !!tokenDelegated && delegatedPostingCompanyId > 0;

  // expose globally as early as possible
  window.__FS_DELEGATED_POSTING__ = isDelegatedPosting;
  window.__FS_POSTING_CONTEXT__ = postingCtx || {
    accessMode: tokenDelegated ? "delegated_workspace" : null,
    launchMode: tokenDelegated ? "posting" : null,
    sourceCompanyId:
      Number(
        postingCtx?.sourceCompanyId ||
        tokenPayload?.source_company_id ||
        currentUser?.source_company_id ||
        0
      ) || null,
    targetCompanyId: delegatedPostingCompanyId,
    companyId: delegatedPostingCompanyId
  };

  // ------------------------------------------------------------
  // 2) Resolve access scope + permissions
  // ------------------------------------------------------------
  const isInternalScope =
    accessScope === "internal" || accessScope === "core";

  let perms = {};

  if (isDelegatedPosting) {
    perms =
      tokenPayload?.permissions ||
      currentUser?.permissions ||
      window.getCurrentPermissions?.() ||
      {};
  } else {
    perms =
      currentUser?.permissions ||
      window.getCurrentPermissions?.() ||
      tokenPayload?.permissions ||
      {};
  }

  const canUseDelegatedPosting =
    !!perms?.can_access_delegated_posting_workspace ||
    !!perms?.can_post_journals ||
    !!perms?.can_prepare_financials ||
    !!perms?.can_access_enterprise_dashboard;

  const canUseDashboardShell =
    isInternalScope || (isDelegatedPosting && canUseDelegatedPosting);

  console.log("TOKEN DEBUG", {
    token: window.getToken?.() || null,
    tokenPayload,
  });

  console.log("bootstrapApp: access mode", {
    accessScope,
    isInternalScope,
    tokenDelegated,
    isDelegatedPosting,
    postingCtx,
    delegatedPostingCompanyId,
    currentUserCompanyId:
      currentUser?.company_id ||
      currentUser?.companyId ||
      currentUser?.company?.id ||
      currentUser?.company_profile?.id ||
      null,
    tokenCompanyId: tokenPayload?.company_id || null,
    canUseDelegatedPosting,
    canUseDashboardShell,
    perms,
  });

  if (!canUseDashboardShell) {
    console.error("bootstrapApp: dashboard shell denied", {
      reason: "canUseDashboardShell=false",
      accessScope,
      isInternalScope,
      tokenDelegated,
      isDelegatedPosting,
      canUseDelegatedPosting,
      postingCtx,
      token: window.getToken?.() || null,
      tokenPayload,
      currentUser,
      perms,
      sessionTokenPresent: !!sessionStorage.getItem("fs_user_token"),
      localTokenPresent: !!localStorage.getItem("fs_user_token"),
    });

    // Delegated users should never be bounced back to practitioner
    // just because postingCtx restored late.
    if (tokenDelegated) {
      console.warn("bootstrapApp: delegated token detected, suppressing bounce to practitioner");
      return;
    }

    window.location.replace("practitionerdashboard.html");
    return;
  }

  // ------------------------------------------------------------
  // 3) Resolve company id
  // ------------------------------------------------------------
  const nativeResolvedCompanyId =
    (typeof getActiveCompanyId === "function" ? getActiveCompanyId() : null) ||
    currentUser?.company_id ||
    currentUser?.companyId ||
    currentUser?.company?.id ||
    currentUser?.company_profile?.id ||
    Number(localStorage.getItem("company_id") || 0) ||
    null;

  const resolvedCompanyId = isDelegatedPosting
    ? delegatedPostingCompanyId
    : nativeResolvedCompanyId;

  if (resolvedCompanyId) {
    localStorage.setItem("company_id", String(resolvedCompanyId));
    CURRENT_COMPANY_ID = Number(resolvedCompanyId);
    window.CURRENT_COMPANY_ID = CURRENT_COMPANY_ID;
    window.__COMPANY_ID__ = CURRENT_COMPANY_ID;

    if (isDelegatedPosting) {
      window.__PR_ACTIVE_COMPANY_ID__ = CURRENT_COMPANY_ID;
      window.__FS_TARGET_COMPANY_ID__ = CURRENT_COMPANY_ID;
      window.__FS_SOURCE_COMPANY_ID__ =
        Number(
          postingCtx?.sourceCompanyId ||
          tokenPayload?.source_company_id ||
          currentUser?.source_company_id ||
          0
        ) || null;

      try {
        if (typeof setActiveCompanyId === "function") {
          setActiveCompanyId(CURRENT_COMPANY_ID);
        }
      } catch (e) {
        console.warn("bootstrapApp: failed to hard-set delegated active company", e);
      }
    }
  }

  if (!resolvedCompanyId) {
    console.warn("bootstrapApp: logged in but NO company_id found; routing to company setup");

    if (typeof applyAuthUI === "function") applyAuthUI(currentUser);
    if (typeof switchScreen === "function") switchScreen("company");
    return;
  }

  // keep localStorage + globals in sync
  localStorage.setItem("company_id", String(resolvedCompanyId));
  CURRENT_COMPANY_ID = Number(resolvedCompanyId);
  window.CURRENT_COMPANY_ID = CURRENT_COMPANY_ID;

  if (typeof refreshCompanyStore === "function") refreshCompanyStore();

  // ------------------------------------------------------------
  // 4) Resolve company object
  // ------------------------------------------------------------
  async function fetchCompanyProfile(cid) {
    if (currentUser?.company && currentUser.company.id) return currentUser.company;
    if (currentUser?.company_profile && currentUser.company_profile.id) return currentUser.company_profile;

    const saved = store.get("fs_company_profile", null);
    if (saved && typeof saved === "object") {
      console.log("bootstrapApp: using cached company profile fallback");
    }

    try {
      const url = (window.ENDPOINTS?.company)
        ? ENDPOINTS.company(cid)
        : `/api/companies/${encodeURIComponent(cid)}`;

      const company = await apiFetch(url, { method: "GET" });
      return company || saved || null;
    } catch (e) {
      console.error("bootstrapApp: failed to fetch company profile", cid, e);
      return saved || null;
    }
  }

  const companyObj = await fetchCompanyProfile(resolvedCompanyId);

  CURRENT_COMPANY =
    companyObj ||
    COMPANY_PROFILE ||
    {
      id: resolvedCompanyId,
      name: currentUser?.company_name || "Your company",
      industry: currentUser?.industry || null,
      sub_industry: currentUser?.sub_industry || null,
    };

  window.CURRENT_COMPANY = CURRENT_COMPANY;

  if (typeof setupNav === "function") setupNav();

  updateHeaderCompanyBadge?.();
  await populateCompanySwitcher?.();

  CURRENT_COMPANY_ID =
    CURRENT_COMPANY?.id ||
    CURRENT_COMPANY?.company_id ||
    Number(resolvedCompanyId) ||
    null;

  window.CURRENT_COMPANY_ID = CURRENT_COMPANY_ID;

  if (CURRENT_COMPANY && typeof store?.set === "function") {
    store.set("fs_company_profile", CURRENT_COMPANY);
  }

  console.log("bootstrapApp: company resolved", {
    CURRENT_COMPANY_ID,
    companyName: CURRENT_COMPANY?.name,
  });

  // ------------------------------------------------------------
  // 5) Hydrate from backend truth
  // ------------------------------------------------------------
  try {
    await ensureCompanyDataLoaded?.();
    FS.control.syncFromCompany?.(window.CURRENT_COMPANY);
    FS.ui.promptReviewChoice?.(window.CURRENT_COMPANY_ID);

    if (window.CURRENT_COMPANY) {
      CURRENT_COMPANY = window.CURRENT_COMPANY;
    }

    if (typeof setupNav === "function") setupNav();

    if (window.CURRENT_COMPANY_ID) {
      CURRENT_COMPANY_ID = window.CURRENT_COMPANY_ID;
    }

    if (CURRENT_COMPANY && typeof store?.set === "function") {
      store.set("fs_company_profile", CURRENT_COMPANY);
    }
  } catch (e) {
    console.warn("ensureCompanyDataLoaded failed:", e);
  }

  // ------------------------------------------------------------
  // 6) Continue existing flow
  // ------------------------------------------------------------
  const addr =
    CURRENT_COMPANY?.physical_address ||
    CURRENT_COMPANY?.postal_address ||
    "";

  FS.policy.isOwnerUser = function (cid) {
    const me = window.currentUser || {};
    const company = window.CURRENT_COMPANY || {};
    const ownerId = company.owner_user_id;
    return ownerId != null && me.id != null && String(ownerId) === String(me.id);
  };

  async function maybeRequireOwnerInvite() {
    const cid = getActiveCompanyId?.() || window.CURRENT_COMPANY_ID;
    if (!cid) return;

    let company = window.CURRENT_COMPANY;

    if (!company || Number(company.id) !== Number(cid) || company.owner_user_id === undefined) {
      try {
        company = await apiFetch(`/api/companies/${encodeURIComponent(cid)}`, { method: "GET" });
        window.CURRENT_COMPANY = company;
      } catch (e) {
        console.warn("[OwnerInvite] could not load company profile", e);
        return;
      }
    }

    const ownerUserId = company.owner_user_id || company.ownerUserId || null;

    if (!ownerUserId) {
      FS.modePrompt.open({
        title: "Invite the Owner",
        message:
          "This company must have an Owner. Invite the Owner to complete setup and approvals.",
        bullets: [
          "Owner can approve customers and post invoices",
          "You can still capture drafts and prepare work",
        ],
        enableLabel: "Invite Owner",
        keepLabel: "Later",
        onEnable: async () => {
          switchScreen?.("users");
          setTimeout(() => document.getElementById("inviteEmail")?.focus(), 50);
        },
        onKeep: () => {},
      });
    }
  }

  try {
    await ensureCompanyDataLoaded();
    FS.ui.promptReviewChoice?.(CURRENT_COMPANY_ID);
  } catch (e) {
    console.warn("ensureCompanyDataLoaded failed:", e);
  }

  if (typeof hydrateCompanyTaxUI === "function") {
    hydrateCompanyTaxUI(CURRENT_COMPANY);
  } else {
    console.warn("hydrateCompanyTaxUI() missing - skipped");
  }

  if (addr && typeof initCompanyMapFromAddress === "function") {
    initCompanyMapFromAddress(addr);
  } else if (addr) {
    console.warn("initCompanyMapFromAddress() missing - skipped");
  }

  if (!isDelegatedPosting) {
    await maybeRequireOwnerInvite();
  }

  // ------------------------------------------------------------
  // 7) Mode + nav
  // ------------------------------------------------------------
  if (!isDelegatedPosting) {
    if (typeof applyMode === "function") {
      $("#modeSelect")?.addEventListener?.("change", applyMode);
      applyMode();
    } else {
      console.warn("applyMode() missing - skipped");
    }
  } else {
    console.log("bootstrapApp: skipping applyMode in delegated workspace");
  }

  if (typeof setupNav === "function") {
    await setupNav();
  } else {
    console.warn("setupNav() missing - skipped");
  }

  // ------------------------------------------------------------
  // 8) COA + IFRS
  // ------------------------------------------------------------
  try {
    await fetchCOAReal();
  } catch (e) {
    console.error(e);
    COA = store.get(K.COA, []);
  }

  buildCoaIndex();
  populateAccountSelects();

  // ------------------------------------------------------------
  // 9) Logged-in header
  // ------------------------------------------------------------
  if (typeof applyAuthUI === "function") applyAuthUI(currentUser);

  window.currentUser = currentUser;
  localStorage.setItem("fs_user", JSON.stringify(currentUser || {}));
  await initHeaderCompanySwitcher?.();

  console.log("[BOOT] before initDashboardModeSwitcher", {
    isDelegatedPosting,
    postingCtx,
    delegatedFlag: window.__FS_DELEGATED_POSTING__,
    postingContextGlobal: window.__FS_POSTING_CONTEXT__,
    href: location.href
  });

  if (typeof initDashboardModeSwitcher === "function") {
    initDashboardModeSwitcher(isDelegatedPosting ? "delegated" : "internal");
  } else {
    console.warn("initDashboardModeSwitcher() missing - skipped");
  }

  // ------------------------------------------------------------
  // 7) Binders & initial renders (UNCHANGED — your full list)
  // ------------------------------------------------------------
  if (typeof loadDashboard === "function") loadDashboard();
  if (typeof bindCOA === "function") bindCOA();
  if (typeof initJournalUI === "function") initJournalUI();
  if (typeof bindPnL === "function") bindPnL();
  if (typeof bindInvoicePostingUI === "function") bindInvoicePostingUI();
  if (typeof bindLedger === "function") bindLedger();
  if (typeof bindTB === "function") bindTB();
  if (typeof bindReports === "function") bindReports();
  //if (typeof bindCustomers === "function") bindCustomers();
  //if (typeof bindCustomerContactsUI === "function") bindCustomerContactsUI();
  //if (typeof bindCustomersKyc === "function") bindCustomersKyc();
  if (typeof updateKycDashboardBadges === "function") updateKycDashboardBadges();
  if (typeof bindCustomerApprovals === "function") bindCustomerApprovals();
  if (typeof bindVendors === "function") bindVendors();
  if (typeof bindAR === "function") bindAR();
  if (typeof wireQuotesScreen === "function") wireQuotesScreen();
  if (typeof bindAP === "function") bindAP();
  if (typeof initUsersScreen === "function") initUsersScreen();
  if (typeof bindVatSettingsForm === "function") bindVatSettingsForm();
  if (typeof bindCoaFilters === "function") bindCoaFilters();
  if (typeof expandVatForSimpleInvoice === "function") expandVatForSimpleInvoice();
  if (typeof getVatAccounts === "function") getVatAccounts();
  if (typeof vatPeriodLabel === "function") vatPeriodLabel();
  if (typeof bindFixedAssets === "function") bindFixedAssets();
  if (typeof bindInventory === "function") bindInventory();
  if (typeof bindPosSummaries === "function") bindPosSummaries();
  if (typeof bindServiceJobsUI === "function") bindServiceJobsUI();
  if (typeof bindQuickBillingUI === "function") bindQuickBillingUI();
  if (typeof bindCoaDrawer === "function") bindCoaDrawer();
  if (typeof bindReportsScreen === "function") bindReportsScreen();
  if (typeof bindLeaseWizard === "function") bindLeaseWizard();
  if (typeof bindLeaseTabs === "function") bindLeaseTabs();   // ✅ ADD THIS
  if (typeof bindBankScreen === "function") bindBankScreen();
  if (typeof bindBankSetupScreen === "function") bindBankSetupScreen();
  if (typeof populateInvoiceBankSelect === "function") populateInvoiceBankSelect();

  bindHeaderAuthButtons();
  bindGlobalAuthButtons();

  // floating filter panel close/open
  document.getElementById("closeFilterPanel")?.addEventListener("click", () => {
    const panel = document.getElementById("coaFilterFloating");
    if (panel) panel.style.display = "none";
  });

  document.getElementById("openFilterPanel")?.addEventListener("click", () => {
    const panel = document.getElementById("coaFilterFloating");
    if (panel) panel.style.display = "block";
  });

  // ✅ FIX: template strings here (these crash later)
  document.getElementById("btnPostApprovedInvoices")?.addEventListener("click", async () => {
    const cid = getActiveCompanyId();
    try {
      const res = await apiFetch(
        `${ENDPOINTS.company(cid)}/invoices/post_approved`,
        { method: "POST" }
      );
      alert(`Posted: ${res.posted?.length || 0}, Failed: ${res.failed?.length || 0}`);
      await loadInvoices(cid);
    } catch (e) {
      console.error("Bulk post approved invoices failed:", e);
      alert("Bulk post failed. Check console/server logs.");
    }
  });

  document.getElementById("invCustomerId")?.addEventListener("change", (e) => {
    const customerId = Number(e.target.value || 0) || null;
    renderCustomerHighlights(customerId);
  });

  // Initial renders (UNCHANGED)
  if (typeof renderCOATable === "function") renderCOATable(COA);

  if (typeof renderTB === "function") renderTB();
  if (typeof renderPnLMini === "function") renderPnLMini();
  if (typeof renderBSMini === "function") renderBSMini();
  if (typeof renderServicesDatalists === "function") renderServicesDatalists();
  if (typeof fillCounterpartyLists === "function") fillCounterpartyLists();
  if (typeof renderCustomers === "function") renderCustomers();
  if (typeof renderVendors === "function") renderVendors();
  if (typeof renderAR === "function") renderAR();
  if (typeof renderARAging === "function") renderARAging();
  if (typeof renderAP === "function") renderAP();
  if (typeof renderAPAging === "function") renderAPAging();
  if (typeof renderStatementViewer === "function") renderStatementViewer();
  if (typeof renderServices === "function") renderServices();
  if (typeof renderInventory === "function") renderInventory();
  if (typeof renderPosSummaries === "function") renderPosSummaries();
  if (typeof renderCashFlow === "function") renderCashFlow();
  if (typeof bindPnLDetailMode === "function") bindPnLDetailMode();

  // VAT screen + VAT ledgers
  if (typeof ensureVatScreen === "function") ensureVatScreen();
  if (typeof bindVatScreen === "function") bindVatScreen();
  if (typeof bindVatSettingsForm === "function") bindVatSettingsForm();

  if (typeof renderVatLedgerForAccount === "function" && typeof getVatAccounts === "function") {
    const { input, output } = getVatAccounts();

    const inputHost = document.getElementById("vatInputLedgerTable");
    const outputHost = document.getElementById("vatOutputLedgerTable");

    if (inputHost && input && input[0]) {
      renderVatLedgerForAccount(input[0].code, inputHost, "Input");
    }
    if (outputHost && output && output[0]) {
      renderVatLedgerForAccount(output[0].code, outputHost, "Output");
    }
  }

  if (typeof renderFixedAssets === "function") renderFixedAssets();

  // Dashboard widgets / final screen
  const urlParams = new URLSearchParams(window.location.search);
  if (urlParams.get("action") === "confirm_success") {
    switchScreen("dashboard");
    return;
  }
  if (urlParams.get("action") === "confirm" && urlParams.get("token")) {
    handleSigninClick({ preventDefault: () => {} });
    return;
  }

  // Mount React Fixed Assets drawer once
  if (typeof window.FS_MOUNT_FIXED_ASSETS_DRAWER === "function") {
    window.FS_MOUNT_FIXED_ASSETS_DRAWER();
  } else {
    console.warn("[PPE] mount function missing: FS_MOUNT_FIXED_ASSETS_DRAWER");
  }

  // ✅ If redirected from signin.html with #screen=..., honor it once
  let routedFromHash = false;
  (function openIntendedFromHash() {
    const m = window.location.hash.match(/screen=([^&]+)/);
    if (!m) return;

    const screen = decodeURIComponent(m[1] || "");
    if (!screen) return;

    routedFromHash = true;

    // clear hash so refresh doesn’t keep forcing it
    history.replaceState(null, "", window.location.pathname);

    switchScreen(screen);
  })();

  // ✅ Default route
  if (!routedFromHash) {
    switchScreen(store.get(K.CURRENT_SCREEN, "dashboard"));
  }
}

window.bootstrapApp = bootstrapApp;


/* ==============================
 * FINAL init wrapper
 * ============================== */
async function enforceAuth() {
  const token = window.getToken?.();
  console.log("enforceAuth: token from storage =", token);

  if (!token) {
    window.currentUser = null;
    return null;
  }

  try {
    const me = await window.apiFetch(window.ENDPOINTS.auth.me, { method: "GET" });
    window.currentUser = me;
    return me;
  } catch (err) {
    console.warn("enforceAuth: /me failed", err?.status, err?.message, err?.url);

    if (err?.status === 401 || err?.status === 403) {
      window.clearToken?.(); // ✅ only if truly unauthorized
    }

    window.currentUser = null;
    return null;
  }
}
window.enforceAuth = enforceAuth;

async function init() {
  const token = window.getToken?.();
  if (!token) {
    window.applyLoggedOutUI?.();
    window.switchScreen?.("sign-in");
    return;
  }

  const me = await window.enforceAuth?.();
  if (!me) {
    window.applyLoggedOutUI?.();
    window.switchScreen?.("sign-in");
    return;
  }

  const postingCtx =
    window.FS_DELEGATED_WORKSPACE?.restorePostingContext?.() ||
    window.restorePostingContext?.() ||
    null;

  const isDelegated =
    !!postingCtx &&
    (postingCtx.launchMode === "posting" || postingCtx.accessMode === "delegated_workspace");

  const cid =
    (isDelegated
      ? Number(postingCtx?.targetCompanyId || postingCtx?.companyId || 0)
      : (me.company_id || me.companyId || me.company?.id || Number(localStorage.getItem("company_id") || 0))
    ) || null;

  if (!cid) {
    window.applyLoggedInUI?.(me);
    window.switchScreen?.("company");
    return;
  }

  localStorage.setItem("company_id", String(cid));
  window.applyLoggedInUI?.(me);

  await window.bootstrapApp?.(me);
}
  window.init = init;

